INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, cefr, topic_id, priority, sort_order, image_keyword, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, ex4, ex4_ko, ex5, ex5_ko) VALUES
('col_academic_03','take','notes','take notes','필기하다','write','"write notes"도 맞지만 take notes는 수업 중에 필기하는 것을 강조해요.','A2','academic',1,3,'notes study lecture writing class','He always takes detailed notes during lectures.','그는 항상 강의 중에 자세한 필기를 해요.','Taking good notes helps you review the material more effectively.','좋은 필기를 하면 내용을 더 효과적으로 복습할 수 있어요.','She takes notes by hand because it helps her remember better.','그녀는 더 잘 기억하기 위해 손으로 필기해요.','He takes notes on his tablet during all his classes.','그는 모든 수업에서 태블릿으로 필기해요.','Taking notes during a discussion is harder than during a lecture.','토론 중에 필기하는 것은 강의 중보다 더 어려워요.'),
('col_academic_21','do','research','do research','연구하다','make','"make research"는 틀린 표현. 연구 활동은 do/conduct research.','A2','academic',1,0,'researcher lab books data analysis','She''s doing research on climate change.','그녀는 기후 변화에 관한 연구를 하고 있어요.','I did extensive research before writing the paper.','논문을 쓰기 전에 광범위한 연구를 했어요.','They do research at one of the top universities.','그들은 최고 대학 중 한 곳에서 연구를 해요.','Doing research requires patience and discipline.','연구는 인내와 규율이 필요해요.','How long did you do research for this project?','이 프로젝트를 위해 얼마나 오래 연구했어요?'),
('col_academic_23','attend','class','attend a class','수업에 출석하다','take','"take a class"는 수강 신청한다는 의미. 그날 출석한다는 의미는 attend a class.','A2','academic',1,0,'classroom students lecture attendance university','She attends every class without missing one.','그녀는 모든 수업에 빠지지 않고 출석해요.','I attended a fascinating class on philosophy.','저는 흥미로운 철학 수업에 출석했어요.','Students are required to attend at least 80% of classes.','학생들은 수업의 80% 이상을 출석해야 해요.','He didn''t attend class because he was sick.','그는 아파서 수업에 출석하지 못했어요.','I plan to attend the morning class instead.','대신 아침 수업에 출석할 계획이에요.'),
('col_academic_01','submit','an essay','submit an essay','에세이를 제출하다','give','"give an essay"는 어색해요. 과제를 제출할 때는 submit 또는 hand in을 써요.','B1','academic',1,1,'essay submit university assignment deadline','Students must submit their essays by midnight on Friday.','학생들은 금요일 자정까지 에세이를 제출해야 해요.','She submitted her essay a day early to avoid last-minute stress.','그녀는 마지막 순간의 스트레스를 피하기 위해 하루 일찍 에세이를 제출했어요.','I submitted my essay through the online portal at 11:58 p.m.','저는 밤 11시 58분에 온라인 포털을 통해 에세이를 제출했어요.','She submitted her essay early to free up the weekend for studying.','그녀는 주말 공부 시간을 확보하기 위해 일찍 에세이를 제출했어요.','Submitting an essay late usually means a grade penalty.','에세이를 늦게 제출하면 보통 성적 감점이 있어요.'),
('col_academic_02','attend','a lecture','attend a lecture','강의에 참석하다','go','"go to a lecture"도 맞지만 attend는 더 격식 있는 표현이에요.','B1','academic',1,2,'lecture university class attend study','She attended every lecture despite having a part-time job.','그녀는 아르바이트를 하면서도 모든 강의에 참석했어요.','Students who attend lectures regularly tend to perform better in exams.','강의에 규칙적으로 참석하는 학생들은 시험에서 더 좋은 성과를 내는 경향이 있어요.','She attended every lecture even when she was tired.','그녀는 피곤할 때도 모든 강의에 참석했어요.','You can attend a lecture from home if the class allows it.','수업이 허용하면 집에서 강의에 참석할 수 있어요.','Attending a lecture in person often helps you stay focused.','직접 강의에 참석하는 것이 집중에 도움이 되는 경우가 많아요.'),
('col_academic_04','pass','an exam','pass an exam','시험에 합격하다','succeed','"succeed in an exam"도 맞지만 pass an exam이 훨씬 더 자연스러운 표현이에요.','B1','academic',1,4,'exam pass study success university','She worked very hard and passed all her exams with distinction.','그녀는 매우 열심히 공부해서 모든 시험에 우수한 성적으로 합격했어요.','You need to pass the exam to qualify for the next level.','다음 단계로 진급하려면 시험에 합격해야 해요.','She passed her TOEFL exam on her first try.','그녀는 첫 번째 시도에 토플 시험에 합격했어요.','He didn''t expect to pass the exam but he did.','그는 시험에 합격할 줄 몰랐는데 합격했어요.','Passing an exam takes preparation, but also a clear mind on the day.','시험에 합격하려면 준비와 함께 당일의 맑은 정신도 필요해요.'),
('col_academic_05','enrol in','a course','enrol in a course','과정에 등록하다','join','"join a course"도 쓰이지만 enrol in은 공식적인 등록 절차를 강조해요.','B1','academic',1,5,'enrolment course university study registration','She enrolled in an online course to improve her academic writing.','그녀는 학문적 글쓰기를 향상시키기 위해 온라인 과정에 등록했어요.','How many students enrolled in the linguistics course this year?','올해 언어학 과정에 몇 명의 학생이 등록했어요?','She enrolled in a postgraduate course at the same university.','그녀는 같은 대학에서 대학원 과정에 등록했어요.','He enrolled in a course taught entirely in Spanish.','그는 전적으로 스페인어로 진행되는 과정에 등록했어요.','Enrolling in a course can be done online in many universities now.','이제 많은 대학에서 온라인으로 과정에 등록할 수 있어요.'),
('col_academic_07','earn','a degree','earn a degree','학위를 취득하다','get','"get a degree"도 맞지만 earn은 노력을 통해 성취한다는 뉘앙스예요.','B1','academic',1,7,'degree university graduation achievement education','She earned a degree in computer science from Seoul National University.','그녀는 서울대학교에서 컴퓨터공학 학위를 취득했어요.','He earned his degree while working full-time at a technology company.','그는 기술 회사에서 전일제로 일하면서 학위를 취득했어요.','She earned a degree in linguistics through a part-time program.','그녀는 시간제 프로그램을 통해 언어학 학위를 취득했어요.','He earned a degree later in life after raising his children.','그는 아이들을 키운 후 늦은 나이에 학위를 취득했어요.','Earning a degree abroad changed her career path entirely.','해외에서 학위를 취득한 것이 그녀의 진로를 완전히 바꿨어요.'),
('col_academic_10','apply','for a scholarship','apply for a scholarship','장학금을 신청하다','get','"get a scholarship"도 맞지만 apply for는 신청 과정을 강조해요. 먼저 신청해야 받을 수 있어요.','B1','academic',1,10,'scholarship university funding apply education','She applied for a scholarship to fund her postgraduate studies.','그녀는 대학원 학업 자금을 마련하기 위해 장학금을 신청했어요.','You should apply for as many scholarships as you are eligible for.','자격이 되는 장학금에 최대한 많이 신청해야 해요.','She applied for a scholarship aimed at first-generation students.','그녀는 1세대 학생들을 위한 장학금에 신청했어요.','He applied for several scholarships and received two.','그는 여러 장학금에 신청했고 두 개를 받았어요.','Applying for a scholarship takes time, but it''s worth the effort.','장학금 신청에는 시간이 걸리지만 그만한 노력의 가치가 있어요.'),
('col_academic_14','meet','a deadline','meet a deadline','마감 기한을 맞추다','do','"do a deadline"은 틀린 표현이에요. 마감 기한을 지킬 때는 meet a deadline을 써요.','B1','academic',1,14,'deadline time management university assignment','She struggled to meet the deadline for her research paper.','그녀는 연구 논문의 마감 기한을 맞추기 위해 애썼어요.','Good time management is essential if you want to meet every deadline.','모든 마감 기한을 맞추고 싶다면 좋은 시간 관리가 필수예요.','She always meets her deadlines, even during exam weeks.','그녀는 시험 주간에도 항상 마감 기한을 맞춰요.','He met the deadline with just thirty seconds to spare.','그는 30초 여유를 두고 마감 기한을 맞췄어요.','Meeting a deadline consistently builds professional trust.','마감 기한을 꾸준히 맞추는 것이 전문적인 신뢰를 쌓아요.'),
('col_academic_15','score','high marks','score high marks','높은 점수를 받다','get','"get high marks"도 맞지만 score는 시험이나 과제에서 특정 점수를 얻는 것을 강조해요.','B1','academic',1,15,'marks score exam grade university','She scored the highest marks in the class on the final exam.','그녀는 기말고사에서 반에서 가장 높은 점수를 받았어요.','Hard work and preparation are the keys to scoring high marks.','열심히 공부하고 준비하는 것이 높은 점수를 받는 열쇠예요.','He scored high marks on the literature exam despite his nerves.','그는 긴장에도 불구하고 문학 시험에서 높은 점수를 받았어요.','She scored high marks in subjects she actually enjoyed.','그녀는 실제로 좋아하는 과목에서 높은 점수를 받았어요.','Scoring high marks is great, but real understanding matters more.','높은 점수를 받는 것도 좋지만 진정한 이해가 더 중요해요.'),
('col_academic_16','take','a gap year','take a gap year','갭이어를 갖다','do','"do a gap year"도 쓰이지만 take a gap year가 훨씬 더 자연스러운 표현이에요.','B1','academic',1,16,'gap year travel university experience education','She decided to take a gap year before starting her university studies.','그녀는 대학 공부를 시작하기 전에 갭이어를 갖기로 결심했어요.','Many students take a gap year to travel and gain real-world experience.','많은 학생들이 여행하고 실제 경험을 쌓기 위해 갭이어를 가져요.','He took a gap year to teach English in rural Vietnam.','그는 갭이어를 가져 베트남 시골에서 영어를 가르쳤어요.','She took a gap year and came back with a clearer career plan.','그녀는 갭이어를 가지고 더 명확한 진로 계획을 가지고 돌아왔어요.','Taking a gap year is a personal decision with many possibilities.','갭이어를 갖는 것은 많은 가능성을 지닌 개인적인 결정이에요.'),
('col_academic_22','write','paper','write a paper','논문을 쓰다','make','"make a paper"는 종이접기에 가까운 표현. 학술 논문은 write a paper.','B1','academic',1,0,'researcher writing laptop academic paper desk','I''m writing a paper on renewable energy.','신재생 에너지에 관한 논문을 쓰고 있어요.','She wrote her first paper as an undergraduate.','그녀는 학부생 때 첫 논문을 썼어요.','Writing a paper takes weeks of preparation.','논문을 쓰려면 몇 주의 준비가 필요해요.','He wrote a paper that was later published.','그는 나중에 출판된 논문을 썼어요.','I need to write a paper for the conference.','학회 발표를 위한 논문을 써야 해요.'),
('col_academic_24','give','lecture','give a lecture','강의를 하다','do','"do a lecture"는 어색해요. 강의는 give a lecture가 표준.','B1','academic',1,0,'professor lecture podium auditorium audience','Professor Kim is giving a lecture on quantum physics.','김 교수는 양자물리학에 관한 강의를 해요.','She gave a brilliant lecture last Tuesday.','그녀는 지난 화요일 멋진 강의를 했어요.','I''ve given lectures at several universities.','저는 여러 대학에서 강의를 한 적이 있어요.','The visiting scholar will give a lecture tonight.','초청 학자가 오늘 밤 강의를 할 거예요.','He gives a lecture every Friday morning.','그는 매주 금요일 아침에 강의를 해요.'),
('col_academic_06','write','a thesis','write a thesis','논문을 쓰다','make','"make a thesis"는 어색해요. 학위 논문을 작성할 때는 write a thesis를 써요.','B2','academic',2,6,'thesis research writing university graduate','He spent two years writing his doctoral thesis.','그는 박사 학위 논문을 쓰는 데 2년을 보냈어요.','Writing a thesis requires strong research and critical thinking skills.','논문을 쓰는 것은 강한 연구 및 비판적 사고 능력을 요구해요.','She wrote her thesis on women in early Korean cinema.','그녀는 초기 한국 영화의 여성에 관한 논문을 썼어요.','Writing a thesis is a marathon, not a sprint.','논문을 쓰는 것은 마라톤이지 단거리 경주가 아니에요.','He wrote his thesis while teaching part-time.','그는 시간제로 가르치면서 논문을 썼어요.'),
('col_academic_08','review','the literature','review the literature','문헌을 검토하다','read','"read the literature"도 맞지만 review는 비판적으로 검토하고 종합하는 뉘앙스예요.','B2','academic',2,8,'literature review research academic study','The first step in any research project is to review the existing literature.','모든 연구 프로젝트의 첫 번째 단계는 기존 문헌을 검토하는 것이에요.','She reviewed the literature to identify gaps in current research.','그녀는 현재 연구의 공백을 파악하기 위해 문헌을 검토했어요.','Before designing the study, she carefully reviewed the literature.','연구를 설계하기 전에 그녀는 문헌을 신중하게 검토했어요.','Reviewing the literature can take a few months for a thesis.','논문을 위해 문헌을 검토하는 데 몇 달이 걸릴 수 있어요.','He reviewed the literature and found a clear research gap.','그는 문헌을 검토하고 명확한 연구 공백을 발견했어요.'),
('col_academic_09','formulate','a hypothesis','formulate a hypothesis','가설을 세우다','make','"make a hypothesis"도 쓰이지만 formulate는 더 체계적이고 논리적인 과정을 강조해요.','B2','academic',2,9,'hypothesis science research experiment study','The scientist formulated a hypothesis based on her preliminary observations.','과학자는 예비 관찰을 바탕으로 가설을 세웠어요.','Students must formulate a clear hypothesis before beginning their experiments.','학생들은 실험을 시작하기 전에 명확한 가설을 세워야 해요.','She formulated a hypothesis about sleep and language learning.','그녀는 수면과 언어 학습에 관한 가설을 세웠어요.','Formulating a hypothesis is one of the first steps in research.','가설을 세우는 것은 연구의 첫 단계 중 하나예요.','He formulated a hypothesis that his data later supported.','그는 후에 데이터가 뒷받침한 가설을 세웠어요.'),
('col_academic_11','sit','an exam','sit an exam','시험을 치르다','take','"take an exam"도 맞고 자주 쓰여요. sit an exam은 영국 영어에서 더 격식 있게 쓰여요.','B2','academic',2,11,'exam university test hall formal','Students must sit the final exam in the examination hall.','학생들은 시험장에서 최종 시험을 치러야 해요.','She sat the entrance exam three times before passing.','그녀는 합격하기까지 입학시험을 세 번 치렀어요.','Students sit the entrance exam in a large hall each November.','학생들은 매년 11월에 대형 강당에서 입학시험을 치러요.','He sat his final exam after months of preparation.','그는 몇 달의 준비 끝에 최종 시험을 치렀어요.','Sitting an exam in another country was a strange experience.','다른 나라에서 시험을 치르는 것은 낯선 경험이었어요.'),
('col_academic_17','pursue','a degree','pursue a degree','학위 취득을 추구하다','study for','"study for a degree"도 맞지만 pursue는 더 목표 지향적인 뉘앙스예요.','B2','academic',2,17,'degree university pursue education goal','She decided to pursue a degree in international relations.','그녀는 국제 관계학 학위 취득을 추구하기로 결심했어요.','He pursued a degree online while working full-time.','그는 전일제로 일하면서 온라인으로 학위 취득을 추구했어요.','She pursued a degree in nursing in her late thirties.','그녀는 30대 후반에 간호학 학위 취득을 추구했어요.','He pursued a degree to change careers from finance to teaching.','그는 금융에서 교직으로 진로를 바꾸기 위해 학위 취득을 추구했어요.','Pursuing a degree later in life takes courage and planning.','인생 후반에 학위 취득을 추구하려면 용기와 계획이 필요해요.'),
('col_academic_18','conduct','an experiment','conduct an experiment','실험을 수행하다','do','"do an experiment"도 맞지만 conduct는 더 체계적이고 격식 있는 실험을 강조해요.','B2','academic',2,18,'experiment science research lab university','The lab conducted an experiment to test the new drug''s effectiveness.','실험실은 새로운 약의 효과를 시험하는 실험을 수행했어요.','Students conducted an experiment to observe the effects of temperature on plant growth.','학생들은 온도가 식물 성장에 미치는 영향을 관찰하기 위해 실험을 수행했어요.','They conducted an experiment to compare two teaching methods.','그들은 두 가지 교수법을 비교하기 위해 실험을 수행했어요.','She conducted an experiment that produced unexpected results.','그녀는 예상치 못한 결과를 낸 실험을 수행했어요.','Conducting an experiment with humans requires ethics approval.','인간을 대상으로 실험을 수행하려면 윤리 승인이 필요해요.'),
('col_academic_19','achieve','academic excellence','achieve academic excellence','학문적 우수성을 달성하다','get','"get academic excellence"는 어색해요. 탁월한 성과를 이룰 때는 achieve를 써요.','B2','academic',2,19,'excellence achievement academic university success','Her goal is to achieve academic excellence throughout her studies.','그녀의 목표는 학업 기간 동안 학문적 우수성을 달성하는 것이에요.','Universities offer scholarships to students who achieve academic excellence.','대학들은 학문적 우수성을 달성한 학생들에게 장학금을 제공해요.','She achieved academic excellence despite working two jobs.','그녀는 두 가지 일을 하면서도 학문적 우수성을 달성했어요.','Achieving academic excellence requires consistency, not perfection.','학문적 우수성을 달성하려면 완벽함이 아닌 일관성이 필요해요.','He achieved academic excellence through curiosity, not pressure.','그는 압박이 아닌 호기심을 통해 학문적 우수성을 달성했어요.'),
('col_academic_12','plagiarise','work','plagiarise work','작업물을 표절하다','copy','"copy work"도 맞지만 plagiarise는 다른 사람의 작업을 자신의 것처럼 제출하는 구체적인 행위예요.','C1','academic',3,12,'plagiarism academic integrity essay university','Students who plagiarise work face serious academic consequences.','작업물을 표절한 학생들은 심각한 학문적 결과에 직면해요.','Always cite your sources — plagiarising even a paragraph is unacceptable.','항상 출처를 인용하세요. 단 하나의 단락을 표절하는 것도 용납되지 않아요.','Universities use software to detect students who plagiarise work.','대학들은 작업물을 표절하는 학생들을 적발하기 위해 소프트웨어를 사용해요.','Plagiarising work, even unintentionally, has serious consequences.','의도하지 않았더라도 작업물을 표절하는 것은 심각한 결과를 가져와요.','Citing properly is the best way to avoid plagiarising work.','적절히 인용하는 것이 작업물 표절을 피하는 가장 좋은 방법이에요.'),
('col_academic_13','defend','a thesis','defend a thesis','논문을 구두 심사에서 발표하다','present','"present a thesis"도 맞지만 defend는 심사위원의 질문에 답하는 구두 시험을 강조해요.','C1','academic',3,13,'thesis defense PhD university examination','She successfully defended her thesis in front of a panel of professors.','그녀는 교수 심사 패널 앞에서 논문을 성공적으로 발표했어요.','Defending your thesis is one of the most challenging parts of a PhD.','논문 구두 심사는 박사 과정에서 가장 도전적인 부분 중 하나예요.','She defended her thesis virtually due to the pandemic.','그녀는 팬데믹으로 인해 가상으로 논문을 발표했어요.','He defended his thesis to a panel of leading scholars.','그는 저명한 학자들로 구성된 패널 앞에서 논문을 발표했어요.','Defending a thesis is intimidating but also a milestone.','논문 구두 심사는 두렵지만 동시에 큰 이정표이기도 해요.'),
('col_academic_20','peer-review','a paper','peer-review a paper','논문을 동료 심사하다','check','"check a paper"도 맞지만 peer-review는 학문적 품질 검증의 공식 절차를 강조해요.','C1','academic',3,20,'peer review academic journal research paper','All research papers submitted to the journal are peer-reviewed.','저널에 제출된 모든 연구 논문은 동료 심사를 받아요.','She was asked to peer-review a paper on climate science.','그녀는 기후 과학에 관한 논문을 동료 심사해 달라는 요청을 받았어요.','She was asked to peer-review a paper on early childhood education.','그녀는 유아 교육에 관한 논문을 동료 심사해 달라는 요청을 받았어요.','He peer-reviews papers in his field about twice a year.','그는 자기 분야의 논문을 1년에 약 두 번 동료 심사해요.','Peer-reviewing a paper takes hours of careful reading.','논문을 동료 심사하는 데는 신중한 독해의 시간이 필요해요.'),
('col_academic_C1_01','conduct','research','conduct research','연구를 수행하다','do','학술적 맥락에서는 ''do research''보다 ''conduct research''가 표준이에요. 논문, 보고서, 학회 발표에서 자주 써요.','C1','academic',2,0,'research laboratory','Her team conducted research on bilingual cognition over five years.','그녀의 팀은 5년에 걸쳐 이중 언어 인지에 관한 연구를 수행했어요.','The institute conducts research into renewable energy policy.','그 연구소는 재생에너지 정책에 관한 연구를 수행해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_academic_C1_02','publish','findings','publish findings','연구 결과를 발표하다','show','연구 결과를 학술지나 보고서 형태로 공식 공개한다는 표현이에요. 학계의 핵심 동사예요.','C1','academic',2,0,'academic journal','The professor published her findings in a peer-reviewed journal last month.','그 교수는 지난달 동료 심사 저널에 자신의 연구 결과를 발표했어요.','They plan to publish their findings at the international conference.','그들은 국제 학회에서 연구 결과를 발표할 계획이에요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_academic_C1_03','review','literature','review the literature','선행 연구를 검토하다','read','논문 작성 초기에 관련 선행 연구를 체계적으로 살펴본다는 학술적 표현이에요. ''literature review''라는 명사형도 자주 써요.','C1','academic',2,0,'library bookshelves','Before formulating her hypothesis, she reviewed the literature thoroughly.','가설을 세우기 전에 그녀는 선행 연구를 철저히 검토했어요.','Doctoral candidates must review the literature in their field extensively.','박사 과정 학생들은 자신의 분야에서 선행 연구를 폭넓게 검토해야 해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_academic_C1_04','test','hypotheses','test hypotheses','가설을 검증하다','try','가설이 맞는지 실험이나 데이터 분석으로 확인한다는 과학적 표현이에요. ''hypothesis''의 복수형은 ''hypotheses''예요.','C1','academic',2,0,'scientific experiment','The experiment was designed to test several competing hypotheses.','그 실험은 경쟁하는 여러 가설들을 검증하기 위해 설계됐어요.','Researchers test hypotheses using rigorous statistical methods.','연구자들은 엄격한 통계 방법을 사용해 가설을 검증해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_academic_C1_05','draw','conclusions','draw conclusions','결론을 도출하다','make','데이터나 증거를 바탕으로 결론에 이른다는 학술적 표현이에요. ''make a conclusion''은 자연스럽지 않아요.','C1','academic',2,0,'data analysis chart','It is premature to draw conclusions from such a small sample size.','이렇게 작은 표본에서 결론을 도출하기에는 시기상조예요.','The author draws compelling conclusions from the data.','저자는 데이터로부터 설득력 있는 결론을 도출해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_academic_C2_01','advance','thesis','advance a thesis','논지를 제시하다','say','논문이나 학술 토론에서 자신의 주장을 공식적으로 내세울 때 써요. ''say''는 단순 발화라 학술 맥락에 부족해요.','C2','academic',3,0,'lecture podium','In her keynote, she advanced a provocative thesis on post-colonial historiography.','기조 연설에서 그녀는 탈식민 역사 서술에 관한 도발적인 논지를 제시했어요.','The author advances the thesis that institutional inertia underpins systemic failure.','저자는 제도적 관성이 체계적 실패의 근간이라는 논지를 제시해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_academic_C2_02','substantiate','claim','substantiate a claim','주장을 입증하다','prove','근거와 자료로 주장을 뒷받침한다는 학술적 표현이에요. ''prove''는 결론적인 증명, ''substantiate''는 근거 제시에 가까워요.','C2','academic',3,0,'research data','The reviewers asked the authors to substantiate their claims with longitudinal data.','심사위원들은 저자들에게 종단 자료로 주장을 입증하라고 요청했어요.','Without primary sources, it is difficult to substantiate such a sweeping claim.','1차 사료 없이는 그렇게 광범위한 주장을 입증하기 어려워요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_academic_C2_03','rebut','argument','rebut an argument','논거를 반박하다','deny','상대의 논거를 근거를 들어 정식으로 반박할 때 써요. ''deny''는 단순 부정이라 학술 토론에 약해요.','C2','academic',3,0,'academic debate','The discussant rebutted the central argument with a series of counterexamples.','토론자는 일련의 반례를 들어 핵심 논거를 반박했어요.','Her latest paper rebuts the prevailing argument on monetary neutrality.','그녀의 최신 논문은 화폐 중립성에 관한 지배적인 논거를 반박해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_academic_C2_04','synthesize','findings','synthesize findings','연구 결과를 종합하다','combine','여러 연구의 결과를 비판적으로 통합한다는 학술 전문 용어예요. ''combine''은 단순 결합이라 의미가 약해요.','C2','academic',3,0,'research papers','The meta-analysis synthesizes findings from forty-three randomized trials.','메타분석은 43건의 무작위 시험 결과를 종합해요.','In her dissertation she synthesizes findings across three disciplines.','박사 논문에서 그녀는 세 학문 분야의 연구 결과를 종합해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_academic_C2_05','operationalize','concept','operationalize a concept','개념을 조작화하다','define','추상적 개념을 측정 가능하게 정의하는 사회과학·심리학 전문 표현이에요. ''define''보다 한 단계 정교한 학술어예요.','C2','academic',3,0,'statistical analysis','The study operationalizes the concept of resilience through three composite indices.','이 연구는 회복탄력성 개념을 세 가지 종합 지수로 조작화해요.','Operationalizing such a nebulous concept poses methodological challenges.','그런 모호한 개념을 조작화하는 일은 방법론적 난제를 낳아요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_body_B1_01','raise','hand','raise your hand','손을 들다','lift','교실에서 질문이나 발표할 때 ''raise''가 자연스러워요. ''lift''는 무거운 물건을 들 때 써요.','B1','body',1,0,'raising hand classroom','Please raise your hand if you have a question.','질문이 있으시면 손을 들어주세요.','She raised her hand to answer first.','그녀는 먼저 답하려고 손을 들었어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_body_B1_02','stretch','legs','stretch your legs','다리를 쭉 펴다','extend','오래 앉아 있다가 일어나 걸을 때 ''stretch your legs''라고 해요. 단순히 늘리는 ''extend''와는 뉘앙스가 달라요.','B1','body',1,0,'stretching legs walk','Let''s stop the car and stretch our legs.','차를 세우고 다리 좀 펴봐요.','I need to stretch my legs after sitting all day.','하루 종일 앉아 있어서 다리를 펴야 해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_body_B1_03','hold','breath','hold your breath','숨을 참다','keep','잠수하거나 긴장될 때 ''hold''를 써요. ''keep your breath''는 어색해요.','B1','body',1,0,'holding breath underwater','Hold your breath when you go underwater.','물속에 들어갈 때 숨을 참으세요.','I held my breath waiting for the results.','결과를 기다리며 숨을 죽였어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_body_B1_04','rub','eyes','rub your eyes','눈을 비비다','scratch','졸리거나 피곤할 때 부드럽게 비비는 동작은 ''rub''이에요. ''scratch''는 가려움을 긁는 거예요.','B1','body',1,0,'rubbing eyes tired','Don''t rub your eyes when they itch.','눈이 가려울 때 비비지 마세요.','He rubbed his eyes and yawned.','그는 눈을 비비며 하품을 했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_body_B1_05','shake','hands','shake hands','악수하다','hold','인사로 손을 흔들어 잡는 행위는 ''shake hands''예요. ''hold hands''는 연인이 손을 잡는 거예요.','B1','body',1,0,'shaking hands business','They shook hands after the meeting.','회의 후에 그들은 악수했어요.','Let''s shake hands and forget about it.','악수하고 잊어버려요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_body_B2_01','tense','muscles','tense up your muscles','근육이 긴장되다','harden','스트레스나 추위로 근육이 굳을 때 ''tense up''을 써요. ''harden''은 물체가 단단해지는 느낌이에요.','B2','body',2,0,'tense muscles stress','My muscles tense up when I''m stressed.','스트레스를 받으면 근육이 긴장돼요.','Try not to tense up your shoulders.','어깨에 힘을 주지 않도록 해보세요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_body_B2_02','loosen','joints','loosen up your joints','관절을 풀다','open','운동 전에 몸을 풀 때 ''loosen up''이 자연스러워요. ''open''은 관절에 어색해요.','B2','body',2,0,'joint stretching warmup','Loosen up your joints before running.','달리기 전에 관절을 풀어주세요.','Gentle stretches will loosen up your joints.','가벼운 스트레칭이 관절을 풀어줘요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_body_B2_03','regain','consciousness','regain consciousness','의식을 되찾다','recover','기절했다가 깨어날 때 ''regain consciousness''가 정확해요. ''recover''는 회복 전반에 써요.','B2','body',2,0,'regain consciousness hospital','He regained consciousness after a few minutes.','그는 몇 분 후에 의식을 되찾았어요.','The patient slowly regained consciousness.','환자는 천천히 의식을 회복했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_body_B2_04','lose','balance','lose your balance','균형을 잃다','drop','미끄러지거나 휘청거릴 때 ''lose your balance''예요. ''drop''은 떨어뜨리는 거예요.','B2','body',2,0,'losing balance slip','I lost my balance on the icy road.','얼어붙은 길에서 균형을 잃었어요.','She lost her balance and fell off the bike.','그녀는 균형을 잃고 자전거에서 떨어졌어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_body_B2_05','catch','breath','catch your breath','숨을 고르다','take','달리고 난 후 숨을 고를 때 ''catch one''s breath''예요. ''take a breath''는 한 번 들이쉬는 거예요.','B2','body',2,0,'catching breath after running','Let me catch my breath before we continue.','계속하기 전에 숨 좀 고를게요.','She paused to catch her breath at the top.','그녀는 정상에서 숨을 고르려고 멈췄어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_body_C1_01','strengthen','core','strengthen the core','코어를 강화하다','thicken','복부와 허리 근육군을 단련할 때 ''strengthen''을 써요. ''thicken''은 살이 두꺼워지는 느낌이라 어색해요.','C1','body',2,0,'core workout plank','Planks help strengthen the core effectively.','플랭크는 코어 강화에 효과적이에요.','A strong core improves overall posture.','강한 코어는 전체 자세를 개선해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_body_C1_02','improve','posture','improve your posture','자세를 개선하다','fix','점진적인 자세 교정에는 ''improve''가 자연스러워요. ''fix''는 즉각적인 수리 느낌이에요.','C1','body',2,0,'good posture office','Yoga can improve your posture over time.','요가는 시간이 지나면서 자세를 개선해줘요.','Sit up straight to improve your posture.','자세를 개선하려면 똑바로 앉으세요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_body_C1_03','maintain','flexibility','maintain flexibility','유연성을 유지하다','keep','꾸준한 노력으로 유지한다는 뉘앙스는 ''maintain''이에요. ''keep''보다 격식 있어요.','C1','body',2,0,'flexibility yoga stretch','Daily stretching helps maintain flexibility.','매일 스트레칭하면 유연성을 유지할 수 있어요.','Dancers must maintain flexibility throughout their career.','무용수들은 평생 유연성을 유지해야 해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_body_C1_04','build','endurance','build endurance','지구력을 기르다','grow','점차 쌓아 올리는 의미로 ''build''가 적합해요. ''grow''는 자연적인 성장 느낌이에요.','C1','body',2,0,'endurance training running','Long runs help build endurance.','장거리 달리기는 지구력을 길러줘요.','It takes months to build endurance for a marathon.','마라톤을 위한 지구력을 기르는 데는 몇 달이 걸려요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_body_C1_05','ease','tension','ease tension','긴장을 풀어주다','remove','서서히 완화시킬 때 ''ease''가 자연스러워요. ''remove''는 완전히 제거하는 강한 의미예요.','C1','body',2,0,'easing tension massage','A warm bath can ease muscle tension.','따뜻한 목욕은 근육 긴장을 풀어줘요.','Deep breathing helps ease tension in the body.','심호흡은 몸의 긴장을 풀어줘요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_body_C2_01','alleviate','strain','alleviate strain','근육 통증을 완화하다','remove','의학적·격식 있는 완화는 ''alleviate''예요. ''remove''는 너무 절대적이에요.','C2','body',3,0,'back strain relief therapy','Proper ergonomics can alleviate strain on the back.','올바른 인체공학은 허리 부담을 완화해줘요.','Physical therapy helps alleviate strain in the joints.','물리치료는 관절의 부담을 완화해줘요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_body_C2_02','rehabilitate','injury','rehabilitate an injury','부상을 재활하다','cure','재활 과정 전체는 ''rehabilitate''예요. ''cure''는 단발성 치료 느낌이에요.','C2','body',3,0,'injury rehabilitation physio','Athletes rehabilitate injuries with specialized programs.','운동선수들은 전문 프로그램으로 부상을 재활해요.','It took six months to rehabilitate her knee injury.','무릎 부상을 재활하는 데 6개월이 걸렸어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_body_C2_03','restore','mobility','restore mobility','움직임을 회복시키다','fix','잃었던 가동 범위를 되찾을 때 ''restore''예요. ''fix''는 단순 수리예요.','C2','body',3,0,'mobility recovery exercise','Surgery helped restore mobility in his shoulder.','수술이 그의 어깨 가동성을 회복시켜 줬어요.','Targeted exercises can restore mobility after injury.','맞춤 운동은 부상 후 가동성을 회복시켜요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_body_C2_04','mitigate','inflammation','mitigate inflammation','염증을 줄이다','kill','염증을 점진적으로 줄일 때 ''mitigate''가 격식 있어요. ''kill''은 너무 강한 표현이에요.','C2','body',3,0,'inflammation reduction ice','Ice packs help mitigate inflammation.','아이스팩은 염증을 줄이는 데 도움이 돼요.','Certain foods can mitigate chronic inflammation.','특정 음식은 만성 염증을 줄여줘요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_body_C2_05','reinforce','musculature','reinforce the musculature','근육 구조를 강화하다','thicken','근육 시스템 전체를 보강하는 격식 표현은 ''reinforce''예요. ''thicken''은 어색해요.','C2','body',3,0,'musculature training gym','Resistance training reinforces the musculature.','저항 운동은 근육 구조를 강화해요.','These exercises reinforce the core musculature.','이 운동들은 코어 근육 구조를 강화해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cafe_21','have','lunch','have lunch','점심을 먹다','eat','"eat lunch"도 가능하지만 have lunch가 더 자연스럽고 자주 쓰여요. breakfast, dinner도 마찬가지.','A1','cafe',1,0,'lunch restaurant friends table eating','Let''s have lunch together tomorrow.','내일 같이 점심 먹어요.','I usually have lunch at noon.','저는 보통 정오에 점심을 먹어요.','Where do you want to have lunch?','어디서 점심 먹을래요?','We had lunch at the new Italian place.','저희는 새 이탈리안 레스토랑에서 점심을 먹었어요.','She had a quick lunch at her desk.','그녀는 책상에서 간단히 점심을 먹었어요.'),
('col_cafe_22','have','breakfast','have breakfast','아침을 먹다','do','do breakfast는 영어에서 거의 안 써요. 아침/점심/저녁 모두 have와 함께.','A1','cafe',1,0,'breakfast eggs toast morning coffee table','I never skip breakfast — I always have something.','저는 아침을 거르지 않아요 — 항상 뭔가 먹어요.','Did you have breakfast this morning?','오늘 아침 먹었어요?','We had breakfast at a cute cafe by the river.','저희는 강가의 귀여운 카페에서 아침을 먹었어요.','He always has breakfast before leaving for work.','그는 출근 전에 항상 아침을 먹어요.','Let''s have breakfast together on Sunday.','일요일에 같이 아침 먹어요.'),
('col_cafe_02','place','an order','place an order','주문하다','make','"make an order"도 쓰이지만 place an order가 더 격식 있고 자주 쓰여요.','A2','cafe',1,2,'order coffee barista cafe menu','Are you ready to place your order?','주문하시겠어요?','She placed her order and found a comfortable seat by the window.','그녀는 주문을 하고 창가의 편안한 자리를 잡았어요.','I placed an order at the counter and waited for my name to be called.','카운터에서 주문을 하고 제 이름이 불릴 때까지 기다렸어요.','They placed their orders together to make things easier.','그들은 일을 수월하게 하기 위해 함께 주문했어요.','You can place an order through the kiosk if there''s a line.','줄이 길면 키오스크로 주문할 수 있어요.'),
('col_cafe_03','pay','the check','pay the check','계산하다','do','"do the check"는 틀린 표현이에요. 계산할 때는 pay를 써요.','A2','cafe',1,3,'check bill payment cafe restaurant','Could we pay the check, please? We''re in a bit of a hurry.','계산해 주세요, 좀 급해서요.','He insisted on paying the check even though it wasn''t his turn.','자기 차례가 아닌데도 그는 계산을 하겠다고 고집했어요.','Could we pay the check separately, please?','각자 계산할 수 있을까요?','She quietly paid the check while he was in the restroom.','그가 화장실에 간 사이 그녀는 조용히 계산을 했어요.','We paid the check and left a generous tip for the waiter.','우리는 계산을 하고 웨이터에게 넉넉한 팁을 남겼어요.'),
('col_cafe_04','take','a seat','take a seat','자리를 잡다','find','"find a seat"도 맞지만 take a seat는 더 격식 있는 표현이에요.','A2','cafe',1,4,'seat cafe table sitting waiting','Please take a seat and someone will be right with you.','자리를 잡으세요, 곧 도와드릴게요.','She took a seat near the window and opened her laptop.','그녀는 창가에 자리를 잡고 노트북을 열었어요.','Please take a seat by the window — the view is lovely.','창가에 자리를 잡으세요 — 전망이 아름다워요.','He took a seat at the bar and ordered an espresso.','그는 바에 자리를 잡고 에스프레소를 주문했어요.','We took a seat outside to enjoy the spring weather.','우리는 봄 날씨를 즐기기 위해 야외에 자리를 잡았어요.'),
('col_cafe_06','have','a bite','have a bite','간단히 먹다','eat','"eat a bite"는 어색해요. 간단하게 먹을 때는 have a bite를 써요.','A2','cafe',1,6,'snack cafe food bite eating','Do you want to grab a bite to eat before the movie?','영화 전에 간단히 뭔가 먹을까요?','We stopped at a cafe to have a bite and rest our feet.','우리는 간단히 먹고 발을 쉬기 위해 카페에 들렀어요.','Let''s have a bite at that new cafe on the corner.','저 모퉁이의 새 카페에서 간단히 먹어요.','I just want to have a bite — nothing too heavy.','간단히 좀 먹고 싶어요 — 너무 무거운 건 말고요.','They had a quick bite before heading to the museum.','그들은 박물관으로 가기 전에 간단히 먹었어요.'),
('col_cafe_07','keep','the change','keep the change','잔돈은 가지세요','take','"take the change"는 다른 뉘앙스예요. 팁을 줄 때는 keep the change를 써요.','A2','cafe',1,7,'tip change money barista cafe','"Keep the change," she said with a smile after paying for her coffee.','"잔돈은 가지세요," 그녀는 커피 값을 내며 미소 지었어요.','He told the barista to keep the change as a tip.','그는 바리스타에게 팁으로 잔돈을 가지라고 했어요.','"Keep the change," he said, leaving a generous tip.','"잔돈은 가지세요," 그는 넉넉한 팁을 남기며 말했어요.','She always tells the driver to keep the change.','그녀는 항상 운전기사에게 잔돈은 가지라고 해요.','He paid with a twenty and told the cashier to keep the change.','그는 20달러로 결제하고 캐셔에게 잔돈은 가지라고 했어요.'),
('col_cafe_09','bring','the menu','bring the menu','메뉴판을 가져오다','give','"give the menu"도 쓰이지만 bring이 더 자연스러운 동작 표현이에요.','A2','cafe',1,9,'menu waiter cafe order food','Could you bring the menu again? I forgot what the specials were.','메뉴판 다시 가져다 줄 수 있어요? 오늘의 특선이 뭔지 잊었어요.','The waiter brought the menu right away.','웨이터가 바로 메뉴판을 가져왔어요.','Could you bring the menu over to our table, please?','메뉴판을 저희 테이블로 가져다 줄 수 있을까요?','The hostess brought the menu and explained today''s specials.','직원이 메뉴판을 가져와서 오늘의 특선을 설명해 줬어요.','They brought the kids'' menu without us even asking.','우리가 부탁하지도 않았는데 어린이 메뉴판을 가져다 줬어요.'),
('col_cafe_14','take','away','take away','테이크아웃하다','carry','"carry away"는 틀린 표현이에요. 테이크아웃할 때는 take away를 써요.','A2','cafe',1,14,'takeaway coffee cup to-go cafe','Could I have this to take away, please?','테이크아웃으로 주세요.','He ordered two lattes to take away on his way to the office.','그는 사무실로 가는 길에 라테 두 잔을 테이크아웃했어요.','Three iced lattes to take away, please.','아이스 라테 세 잔 테이크아웃으로 주세요.','She prefers to take away her morning coffee on workdays.','그녀는 평일에 아침 커피를 테이크아웃하는 걸 선호해요.','You can save a few cents by taking your drink away in a reusable cup.','재사용 컵으로 테이크아웃하면 몇 푼 아낄 수 있어요.'),
('col_cafe_17','go','for a coffee','go for a coffee','커피 마시러 가다','drink','"drink a coffee"는 어색해요. 커피 마시러 갈 때는 go for a coffee를 써요.','A2','cafe',1,17,'coffee shop morning routine cafe break','Want to go for a coffee after the meeting?','회의 후에 커피 마시러 갈까요?','She went for a coffee every morning to start her day.','그녀는 매일 아침 하루를 시작하기 위해 커피 마시러 갔어요.','I always go for a coffee with my mom on Sunday mornings.','저는 일요일 아침마다 엄마와 커피 마시러 가요.','They went for a coffee to discuss the new business idea.','그들은 새로운 사업 아이디어를 논의하기 위해 커피 마시러 갔어요.','Let''s go for a coffee and finish the conversation we started.','커피 마시러 가서 못다 한 이야기를 마저 해요.'),
('col_cafe_20','sit','in','sit in','매장 내에서 먹다/마시다','stay','"stay in"은 다른 의미예요. 매장에서 먹을 때는 sit in 또는 eat in을 써요.','A2','cafe',1,20,'sit in dine in cafe indoor table','"Would you like to sit in or take away?" the barista asked.','"드시고 가실 건가요, 테이크아웃하실 건가요?" 바리스타가 물었어요.','We decided to sit in because it was raining outside.','밖에 비가 와서 우리는 매장에서 먹기로 했어요.','"I''ll sit in for now," she said as she found a corner table.','"일단 매장에서 마실게요," 그녀는 구석 테이블을 찾으며 말했어요.','They decided to sit in to enjoy the cafe''s warm interior.','그들은 카페의 따뜻한 인테리어를 즐기려고 매장에서 먹기로 했어요.','It''s nicer to sit in than to take away on a cold day.','추운 날엔 테이크아웃보다 매장에서 먹는 게 더 좋아요.'),
('col_cafe_23','order','takeout','order takeout','음식을 포장 주문하다','take','"take takeout"은 어색해요. 포장 주문은 order takeout (미국식). 영국에서는 takeaway.','A2','cafe',1,0,'takeout containers food delivery bag restaurant','Let''s order takeout tonight — I''m too tired to cook.','오늘 밤은 포장 주문해요 — 요리하기 너무 피곤해요.','We ordered takeout from our favorite Thai place.','우리는 즐겨 가는 태국 식당에서 포장 주문했어요.','I order takeout twice a week.','저는 일주일에 두 번 포장 주문을 해요.','Did you order takeout for the office?','사무실용 포장 주문했어요?','They ordered takeout instead of going out.','그들은 외출 대신 포장 주문을 했어요.'),
('col_cafe_01','make','a reservation','make a reservation','예약하다','do','"do a reservation"은 틀린 표현이에요. 예약할 때는 make를 써요.','B1','cafe',1,1,'reservation booking table restaurant cafe','I''d like to make a reservation for two for this Saturday evening.','이번 토요일 저녁에 두 명 예약하고 싶어요.','It''s best to make a reservation in advance for popular cafes.','인기 있는 카페는 미리 예약하는 게 좋아요.','You can make a reservation through the cafe''s mobile app.','카페 모바일 앱으로 예약을 할 수 있어요.','She made a reservation for the rooftop seats well in advance.','그녀는 옥상 자리를 미리 예약해뒀어요.','Don''t forget to make a reservation if it''s a busy weekend.','바쁜 주말이라면 예약하는 걸 잊지 마세요.'),
('col_cafe_05','get','a refill','get a refill','리필을 받다','take','"take a refill"도 쓰이지만 get a refill이 더 자연스러운 구어체예요.','B1','cafe',1,5,'refill coffee drink cup cafe','Could I get a refill on my coffee, please?','커피 리필 받을 수 있을까요?','He got a free refill because he''d been waiting so long.','그는 너무 오래 기다렸다는 이유로 무료 리필을 받았어요.','You can get a refill on your drip coffee at no extra charge.','드립 커피는 추가 요금 없이 리필을 받을 수 있어요.','He got a refill before settling in for a long study session.','그는 긴 공부를 위해 자리 잡기 전에 리필을 받았어요.','She got a free refill because she''s a loyalty member.','그녀는 멤버십 회원이라서 무료 리필을 받았어요.'),
('col_cafe_08','make','a suggestion','make a suggestion','추천하다, 제안하다','give','"give a suggestion"도 쓰이지만 make a suggestion이 더 자주 쓰여요.','B1','cafe',2,8,'recommendation suggestion menu drink cafe','Could you make a suggestion? I''m not sure what to order.','추천해 줄 수 있어요? 뭘 주문할지 잘 모르겠어요.','The barista made a great suggestion — the seasonal latte.','바리스타가 훌륭한 추천을 해줬어요 — 시즌 라테요.','Could you make a suggestion for a non-dairy drink?','유제품이 없는 음료를 추천해 줄 수 있어요?','She made a suggestion to try the new pastry of the week.','그녀는 이번 주의 새로운 페이스트리를 시도해 보라고 추천했어요.','May I make a suggestion based on your usual order?','평소 주문하시는 것을 바탕으로 추천을 드려도 될까요?'),
('col_cafe_10','hold','a table','hold a table','자리를 맡아두다','keep','"keep a table"도 쓰이지만 hold a table이 더 자연스러운 표현이에요.','B1','cafe',2,10,'table reservation holding waiting friends','Can you hold a table for us? We''ll be there in ten minutes.','자리 좀 맡아둘 수 있어요? 10분 후에 도착할게요.','She asked her friend to hold a table while she parked the car.','그녀는 주차하는 동안 친구에게 자리를 맡아달라고 했어요.','Could you hold a table for four under my name?','제 이름으로 4인 테이블을 잡아둘 수 있을까요?','They held a table for us even though we were running late.','우리가 늦었는데도 그들은 우리를 위해 자리를 맡아뒀어요.','She held a table by the window so we could watch the rain.','비를 볼 수 있도록 그녀가 창가 자리를 맡아뒀어요.'),
('col_cafe_11','split','the bill','split the bill','계산을 나누다','divide','"divide the bill"도 맞지만 split the bill이 훨씬 더 자연스러운 표현이에요.','B1','cafe',1,11,'bill split payment friends cafe','Should we split the bill or take turns paying?','계산을 나눌까요, 아니면 교대로 낼까요?','They always split the bill when they go out for coffee.','그들은 커피 마시러 나갈 때 항상 계산을 나눠요.','Let''s split the bill three ways since we each had our own dish.','각자 다른 음식을 시켰으니 셋이 계산을 나눠요.','They decided to split the bill evenly to keep it simple.','그들은 간단하게 하려고 계산을 똑같이 나눴어요.','Splitting the bill is normal among friends in our group.','우리 친구들 사이에서 계산을 나누는 건 흔한 일이에요.'),
('col_cafe_12','ask','for a recommendation','ask for a recommendation','추천을 부탁하다','request','"request a recommendation"도 맞지만 ask for가 더 일상적이에요.','B1','cafe',1,12,'recommendation barista drink advice','I asked the barista for a recommendation and loved what she suggested.','바리스타에게 추천을 부탁했더니 추천해준 게 정말 좋았어요.','Don''t be shy to ask for a recommendation if you''re not sure what to order.','뭘 주문할지 모르겠으면 추천을 부탁하는 걸 부끄러워하지 마세요.','I asked the waiter for a recommendation on a light dessert.','저는 웨이터에게 가벼운 디저트 추천을 부탁했어요.','When in doubt, ask for a recommendation from the staff.','잘 모를 때는 직원에게 추천을 부탁하세요.','He asked for a recommendation since it was his first visit.','그는 첫 방문이라 추천을 부탁했어요.'),
('col_cafe_13','enjoy','the atmosphere','enjoy the atmosphere','분위기를 즐기다','like','"like the atmosphere"도 맞지만 enjoy가 더 적극적으로 즐기는 뉘앙스예요.','B1','cafe',2,13,'atmosphere cafe cozy interior ambiance','We sat for hours just enjoying the atmosphere of the cozy cafe.','우리는 아늑한 카페의 분위기를 즐기면서 몇 시간을 앉아 있었어요.','She goes there not just for the coffee but to enjoy the atmosphere.','그녀는 커피뿐 아니라 분위기를 즐기기 위해 거기에 가요.','I love coming here just to enjoy the atmosphere of soft jazz.','저는 잔잔한 재즈 분위기를 즐기러 여기 오는 걸 좋아해요.','They sat outside to enjoy the atmosphere of the street market.','그들은 거리 시장의 분위기를 즐기기 위해 야외에 앉았어요.','The cafe is small but you can really enjoy the atmosphere.','카페는 작지만 분위기를 정말 즐길 수 있어요.'),
('col_cafe_15','run','out of','run out of','~이 다 떨어지다','finish','"finish"는 사람이 다 먹을 때 쓰고, 재고가 떨어질 때는 run out of를 써요.','B1','cafe',1,15,'out of stock sold out cafe menu item','I''m sorry, we''ve run out of oat milk today.','죄송해요, 오늘 오트 밀크가 다 떨어졌어요.','The popular cake runs out quickly on weekends.','그 인기 케이크는 주말에 빨리 다 떨어져요.','We''ve run out of paper cups, so please use a mug.','종이컵이 다 떨어져서, 머그컵을 사용해 주세요.','The cafe runs out of croissants by lunchtime every day.','그 카페는 매일 점심 시간 무렵에 크루아상이 다 떨어져요.','I almost ran out of cash before the trip ended.','여행이 끝나기 전에 현금이 거의 다 떨어졌어요.'),
('col_cafe_16','catch','up','catch up over coffee','커피 한잔하며 근황을 나누다','meet','"meet for coffee"도 맞지만 catch up에는 서로 소식을 나눈다는 뉘앙스가 있어요.','B1','cafe',2,16,'friends coffee catching up talking cafe','Let''s catch up over coffee sometime this week.','이번 주 중에 커피 한잔하며 근황 나눠요.','They caught up over coffee and it was like no time had passed.','그들은 커피 한잔하며 근황을 나눴는데 시간이 전혀 안 지난 것 같았어요.','We finally caught up over coffee after months of busy schedules.','몇 달간의 바쁜 일정 끝에 우리는 마침내 커피 한잔하며 근황을 나눴어요.','She invited me to catch up over coffee at her favorite spot.','그녀는 자기가 좋아하는 곳에서 커피 한잔하며 근황 나누자고 저를 초대했어요.','Catching up over coffee is one of my favorite weekend habits.','커피 한잔하며 근황을 나누는 건 제 좋아하는 주말 습관 중 하나예요.'),
('col_cafe_19','leave','a tip','leave a tip','팁을 남기다','give','"give a tip"도 맞지만 leave a tip은 자리를 떠나며 놓고 가는 뉘앙스예요.','B1','cafe',2,19,'tip gratuity service waiter café','She always leaves a generous tip when the service is great.','그녀는 서비스가 좋으면 항상 넉넉한 팁을 남겨요.','It''s customary to leave a tip at sit-down cafes in the US.','미국에서는 좌석 카페에서 팁을 남기는 것이 관례예요.','I left a tip in cash even though I paid by card.','저는 카드로 결제했지만 팁은 현금으로 남겼어요.','They left a small tip and thanked the server warmly.','그들은 적은 팁을 남기고 서버에게 따뜻하게 감사를 표했어요.','You don''t have to leave a tip at counter-service cafes.','카운터 서비스 카페에서는 팁을 남기지 않아도 돼요.'),
('col_cafe_24','grab','bite','grab a bite','간단히 먹다','get','"get a bite"는 살짝 어색. grab a bite는 가볍게 식사 한다는 캐주얼 표현.','B1','cafe',1,0,'quick meal snack street food casual eating','Let''s grab a bite before the movie.','영화 보기 전에 간단히 먹어요.','I only have time to grab a bite for lunch.','점심은 간단히 먹을 시간만 있어요.','We grabbed a bite at the food truck.','우리는 푸드트럭에서 간단히 먹었어요.','Do you want to grab a bite after work?','퇴근 후에 간단히 먹을래요?','She grabbed a quick bite between meetings.','그녀는 회의 사이에 간단히 끼니를 때웠어요.'),
('col_cafe_18','brew','coffee','brew coffee','커피를 내리다','make','"make coffee"도 맞지만 brew는 전통적인 커피 추출 방식을 강조해요.','B2','cafe',2,18,'brewing coffee pour over barista craft','She brews her own coffee at home every morning.','그녀는 매일 아침 집에서 직접 커피를 내려요.','This cafe brews coffee using traditional pour-over methods.','이 카페는 전통적인 핸드드립 방식으로 커피를 내려요.','They brew coffee using a single-origin Ethiopian bean.','그들은 싱글 오리진 에티오피아 원두로 커피를 내려요.','He learned to brew coffee from a barista in Melbourne.','그는 멜버른의 한 바리스타에게서 커피 내리는 법을 배웠어요.','The smell of coffee being brewed filled the whole apartment.','커피를 내리는 향이 아파트 전체에 가득했어요.'),
('col_cafe_C1_01','place','an order','place an order','주문을 넣다','make','''place an order''는 격식 있는 표현으로, 식당이나 카페에서 직원에게 정중하게 주문할 때 자주 써요. ''make an order''보다 더 자연스러워요.','C1','cafe',2,0,'restaurant order menu','Would you like to place an order, sir?','주문하시겠어요, 손님?','I''d like to place an order for delivery, please.','배달 주문을 넣고 싶어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cafe_C1_02','split','the bill','split the bill','계산을 나누다','divide','친구나 동료와 식사 후 더치페이할 때 쓰는 표준 표현이에요. ''divide''보다 ''split''이 훨씬 자연스럽게 들려요.','C1','cafe',2,0,'restaurant bill payment','Shall we split the bill evenly?','계산을 똑같이 나눌까요?','Let''s split the bill three ways.','셋이서 나눠서 계산해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cafe_C1_03','settle','the tab','settle the tab','계산을 정산하다','pay','바나 카페에서 미리 주문한 음료/음식 값을 마지막에 한꺼번에 정산할 때 써요. 격식 있고 세련된 표현이에요.','C1','cafe',2,0,'bar tab payment','I''ll settle the tab on my way out.','나갈 때 정산할게요.','He kindly offered to settle the tab for everyone.','그가 친절하게 모두의 계산을 해주겠다고 했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cafe_C1_04','savor','the moment','savor the moment','순간을 음미하다','enjoy','단순히 즐기는 것을 넘어, 천천히 깊이 음미한다는 뉘앙스예요. 카페에서 여유롭게 시간을 보낼 때 어울려요.','C1','cafe',2,0,'coffee moment relax','She closed her eyes to savor the moment.','그녀는 그 순간을 음미하려 눈을 감았어요.','I love to savor the moment with a quiet espresso.','조용히 에스프레소 한 잔과 그 순간을 음미하는 걸 좋아해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cafe_C1_05','linger','over coffee','linger over coffee','커피를 마시며 오래 머물다','stay','커피 한 잔을 두고 오래 앉아 대화하거나 시간을 보낸다는 우아한 표현이에요. 카페 문화를 묘사할 때 자주 등장해요.','C1','cafe',2,0,'paris cafe coffee','We lingered over coffee for hours.','우린 커피를 마시며 몇 시간이나 머물렀어요.','Parisians love to linger over coffee in the afternoon.','파리지앵들은 오후에 커피를 천천히 즐기는 걸 좋아해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cafe_C2_01','savor','aroma','savor the aroma','향을 음미하다','smell','향이나 맛을 천천히 즐길 때 ''savor''를 써요. ''smell''은 단순히 냄새를 맡는 의미라서 격이 떨어져요.','C2','cafe',3,0,'coffee aroma','She paused to savor the aroma of the freshly ground Ethiopian beans.','그녀는 잠시 멈춰 갓 갈아낸 에티오피아 원두의 향을 음미했어요.','Connoisseurs savor the aroma before taking the first sip.','감정가들은 첫 모금을 마시기 전에 향을 음미해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cafe_C2_02','cultivate','palate','cultivate a palate','미각을 기르다','make','미각이나 취향을 시간을 들여 발달시킨다는 격식 있는 표현이에요. 와인, 커피, 음식 비평에서 자주 써요.','C2','cafe',3,0,'coffee tasting','Years of tasting rare brews have helped him cultivate a discerning palate.','수년간 희귀한 커피를 시음하며 그는 까다로운 미각을 길렀어요.','A sommelier must cultivate a palate sensitive to the subtlest notes.','소믈리에는 미묘한 향에도 예민한 미각을 길러야 해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cafe_C2_03','frequent','establishment','frequent an establishment','한 가게를 자주 다니다','visit','카페나 식당 같은 가게를 자주 방문한다는 문어체 표현이에요. ''visit''보다 훨씬 격식 있어요.','C2','cafe',3,0,'cafe interior','Literary figures of the era frequented the establishment on Boulevard Saint-Germain.','그 시대의 문인들은 생제르맹 대로의 그 가게를 자주 드나들었어요.','He has frequented this establishment for over two decades.','그는 20년 넘게 이 가게를 다니고 있어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cafe_C2_04','exude','ambiance','exude ambiance','분위기를 자아내다','have','공간이 특정한 분위기를 강하게 풍긴다는 뜻이에요. 인테리어 평론이나 여행 기사에 자주 등장해요.','C2','cafe',3,0,'candlelit cafe','The candlelit corner exudes an ambiance reminiscent of 1920s Vienna.','촛불이 켜진 그 구석은 1920년대 빈을 연상시키는 분위기를 풍겨요.','Their flagship cafe exudes an ambiance of understated luxury.','그들의 플래그십 카페는 은은한 고급스러움의 분위기를 자아내요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cafe_C2_05','extol','virtues','extol the virtues','장점을 극찬하다','praise','무언가의 장점을 강하게, 또는 다소 과장되게 칭찬할 때 써요. 격식 있고 약간 비꼬는 뉘앙스도 가능해요.','C2','cafe',3,0,'barista pour over','The barista extolled the virtues of single-origin Geisha coffee.','바리스타는 싱글 오리진 게이샤 커피의 장점을 극찬했어요.','Critics have long extolled the virtues of slow brewing.','비평가들은 오랫동안 슬로우 브루잉의 장점을 극찬해 왔어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cooking_B1_01','chop','onions','chop onions','양파를 다지다','cut','''chop''은 칼로 잘게 토막내는 동작이에요. 단순한 ''cut''보다 요리 맥락에서 훨씬 자연스러워요.','B1','cooking',1,0,'chopping onions cutting board','Could you chop the onions for me?','양파 좀 다져 줄래요?','I always cry when I chop onions.','저는 양파를 다질 때마다 눈물이 나요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cooking_B1_02','boil','water','boil water','물을 끓이다','heat','''boil''은 100도까지 끓여서 기포가 올라오게 하는 거예요. ''heat water''는 단순히 데우는 느낌이라 차이가 있어요.','B1','cooking',1,0,'boiling water pot stove','First, boil some water in a large pot.','먼저 큰 냄비에 물을 끓이세요.','It takes about five minutes to boil water.','물을 끓이는 데 5분 정도 걸려요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cooking_B1_03','stir','the pot','stir the pot','냄비를 젓다','mix','냄비 안 재료를 숟가락으로 빙빙 돌리며 섞는 동작이에요. ''mix''보다 요리할 때 더 자연스러워요.','B1','cooking',1,0,'stirring pot wooden spoon','Please stir the pot every few minutes.','몇 분마다 냄비를 저어 주세요.','He stirred the pot slowly with a wooden spoon.','그는 나무 숟가락으로 천천히 냄비를 저었어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cooking_B1_04','preheat','the oven','preheat the oven','오븐을 예열하다','warm','굽기 전에 오븐을 미리 데우는 필수 단계예요. ''warm''보다 ''preheat''이 요리 레시피의 표준 표현이에요.','B1','cooking',1,0,'oven preheat dial','Preheat the oven to 180 degrees.','오븐을 180도로 예열하세요.','Don''t forget to preheat the oven first.','오븐 먼저 예열하는 거 잊지 마세요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cooking_B1_05','add','salt','add salt','소금을 넣다','put','''add''는 요리에 재료를 ''넣어 더한다''는 표준 표현이에요. ''put salt''도 가능하지만 ''add''가 훨씬 자연스러워요.','B1','cooking',1,0,'adding salt soup','Add a pinch of salt to the soup.','수프에 소금을 조금만 넣으세요.','I usually add salt at the end.','저는 보통 마지막에 소금을 넣어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cooking_B2_01','season','to taste','season to taste','입맛에 맞게 간하다','salt','레시피 마지막에 자주 등장하는 표현이에요. 소금/후추 등으로 본인 입맛에 맞춰 간을 한다는 뜻이에요.','B2','cooking',2,0,'salt pepper seasoning dish','Season to taste with salt and pepper.','소금과 후추로 입맛에 맞게 간하세요.','Always season to taste before serving.','내기 전에 꼭 입맛에 맞춰 간을 보세요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cooking_B2_02','marinate','overnight','marinate overnight','하룻밤 재워두다','soak','고기나 생선을 양념에 ''재워서'' 맛이 배게 하는 거예요. ''soak''은 그냥 담그는 거라 요리에서는 ''marinate''가 정확해요.','B2','cooking',2,0,'marinated meat bowl fridge','Marinate the chicken overnight for the best flavor.','닭고기를 하룻밤 재워야 맛이 제일 좋아요.','The beef needs to marinate overnight in soy sauce.','소고기는 간장에 하룻밤 재워야 해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cooking_B2_03','drain','the pasta','drain the pasta','파스타 물을 빼다','remove','삶은 파스타에서 물을 따라내는 동작이에요. 체(콜랜더)에 부어 물을 빼는 표준 표현이에요.','B2','cooking',2,0,'draining pasta colander','Drain the pasta but save a cup of water.','파스타 물을 빼되 한 컵은 남겨두세요.','I always drain the pasta in the sink.','저는 항상 싱크대에서 파스타 물을 빼요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cooking_B2_04','whisk','eggs','whisk eggs','계란을 휘젓다','beat','거품기로 빠르게 휘저어 공기를 넣는 동작이에요. ''beat eggs''도 가능하지만 ''whisk''가 도구를 강조해요.','B2','cooking',2,0,'whisking eggs bowl','Whisk the eggs until light and fluffy.','계란이 폭신해질 때까지 휘저으세요.','She whisked the eggs vigorously.','그녀는 계란을 힘차게 휘저었어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cooking_B2_05','sauté','vegetables','sauté vegetables','채소를 볶다','cook','소량의 기름에 센 불로 빠르게 볶는 거예요. 프랑스어에서 온 요리 전문 용어로 ''cook''보다 정확해요.','B2','cooking',2,0,'sauteing vegetables pan','Sauté the vegetables until tender.','채소가 부드러워질 때까지 볶으세요.','He sautéed the mushrooms in butter.','그는 버터에 버섯을 볶았어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cooking_C1_01','render','fat','render fat','기름을 녹여내다','melt','베이컨이나 삼겹살 같은 고기에서 지방을 천천히 녹여 추출하는 요리 전문 표현이에요. ''melt''보다 훨씬 전문적이에요.','C1','cooking',2,0,'bacon fat rendering pan','Render the bacon fat over low heat.','약불에 베이컨 기름을 녹여내세요.','Chefs render the duck fat for extra flavor.','셰프들은 풍미를 더하려고 오리 기름을 녹여내요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cooking_C1_02','reduce','a sauce','reduce a sauce','소스를 졸이다','thicken','소스를 약불에 끓여서 수분을 날려 농축시키는 요리 기법이에요. ''thicken''은 결과만 말하지만 ''reduce''는 과정을 정확히 표현해요.','C1','cooking',2,0,'reducing sauce pan stove','Reduce the sauce by half before serving.','내기 전에 소스를 반으로 졸이세요.','The wine sauce needs to reduce for 20 minutes.','와인 소스는 20분간 졸여야 해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cooking_C1_03','garnish','a dish','garnish a dish','요리를 장식하다','decorate','허브나 채소로 음식 위에 마무리 장식을 얹는 요리 표준 표현이에요. ''decorate''는 케이크에나 쓰고 요리에는 ''garnish''가 맞아요.','C1','cooking',2,0,'garnished plate parsley dish','Garnish the dish with fresh parsley.','신선한 파슬리로 요리를 장식하세요.','A good chef always garnishes the plate carefully.','훌륭한 셰프는 항상 접시를 정성껏 장식해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cooking_C1_04','infuse','with flavor','infuse with flavor','풍미를 우려내다','add','오일이나 액체에 허브/향신료의 맛을 천천히 우려내는 격조 있는 표현이에요. ''add''보다 훨씬 세련되게 들려요.','C1','cooking',2,0,'infused oil herbs jar','Infuse the oil with garlic and herbs.','오일에 마늘과 허브의 풍미를 우려내세요.','Slowly infuse the milk with vanilla.','우유에 바닐라 향을 천천히 우려내세요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cooking_C1_05','carve','a roast','carve a roast','구이를 썰다','cut','큰 덩어리 고기를 식탁에서 우아하게 얇게 썰어내는 동작이에요. ''cut''은 너무 일반적이라 격식 자리에는 ''carve''가 정확해요.','C1','cooking',2,0,'carving roast turkey knife','Father always carves the roast at Christmas.','아버지는 항상 크리스마스에 구이를 썰어요.','He carved the roast with a sharp knife.','그는 날카로운 칼로 구이를 썰었어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cooking_C2_01','emulsify','a vinaigrette','emulsify a vinaigrette','비네그레트를 유화시키다','mix','서로 섞이지 않는 기름과 식초를 강제로 결합시키는 화학적 요리 기법이에요. ''mix''와 차원이 다른 전문 용어예요.','C2','cooking',3,0,'emulsified vinaigrette dressing jar','Whisk vigorously to emulsify the vinaigrette.','힘차게 저어 비네그레트를 유화시키세요.','A good dressing must be properly emulsified.','좋은 드레싱은 제대로 유화되어야 해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cooking_C2_02','caramelize','sugar','caramelize sugar','설탕을 캐러멜화하다','burn','설탕을 천천히 가열해 갈색으로 변하게 하는 정밀한 요리 기법이에요. ''burn''은 실패이고 ''caramelize''는 완벽한 결과를 뜻해요.','C2','cooking',3,0,'caramelized sugar golden pan','Slowly caramelize the sugar until amber.','설탕이 호박색이 될 때까지 천천히 캐러멜화하세요.','Caramelizing onions takes at least 30 minutes.','양파를 캐러멜화하려면 최소 30분은 걸려요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cooking_C2_03','macerate','berries','macerate berries','베리를 절이다','soak','베리에 설탕이나 술을 뿌려 즙이 우러나오게 하는 디저트 기법이에요. ''soak''보다 훨씬 전문적인 페이스트리 용어예요.','C2','cooking',3,0,'macerated strawberries sugar bowl','Macerate the strawberries in sugar for an hour.','딸기를 설탕에 한 시간 절이세요.','Macerated berries make a wonderful dessert topping.','절인 베리는 훌륭한 디저트 토핑이 돼요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cooking_C2_04','brine','poultry','brine poultry','가금류를 염지하다','salt','소금물에 닭이나 칠면조를 담가 부드럽고 촉촉하게 만드는 전문 기법이에요. ''salt''와는 차원이 다른 정밀한 표현이에요.','C2','cooking',3,0,'brining turkey saltwater container','Brine the turkey for 24 hours before roasting.','칠면조를 굽기 전 24시간 동안 염지하세요.','Brining poultry guarantees juicy meat.','가금류를 염지하면 육즙이 풍부해져요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_cooking_C2_05','deconstruct','a classic','deconstruct a classic','클래식 요리를 해체하다','remake','전통 요리를 구성 요소별로 분해해 새로운 형태로 재구성하는 모더니즘 요리 철학이에요. ''remake''는 너무 단순해요.','C2','cooking',3,0,'deconstructed dessert modern plate','The chef deconstructed a classic tiramisu.','셰프는 클래식 티라미수를 해체해서 재구성했어요.','Deconstructed dishes are popular in fine dining.','해체 요리는 파인 다이닝에서 인기예요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_culture_21','watch','movie','watch a movie','영화를 보다','see','"see a movie"는 극장에서 본다는 뉘앙스. 집에서 보는 건 watch a movie가 더 자연스러워요.','A1','culture',1,0,'movie watching couch popcorn screen home','Let''s watch a movie tonight.','오늘 밤 영화 봐요.','I watched a great movie on Netflix yesterday.','어제 넷플릭스에서 좋은 영화를 봤어요.','We watched the movie twice — it was that good.','너무 좋아서 영화를 두 번 봤어요.','She watches movies in English to practice.','그녀는 연습 삼아 영어 영화를 봐요.','Have you watched the new Korean movie?','새로 나온 한국 영화 봤어요?'),
('col_culture_22','play','music','play music','음악을 연주하다/틀다','do','"do music"은 어색해요. 악기 연주든 음악 재생이든 play music.','A1','culture',1,0,'music speakers piano playing instrument','He plays music every evening to relax.','그는 매일 저녁 긴장을 풀려고 음악을 틀어요.','She plays beautiful piano music.','그녀는 아름다운 피아노 연주를 해요.','The DJ played music all night long.','DJ가 밤새 음악을 틀었어요.','My neighbor plays music too loud.','옆집 사람이 음악을 너무 크게 틀어요.','Can you play some music while we cook?','요리하는 동안 음악 좀 틀어 줄래요?'),
('col_culture_23','read','book','read a book','책을 읽다','do','"do a book"은 틀린 표현. 독서는 read a book.','A1','culture',1,0,'person reading book cozy library quiet','I read a book before bed every night.','저는 매일 밤 자기 전에 책을 읽어요.','She read three books during her vacation.','그녀는 휴가 동안 책 세 권을 읽었어요.','Have you read any good books lately?','최근에 좋은 책 읽은 거 있어요?','He read the entire book in one sitting.','그는 한 자리에서 책을 다 읽었어요.','Reading books is a great way to relax.','책 읽기는 좋은 휴식 방법이에요.'),
('col_culture_02','hold','an exhibition','hold an exhibition','전시회를 열다','make','"make an exhibition"은 창피를 당한다는 뜻이에요. 전시를 열 때는 hold를 써요.','B1','culture',1,2,'exhibition gallery art museum show','The gallery is holding an exhibition of contemporary Korean art.','갤러리는 현대 한국 예술 전시회를 열고 있어요.','They held an exhibition celebrating local artists.','그들은 지역 예술가들을 기리는 전시회를 열었어요.','The museum is holding an exhibition of rare ancient pottery.','박물관은 희귀한 고대 도자기 전시회를 열고 있어요.','They held an exhibition to mark the artist''s 50th anniversary.','그들은 작가의 50주년을 기념하기 위해 전시회를 열었어요.','The gallery holds an exhibition every two months.','그 갤러리는 두 달에 한 번 전시회를 열어요.'),
('col_culture_03','make','art','make art','예술 작품을 만들다','do','"do art"도 쓰이지만 make art는 창작 행위를 더 강조해요.','B1','culture',2,3,'art studio creating painting artist','She makes art that challenges social norms.','그녀는 사회적 규범에 도전하는 예술 작품을 만들어요.','Making art can be a powerful way to process emotions.','예술 작품을 만드는 것은 감정을 처리하는 강력한 방법이 될 수 있어요.','He makes art using recycled materials from his neighborhood.','그는 동네에서 나온 재활용 재료로 예술 작품을 만들어요.','She started making art seriously after retiring from teaching.','그녀는 교직에서 은퇴한 후 본격적으로 예술 작품을 만들기 시작했어요.','Making art every day helps her process her emotions.','매일 예술 작품을 만드는 것이 그녀가 감정을 처리하는 데 도움이 돼요.'),
('col_culture_04','give','a concert','give a concert','콘서트를 열다','make','"make a concert"는 틀린 표현이에요. 콘서트를 개최할 때는 give를 써요.','B1','culture',1,4,'concert music performance hall singer','The orchestra gave a stunning concert at the concert hall.','오케스트라는 콘서트 홀에서 감동적인 콘서트를 열었어요.','She gave her first major concert in front of 5,000 people.','그녀는 5,000명 앞에서 첫 번째 주요 콘서트를 열었어요.','The pianist gave a concert in front of a packed audience.','그 피아니스트는 만석인 청중 앞에서 콘서트를 열었어요.','She gives a concert in her hometown every winter.','그녀는 매년 겨울 고향에서 콘서트를 열어요.','The choir gave a beautiful concert at the cathedral.','합창단은 성당에서 아름다운 콘서트를 열었어요.'),
('col_culture_05','break','records','break records','기록을 깨다','set','기록을 새로 세울 때는 set, 기존 기록을 뛰어넘을 때는 break를 써요.','B1','culture',2,5,'record breaking music film box office','The film broke box office records in its opening weekend.','그 영화는 개봉 주말 박스오피스 기록을 깼어요.','The band broke attendance records with their world tour.','그 밴드는 월드 투어로 관객 수 기록을 깼어요.','The album broke records for streaming numbers in its first week.','그 앨범은 첫 주에 스트리밍 수 기록을 깼어요.','The musical broke records on Broadway last year.','그 뮤지컬은 작년에 브로드웨이에서 기록을 깼어요.','The exhibition broke attendance records at the museum.','그 전시회는 박물관 관람객 수 기록을 깼어요.'),
('col_culture_14','attend','a performance','attend a performance','공연을 관람하다','go','"go to a performance"도 맞지만 attend는 더 격식 있는 표현이에요.','B1','culture',2,14,'performance theater concert attend arts','We attended a breathtaking ballet performance at the national theater.','우리는 국립 극장에서 숨막히는 발레 공연을 관람했어요.','She attends live performances whenever she can.','그녀는 가능할 때마다 라이브 공연을 관람해요.','We attended a stunning ballet performance last Saturday.','지난 토요일에 우리는 멋진 발레 공연을 관람했어요.','They attended a traditional folk performance during their travels.','그들은 여행 중에 전통 민속 공연을 관람했어요.','I try to attend a performance at the opera house once a year.','저는 1년에 한 번은 오페라 하우스에서 공연을 관람하려고 해요.'),
('col_culture_01','put','on a performance','put on a performance','공연을 선보이다','make','"make a performance"는 어색해요. 공연을 무대에 올릴 때는 put on을 써요.','B2','culture',1,1,'performance theater stage show arts','The theater company put on a spectacular performance last night.','극단은 어젯밤 화려한 공연을 선보였어요.','The school put on a performance of Romeo and Juliet.','학교는 로미오와 줄리엣 공연을 선보였어요.','The students put on a performance to raise money for charity.','학생들은 자선 모금을 위해 공연을 선보였어요.','They put on a performance every Friday evening for the community.','그들은 지역사회를 위해 매주 금요일 저녁에 공연을 선보여요.','Local children put on a performance during the summer festival.','동네 아이들이 여름 축제 동안 공연을 선보였어요.'),
('col_culture_06','take','inspiration','take inspiration','영감을 얻다','get','"get inspiration"도 맞지만 take inspiration은 의도적으로 받아들이는 뉘앙스예요.','B2','culture',2,6,'inspiration art creative design culture','She takes inspiration from Korean traditional patterns in her designs.','그녀는 디자인에서 한국 전통 문양에서 영감을 얻어요.','The artist took inspiration from the landscape during her travels.','그 예술가는 여행 중에 풍경에서 영감을 얻었어요.','She takes inspiration from her grandmother''s old recipes.','그녀는 할머니의 옛 요리법에서 영감을 얻어요.','The composer took inspiration from sounds in nature.','작곡가는 자연의 소리에서 영감을 얻었어요.','Many designers take inspiration from street fashion.','많은 디자이너들이 스트리트 패션에서 영감을 얻어요.'),
('col_culture_07','get','recognition','get recognition','인정을 받다','receive','"receive recognition"도 맞지만 get은 더 구어체적이에요.','B2','culture',2,7,'recognition award achievement culture arts','She finally got the recognition she deserved for her work.','그녀는 마침내 자신의 작업에 대한 마땅한 인정을 받았어요.','The young director got international recognition at Cannes.','그 젊은 감독은 칸에서 국제적인 인정을 받았어요.','After years of small shows, she finally got recognition.','오랜 작은 공연 끝에 그녀는 마침내 인정을 받았어요.','His work got recognition from the international art community.','그의 작품은 국제 예술계로부터 인정을 받았어요.','Some artists only get recognition long after they are gone.','어떤 예술가들은 세상을 떠난 한참 뒤에야 인정을 받기도 해요.'),
('col_culture_08','keep','tradition','keep a tradition alive','전통을 이어가다','save','"save a tradition"도 쓰이지만 keep alive는 지속적인 유지를 강조해요.','B2','culture',2,8,'tradition culture heritage community festival','The community works hard to keep its cultural traditions alive.','그 공동체는 문화적 전통을 이어가기 위해 열심히 노력해요.','Festivals are a great way to keep traditional customs alive.','축제는 전통적인 관습을 이어가는 훌륭한 방법이에요.','My grandmother teaches me recipes to keep our family traditions alive.','할머니는 가족 전통을 이어가기 위해 저에게 요리법을 가르쳐 주세요.','Folk dance classes help keep cultural traditions alive.','민속 춤 수업이 문화적 전통을 이어가는 데 도움이 돼요.','Storytelling has kept tribal traditions alive for generations.','이야기하기는 세대에 걸쳐 부족 전통을 이어왔어요.'),
('col_culture_09','run','a festival','run a festival','축제를 진행하다','make','"make a festival"은 어색해요. 축제를 운영할 때는 run을 써요.','B2','culture',2,9,'festival culture event running annual','The city has been running the film festival for over 30 years.','그 도시는 30년 이상 영화제를 진행해 왔어요.','They run the cultural festival every autumn with community support.','그들은 지역사회 지원으로 매년 가을 문화 축제를 진행해요.','A small team of volunteers runs the local jazz festival.','작은 자원봉사자 팀이 지역 재즈 축제를 진행해요.','They run the festival on donations and ticket sales.','그들은 기부금과 티켓 판매로 축제를 진행해요.','Running a festival takes a full year of preparation.','축제를 진행하려면 1년의 준비 기간이 필요해요.'),
('col_culture_10','make','history','make history','역사를 만들다','do','"do history"는 틀린 표현이에요. 역사적인 순간을 만들 때는 make를 써요.','B2','culture',2,10,'history milestone achievement culture arts','She made history as the first woman to win the award.','그녀는 그 상을 수상한 최초의 여성으로 역사를 만들었어요.','The performance made history at Carnegie Hall.','그 공연은 카네기 홀에서 역사를 만들었어요.','She made history as the youngest conductor at the opera house.','그녀는 오페라 하우스의 최연소 지휘자로 역사를 만들었어요.','The team made history by winning the title for the first time.','그 팀은 처음으로 우승하며 역사를 만들었어요.','They made history by performing the play in three languages.','그들은 그 연극을 세 가지 언어로 공연하며 역사를 만들었어요.'),
('col_culture_12','celebrate','diversity','celebrate diversity','다양성을 축하하다','support','"support diversity"도 맞지만 celebrate는 더 적극적인 인정을 강조해요.','B2','culture',2,12,'diversity culture celebration inclusion society','The festival was designed to celebrate cultural diversity.','그 축제는 문화적 다양성을 축하하기 위해 기획됐어요.','Great cities celebrate diversity in all its forms.','훌륭한 도시들은 다양한 형태의 다양성을 축하해요.','The school holds an annual event to celebrate diversity.','그 학교는 다양성을 축하하기 위한 연례 행사를 열어요.','The street parade celebrates diversity in our city.','그 거리 퍼레이드는 우리 도시의 다양성을 축하해요.','Companies celebrate diversity through employee resource groups.','기업들은 직원 자원 그룹을 통해 다양성을 축하해요.'),
('col_culture_13','preserve','heritage','preserve heritage','유산을 보존하다','keep','"keep heritage"는 어색해요. 문화유산을 보존할 때는 preserve를 써요.','B2','culture',2,13,'heritage preservation culture museum history','It''s essential to preserve our cultural heritage for future generations.','미래 세대를 위해 문화 유산을 보존하는 것이 필수적이에요.','The museum works to preserve local heritage through exhibitions.','박물관은 전시를 통해 지역 유산을 보존하기 위해 노력해요.','UNESCO works to preserve cultural heritage around the world.','유네스코는 전 세계 문화유산을 보존하기 위해 노력해요.','The community center preserves the heritage of their neighborhood.','주민 센터는 동네의 유산을 보존해요.','Preserving heritage helps us understand who we are.','유산을 보존하는 것은 우리가 누구인지를 이해하는 데 도움이 돼요.'),
('col_culture_15','launch','an art project','launch an art project','예술 프로젝트를 시작하다','start','"start an art project"도 맞지만 launch는 공식적인 시작을 강조해요.','B2','culture',2,15,'art project launch exhibition gallery start','The artist launched a community art project in the city center.','그 예술가는 시내 중심부에서 지역 사회 예술 프로젝트를 시작했어요.','The gallery is launching a new exhibition series next month.','갤러리는 다음 달에 새로운 전시 시리즈를 시작해요.','They launched an art project to brighten the local subway station.','그들은 지역 지하철역을 환하게 하기 위해 예술 프로젝트를 시작했어요.','The artist launched an art project on social justice.','그 예술가는 사회 정의에 관한 예술 프로젝트를 시작했어요.','They launched an art project that involved children from five schools.','그들은 다섯 학교의 아이들이 참여하는 예술 프로젝트를 시작했어요.'),
('col_culture_16','draw','crowds','draw crowds','군중을 끌어들이다','get','"get crowds"도 맞지만 draw는 매력으로 끌어들이는 뉘앙스예요.','B2','culture',2,16,'crowd attraction cultural event performance','The street performer drew large crowds on the weekend.','거리 공연자는 주말에 많은 군중을 끌어들였어요.','The new sculpture in the plaza draws crowds every day.','광장의 새 조각품은 매일 군중을 끌어들여요.','The new public art piece drew crowds from across the city.','새 공공 예술 작품은 도시 전역에서 군중을 끌어들였어요.','The street parade drew crowds despite the bad weather.','거리 퍼레이드는 궂은 날씨에도 불구하고 군중을 끌어들였어요.','The night market draws crowds every weekend.','야시장은 주말마다 군중을 끌어들여요.'),
('col_culture_17','debut','as','debut as','~으로 데뷔하다','start','"start as"도 맞지만 debut는 공식적인 첫 등장을 강조해요.','B2','culture',2,17,'debut career artist solo performance','She debuted as a solo artist after leaving the group.','그녀는 그룹을 떠난 후 솔로 아티스트로 데뷔했어요.','He debuted as a director with a critically acclaimed short film.','그는 비평가들에게 호평을 받은 단편 영화로 감독으로 데뷔했어요.','She debuted as a stand-up comedian at a small club in Seoul.','그녀는 서울의 작은 클럽에서 스탠드업 코미디언으로 데뷔했어요.','He debuted as a novelist with a book about his childhood.','그는 어린 시절에 관한 책으로 소설가로 데뷔했어요.','She debuted as a model at the age of 16.','그녀는 16세에 모델로 데뷔했어요.'),
('col_culture_19','appreciate','art','appreciate art','예술을 감상하다','enjoy','"enjoy art"도 맞지만 appreciate는 더 깊은 이해를 강조해요.','B2','culture',2,19,'art appreciation museum gallery culture','She learned to appreciate classical art during her studies.','그녀는 학업 중에 고전 예술을 감상하는 법을 배웠어요.','Visiting museums is a wonderful way to appreciate different art forms.','박물관을 방문하는 것은 다양한 예술 형태를 감상하는 훌륭한 방법이에요.','You don''t need formal training to appreciate art.','예술을 감상하는 데 정식 교육이 필요하지는 않아요.','He learned to appreciate art by visiting galleries every weekend.','그는 매 주말 갤러리를 방문하며 예술을 감상하는 법을 배웠어요.','Children learn to appreciate art through hands-on activities.','아이들은 직접 해보는 활동을 통해 예술을 감상하는 법을 배워요.'),
('col_culture_11','blend','cultures','blend cultures','문화를 융합하다','mix','"mix cultures"도 맞지만 blend는 더 자연스럽고 조화로운 융합을 강조해요.','C1','culture',3,11,'culture blend fusion diversity multicultural','Her cooking blends Korean and Italian culinary traditions.','그녀의 요리는 한국과 이탈리아 요리 전통을 융합해요.','The city has always been a place where different cultures blend.','그 도시는 항상 서로 다른 문화가 융합되는 곳이었어요.','The chef blends Korean and French cuisines with elegance.','그 셰프는 한국과 프랑스 요리를 우아하게 융합해요.','The neighborhood blends different cultures and feels alive.','그 동네는 다양한 문화를 융합하여 활기차게 느껴져요.','Their music blends traditional and modern styles.','그들의 음악은 전통과 현대 스타일을 융합해요.'),
('col_culture_18','commission','a work','commission a work','작품을 의뢰하다','order','"order a work"도 쓰이지만 commission은 예술 작품 의뢰에 전문적인 표현이에요.','C1','culture',3,18,'commission art mural sculpture gallery','The museum commissioned a new sculpture for its entrance.','박물관은 입구를 위한 새로운 조각 작품을 의뢰했어요.','She was commissioned to paint a mural for the city hall.','그녀는 시청을 위한 벽화를 그리도록 의뢰받았어요.','A wealthy patron commissioned a work for the new library.','부유한 후원자가 새 도서관을 위한 작품을 의뢰했어요.','The hotel commissioned a work to feature in its lobby.','호텔은 로비에 전시할 작품을 의뢰했어요.','They commissioned a work from a local artist to support the community.','그들은 지역사회를 지원하기 위해 지역 예술가에게 작품을 의뢰했어요.'),
('col_culture_20','gain','cultural insight','gain cultural insight','문화적 통찰을 얻다','get','"get cultural insight"도 맞지만 gain은 점차 깊어지는 이해를 강조해요.','C1','culture',3,20,'cultural insight travel exchange understanding','Traveling abroad is a great way to gain cultural insight.','해외여행은 문화적 통찰을 얻는 훌륭한 방법이에요.','The exchange program helped students gain cultural insight.','교환 프로그램은 학생들이 문화적 통찰을 얻는 데 도움이 됐어요.','Living abroad helped me gain cultural insight in unexpected ways.','해외 생활은 예상치 못한 방식으로 제가 문화적 통찰을 얻는 데 도움이 됐어요.','Documentaries are an easy way to gain cultural insight.','다큐멘터리는 문화적 통찰을 얻는 쉬운 방법이에요.','Reading translated literature helps you gain cultural insight.','번역 문학을 읽으면 문화적 통찰을 얻는 데 도움이 돼요.'),
('col_culture_C1_01','embrace','diversity','embrace diversity','다양성을 포용하다','accept','단순히 받아들이는 것이 아니라 적극적으로 환영하고 가치를 둔다는 뜻이에요. 조직 가치 선언문에 자주 등장해요.','C1','culture',2,0,'diverse group','The university actively embraces diversity in its student body and faculty.','그 대학은 학생과 교수진의 다양성을 적극적으로 포용해요.','Modern workplaces must embrace diversity to remain competitive.','현대 직장은 경쟁력을 유지하려면 다양성을 포용해야 해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_culture_C1_02','preserve','heritage','preserve heritage','유산을 보존하다','keep','문화적, 역사적 가치를 후대에 전하기 위해 지킨다는 격식 표현이에요. UNESCO 문서에서 표준이에요.','C1','culture',2,0,'historic building','The foundation works tirelessly to preserve the heritage of indigenous communities.','그 재단은 원주민 공동체의 유산을 보존하기 위해 끊임없이 노력해요.','Local artisans help preserve a heritage that spans generations.','지역 장인들은 여러 세대에 걸친 유산을 보존하는 데 기여해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_culture_C1_03','challenge','stereotypes','challenge stereotypes','고정관념에 도전하다','change','기존의 편견이나 고정관념에 정면으로 맞선다는 뜻이에요. 사회 비평, 광고 캠페인에서 자주 보여요.','C1','culture',2,0,'breaking barriers','Her documentary boldly challenges stereotypes about rural communities.','그녀의 다큐멘터리는 농촌 공동체에 대한 고정관념에 과감히 도전해요.','The campaign was designed to challenge stereotypes about ageing.','그 캠페인은 노화에 대한 고정관념에 도전하기 위해 기획됐어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_culture_C1_04','appreciate','art','appreciate art','예술을 감상하다','like','단순한 호감을 넘어 가치를 이해하며 감상한다는 격식 표현이에요. 미술관 안내문이나 평론에 어울려요.','C1','culture',2,0,'art gallery','Learning to appreciate art often begins with understanding its historical context.','예술을 감상하는 법은 보통 그 역사적 맥락을 이해하는 데서 시작해요.','She has cultivated an ability to appreciate art across many periods.','그녀는 다양한 시대의 예술을 감상할 수 있는 안목을 길렀어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_culture_C1_05','celebrate','traditions','celebrate traditions','전통을 기리다','do','문화 전통을 의식적으로 기념하고 가치를 인정한다는 뜻이에요. 명절, 축제 보도에서 표준 표현이에요.','C1','culture',2,0,'traditional festival','The festival celebrates the traditions of the Andean highlands.','그 축제는 안데스 고원의 전통을 기려요.','Families gather every autumn to celebrate the traditions of Chuseok.','가족들은 매년 가을 추석의 전통을 기리기 위해 모여요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_culture_C2_01','embrace','tradition','embrace tradition','전통을 받아들이다','follow','전통을 적극적이고 긍정적으로 수용한다는 뉘앙스예요. 문화 평론, 정책 담론에서 자주 써요.','C2','culture',3,0,'traditional craft hands','The contemporary chef embraces tradition while reinventing classic recipes.','그 현대 셰프는 전통을 받아들이면서도 고전적 레시피를 재해석해요.','Many designers embrace tradition as a source of innovation, not constraint.','많은 디자이너들은 전통을 제약이 아닌 혁신의 원천으로 받아들여요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_culture_C2_02','transcend','boundaries','transcend boundaries','경계를 초월하다','cross','단순히 ''넘는다''가 아니라 한계 자체를 초월하여 새로운 차원에 이른다는 격식 표현이에요. 예술 평론의 단골 표현이에요.','C2','culture',3,0,'art installation gallery','Her installations transcend the boundaries between sculpture and performance.','그녀의 설치 작품은 조각과 퍼포먼스의 경계를 초월해요.','Truly great cinema transcends linguistic and cultural boundaries.','진정으로 위대한 영화는 언어와 문화의 경계를 초월해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_culture_C2_03','epitomize','elegance','epitomize elegance','우아함의 전형이 되다','show','어떤 자질의 완벽한 본보기가 된다는 격식 동사예요. 패션, 인물 평론, 디자인 평가에 적합해요.','C2','culture',3,0,'elegant ballroom','Her tailored silhouette epitomizes mid-century elegance.','그녀의 재단된 실루엣은 20세기 중반 우아함의 전형이에요.','The opera house epitomizes the elegance of the Belle Epoque.','그 오페라 하우스는 벨 에포크 시대 우아함의 전형이에요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_culture_C2_04','challenge','convention','challenge convention','관습에 도전하다','break','기존의 통념이나 관습에 의문을 제기하며 맞선다는 격식 표현이에요. 예술과 학술 비평에서 표준이에요.','C2','culture',3,0,'avant-garde art','The avant-garde movement sought to challenge every convention of academic painting.','아방가르드 운동은 학파 회화의 모든 관습에 도전하려 했어요.','Her debut novel challenges convention in both form and content.','그녀의 데뷔작은 형식과 내용 모두에서 관습에 도전해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_culture_C2_05','blend','influences','blend influences','영향을 융합하다','mix','서로 다른 문화나 양식의 영향을 조화롭게 결합한다는 표현이에요. 음악, 요리, 디자인 평론에서 자주 보여요.','C2','culture',3,0,'fusion cuisine','The composer skillfully blends European and East Asian musical influences.','그 작곡가는 유럽과 동아시아의 음악적 영향을 능숙하게 융합해요.','Their cuisine blends Andalusian and North African influences with quiet sophistication.','그들의 요리는 안달루시아와 북아프리카의 영향을 잔잔한 세련됨으로 융합해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_discussion_24','have','idea','have an idea','아이디어가 있다','get','"get an idea"는 떠올랐다는 순간의 표현. 보유 중이라는 의미는 have an idea.','A1','discussion',1,0,'lightbulb idea inspiration person thinking','I have an idea for our next project.','다음 프로젝트 아이디어가 있어요.','Do you have any idea what time it is?','지금 몇 시인지 짐작이 가요?','She has lots of creative ideas.','그녀는 창의적인 아이디어가 많아요.','I have an idea — let''s try a different approach.','아이디어가 있어요 — 다른 방법을 시도해 봐요.','He had an idea that turned out to be brilliant.','그는 결국 훌륭한 것으로 밝혀진 아이디어가 있었어요.'),
('col_discussion_22','make','mistake','make a mistake','실수를 하다','do','"do a mistake"은 흔한 오류예요. 실수는 항상 make와 함께 써요.','A2','discussion',1,0,'person realization mistake correcting paper','Everyone makes mistakes sometimes.','누구나 가끔 실수를 해요.','I made a mistake in the report — I''ll fix it.','보고서에 실수를 했어요 — 수정할게요.','Don''t be afraid to make mistakes when learning.','배울 때 실수하는 걸 두려워하지 마세요.','She admitted she had made a serious mistake.','그녀는 심각한 실수를 했다고 인정했어요.','We learn the most from the mistakes we make.','우리는 자신이 한 실수에서 가장 많이 배워요.'),
('col_discussion_23','give','example','give an example','예를 들다','make','"make an example"은 다른 의미 (남에게 본보기로 삼다)예요. 단순 예시는 give an example.','A2','discussion',1,0,'teacher example explaining whiteboard students','Can you give an example to clarify?','명확히 하기 위해 예를 들어 줄 수 있나요?','Let me give you an example from my own experience.','제 경험에서 예를 들어 드릴게요.','The teacher gave several examples to illustrate the concept.','선생님은 개념을 설명하기 위해 여러 예를 들었어요.','She gave an example that everyone could relate to.','그녀는 모두가 공감할 수 있는 예를 들었어요.','Could you give me a concrete example?','구체적인 예를 들어 줄 수 있나요?'),
('col_discussion_01','raise','a point','raise a point','요점을 제기하다','make','"make a point"도 맞지만 raise a point는 새로운 관점을 꺼내는 뉘앙스예요.','B1','discussion',1,1,'discussion meeting debate point talking','She raised an important point about the budget during the meeting.','그녀는 회의 중에 예산에 대한 중요한 요점을 제기했어요.','He raised several valid points that changed the direction of the debate.','그는 토론의 방향을 바꾸는 여러 타당한 요점을 제기했어요.','He raised a thoughtful point during the team discussion.','그는 팀 토론 중 사려 깊은 요점을 제기했어요.','She raised a point that no one had considered before.','그녀는 아무도 이전에 고려하지 않은 요점을 제기했어요.','Raising a quick point at the end can change the tone of a meeting.','회의 마지막에 짧은 요점을 제기하면 분위기가 바뀔 수 있어요.'),
('col_discussion_07','hold','a debate','hold a debate','토론을 개최하다','make','"make a debate"는 어색해요. 토론을 개최할 때는 hold를 써요.','B1','discussion',1,7,'debate school discussion audience event','The school held a debate on the topic of climate change.','학교는 기후 변화 주제로 토론을 개최했어요.','We hold a monthly debate on current affairs.','우리는 시사 문제에 대한 월례 토론을 개최해요.','The university holds a debate on current issues every semester.','그 대학은 매 학기마다 시사 문제에 대한 토론을 개최해요.','They held a debate between the two candidates last night.','그들은 어젯밤 두 후보 사이의 토론을 개최했어요.','Holding a debate online attracted a much wider audience.','온라인으로 토론을 개최하니 훨씬 더 많은 청중이 모였어요.'),
('col_discussion_08','come to','a conclusion','come to a conclusion','결론에 이르다','make','"make a conclusion"은 학문적으로 어색해요. 결론에 도달할 때는 come to 또는 draw를 써요.','B1','discussion',1,8,'conclusion decision discussion result meeting','After reviewing the data, we came to a clear conclusion.','데이터를 검토한 후 우리는 명확한 결론에 이르렀어요.','It took weeks of discussion before they could come to a conclusion.','결론에 이르는 데 수 주간의 토론이 필요했어요.','After analyzing the data, they came to a surprising conclusion.','데이터를 분석한 후 그들은 놀라운 결론에 이르렀어요.','We came to the conclusion that the project was not feasible.','우리는 그 프로젝트가 실현 가능하지 않다는 결론에 이르렀어요.','Coming to a conclusion sometimes requires sleeping on it.','결론에 이르는 것은 때로 하룻밤 자고 생각해야 해요.'),
('col_discussion_09','express','an opinion','express an opinion','의견을 표현하다','say','"say an opinion"은 어색해요. 의견을 말할 때는 express 또는 share를 써요.','B1','discussion',1,9,'opinion expression discussion talking','Everyone was encouraged to express their opinion freely.','모든 사람이 자유롭게 의견을 표현하도록 장려됐어요.','She expressed her opinion clearly without being aggressive.','그녀는 공격적이지 않게 자신의 의견을 명확하게 표현했어요.','In healthy discussions, everyone should feel safe to express an opinion.','건강한 토론에서는 모두가 안전하게 의견을 표현할 수 있어야 해요.','He expressed his opinion calmly even when others disagreed.','그는 다른 사람들이 동의하지 않을 때도 침착하게 의견을 표현했어요.','She expressed her opinion through a beautifully written essay.','그녀는 아름답게 쓰인 에세이를 통해 의견을 표현했어요.'),
('col_discussion_11','make','a point','make a point','요점을 말하다','do','"do a point"는 틀린 표현이에요. 요점을 전달할 때는 make를 써요.','B1','discussion',1,11,'point discussion meeting argument','He made a very good point about the importance of communication.','그는 소통의 중요성에 대해 매우 좋은 요점을 말했어요.','I''d like to make a point before we move on.','계속 진행하기 전에 요점을 말하고 싶어요.','He made a really good point about how we should measure success.','그는 우리가 성공을 어떻게 측정해야 하는지에 대해 정말 좋은 요점을 말했어요.','She made a point that completely shifted the team''s thinking.','그녀는 팀의 사고를 완전히 바꾸는 요점을 말했어요.','Making a point clearly is more important than making many points.','많은 요점을 말하는 것보다 한 요점을 명확히 말하는 게 더 중요해요.'),
('col_discussion_13','disagree','with','disagree with','~에 동의하지 않다','oppose','"oppose"도 맞지만 disagree with가 더 일상적이고 부드러운 반대예요.','B1','discussion',1,13,'disagree debate discussion opinion','I respect your view, but I disagree with your conclusion.','당신의 견해를 존중하지만 결론에는 동의하지 않아요.','She politely disagreed with the proposal during the meeting.','그녀는 회의에서 정중하게 제안에 동의하지 않았어요.','I disagree with the idea, but I respect how you presented it.','그 아이디어에는 동의하지 않지만 제시한 방식은 존중해요.','She politely disagreed with her mentor''s advice.','그녀는 멘토의 조언에 정중하게 동의하지 않았어요.','It''s OK to disagree with someone you usually agree with.','평소에 동의하는 사람과도 동의하지 않을 수 있어요.'),
('col_discussion_21','make','sense','make sense','말이 되다, 이해가 되다','do','"do sense"는 틀린 표현이에요. 어떤 설명이나 상황이 논리적일 때 make sense를 써요.','B1','discussion',1,0,'people understanding clarity conversation aha moment','Your explanation makes sense to me now.','이제 당신의 설명이 이해가 돼요.','It doesn''t make sense to leave so early.','그렇게 일찍 떠나는 건 말이 안 돼요.','Does this make sense, or should I explain again?','이해가 되나요, 아니면 다시 설명할까요?','His decision makes sense given the circumstances.','상황을 고려하면 그의 결정이 이해가 돼요.','The instructions don''t make sense — there must be a typo.','설명서가 말이 안 돼요 — 오타가 있는 게 분명해요.'),
('col_discussion_02','reach','a consensus','reach a consensus','합의에 이르다','get','"get a consensus"도 쓰이지만 reach는 노력 끝에 도달하는 뉘앙스예요.','B2','discussion',2,2,'agreement consensus discussion team','After two hours of debate, the group reached a consensus.','두 시간의 토론 끝에 그룹은 합의에 이르렀어요.','It was difficult to reach a consensus on such a controversial topic.','그렇게 논쟁적인 주제에서 합의에 이르기가 어려웠어요.','The committee reached a consensus after hours of debate.','위원회는 몇 시간의 토론 끝에 합의에 이르렀어요.','It''s rare to reach a consensus on such polarizing topics.','그렇게 의견이 갈리는 주제에서 합의에 이르는 것은 드물어요.','They reached a consensus by finding common ground.','그들은 공통점을 찾아 합의에 이르렀어요.'),
('col_discussion_03','put forward','an argument','put forward an argument','주장을 내놓다','say','"say an argument"는 어색해요. 논거를 제시할 때는 put forward를 써요.','B2','discussion',2,3,'argument debate discussion point','She put forward a compelling argument for changing the policy.','그녀는 정책 변경을 위한 설득력 있는 주장을 내놓았어요.','The professor put forward several arguments to support his theory.','교수는 자신의 이론을 뒷받침하기 위해 여러 주장을 내놓았어요.','He put forward a strong argument backed up by statistics.','그는 통계로 뒷받침된 강력한 주장을 내놓았어요.','She put forward an argument based on her own research.','그녀는 자신의 연구를 바탕으로 주장을 내놓았어요.','Putting forward a clear argument helps move the discussion forward.','명확한 주장을 내놓으면 토론이 진전되는 데 도움이 돼요.'),
('col_discussion_04','take','a stance','take a stance','입장을 취하다','have','"have a stance"도 쓰이지만 take a stance는 의도적인 선택을 강조해요.','B2','discussion',2,4,'stance opinion position discussion debate','The company took a clear stance on environmental issues.','그 회사는 환경 문제에 대해 명확한 입장을 취했어요.','It''s important to take a stance and defend it with evidence.','입장을 취하고 그것을 증거로 뒷받침하는 것이 중요해요.','She took a strong stance against the proposed changes.','그녀는 제안된 변경에 강한 입장을 취했어요.','It''s not always easy to take a stance on sensitive issues.','민감한 문제에 입장을 취하기가 항상 쉽지는 않아요.','Leaders are expected to take a stance when needed.','리더들은 필요할 때 입장을 취해야 해요.'),
('col_discussion_06','back up','a claim','back up a claim','주장을 뒷받침하다','prove','"prove a claim"도 맞지만 back up은 증거나 논거로 지지하는 뉘앙스예요.','B2','discussion',2,6,'evidence claim support data proof','You need to back up your claim with solid data.','주장을 탄탄한 데이터로 뒷받침해야 해요.','She backed up her claim with research from three different studies.','그녀는 세 가지 다른 연구의 결과로 자신의 주장을 뒷받침했어요.','She backed up her claim with evidence from peer-reviewed journals.','그녀는 동료 심사 저널의 증거로 주장을 뒷받침했어요.','You should always be ready to back up your claim with examples.','예시로 주장을 뒷받침할 준비가 항상 되어 있어야 해요.','He backed up his claim with figures from a recent survey.','그는 최근 설문 조사 수치로 자신의 주장을 뒷받침했어요.'),
('col_discussion_12','open up','a discussion','open up a discussion','토론을 시작하다','start','"start a discussion"도 맞지만 open up은 더 넓은 참여를 유도하는 뉘앙스예요.','B2','discussion',2,12,'discussion open dialogue group panel','The moderator opened up a discussion on workplace diversity.','사회자는 직장 다양성에 대한 토론을 시작했어요.','The documentary opened up a wider public discussion on the issue.','그 다큐멘터리는 그 문제에 대해 더 넓은 공개 토론을 시작했어요.','The teacher opened up a discussion about cyberbullying in school.','선생님은 학교에서의 사이버 괴롭힘에 대한 토론을 시작했어요.','Her question opened up a discussion that lasted the whole hour.','그녀의 질문이 한 시간 내내 이어진 토론을 시작했어요.','A well-timed question can open up a discussion in any meeting.','적절한 타이밍의 질문은 어느 회의에서나 토론을 시작할 수 있어요.'),
('col_discussion_14','build on','an idea','build on an idea','아이디어를 발전시키다','develop','"develop an idea"도 맞지만 build on은 기존 아이디어를 기반으로 발전시키는 뉘앙스예요.','B2','discussion',2,14,'idea develop build discussion creative','Let''s build on that idea and explore it further.','그 아이디어를 발전시켜 더 깊이 탐구해 봐요.','She built on her colleague''s suggestion to create a new proposal.','그녀는 동료의 제안을 발전시켜 새로운 제안서를 만들었어요.','She built on her teammate''s idea and made it even better.','그녀는 팀원의 아이디어를 발전시켜 더 좋게 만들었어요.','Good brainstorming sessions involve building on each other''s ideas.','좋은 브레인스토밍 세션에서는 서로의 아이디어를 발전시켜요.','He built on the original concept to create something completely new.','그는 원래 개념을 발전시켜 완전히 새로운 것을 만들었어요.'),
('col_discussion_15','summarise','the key points','summarise the key points','핵심 요점을 요약하다','explain','"explain the key points"도 맞지만 summarise는 간결하게 정리하는 것을 강조해요.','B2','discussion',2,15,'summary key points meeting discussion notes','At the end of the meeting, she summarised the key points discussed.','회의 말미에 그녀는 논의된 핵심 요점을 요약했어요.','Could you summarise the key points in one paragraph?','핵심 요점을 한 단락으로 요약해 줄 수 있어요?','Let me summarise the key points before we wrap up.','마무리하기 전에 핵심 요점을 요약할게요.','She summarised the key points so newcomers could catch up.','그녀는 새로 온 사람들이 따라잡을 수 있도록 핵심 요점을 요약했어요.','I always summarise the key points at the end of my notes.','저는 항상 노트의 끝에 핵심 요점을 요약해요.'),
('col_discussion_19','invite','feedback','invite feedback','피드백을 요청하다','ask','"ask for feedback"도 맞지만 invite feedback은 더 개방적이고 따뜻한 뉘앙스예요.','B2','discussion',2,19,'feedback discussion invite team comment','At the end of her presentation, she invited feedback from the audience.','발표 마지막에 그녀는 청중에게 피드백을 요청했어요.','The manager invited feedback from the whole team about the new process.','관리자는 새 프로세스에 대해 팀 전체에게 피드백을 요청했어요.','She invited feedback on the draft before submitting it.','그녀는 제출 전에 초안에 대한 피드백을 요청했어요.','The conference organizers invited feedback from all attendees.','컨퍼런스 주최 측은 모든 참석자들에게 피드백을 요청했어요.','Inviting feedback openly shows that you''re open to growth.','피드백을 공개적으로 요청하는 것은 성장에 열려 있음을 보여줘요.'),
('col_discussion_20','wrap up','a discussion','wrap up a discussion','토론을 마무리하다','end','"end a discussion"도 맞지만 wrap up은 요약하며 마무리하는 뉘앙스예요.','B2','discussion',2,20,'wrap up discussion close meeting end','Let''s wrap up the discussion and agree on next steps.','토론을 마무리하고 다음 단계에 합의해요.','She wrapped up the discussion by thanking everyone for their input.','그녀는 모든 사람의 의견에 감사하며 토론을 마무리했어요.','Let''s wrap up the discussion and revisit it next week.','토론을 마무리하고 다음 주에 다시 논의해요.','She wrapped up the discussion with three clear action items.','그녀는 세 가지 명확한 실행 항목으로 토론을 마무리했어요.','Wrapping up a discussion clearly helps people leave with purpose.','토론을 명확히 마무리하면 사람들이 목적의식을 가지고 떠날 수 있어요.'),
('col_discussion_25','take','position','take a position','입장을 정하다','hold','"hold a position"은 자리(직위)를 가진다는 의미. 의견 표명은 take a position on...','B2','discussion',1,0,'debate stance opinion confident speaker','She took a strong position on the issue.','그녀는 그 문제에 대해 강한 입장을 정했어요.','It''s time for the company to take a position.','회사가 입장을 정할 때예요.','He took the position that we should wait.','그는 우리가 기다려야 한다는 입장을 취했어요.','Don''t be afraid to take a position in the debate.','토론에서 입장을 정하는 걸 두려워하지 마세요.','The government took a neutral position on the matter.','정부는 그 사안에 중립적 입장을 취했어요.'),
('col_discussion_05','challenge','an assumption','challenge an assumption','가정에 의문을 제기하다','question','"question an assumption"도 맞지만 challenge는 더 직접적인 반박을 강조해요.','C1','discussion',3,5,'challenge assumption critical thinking debate','He challenged the assumption that everyone agrees with the new system.','그는 모든 사람이 새로운 시스템에 동의한다는 가정에 의문을 제기했어요.','Good critical thinkers are willing to challenge their own assumptions.','좋은 비판적 사고자들은 자신의 가정에도 기꺼이 의문을 제기해요.','He challenged the assumption that working longer means working better.','그는 더 오래 일하는 것이 더 잘 일하는 것이라는 가정에 의문을 제기했어요.','Children naturally challenge the assumptions of adults.','아이들은 자연스럽게 어른들의 가정에 의문을 제기해요.','A good teacher encourages students to challenge assumptions.','좋은 선생님은 학생들이 가정에 의문을 제기하도록 격려해요.'),
('col_discussion_10','acknowledge','a viewpoint','acknowledge a viewpoint','관점을 인정하다','accept','"accept a viewpoint"도 맞지만 acknowledge는 완전히 동의하지 않아도 인정하는 뉘앙스예요.','C1','discussion',3,10,'viewpoint acknowledge discussion respect','A good debater always acknowledges the opposing viewpoint.','좋은 토론자는 항상 반대 관점을 인정해요.','She acknowledged his viewpoint before explaining why she disagreed.','그녀는 반박하기 전에 그의 관점을 인정했어요.','It''s respectful to acknowledge a viewpoint before responding.','답변하기 전에 관점을 인정하는 것은 존중하는 행동이에요.','She acknowledged my viewpoint and offered a different perspective.','그녀는 제 관점을 인정하고 다른 관점을 제시했어요.','Acknowledging the opposing viewpoint makes your argument stronger.','반대 관점을 인정하면 자신의 주장이 더 강해져요.'),
('col_discussion_16','draw','a distinction','draw a distinction','구분하다, 차이를 명확히 하다','make','"make a distinction"도 맞지만 draw a distinction은 논거에서 더 학문적으로 쓰여요.','C1','discussion',3,16,'distinction difference concept debate analysis','We need to draw a distinction between fact and opinion.','사실과 의견을 구분할 필요가 있어요.','The speaker drew a clear distinction between the two concepts.','연사는 두 개념 사이의 명확한 구분을 지었어요.','She drew a clear distinction between persuasion and manipulation.','그녀는 설득과 조작 사이의 명확한 구분을 지었어요.','The article draws a distinction between correlation and causation.','그 기사는 상관관계와 인과관계의 차이를 명확히 해요.','Drawing a clear distinction is the first step toward clear thinking.','명확하게 구분하는 것이 명확한 사고의 첫 걸음이에요.'),
('col_discussion_17','shift','the focus','shift the focus','초점을 바꾸다','change','"change the focus"도 맞지만 shift는 점진적인 변화를 강조해요.','C1','discussion',3,17,'focus discussion shift change topic','The moderator shifted the focus to the economic aspects.','사회자는 경제적 측면으로 초점을 바꿨어요.','He tried to shift the focus away from the controversial point.','그는 논란이 되는 요점에서 초점을 바꾸려 했어요.','She tactfully shifted the focus back to the original question.','그녀는 재치 있게 초점을 원래 질문으로 다시 옮겼어요.','The host shifted the focus to lighter topics after the heated debate.','진행자는 격렬한 토론 후 가벼운 주제로 초점을 옮겼어요.','Sometimes you need to shift the focus to keep the conversation moving.','때로는 대화가 계속되도록 초점을 옮길 필요가 있어요.'),
('col_discussion_18','reach','an impasse','reach an impasse','교착 상태에 빠지다','get','"get stuck"도 맞지만 reach an impasse는 협상이나 토론에서 더 격식 있는 표현이에요.','C1','discussion',3,18,'impasse stuck negotiation discussion deadlock','The negotiations reached an impasse after three days.','협상은 3일 후 교착 상태에 빠졌어요.','Discussions reached an impasse when neither side would compromise.','어느 쪽도 타협하지 않으려 하자 토론이 교착 상태에 빠졌어요.','Talks have reached an impasse over the issue of pay.','협상이 임금 문제로 교착 상태에 빠졌어요.','When discussions reach an impasse, a mediator can sometimes help.','토론이 교착 상태에 빠지면 중재자가 때로 도움이 될 수 있어요.','They reached an impasse and decided to revisit the issue next week.','그들은 교착 상태에 빠져서 다음 주에 다시 논의하기로 했어요.'),
('col_discussion_C1_01','raise','point','raise a point','의견을 제기하다','say','회의나 토론에서 새로운 논점을 정중하게 꺼낼 때 써요. ''say a point''는 자연스럽지 않아요.','C1','discussion',2,0,'meeting discussion','May I raise a point about the proposed timeline?','제안된 일정에 관해 한 가지 의견을 제기해도 될까요?','She raised an important point about ethical considerations.','그녀는 윤리적 고려사항에 관한 중요한 의견을 제기했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_discussion_C1_02','build','consensus','build consensus','합의를 형성하다','make','여러 사람의 의견을 모아 동의를 끌어낸다는 격식 표현이에요. 정책, 회의, 협의 맥락에서 자주 써요.','C1','discussion',2,0,'roundtable meeting','The chair worked hard to build consensus among committee members.','의장은 위원들 사이의 합의를 형성하기 위해 열심히 노력했어요.','Building consensus takes time but produces lasting decisions.','합의를 형성하는 데는 시간이 걸리지만 지속 가능한 결정을 낳아요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_discussion_C1_03','voice','opinion','voice an opinion','의견을 표명하다','tell','자신의 의견을 공개적으로 분명하게 표현한다는 격식 표현이에요. ''give an opinion''보다 더 적극적인 뉘앙스예요.','C1','discussion',2,0,'public speaker','Everyone was encouraged to voice their opinion during the open forum.','공개 토론에서 모두가 의견을 표명하도록 권장됐어요.','She voiced a dissenting opinion at the board meeting.','그녀는 이사회에서 반대 의견을 표명했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_discussion_C1_04','address','concerns','address concerns','우려 사항을 다루다','answer','제기된 걱정거리를 진지하게 검토하고 대응한다는 표현이에요. 비즈니스, 정치, 학술 토론의 표준 어휘예요.','C1','discussion',2,0,'town hall meeting','The CEO took time to address employees'' concerns about restructuring.','CEO는 구조조정에 대한 직원들의 우려를 다루는 데 시간을 들였어요.','Please address any concerns before we proceed with the vote.','투표를 진행하기 전에 우려 사항이 있으면 다뤄 주세요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_discussion_C1_05','weigh','options','weigh the options','선택지를 저울질하다','think','여러 가능성의 장단점을 신중히 비교 검토한다는 표현이에요. 의사결정 회의에서 자주 써요.','C1','discussion',2,0,'balance scale','The committee weighed the options carefully before announcing its decision.','위원회는 결정을 발표하기 전에 선택지를 신중히 저울질했어요.','We need to weigh the options before committing resources.','자원을 투입하기 전에 선택지를 저울질해야 해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_discussion_C2_01','reach','consensus','reach consensus','합의에 이르다','make','논의 끝에 참석자 다수가 동의에 도달했다는 격식 표현이에요. ''make''는 어색하고, ''reach''가 표준 학술·외교 용어예요.','C2','discussion',3,0,'meeting handshake','After three days of deliberation, the committee finally reached consensus on the wording.','사흘간의 숙의 끝에 위원회는 마침내 문안에 합의를 이루었어요.','Reaching consensus on such a contentious issue will require sustained dialogue.','그렇게 첨예한 사안에서 합의에 이르려면 지속적인 대화가 필요해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_discussion_C2_02','raise','objections','raise objections','이의를 제기하다','say','회의나 토론에서 공식적으로 반대 의견을 제기할 때 쓰는 격식 표현이에요. ''say''는 격이 떨어져요.','C2','discussion',3,0,'board meeting','Several board members raised objections to the proposed restructuring.','여러 이사회 구성원이 제안된 구조조정에 이의를 제기했어요.','If you wish to raise objections, please do so before the vote is called.','이의를 제기하시려면 표결 전에 해 주세요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_discussion_C2_03','voice','concerns','voice concerns','우려를 표명하다','tell','걱정이나 우려를 공개적으로 표현한다는 외교적·격식 표현이에요. ''tell''은 격이 부족해요.','C2','discussion',3,0,'concerned speaker','Stakeholders voiced grave concerns over the environmental impact assessment.','이해관계자들은 환경 영향 평가에 대해 심각한 우려를 표명했어요.','She voiced her concerns directly to the steering committee.','그녀는 운영위원회에 직접 우려를 표명했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_discussion_C2_04','challenge','assumptions','challenge assumptions','전제에 의문을 제기하다','doubt','논의의 바탕이 되는 전제를 근본부터 재검토하자는 비판적 사고 표현이에요. ''doubt''보다 학술적이고 적극적이에요.','C2','discussion',3,0,'debate forum','The keynote speaker urged delegates to challenge their assumptions about productivity.','기조 연사는 대표단에게 생산성에 대한 전제를 재검토하라고 촉구했어요.','A good moderator challenges assumptions rather than reinforcing them.','좋은 사회자는 전제를 강화하기보다 의문을 제기해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_discussion_C2_05','concede','point','concede a point','논점을 인정하다','agree','토론에서 상대의 주장이 일리 있다고 일부 인정하는 격식 표현이에요. ''agree''보다 부분적이고 외교적인 뉘앙스예요.','C2','discussion',3,0,'panel discussion','The minister graciously conceded the point on fiscal accountability.','장관은 재정 책임 문제에 관한 논점을 정중히 인정했어요.','Conceding a point does not weaken your overall position.','한 논점을 인정한다고 해서 전체 입장이 약해지지는 않아요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_economy_23','open','account','open an account','계좌를 개설하다','start','"start an account"도 비공식적으로 쓰이지만 은행 표준은 open an account.','A2','economy',1,0,'bank account opening teller paperwork desk','I''d like to open a savings account.','저축 계좌를 개설하고 싶어요.','You need ID to open an account.','계좌를 개설하려면 신분증이 필요해요.','She opened an account at the local bank.','그녀는 지역 은행에서 계좌를 개설했어요.','Can I open an account online?','온라인으로 계좌를 개설할 수 있나요?','He opened a joint account with his spouse.','그는 배우자와 공동 계좌를 개설했어요.'),
('col_economy_10','pay','taxes','pay taxes','세금을 내다','give','"give taxes"는 틀린 표현이에요. 세금을 낼 때는 pay를 써요.','B1','economy',1,10,'taxes payment government finance citizen','Every citizen is required to pay taxes by law.','모든 시민은 법에 따라 세금을 내야 해요.','He always pays his taxes on time to avoid penalties.','그는 항상 벌금을 피하기 위해 제때 세금을 내요.','Self-employed people often have to pay taxes quarterly.','자영업자들은 분기마다 세금을 내야 하는 경우가 많아요.','She pays her taxes online to make things easier.','그녀는 일을 더 쉽게 처리하기 위해 온라인으로 세금을 내요.','It''s our duty to pay taxes that fund public services.','공공 서비스의 재원이 되는 세금을 내는 것은 우리의 의무예요.'),
('col_economy_22','invest','money','invest money','돈을 투자하다','put','"put money"도 쓰이지만 정식 투자는 invest money. put money in은 더 캐주얼.','B1','economy',1,0,'investor money stocks chart growth portfolio','She invests money in tech stocks.','그녀는 기술주에 돈을 투자해요.','I''ve invested money in real estate for years.','저는 수년간 부동산에 돈을 투자해 왔어요.','Don''t invest money you can''t afford to lose.','잃어도 괜찮을 돈만 투자하세요.','He invested all his money in his startup.','그는 자기 스타트업에 모든 돈을 투자했어요.','Where''s the best place to invest money right now?','지금 돈을 투자하기 가장 좋은 곳은 어디예요?'),
('col_economy_01','make','a profit','make a profit','이익을 내다','do','"do a profit"은 틀린 표현이에요. 이익을 창출할 때는 make를 써요.','B2','economy',1,1,'profit business finance revenue success','The startup finally made a profit after two years of losses.','그 스타트업은 2년간의 적자 끝에 마침내 이익을 냈어요.','They made a substantial profit on the sale of the property.','그들은 부동산 매각으로 상당한 이익을 냈어요.','Small farms can make a profit by selling directly to customers.','소규모 농장은 고객에게 직접 판매하여 이익을 낼 수 있어요.','The company made a profit despite the difficult market conditions.','회사는 어려운 시장 상황에도 불구하고 이익을 냈어요.','It''s not easy to make a profit in the first year of business.','사업 첫해에 이익을 내는 것은 쉽지 않아요.'),
('col_economy_02','take','a risk','take a risk','위험을 감수하다','do','"do a risk"는 틀린 표현이에요. 위험을 감수할 때는 take를 써요.','B2','economy',2,2,'risk investment business decision finance','Every entrepreneur has to take risks to grow their business.','모든 기업가는 사업을 성장시키기 위해 위험을 감수해야 해요.','She took a calculated risk and it paid off in the end.','그녀는 계산된 위험을 감수했고 결국 성과를 거뒀어요.','Investors should take calculated risks based on solid research.','투자자들은 탄탄한 연구를 바탕으로 계산된 위험을 감수해야 해요.','She took a big risk by leaving her stable job to start a company.','그녀는 안정적인 직장을 떠나 회사를 시작하는 큰 위험을 감수했어요.','Taking risks is part of growth, both personal and financial.','위험을 감수하는 것은 개인적 성장과 재정적 성장 모두의 일부예요.'),
('col_economy_03','run','a business','run a business','사업을 운영하다','make','"make a business"는 사업을 만드는 것이고, run은 운영하는 것이에요.','B2','economy',1,3,'business operation management entrepreneur','She has been running a small bakery business for five years.','그녀는 5년 동안 작은 베이커리 사업을 운영해 왔어요.','Running a business during a recession is very challenging.','경기 침체 기간에 사업을 운영하는 것은 매우 도전적이에요.','Her parents have been running a family business for three generations.','그녀의 부모님은 가족 사업을 3대에 걸쳐 운영해 왔어요.','Running a business requires juggling many responsibilities at once.','사업을 운영하려면 한꺼번에 많은 책임을 처리해야 해요.','He''s been running a successful online business for a decade.','그는 10년째 성공적인 온라인 사업을 운영하고 있어요.'),
('col_economy_07','make','an investment','make an investment','투자하다','do','"do an investment"는 틀린 표현이에요. 투자할 때는 make를 써요.','B2','economy',2,7,'investment finance business growth return','He made a significant investment in renewable energy.','그는 재생에너지에 상당한 투자를 했어요.','It''s important to make wise investments for the future.','미래를 위해 현명한 투자를 하는 것이 중요해요.','She made her first investment in index funds at age 22.','그녀는 22세에 인덱스 펀드에 처음으로 투자했어요.','Making an investment in education usually pays off in the long term.','교육에 투자하는 것은 보통 장기적으로 보상받아요.','They made a small investment that grew into something significant.','그들은 작은 투자를 했는데 그것이 상당한 규모로 성장했어요.'),
('col_economy_08','get','a loan','get a loan','대출을 받다','take','"take a loan"도 맞지만 get a loan이 더 구어체적이에요.','B2','economy',2,8,'loan bank borrowing credit finance','She got a loan from the bank to start her business.','그녀는 사업을 시작하기 위해 은행에서 대출을 받았어요.','It can be difficult to get a loan with a low credit score.','신용 점수가 낮으면 대출받기 어려울 수 있어요.','It''s easier to get a loan if you have a steady income.','안정적인 수입이 있으면 대출을 받기가 더 쉬워요.','He got a student loan to pay for his masters degree.','그는 석사 학위 비용을 위해 학자금 대출을 받았어요.','Many small businesses get a loan to expand their operations.','많은 소규모 사업체들이 운영 확장을 위해 대출을 받아요.'),
('col_economy_09','set','a budget','set a budget','예산을 세우다','make','"make a budget"도 쓰이지만 set a budget이 더 격식 있어요.','B2','economy',1,9,'budget finance planning money business','The finance team set a budget for the new quarter.','재무팀은 새 분기를 위한 예산을 세웠어요.','You should set a budget before you start spending on the event.','행사 지출을 시작하기 전에 예산을 세워야 해요.','I set a strict budget at the start of each month.','저는 매월 초에 엄격한 예산을 세워요.','They set a budget for the kitchen renovation but went slightly over.','그들은 주방 리노베이션 예산을 세웠지만 약간 초과했어요.','Couples who set a budget together tend to argue less about money.','함께 예산을 세우는 부부는 돈에 관해 덜 다투는 경향이 있어요.'),
('col_economy_12','boost','the economy','boost the economy','경제를 활성화하다','increase','"increase the economy"는 어색해요. 경제 활성화에는 boost를 써요.','B2','economy',2,12,'economy growth boost government GDP','The government introduced tax cuts to boost the economy.','정부는 경제를 활성화하기 위해 세금 감면을 도입했어요.','Tourism plays a key role in boosting the local economy.','관광업은 지역 경제 활성화에 중요한 역할을 해요.','Free public transport can boost the local economy in surprising ways.','무료 대중교통은 놀라운 방식으로 지역 경제를 활성화할 수 있어요.','New tech jobs are boosting the economy of smaller cities.','새로운 기술 일자리들이 작은 도시들의 경제를 활성화하고 있어요.','Investing in education boosts the economy over the long term.','교육에 투자하는 것은 장기적으로 경제를 활성화해요.'),
('col_economy_14','cut','spending','cut spending','지출을 삭감하다','reduce','"reduce spending"도 맞지만 cut은 더 적극적인 삭감을 의미해요.','B2','economy',2,14,'spending cut budget austerity finance','The government announced plans to cut public spending.','정부는 공공 지출 삭감 계획을 발표했어요.','Businesses often cut spending during times of uncertainty.','기업들은 불확실한 시기에 종종 지출을 삭감해요.','Households are cutting spending on dining out due to higher prices.','가정들은 가격 상승으로 외식 지출을 삭감하고 있어요.','The school district cut spending on new equipment this year.','학군은 올해 새 장비에 대한 지출을 삭감했어요.','Cutting spending suddenly can hurt the economy in the short term.','갑작스러운 지출 삭감은 단기적으로 경제에 해를 끼칠 수 있어요.'),
('col_economy_19','go','bankrupt','go bankrupt','파산하다','become','"become bankrupt"도 맞지만 go bankrupt가 훨씬 더 자주 쓰여요.','B2','economy',2,19,'bankrupt business failure closure finance','Several small businesses went bankrupt during the pandemic.','여러 소규모 사업체가 팬데믹 기간에 파산했어요.','The company went bankrupt after years of poor management.','그 회사는 수년간의 경영 부실 끝에 파산했어요.','The retailer went bankrupt after three years of declining sales.','그 소매업체는 3년간 매출 감소 끝에 파산했어요.','Many restaurants went bankrupt during the lockdown period.','많은 식당들이 봉쇄 기간 동안 파산했어요.','Companies can avoid going bankrupt with better cash flow management.','기업은 더 나은 현금 흐름 관리로 파산을 피할 수 있어요.'),
('col_economy_21','earn','living','earn a living','생계를 꾸리다','make','"make a living"도 흔히 쓰여요. 둘 다 정답이지만 earn은 노동으로 번다는 뉘앙스가 강해요.','B2','economy',1,0,'working person job income livelihood paycheck','He earns a living as a freelance designer.','그는 프리랜서 디자이너로 생계를 꾸려요.','It''s hard to earn a living in this town.','이 동네에서 생계를 꾸리기는 어려워요.','She earns a comfortable living as a translator.','그녀는 번역가로 안정적인 생계를 꾸려요.','My parents worked hard to earn a living.','부모님은 생계를 꾸리기 위해 열심히 일하셨어요.','How do you earn a living these days?','요즘 어떻게 생계를 꾸리세요?'),
('col_economy_24','take','loan','take out a loan','대출을 받다','get','"get a loan"도 가능하지만 take out a loan이 더 공식적인 표현이에요.','B2','economy',1,0,'bank loan documents signing mortgage finance','They took out a loan to buy their first home.','그들은 첫 집을 사기 위해 대출을 받았어요.','I''m thinking of taking out a student loan.','학자금 대출을 받을까 생각 중이에요.','She took out a loan to start her business.','그녀는 사업을 시작하기 위해 대출을 받았어요.','Be careful before you take out a loan.','대출을 받기 전에 신중하세요.','He took out a small loan to cover medical bills.','그는 의료비를 충당하기 위해 소액 대출을 받았어요.'),
('col_economy_04','keep','costs down','keep costs down','비용을 낮추다','reduce','"reduce costs"도 맞지만 keep costs down은 지속적으로 낮은 수준을 유지하는 뉘앙스예요.','C1','economy',2,4,'costs reduction budget business finance','The company introduced automation to keep production costs down.','회사는 생산 비용을 낮추기 위해 자동화를 도입했어요.','We need to find ways to keep our operating costs down.','운영 비용을 낮게 유지할 방법을 찾아야 해요.','Restaurants struggle to keep costs down with rising food prices.','식당들은 식재료 가격 상승으로 비용을 낮추기가 어려워요.','We keep our overhead costs down by working from home.','우리는 재택근무로 간접비를 낮춰요.','Buying in bulk helps families keep their grocery costs down.','대용량 구매가 가정이 식료품 비용을 낮추는 데 도움이 돼요.'),
('col_economy_05','break','even','break even','손익분기점에 도달하다','reach','"reach even"은 틀린 표현이에요. 손익분기점을 맞출 때는 break even을 써요.','C1','economy',2,5,'break even business profit loss finance','Most startups take at least two years to break even.','대부분의 스타트업은 손익분기점에 도달하는 데 최소 2년이 걸려요.','We broke even on the project, which we considered a success.','우리는 프로젝트에서 손익분기점을 맞췄는데, 그것을 성공으로 여겼어요.','It took the cafe 18 months to break even.','그 카페가 손익분기점에 도달하는 데 18개월이 걸렸어요.','Once you break even, every additional sale is pure profit.','일단 손익분기점을 맞추면, 그 이후 매출은 모두 순수익이에요.','The film just barely broke even at the box office.','그 영화는 박스오피스에서 간신히 손익분기점에 도달했어요.'),
('col_economy_06','hold','shares','hold shares','주식을 보유하다','have','"have shares"도 맞지만 hold shares는 지속적인 보유를 강조해요.','C1','economy',3,6,'shares stocks investment portfolio finance','She holds shares in several major tech companies.','그녀는 여러 주요 기술 기업의 주식을 보유하고 있어요.','It''s risky to hold too many shares in a single company.','한 회사에 너무 많은 주식을 보유하는 것은 위험해요.','My grandparents have been holding shares in the same company for decades.','저희 조부모님은 수십 년 동안 같은 회사의 주식을 보유해 오셨어요.','Many employees hold shares in their own company.','많은 직원들이 자기 회사 주식을 보유해요.','Holding shares long-term often yields better returns than trading often.','주식을 장기로 보유하는 것이 자주 거래하는 것보다 더 나은 수익을 가져오는 경우가 많아요.'),
('col_economy_11','face','a recession','face a recession','경기 침체에 직면하다','have','"have a recession"도 쓰이지만 face는 어려운 상황에 직면하는 뉘앙스예요.','C1','economy',2,11,'recession economy crisis finance decline','Many countries faced a recession after the global financial crisis.','많은 나라들이 글로벌 금융 위기 이후 경기 침체에 직면했어요.','Small businesses suffer most when a country faces a recession.','나라가 경기 침체에 직면할 때 소규모 사업체가 가장 큰 타격을 받아요.','The tourism industry was hit hard when the region faced a recession.','관광 산업은 그 지역이 경기 침체에 직면했을 때 큰 타격을 입었어요.','When countries face a recession, unemployment usually rises.','나라가 경기 침체에 직면하면 실업률이 보통 증가해요.','Even strong economies can face a recession every few years.','강한 경제도 몇 년에 한 번씩 경기 침체에 직면할 수 있어요.'),
('col_economy_13','generate','revenue','generate revenue','수익을 창출하다','make','"make revenue"도 쓰이지만 generate는 다양한 경로로 창출하는 뉘앙스예요.','C1','economy',3,13,'revenue income business finance stream','The app generates revenue through subscriptions and ads.','그 앱은 구독과 광고를 통해 수익을 창출해요.','New products helped the company generate more revenue.','신제품이 회사가 더 많은 수익을 창출하는 데 도움이 됐어요.','The cafe generates revenue from both online and in-store sales.','그 카페는 온라인과 매장 판매 모두에서 수익을 창출해요.','YouTube channels generate revenue mainly through ads and sponsorships.','유튜브 채널은 주로 광고와 스폰서십을 통해 수익을 창출해요.','New revenue streams help businesses generate revenue more steadily.','새로운 수익 모델은 기업이 더 안정적으로 수익을 창출하는 데 도움이 돼요.'),
('col_economy_15','raise','interest rates','raise interest rates','금리를 올리다','increase','"increase interest rates"도 맞지만 raise는 중앙은행의 조치를 강조해요.','C1','economy',3,15,'interest rate bank inflation finance policy','The central bank raised interest rates to control inflation.','중앙은행은 인플레이션을 통제하기 위해 금리를 올렸어요.','Raising interest rates can slow down economic growth.','금리를 올리면 경제 성장이 둔화될 수 있어요.','The central bank raised interest rates by half a percent yesterday.','중앙은행은 어제 금리를 0.5% 올렸어요.','Raising interest rates makes borrowing more expensive for households.','금리를 올리면 가정의 대출이 더 비싸져요.','Some economists argue that raising interest rates too quickly is risky.','일부 경제학자들은 금리를 너무 빠르게 올리는 것이 위험하다고 주장해요.'),
('col_economy_16','run','a deficit','run a deficit','적자를 기록하다','have','"have a deficit"도 맞지만 run a deficit은 지속적인 상태를 강조해요.','C1','economy',3,16,'deficit budget government finance loss','The country has been running a budget deficit for several years.','그 나라는 몇 년간 재정 적자를 기록하고 있어요.','The company ran a deficit in its first year of operation.','회사는 운영 첫 해에 적자를 기록했어요.','Several airlines ran a deficit during the height of the pandemic.','여러 항공사가 팬데믹 절정기에 적자를 기록했어요.','Running a deficit isn''t always bad if you''re investing in growth.','성장에 투자한다면 적자를 기록하는 것이 항상 나쁜 건 아니에요.','The non-profit ran a deficit but continued its mission.','그 비영리 단체는 적자를 기록했지만 사명을 계속 이어갔어요.'),
('col_economy_17','attract','investment','attract investment','투자를 유치하다','get','"get investment"도 맞지만 attract는 적극적으로 끌어들이는 뉘앙스예요.','C1','economy',3,17,'investment attract foreign business economy','The city has worked hard to attract foreign investment.','그 도시는 외국 투자를 유치하기 위해 열심히 노력했어요.','Good infrastructure and low taxes help attract investment.','좋은 인프라와 낮은 세금이 투자를 유치하는 데 도움이 돼요.','Stable governance helps cities attract investment over time.','안정적인 거버넌스는 도시들이 시간이 지나며 투자를 유치하는 데 도움이 돼요.','The new tech hub has attracted investment from around the world.','새 기술 허브는 전 세계에서 투자를 유치했어요.','They attracted investment by showing strong projected returns.','그들은 강력한 예상 수익률을 보여 투자를 유치했어요.'),
('col_economy_18','drive','growth','drive growth','성장을 이끌다','make','"make growth"는 틀린 표현이에요. 성장을 주도할 때는 drive를 써요.','C1','economy',3,18,'growth economic drive GDP business','Innovation is what drives growth in the technology sector.','혁신이 기술 분야의 성장을 이끄는 것이에요.','The new policy is expected to drive economic growth.','새 정책이 경제 성장을 이끌 것으로 기대돼요.','Strong consumer demand is helping drive growth in the retail sector.','강한 소비자 수요가 소매 부문의 성장을 이끄는 데 도움이 되고 있어요.','Education has historically driven growth in developing economies.','교육은 역사적으로 개발도상국 경제의 성장을 이끌어 왔어요.','Small businesses drive growth in many local communities.','소규모 사업체들이 많은 지역사회의 성장을 이끌어요.'),
('col_economy_20','control','inflation','control inflation','인플레이션을 통제하다','reduce','"reduce inflation"도 맞지만 control은 상승을 막는 것을 강조해요.','C1','economy',3,20,'inflation control price economy monetary policy','Central banks use interest rates as a tool to control inflation.','중앙은행은 인플레이션을 통제하는 수단으로 금리를 사용해요.','It has been difficult to control inflation since the energy crisis.','에너지 위기 이후 인플레이션을 통제하기가 어려웠어요.','Governments use various tools to control inflation during crises.','정부는 위기 동안 인플레이션을 통제하기 위해 다양한 도구를 사용해요.','Controlling inflation while maintaining growth is a delicate balance.','인플레이션을 통제하면서 성장을 유지하는 것은 미묘한 균형이에요.','Even successful economies can struggle to control inflation.','성공적인 경제도 인플레이션을 통제하는 데 어려움을 겪을 수 있어요.'),
('col_economy_C1_01','boost','growth','boost growth','성장을 촉진하다','rise','경제 성장률을 끌어올린다는 표준 표현이에요. 정책, 투자, 무역 관련 기사에서 자주 등장해요.','C1','economy',2,0,'rising chart','The central bank lowered rates to boost growth in the manufacturing sector.','중앙은행은 제조업 성장을 촉진하기 위해 금리를 인하했어요.','Tax incentives are designed to boost growth among small businesses.','세제 혜택은 중소기업 성장을 촉진하기 위해 설계됐어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_economy_C1_02','tackle','inflation','tackle inflation','인플레이션에 대응하다','fight','''fight''도 가능하지만 ''tackle''이 정책적·전략적으로 문제를 다룬다는 뉘앙스라 신문에서 더 흔해요.','C1','economy',2,0,'inflation chart','The government unveiled a new package to tackle inflation and stabilize prices.','정부는 인플레이션에 대응하고 물가를 안정시키기 위한 새 패키지를 공개했어요.','Policymakers are under pressure to tackle inflation without triggering a recession.','정책 입안자들은 경기 침체를 유발하지 않고 인플레이션에 대응해야 한다는 압박을 받고 있어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_economy_C1_03','raise','interest rates','raise interest rates','금리를 인상하다','lift','중앙은행이 기준 금리를 올린다는 정확한 표현이에요. ''lift''는 일상 영어라 금융 보도에는 어울리지 않아요.','C1','economy',2,0,'federal reserve','The Federal Reserve is expected to raise interest rates again next quarter.','연준은 다음 분기에 다시 금리를 인상할 것으로 예상돼요.','Raising interest rates too quickly could slow the housing market.','금리를 너무 빨리 인상하면 주택 시장이 둔화될 수 있어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_economy_C1_04','spur','demand','spur demand','수요를 자극하다','make','소비자 수요를 단시간에 늘린다는 격식 있는 표현이에요. 마케팅이나 정책 보고서에 자주 써요.','C1','economy',2,0,'shopping demand','Holiday discounts spurred demand for electronics across the region.','연휴 할인이 지역 전반에 걸쳐 전자제품 수요를 자극했어요.','Government subsidies have spurred demand for electric vehicles.','정부 보조금이 전기차 수요를 자극했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_economy_C1_05','rebound','recession','rebound from recession','불황에서 회복하다','come','경제가 침체기 이후 다시 활기를 되찾는다는 표현이에요. 분기 실적이나 거시 경제 분석에 자주 나와요.','C1','economy',2,0,'economic recovery','The economy is finally rebounding from the deepest recession in a decade.','경제가 마침내 10년 만의 가장 깊은 불황에서 회복하고 있어요.','Tourism has rebounded from the recession faster than analysts predicted.','관광업은 분석가들의 예상보다 빠르게 불황에서 회복했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_economy_C2_01','weather','downturn','weather a downturn','경기 침체를 견뎌내다','survive','경제적 어려움을 견뎌낸다는 격식 표현이에요. ''survive''보다 능동적으로 버틴다는 뉘앙스가 강해요.','C2','economy',3,0,'stock market chart','Well-capitalised firms are better positioned to weather a prolonged downturn.','자본이 탄탄한 기업들이 장기 침체를 견뎌낼 입지가 더 좋아요.','The conglomerate weathered the 2008 downturn without layoffs.','그 대기업은 해고 없이 2008년 침체를 견뎌냈어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_economy_C2_02','stimulate','growth','stimulate growth','성장을 촉진하다','make','정책이나 투자가 경제 성장을 자극한다는 표준 경제 용어예요. 금융 기사와 정책 보고서에 자주 등장해요.','C2','economy',3,0,'economic growth chart','The central bank cut rates to stimulate growth in the manufacturing sector.','중앙은행은 제조업 성장을 촉진하기 위해 금리를 인하했어요.','Tax incentives are designed to stimulate growth in green industries.','세제 혜택은 친환경 산업의 성장을 촉진하기 위해 설계됐어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_economy_C2_03','curb','inflation','curb inflation','인플레이션을 억제하다','stop','인플레이션의 상승세를 통제하고 억제한다는 의미예요. ''stop''은 너무 단정적이라 경제 맥락에 어울리지 않아요.','C2','economy',3,0,'inflation graph','Aggressive rate hikes were necessary to curb runaway inflation.','폭주하는 인플레이션을 억제하기 위해 공격적인 금리 인상이 필요했어요.','The new fiscal policy aims to curb inflation without triggering a recession.','새 재정 정책은 경기 침체 없이 인플레이션을 억제하는 것이 목표예요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_economy_C2_04','hedge','risk','hedge against risk','위험을 헤지하다','protect','금융 상품으로 위험을 상쇄한다는 전문 용어예요. ''protect against''보다 정확하고 기술적이에요.','C2','economy',3,0,'financial derivatives','Institutional investors hedge against currency risk using derivatives.','기관 투자자들은 파생상품으로 환위험을 헤지해요.','Gold has traditionally been used to hedge against inflation risk.','금은 전통적으로 인플레이션 위험을 헤지하는 데 사용돼 왔어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_economy_C2_05','fuel','speculation','fuel speculation','추측을 부추기다','cause','소문이나 추측에 불을 지핀다는 뉘앙스예요. 시장이나 인수합병 기사에서 자주 보여요.','C2','economy',3,0,'speculation news','The CEO''s sudden resignation fuelled speculation about an imminent takeover.','CEO의 갑작스러운 사임은 임박한 인수에 대한 추측을 부추겼어요.','Vague guidance fuelled speculation among analysts.','모호한 가이던스가 애널리스트들 사이에서 추측을 부추겼어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_education_21','do','homework','do homework','숙제를 하다','make','"make homework"은 한국 학습자의 흔한 오류예요. 숙제는 항상 do와 함께 써요.','A1','education',1,0,'student homework desk notebook studying','I have to do my homework before dinner.','저녁 먹기 전에 숙제를 해야 해요.','Did you do your math homework yet?','수학 숙제 벌써 했어요?','She always does her homework right after school.','그녀는 항상 학교 끝나자마자 숙제를 해요.','I''ll do my homework as soon as I get home.','집에 가자마자 숙제할게요.','It''s hard to do homework when it''s noisy.','시끄러울 때는 숙제하기 어려워요.'),
('col_education_22','take','notes','take notes','필기를 하다','write','"write notes"도 가능하지만, 강의 중 필기는 take notes가 더 자연스러워요.','A2','education',1,0,'student notebook pen writing lecture','Students take notes during the lecture.','학생들은 강의 중에 필기를 해요.','I always take notes when reading textbooks.','저는 교과서를 읽을 때 항상 필기를 해요.','Did you take notes in today''s class?','오늘 수업에서 필기했어요?','She takes very detailed notes in every meeting.','그녀는 모든 회의에서 매우 자세한 필기를 해요.','Taking notes helps me remember the material better.','필기를 하면 내용을 더 잘 기억할 수 있어요.'),
('col_education_24','pass','exam','pass an exam','시험에 합격하다','do','"do an exam"은 시험을 본다는 뜻. 합격은 pass an exam (반대는 fail).','A2','education',1,0,'student exam paper passed grade certificate','She passed the exam with flying colors.','그녀는 우수한 성적으로 시험에 합격했어요.','I need to pass this exam to graduate.','졸업하려면 이 시험에 합격해야 해요.','He passed his driving exam on the first try.','그는 운전 시험을 처음에 합격했어요.','Did you pass the certification exam?','자격증 시험 합격했어요?','Studying hard pays off when you pass an exam.','열심히 공부하면 시험 합격으로 보상받아요.'),
('col_education_25','fail','test','fail a test','시험에 떨어지다','lose','"lose a test"는 틀린 표현. 시험을 떨어지면 fail. (lose는 시합에서 짐)','A2','education',1,0,'student failed test paper disappointed grade','I failed the test because I didn''t study.','공부를 안 해서 시험에 떨어졌어요.','Failing a test isn''t the end of the world.','시험에 떨어진다고 세상이 끝나는 건 아니에요.','She was upset about failing the math test.','그녀는 수학 시험에 떨어진 것에 속상해했어요.','He failed the test by just one point.','그는 단 1점 차이로 시험에 떨어졌어요.','You won''t fail the test if you prepare well.','잘 준비하면 시험에 떨어지지 않을 거예요.'),
('col_education_01','take','an exam','take an exam','시험을 보다','do','"do an exam"도 쓰이지만 take an exam이 더 표준적인 표현이에요.','B1','education',1,1,'exam test school study academic','She''s going to take her final exams next week.','그녀는 다음 주에 기말 시험을 볼 예정이에요.','He took the entrance exam twice before passing it.','그는 합격하기 전에 입학시험을 두 번 봤어요.','I''m going to take an exam to get my driver''s license next month.','저는 다음 달에 운전면허 시험을 볼 거예요.','They took an exam in three different subjects on the same day.','그들은 같은 날 세 가지 과목의 시험을 봤어요.','Taking an exam is less stressful when you''ve studied consistently.','꾸준히 공부했을 때 시험을 보는 게 덜 부담돼요.'),
('col_education_02','make','notes','make notes','필기하다','write','"write notes"도 맞지만 make notes는 핵심 내용을 정리하는 뉘앙스예요.','B1','education',1,2,'notes studying class lecture student','Make notes as you read so you can review them later.','나중에 복습할 수 있도록 읽으면서 필기하세요.','She made detailed notes during the lecture.','그녀는 강의 중에 자세한 필기를 했어요.','He makes notes in the margins of his textbooks.','그는 교과서 여백에 필기를 해요.','Make notes on important formulas before the math exam.','수학 시험 전에 중요한 공식에 대해 필기하세요.','Making notes by hand helps her remember the material better.','손으로 필기하는 것이 그녀가 내용을 더 잘 기억하는 데 도움이 돼요.'),
('col_education_04','give','a presentation','give a presentation','발표를 하다','make','"make a presentation"도 쓰이지만 give가 더 자연스럽고 자주 쓰여요.','B1','education',1,4,'presentation class school student academic','Every student has to give a presentation at the end of the term.','모든 학생이 학기 말에 발표를 해야 해요.','He gave an impressive presentation on climate change.','그는 기후 변화에 대한 인상적인 발표를 했어요.','She gave a presentation about her exchange experience in Korea.','그녀는 한국에서의 교환학생 경험에 대한 발표를 했어요.','I''m a little nervous to give a presentation in front of professors.','저는 교수님들 앞에서 발표하는 게 조금 긴장돼요.','Giving a presentation is easier when you really know the topic.','주제를 정말 잘 알고 있으면 발표하기가 더 쉬워요.'),
('col_education_06','break','a record','break a record','기록을 깨다','set','기록을 새로 세울 때는 set, 기존 기록을 뛰어넘을 때는 break을 써요.','B1','education',2,6,'record school achievement academic sport','She broke the school record for the fastest 100m sprint.','그녀는 학교 100m 최고 기록을 깼어요.','The student broke the record for the highest entrance exam score.','그 학생은 입학 시험 최고 점수 기록을 깼어요.','He broke the long jump record at the university sports day.','그는 대학 체육대회에서 멀리뛰기 기록을 깼어요.','She broke the record for the highest math score in the district.','그녀는 그 지역에서 최고 수학 점수 기록을 깼어요.','Breaking a school record was always one of his dreams.','학교 기록을 깨는 건 그의 오랜 꿈 중 하나였어요.'),
('col_education_08','make','progress','make progress','발전하다','do','"do progress"는 틀린 표현이에요. 발전이 있을 때는 make progress를 써요.','B1','education',1,8,'progress study academic improvement learning','She''s making excellent progress in her English studies.','그녀는 영어 공부에서 뛰어난 발전을 이루고 있어요.','Don''t worry if it''s slow — as long as you''re making progress.','느려도 괜찮아요 — 발전하고 있는 한은요.','You''ve made huge progress since the beginning of the course.','강의 시작 이후로 정말 많은 발전을 이뤘어요.','The teacher told me my son is making steady progress in writing.','선생님이 제 아들이 글쓰기에서 꾸준한 발전을 이루고 있다고 말씀하셨어요.','You make progress by practicing a little bit every day.','매일 조금씩 연습함으로써 발전을 이루는 거예요.'),
('col_education_09','get','a degree','get a degree','학위를 받다','take','"take a degree"도 쓰이지만 get a degree가 더 구어체적이에요.','B1','education',1,9,'degree graduation university diploma academic','She got a degree in economics from Seoul National University.','그녀는 서울대학교에서 경제학 학위를 받았어요.','He worked part-time while getting his degree.','그는 학위를 받는 동안 아르바이트를 했어요.','She got a master''s degree in computer science last year.','그녀는 작년에 컴퓨터 공학 석사 학위를 받았어요.','He''s the first in his family to get a college degree.','그는 가족 중 처음으로 대학 학위를 받았어요.','You can get a degree online from many accredited universities now.','이제 많은 인증된 대학에서 온라인으로 학위를 받을 수 있어요.'),
('col_education_10','set','goals','set goals','목표를 세우다','make','"make goals"는 어색해요. 목표를 설정할 때는 set을 써요.','B1','education',1,10,'goals academic setting planning study','Setting clear goals at the start of the semester helps you stay on track.','학기 초에 명확한 목표를 세우면 계획대로 진행하는 데 도움이 돼요.','She set ambitious academic goals and worked hard to achieve them.','그녀는 도전적인 학업 목표를 세우고 달성하기 위해 열심히 노력했어요.','I set small daily goals to stay motivated.','저는 동기 부여를 유지하기 위해 작은 일일 목표를 세워요.','They set goals together as a family at the start of each year.','그들은 매년 초에 가족으로서 함께 목표를 세워요.','Setting realistic goals matters more than setting big ones.','큰 목표를 세우는 것보다 현실적인 목표를 세우는 게 더 중요해요.'),
('col_education_11','pass','an exam','pass an exam','시험에 합격하다','succeed','"succeed an exam"은 틀린 표현이에요. 시험에 합격할 때는 pass를 써요.','B1','education',1,11,'exam pass result success school','She studied hard and passed all her exams on the first try.','그녀는 열심히 공부해서 모든 시험을 첫 번째 시도에 통과했어요.','You need at least 60% to pass the exam.','시험을 통과하려면 최소 60%가 필요해요.','I''m relieved I passed the exam without having to retake it.','시험을 재시험 없이 통과해서 안도했어요.','She passed her driving exam on the second attempt.','그녀는 운전면허 시험을 두 번째 시도에 통과했어요.','Passing the exam felt like a huge weight off my shoulders.','시험을 통과하니까 어깨의 큰 짐이 내려간 기분이었어요.'),
('col_education_12','attend','lectures','attend lectures','강의에 참석하다','go','"go to lectures"도 맞지만 attend는 더 격식 있는 표현이에요.','B1','education',1,12,'lecture university attendance class study','You''re expected to attend all lectures unless you''re ill.','아프지 않은 한 모든 강의에 참석해야 해요.','He attended every lecture and still failed the exam.','그는 모든 강의에 참석했는데도 시험에 떨어졌어요.','I attended lectures online during the pandemic.','저는 팬데믹 동안 강의에 온라인으로 참석했어요.','He attended every lecture without missing a single one.','그는 하나도 빠짐없이 모든 강의에 참석했어요.','Attending lectures regularly often makes a huge difference in your grade.','꾸준히 강의에 참석하는 것이 종종 성적에 큰 차이를 만들어요.'),
('col_education_13','submit','an assignment','submit an assignment','과제를 제출하다','hand','"hand in an assignment"도 맞지만 submit이 더 격식 있는 표현이에요.','B1','education',1,13,'assignment homework submit deadline school','You need to submit the assignment before midnight on Friday.','금요일 자정 전에 과제를 제출해야 해요.','She submitted her assignment early and had time to review it.','그녀는 과제를 일찍 제출해서 검토할 시간이 있었어요.','I submitted my assignment with five minutes to spare.','저는 5분 여유를 두고 과제를 제출했어요.','She submitted her assignment on the wrong portal by mistake.','그녀는 실수로 잘못된 포털에 과제를 제출했어요.','Submitting an assignment late can affect your grade significantly.','과제를 늦게 제출하면 성적에 큰 영향을 미칠 수 있어요.'),
('col_education_16','graduate','from','graduate from','졸업하다','finish','"finish university"도 맞지만 graduate from이 더 격식 있는 표현이에요.','B1','education',1,16,'graduation diploma university ceremony','She graduated from university with honors.','그녀는 우등으로 대학을 졸업했어요.','He plans to graduate from law school next year.','그는 내년에 로스쿨을 졸업할 계획이에요.','He graduated from medical school in just six years.','그는 6년 만에 의과대학을 졸업했어요.','My mother graduated from a teacher''s college in the 1980s.','저희 어머니는 1980년대에 교대를 졸업하셨어요.','She graduated from a top business school overseas.','그녀는 해외의 최고 경영대학원을 졸업했어요.'),
('col_education_17','review','notes','review notes','필기를 복습하다','read','"read notes"도 맞지만 review는 이해를 확인하는 뉘앙스가 있어요.','B1','education',1,17,'review studying notes preparation exam','I always review my notes before going to bed.','나는 자기 전에 항상 필기를 복습해요.','She reviewed her notes and felt ready for the test.','그녀는 필기를 복습하고 시험 준비가 되었다고 느꼈어요.','Review your notes within 24 hours to remember more.','더 많이 기억하려면 24시간 이내에 필기를 복습하세요.','She reviews her notes on the bus ride home.','그녀는 집에 가는 버스에서 필기를 복습해요.','Reviewing notes regularly is more effective than cramming.','필기를 꾸준히 복습하는 것이 벼락치기보다 더 효과적이에요.'),
('col_education_19','fail','an exam','fail an exam','시험에 떨어지다','lose','"lose an exam"은 틀린 표현이에요. 시험에 실패할 때는 fail을 써요.','B1','education',1,19,'fail exam result retry study','He failed the exam but was determined to try again.','그는 시험에 떨어졌지만 다시 도전하기로 굳게 마음먹었어요.','Don''t be too hard on yourself if you fail an exam.','시험에 떨어져도 자책하지 마세요.','She failed the exam by just one point.','그녀는 단 1점 차이로 시험에 떨어졌어요.','Failing an exam taught him to study more strategically.','시험에 떨어진 경험이 그가 더 전략적으로 공부하도록 가르쳐 줬어요.','Many successful people failed exams at some point in their lives.','많은 성공한 사람들이 인생에서 한 번쯤 시험에 떨어진 적이 있어요.'),
('col_education_23','make','progress','make progress','진전을 이루다','do','"do progress"는 틀린 표현. 어떤 일이 나아가는 건 항상 make progress.','B1','education',1,0,'student studying improvement progress chart','You''re making great progress with your English!','영어 실력이 정말 많이 늘고 있어요!','We''ve made significant progress on the project.','프로젝트에서 상당한 진전을 이뤘어요.','It''s slow, but I''m making progress.','느리지만 진전을 이루고 있어요.','She made remarkable progress in just one month.','그녀는 한 달 만에 놀라운 진전을 이뤘어요.','Are you making any progress on your thesis?','논문에 진전이 있나요?'),
('col_education_03','do','research','do research','연구하다','make','"make research"는 틀린 표현이에요. 연구할 때는 do research를 써요.','B2','education',1,3,'research library academic study university','She spent the summer doing research for her dissertation.','그녀는 여름 동안 논문을 위한 연구를 했어요.','The professor encouraged students to do independent research.','교수는 학생들이 독립적으로 연구를 하도록 장려했어요.','He''s doing research on artificial intelligence in education.','그는 교육에서의 인공지능에 대한 연구를 하고 있어요.','You need to do research before forming a strong opinion.','확고한 의견을 갖기 전에 연구를 해야 해요.','She has been doing research at the university lab since freshman year.','그녀는 1학년 때부터 대학 실험실에서 연구를 해 왔어요.'),
('col_education_05','keep','up with','keep up with the coursework','수업 진도를 따라가다','follow','"follow the coursework"는 어색해요. 진도를 따라갈 때는 keep up with를 써요.','B2','education',2,5,'coursework study keeping up academic university','It can be hard to keep up with the coursework in the first semester.','1학기에 수업 진도를 따라가기 어려울 수 있어요.','She struggled to keep up with all the reading assignments.','그녀는 모든 독서 과제를 따라가느라 힘들었어요.','He used a study schedule to keep up with the coursework.','그는 수업 진도를 따라가기 위해 학습 계획표를 활용했어요.','It''s normal to fall behind sometimes — just try to keep up.','가끔 뒤처지는 건 정상이에요 — 그저 따라가려고 노력해요.','She formed a study group to help her keep up with the coursework.','그녀는 수업 진도를 따라가기 위해 스터디 그룹을 만들었어요.'),
('col_education_07','hold','a discussion','hold a discussion','토론을 하다','make','"make a discussion"은 어색해요. 토론을 진행할 때는 hold를 써요.','B2','education',2,7,'discussion class debate students group','The teacher held a discussion about ethical issues in science.','선생님은 과학에서의 윤리적 문제에 대한 토론을 했어요.','We held a group discussion and everyone shared their views.','우리는 그룹 토론을 하며 모두가 의견을 나눴어요.','They held a discussion on inclusive education in the classroom.','그들은 교실에서 포용적 교육에 대한 토론을 했어요.','We held a discussion in small groups before sharing as a class.','우리는 학급 전체에 공유하기 전에 소그룹으로 토론을 했어요.','Holding a discussion helps students develop critical thinking.','토론을 하면 학생들이 비판적 사고를 키우는 데 도움이 돼요.'),
('col_education_14','earn','a scholarship','earn a scholarship','장학금을 받다','get','"get a scholarship"도 맞지만 earn은 노력으로 얻는 뉘앙스를 강조해요.','B2','education',2,14,'scholarship award academic achievement university','She earned a full scholarship based on her academic performance.','그녀는 학업 성취를 바탕으로 전액 장학금을 받았어요.','He worked extremely hard to earn a scholarship for university.','그는 대학 장학금을 받기 위해 정말 열심히 공부했어요.','He earned a scholarship through his community service work.','그는 지역사회 봉사활동으로 장학금을 받았어요.','She earned a partial scholarship that covered her tuition.','그녀는 등록금을 충당하는 부분 장학금을 받았어요.','You can earn a scholarship for academic, athletic, or artistic achievement.','학업, 체육, 또는 예술적 성취로 장학금을 받을 수 있어요.'),
('col_education_15','enroll','in a course','enroll in a course','수업에 등록하다','join','"join a course"도 쓰이지만 enroll은 공식적인 등록을 강조해요.','B2','education',2,15,'course enrollment class online learning','She enrolled in an online course to improve her data skills.','그녀는 데이터 기술을 향상시키기 위해 온라인 강좌에 등록했어요.','You can enroll in the course anytime before the semester starts.','학기 시작 전 언제든지 강좌에 등록할 수 있어요.','I enrolled in a Korean language course at the community center.','저는 주민 센터에서 한국어 강좌에 등록했어요.','You can enroll in a course at any point during the semester.','학기 중 언제든지 강좌에 등록할 수 있어요.','Enrolling in a course online is usually quick and easy.','온라인으로 강좌에 등록하는 건 보통 빠르고 쉬워요.'),
('col_education_18','conduct','an experiment','conduct an experiment','실험을 하다','do','"do an experiment"도 맞지만 conduct는 더 격식 있는 표현이에요.','B2','education',2,18,'experiment science lab research school','The students conducted a chemistry experiment in the lab.','학생들은 실험실에서 화학 실험을 했어요.','Before drawing conclusions, you should conduct the experiment at least twice.','결론을 내리기 전에 실험을 최소 두 번 해야 해요.','They conducted an experiment to test the effects of caffeine on memory.','그들은 카페인이 기억에 미치는 영향을 시험하기 위해 실험을 했어요.','The class conducted an experiment using simple household materials.','그 수업은 간단한 가정용 재료를 사용해 실험을 했어요.','Conducting an experiment requires careful planning and observation.','실험을 하려면 신중한 계획과 관찰이 필요해요.'),
('col_education_20','broaden','knowledge','broaden knowledge','지식을 넓히다','increase','"increase knowledge"도 맞지만 broaden은 더 넓은 범위로 확장하는 뉘앙스예요.','B2','education',2,20,'knowledge learning education books reading','Reading widely is one of the best ways to broaden your knowledge.','폭넓게 독서하는 것은 지식을 넓히는 가장 좋은 방법 중 하나예요.','She joined a study group to broaden her knowledge of history.','그녀는 역사 지식을 넓히기 위해 스터디 그룹에 참여했어요.','Traveling abroad really broadens your knowledge of other cultures.','해외여행은 다른 문화에 대한 지식을 정말로 넓혀줘요.','Podcasts have helped me broaden my knowledge in many fields.','팟캐스트가 여러 분야에서 제 지식을 넓히는 데 도움이 됐어요.','Reading widely is one way to broaden your knowledge effortlessly.','폭넓게 독서하는 것은 노력 없이 지식을 넓히는 한 가지 방법이에요.'),
('col_education_C1_01','earn','degree','earn a degree','학위를 취득하다','get','시간과 노력을 들여 학위를 받았다는 격식 있는 표현이에요. ''get a degree''보다 더 무게감 있게 들려요.','C1','education',2,0,'graduation diploma','She earned a master''s degree in linguistics.','그녀는 언어학 석사 학위를 취득했어요.','He earned his degree while working full-time.','그는 풀타임으로 일하면서 학위를 취득했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_education_C1_02','broaden','horizons','broaden horizons','시야를 넓히다','open','경험이나 학습을 통해 사고와 관점을 확장한다는 의미예요. 교육·여행 분야에서 매우 자주 써요.','C1','education',2,0,'student abroad horizon','Studying abroad really broadens your horizons.','해외 유학은 시야를 정말 넓혀줘요.','Reading widely is one of the best ways to broaden your horizons.','폭넓게 읽는 것은 시야를 넓히는 가장 좋은 방법 중 하나예요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_education_C1_03','grasp','concept','grasp a concept','개념을 이해하다','catch','추상적인 개념을 정확히 이해한다는 학술적 표현이에요. ''catch''는 부자연스러워요.','C1','education',2,0,'student understanding book','Most students grasp the concept of supply and demand quickly.','대부분의 학생들은 수요와 공급 개념을 빠르게 이해해요.','It took me a while to grasp the concept of quantum mechanics.','양자역학 개념을 이해하는 데 시간이 좀 걸렸어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_education_C1_04','master','subject','master a subject','한 과목을 통달하다','learn','단순히 배우는 것을 넘어 매우 깊이 있게 익혔다는 뜻이에요. 학업과 전문 분야에서 두루 써요.','C1','education',2,0,'student studying mastery','It takes years of practice to master a subject like calculus.','미적분 같은 과목을 통달하는 데는 수년간의 연습이 필요해요.','She has mastered the subject of medieval history.','그녀는 중세사 분야를 통달했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_education_C1_05','ace','exam','ace an exam','시험을 잘 보다','win','시험을 매우 잘 봐서 최고 점수를 받는다는 미국식 표현이에요. 캐주얼하지만 C1 수준에서 흔히 써요.','C1','education',2,0,'exam test perfect score','She aced her final exam without breaking a sweat.','그녀는 땀 한 방울 흘리지 않고 기말고사를 잘 봤어요.','If you study hard, you''ll ace the exam.','열심히 공부하면 시험을 잘 볼 거예요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_education_C2_01','pursue','scholarship','pursue scholarship','학문을 추구하다','study','단순한 공부가 아니라 평생에 걸친 학문적 탐구를 의미하는 격식 표현이에요. 학술 추천서나 학자의 약력에 잘 어울려요.','C2','education',3,0,'university library','After completing her doctorate, she chose to pursue scholarship at Oxford.','박사 학위를 마친 뒤, 그녀는 옥스퍼드에서 학문을 추구하기로 했어요.','The institute supports those who wish to pursue scholarship in the humanities.','그 연구소는 인문학 분야에서 학문을 추구하고자 하는 이들을 지원해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_education_C2_02','expand','horizons','expand horizons','시야를 넓히다','open','경험이나 학습을 통해 사고와 가능성의 범위를 확장한다는 격식 있는 표현이에요. 대학 안내서, 추천사에 자주 등장해요.','C2','education',3,0,'study abroad students','A semester abroad invariably expands students'' horizons in profound ways.','한 학기의 해외 연수는 어김없이 학생들의 시야를 깊이 있게 넓혀줘요.','Reading widely is the surest means of expanding one''s horizons.','폭넓은 독서는 시야를 넓히는 가장 확실한 방법이에요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_education_C2_03','impart','knowledge','impart knowledge','지식을 전수하다','give','지식이나 지혜를 정성껏 전달한다는 격식 있는 교육적 표현이에요. 교수, 멘토, 장인에 관한 글의 표준 표현이에요.','C2','education',3,0,'professor lecturing','A great mentor does more than impart knowledge; she shapes character.','훌륭한 멘토는 지식을 전수하는 것 이상으로 인격을 형성해줘요.','The professor sought to impart knowledge that would outlast any single lecture.','그 교수는 어떤 한 강의보다 더 오래 남을 지식을 전수하고자 했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_education_C2_04','foster','critical thinking','foster critical thinking','비판적 사고를 기르다','teach','비판적 사고력을 자연스럽게 길러준다는 교육학 표준 표현이에요. 커리큘럼 설명서, 교육 정책 문서에 자주 보여요.','C2','education',3,0,'classroom discussion','The new curriculum is explicitly designed to foster critical thinking from an early age.','새 교육과정은 어린 나이부터 비판적 사고를 기르도록 명시적으로 설계됐어요.','Socratic seminars foster critical thinking far more effectively than rote learning.','소크라테스식 세미나는 암기 학습보다 훨씬 효과적으로 비판적 사고를 길러줘요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_education_C2_05','cultivate','expertise','cultivate expertise','전문성을 함양하다','get','시간과 노력을 들여 깊은 전문성을 키운다는 격식 있는 표현이에요. 경력 개발, 학술 약력, 채용 공고에 자주 써요.','C2','education',3,0,'researcher laboratory','It takes a decade of focused practice to cultivate expertise of this calibre.','이 정도 수준의 전문성을 함양하려면 10년의 집중적인 수련이 필요해요.','The fellowship enables scholars to cultivate expertise in emerging fields.','그 펠로우십은 학자들이 신흥 분야에서 전문성을 함양할 수 있게 해줘요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_emotion_23','have','fun','have fun','재미있게 놀다, 즐기다','do','"do fun"은 틀린 표현이에요. 즐거운 활동을 할 때는 have fun을 써요.','A1','emotion',1,0,'people laughing party fun celebration','We had so much fun at the party last night.','어젯밤 파티에서 정말 즐거웠어요.','Have fun on your trip!','여행 잘 다녀오세요!','The kids are having fun at the playground.','아이들이 놀이터에서 재미있게 놀고 있어요.','Did you have fun at the concert?','콘서트에서 즐거웠어요?','Let''s have fun while we can.','할 수 있을 때 즐겨요.'),
('col_emotion_07','get','excited','get excited','신이 나다, 흥분하다','become','"become excited"도 맞지만 get excited가 훨씬 자연스러운 구어체예요.','A2','emotion',1,7,'excitement happy joy celebration','The kids got excited when they heard about the trip.','아이들은 여행 소식을 들었을 때 신이 났어요.','I always get excited before a big performance.','큰 공연 전에는 항상 설레고 흥분돼요.','My niece gets excited every time she sees a dog on the street.','제 조카는 길에서 강아지를 볼 때마다 신이 나요.','I got really excited when I received the acceptance email.','합격 이메일을 받았을 때 정말 신이 났어요.','They got excited about the upcoming family vacation.','그들은 다가오는 가족 휴가에 신이 났어요.'),
('col_emotion_22','keep','calm','keep calm','침착함을 유지하다','stay','stay calm도 가능하지만 keep calm이 어디서나 자연스러워요. 영국 슬로건 "Keep Calm and Carry On"으로도 유명.','A2','emotion',1,0,'calm person meditation breathing peaceful','Try to keep calm during the interview.','면접 중에 침착함을 유지하세요.','She kept calm even in the emergency.','그녀는 비상 상황에서도 침착했어요.','Keep calm and don''t panic.','침착하고 당황하지 마세요.','It''s hard to keep calm when everyone is shouting.','모두가 소리치고 있을 때 침착하기는 어려워요.','Deep breathing helps me keep calm under stress.','깊은 호흡이 스트레스 상황에서 침착함을 유지하는 데 도움이 돼요.'),
('col_emotion_24','get','angry','get angry','화가 나다','become','"become angry"는 격식 있는 문어체. 일상에서는 get angry가 훨씬 자연스러워요.','A2','emotion',1,0,'angry person frowning frustrated emotion face','Don''t get angry — let''s talk about it calmly.','화내지 말고 차분히 얘기해요.','She got angry when she heard the rumor.','그녀는 그 소문을 듣고 화가 났어요.','I rarely get angry, but this time I was furious.','저는 거의 화내지 않지만 이번엔 격분했어요.','He gets angry when people are late.','그는 사람들이 늦으면 화를 내요.','Why are you getting angry over such a small thing?','왜 그렇게 사소한 일에 화를 내요?'),
('col_emotion_01','make','an effort','make an effort','노력하다','do','"do an effort"는 틀린 표현이에요. 노력할 때는 make an effort를 써요.','B1','emotion',1,1,'effort trying hard determination','She made a real effort to stay positive during a difficult time.','그녀는 힘든 시간 동안 긍정적으로 있으려고 정말 노력했어요.','Please make an effort to understand how others are feeling.','다른 사람의 감정을 이해하려고 노력해 주세요.','I made an effort to learn a few words of Korean before my trip.','여행 전에 한국어를 몇 마디 배우려고 노력했어요.','They made an effort to include everyone in the conversation.','그들은 모두를 대화에 포함시키려고 노력했어요.','You can tell he made a real effort to improve his work.','그가 자기 일을 개선하려고 정말 노력했다는 게 보여요.'),
('col_emotion_02','feel','relieved','feel relieved','안도감을 느끼다','get','"get relieved"도 쓰이지만 feel relieved가 더 자연스러운 표현이에요.','B1','emotion',1,2,'relief calm relaxed good news','I felt relieved when I heard the test results were fine.','검사 결과가 괜찮다는 말을 들었을 때 안도감을 느꼈어요.','She felt relieved after finally talking to someone about her worries.','그녀는 마침내 걱정을 누군가에게 털어놓은 후 안도감을 느꼈어요.','We all felt relieved once the deadline finally passed.','마감일이 마침내 지나자 우리 모두 안도감을 느꼈어요.','He felt relieved to see his daughter safely home from school.','그는 딸이 학교에서 안전하게 돌아온 것을 보고 안도감을 느꼈어요.','I felt relieved knowing the surgery had gone well.','수술이 잘 끝났다는 것을 알고 안도감을 느꼈어요.'),
('col_emotion_03','get','frustrated','get frustrated','짜증이 나다','become','"become frustrated"도 맞지만 get frustrated가 더 구어체적이에요.','B1','emotion',1,3,'frustration stressed upset difficult','It''s easy to get frustrated when things don''t go as planned.','일이 계획대로 되지 않을 때 짜증이 나기 쉬워요.','He got frustrated trying to explain the same thing over and over.','그는 같은 것을 반복해서 설명하다가 짜증이 났어요.','She got frustrated with the slow Wi-Fi during the meeting.','그녀는 회의 중 느린 와이파이 때문에 짜증이 났어요.','Don''t get frustrated — learning a language takes time.','짜증 내지 마세요 — 언어를 배우는 데는 시간이 걸려요.','He got frustrated when the printer kept jamming.','그는 프린터가 계속 걸려서 짜증이 났어요.'),
('col_emotion_04','have','a feeling','have a feeling','느낌이 있다, 예감이 있다','get','"get a feeling"도 쓰이지만 have a feeling이 더 일반적이에요.','B1','emotion',1,4,'intuition feeling hunch emotion','I have a feeling something is about to change.','뭔가 바뀔 것 같은 느낌이 있어요.','She had a feeling he wasn''t telling the whole truth.','그녀는 그가 전부를 말하지 않는다는 느낌이 들었어요.','I have a feeling it''s going to rain this afternoon.','오후에 비가 올 것 같은 느낌이 있어요.','She had a feeling they would meet again someday.','그녀는 그들이 언젠가 다시 만날 것 같은 느낌이 들었어요.','We had a feeling something exciting was about to happen.','뭔가 신나는 일이 곧 일어날 것 같은 느낌이 있었어요.'),
('col_emotion_05','keep','calm','keep calm','침착함을 유지하다','stay','"stay calm"도 맞지만 keep calm이 더 명령형으로 자주 쓰여요.','B1','emotion',1,5,'calm composure stress management','Try to keep calm even when the situation feels overwhelming.','상황이 벅차게 느껴질 때도 침착함을 유지하려고 노력해요.','She kept calm throughout the whole stressful interview.','그녀는 스트레스 넘치는 면접 내내 침착함을 유지했어요.','Try to keep calm and breathe deeply during the test.','시험 중에 침착함을 유지하면서 깊게 호흡해 보세요.','He kept calm even when the children were crying loudly.','그는 아이들이 큰 소리로 울 때도 침착함을 유지했어요.','The pilot kept calm and landed the plane safely.','조종사는 침착함을 유지하며 비행기를 안전하게 착륙시켰어요.'),
('col_emotion_09','give','support','give support','지지하다, 지원하다','make','"make support"는 틀린 표현이에요. 지지할 때는 give support를 써요.','B1','emotion',1,9,'support friends help comfort','Her friends gave her support when she was going through a tough time.','친구들은 그녀가 힘든 시간을 겪을 때 지지해 줬어요.','It means a lot when people give support without being asked.','물어보지 않아도 지지해 주는 사람들이 있다는 게 큰 의미가 있어요.','My family gave me support throughout my entire career change.','제 가족은 제 커리어 전환 내내 지지해 줬어요.','The community gave support to the families affected by the flood.','지역사회는 홍수 피해 가족들을 지지해 줬어요.','It''s important to give support to colleagues who are struggling.','힘들어하는 동료를 지지해 주는 것이 중요해요.'),
('col_emotion_06','break','down','break down','감정이 무너지다, 울음을 터뜨리다','fall','"fall down"은 감정적 의미가 없어요. 감정이 무너질 때는 break down을 써요.','B2','emotion',1,6,'crying emotional breakdown tears','She broke down when she heard the sad news.','그녀는 슬픈 소식을 들었을 때 눈물을 터뜨렸어요.','He tried to hold it together but eventually broke down crying.','그는 참으려고 했지만 결국 눈물을 터뜨리며 무너졌어요.','I almost broke down during the farewell speech.','저는 작별 연설 중에 거의 무너질 뻔했어요.','She broke down in tears when she opened the letter.','그녀는 편지를 열어보고 눈물을 터뜨리며 무너졌어요.','After weeks of pressure, he finally broke down at home.','몇 주간의 압박 끝에 그는 결국 집에서 무너졌어요.'),
('col_emotion_08','feel','overwhelmed','feel overwhelmed','압도되다, 벅차다','get','"get overwhelmed"도 쓰이지만 feel overwhelmed가 감정 표현에 더 자연스러워요.','B2','emotion',2,8,'overwhelmed stress too much pressure','She felt overwhelmed by all the responsibilities at once.','그녀는 한꺼번에 쏟아지는 모든 책임에 압도되었어요.','It''s normal to feel overwhelmed when starting something new.','새로운 것을 시작할 때 벅차게 느끼는 건 자연스러운 일이에요.','I feel overwhelmed by the amount of homework this week.','이번 주에 숙제가 너무 많아서 벅차게 느껴져요.','New parents often feel overwhelmed in the first few months.','신생아 부모들은 첫 몇 달간 종종 벅차게 느껴요.','He felt overwhelmed by the kindness of strangers after the accident.','그는 사고 후에 낯선 이들의 친절에 압도되었어요.'),
('col_emotion_10','take','it personally','take it personally','개인적으로 받아들이다','get','"get it personally"는 틀린 표현이에요. 개인적으로 받아들일 때는 take를 써요.','B2','emotion',2,10,'sensitivity personal criticism reaction','Please don''t take it personally — it wasn''t directed at you.','개인적으로 받아들이지 마세요 — 당신을 겨냥한 말이 아니었어요.','He tends to take criticism personally even when it''s constructive.','그는 건설적인 비판도 개인적으로 받아들이는 경향이 있어요.','She took the feedback personally even though it was about the project.','프로젝트에 관한 피드백이었는데도 그녀는 개인적으로 받아들였어요.','Try not to take it personally when people are just being honest.','사람들이 솔직하게 말하는 것뿐일 때는 개인적으로 받아들이지 않으려 해보세요.','I used to take everything personally, but I''ve learned not to.','저는 모든 걸 개인적으로 받아들이곤 했는데, 이제는 그러지 않으려고 해요.'),
('col_emotion_11','hold','back tears','hold back tears','눈물을 참다','stop','"stop tears"는 어색해요. 눈물을 참을 때는 hold back을 써요.','B2','emotion',2,11,'tears emotion sad farewell holding back','She tried to hold back tears as she said goodbye.','그녀는 작별 인사를 하면서 눈물을 참으려 했어요.','He held back tears during the entire ceremony.','그는 행사 내내 눈물을 참았어요.','I had to hold back tears when I watched the documentary.','저는 그 다큐멘터리를 보면서 눈물을 참아야 했어요.','She held back tears as she read the letter from her father.','그녀는 아버지의 편지를 읽으면서 눈물을 참았어요.','It was hard to hold back tears at his retirement party.','그의 은퇴식에서 눈물을 참기 힘들었어요.'),
('col_emotion_12','lose','patience','lose patience','인내심을 잃다','run','"run patience"는 틀린 표현이에요. 인내심을 잃을 때는 lose patience를 써요.','B2','emotion',2,12,'patience frustration waiting tired','I finally lost patience after waiting for over an hour.','한 시간 넘게 기다리다가 마침내 인내심을 잃었어요.','She tries not to lose patience with her students.','그녀는 학생들에게 인내심을 잃지 않으려고 노력해요.','He lost patience with the customer who kept changing his order.','그는 주문을 계속 바꾸는 손님에게 인내심을 잃었어요.','It''s easy to lose patience when you''re tired and hungry.','피곤하고 배고프면 인내심을 잃기 쉬워요.','The parent lost patience after asking the child five times.','부모는 아이에게 다섯 번이나 부탁한 끝에 인내심을 잃었어요.'),
('col_emotion_13','boost','confidence','boost confidence','자신감을 높이다','increase','"increase confidence"도 쓰이지만 boost가 더 생동감 있는 표현이에요.','B2','emotion',2,13,'confidence self-esteem positive empowerment','Positive feedback really boosted her confidence.','긍정적인 피드백이 그녀의 자신감을 크게 높여줬어요.','Exercise can boost your confidence as well as your health.','운동은 건강뿐 아니라 자신감도 높여줄 수 있어요.','Learning a new skill can really boost your confidence.','새로운 기술을 배우는 건 자신감을 크게 높여줄 수 있어요.','A good haircut sometimes boosts your confidence overnight.','괜찮은 헤어컷이 하룻밤 만에 자신감을 높여주기도 해요.','Winning the small contest boosted her confidence to enter bigger ones.','작은 대회에서 우승한 것이 더 큰 대회에 참가할 자신감을 높여줬어요.'),
('col_emotion_14','deal with','emotions','deal with emotions','감정을 다루다','handle','"handle emotions"도 맞지만 deal with emotions가 더 자주 쓰여요.','B2','emotion',2,14,'emotions mental health therapy coping','It''s important to learn how to deal with difficult emotions.','어려운 감정을 어떻게 다루는지 배우는 것이 중요해요.','He wasn''t sure how to deal with his emotions after the breakup.','그는 이별 후 자신의 감정을 어떻게 다뤄야 할지 몰랐어요.','Therapy helped him learn to deal with his emotions in a healthy way.','상담은 그가 감정을 건강하게 다루는 법을 배우는 데 도움이 됐어요.','She''s still figuring out how to deal with her emotions after the divorce.','그녀는 이혼 후 감정을 어떻게 다뤄야 할지 아직 알아가는 중이에요.','Journaling is one way to deal with emotions you can''t express out loud.','일기 쓰기는 소리 내어 표현하지 못하는 감정을 다루는 한 가지 방법이에요.'),
('col_emotion_15','express','gratitude','express gratitude','감사를 표현하다','show','"show gratitude"도 맞지만 express가 더 격식 있는 표현이에요.','B2','emotion',2,15,'gratitude thankful appreciation kindness','She took the time to express gratitude to everyone who helped her.','그녀는 도움을 준 모든 사람에게 감사를 표현하는 시간을 가졌어요.','It''s good to express gratitude even for small acts of kindness.','작은 친절에도 감사를 표현하는 것이 좋아요.','She wrote a card to express gratitude to her mentor.','그녀는 멘토에게 감사를 표현하기 위해 카드를 썼어요.','It''s easy to forget to express gratitude in our busy lives.','바쁜 일상에서는 감사를 표현하는 걸 잊기 쉬워요.','He expressed gratitude in his speech to everyone who supported him.','그는 연설에서 자신을 지지해 준 모두에게 감사를 표현했어요.'),
('col_emotion_16','feel','at ease','feel at ease','편안함을 느끼다','be','"be at ease"도 맞지만 feel at ease가 감정 상태를 더 잘 표현해요.','B2','emotion',2,16,'comfortable relaxed welcoming atmosphere','I immediately felt at ease when I walked into the room.','방에 들어가자마자 편안함을 느꼈어요.','He helped everyone feel at ease with his warm personality.','그는 따뜻한 성격으로 모든 사람이 편안함을 느끼게 해줬어요.','I feel at ease in my grandmother''s kitchen even after all these years.','그 오랜 시간이 지난 후에도 할머니 부엌에서는 편안함을 느껴요.','She always made her guests feel at ease with her gentle humor.','그녀는 부드러운 유머로 손님들을 항상 편안하게 해줬어요.','The therapist''s calm voice helped me feel at ease right away.','상담사의 차분한 목소리 덕분에 저는 바로 편안함을 느꼈어요.'),
('col_emotion_17','put','a smile on','put a smile on someone''s face','누군가를 미소 짓게 하다','make','"make a smile"은 어색해요. put a smile on someone''s face가 자연스러운 표현이에요.','B2','emotion',3,17,'smile happiness joy surprise gift','A small gift can put a smile on someone''s face.','작은 선물 하나가 누군가를 미소 짓게 할 수 있어요.','Her surprise visit really put a smile on his face.','그녀의 깜짝 방문이 정말 그를 미소 짓게 했어요.','Your sweet message really put a smile on my face this morning.','당신의 다정한 메시지가 오늘 아침 정말 저를 미소 짓게 했어요.','Watching the kids play put a smile on the old man''s face.','아이들이 노는 모습이 노인을 미소 짓게 했어요.','A warm cup of tea on a cold day always puts a smile on her face.','추운 날 따뜻한 차 한 잔이 항상 그녀를 미소 짓게 해요.'),
('col_emotion_18','get','carried away','get carried away','감정에 휩쓸리다','be','"be carried away"도 맞지만 get carried away가 더 구어체적이에요.','B2','emotion',2,18,'emotion excitement impulsive reaction','Don''t get carried away — let''s think this through calmly.','감정에 휩쓸리지 마세요 — 차분하게 생각해 봐요.','She got carried away with excitement and forgot to check the details.','그녀는 흥분에 휩쓸려서 세부 사항을 확인하는 것을 잊었어요.','I got carried away shopping and spent more than I planned.','저는 쇼핑에 휩쓸려서 계획보다 더 많이 썼어요.','He got carried away with the joke and went too far.','그는 농담에 휩쓸려서 도가 지나쳤어요.','Try not to get carried away when you''re negotiating a price.','가격 흥정을 할 때 휩쓸리지 않도록 조심하세요.'),
('col_emotion_21','lose','temper','lose your temper','화를 내다, 성을 내다','have','"have temper"는 어색해요. 갑자기 화를 표출할 때 lose your temper를 써요.','B2','emotion',1,0,'angry person frustrated outburst office','Try not to lose your temper in front of customers.','고객 앞에서는 화를 내지 않도록 하세요.','He lost his temper when he heard the news.','그는 그 소식을 듣고 화를 냈어요.','I''ve never seen her lose her temper before.','그녀가 화내는 걸 본 적이 없어요.','Don''t lose your temper — let''s talk calmly.','화내지 말고 차분히 얘기해요.','He apologized for losing his temper earlier.','그는 아까 화낸 것에 대해 사과했어요.'),
('col_emotion_25','break','heart','break someone''s heart','마음을 아프게 하다','hurt','"hurt someone''s heart"는 어색해요. 깊이 상심하게 만들 때는 break someone''s heart.','B2','emotion',1,0,'broken heart sad goodbye breakup emotion','It broke her heart when he moved away.','그가 멀리 이사 갔을 때 그녀의 마음이 찢어졌어요.','Don''t break his heart — be honest from the start.','그의 마음을 아프게 하지 말고 처음부터 솔직해지세요.','The news broke my heart.','그 소식에 마음이 찢어졌어요.','She broke his heart when she ended the relationship.','그녀가 관계를 끝냈을 때 그의 마음을 아프게 했어요.','It broke their hearts to leave their pet behind.','반려동물을 두고 가는 게 그들의 마음을 아프게 했어요.'),
('col_emotion_19','come','to terms with','come to terms with','받아들이다, 인정하다','accept','"accept"도 맞지만 come to terms with는 시간이 걸리는 수용을 의미해요.','C1','emotion',3,19,'acceptance grief loss healing','It took him months to come to terms with the loss.','그는 상실을 받아들이는 데 몇 달이 걸렸어요.','She finally came to terms with the fact that things had changed.','그녀는 마침내 상황이 변했다는 사실을 받아들였어요.','She''s slowly coming to terms with the diagnosis.','그녀는 천천히 그 진단을 받아들이고 있어요.','It took years for him to come to terms with his childhood.','그가 어린 시절을 받아들이기까지 몇 년이 걸렸어요.','She came to terms with the fact that some friendships fade with time.','그녀는 어떤 우정은 시간이 지나며 옅어진다는 사실을 받아들였어요.'),
('col_emotion_20','reach','a breaking point','reach a breaking point','한계에 다다르다','get','"get a breaking point"는 어색해요. 한계에 이를 때는 reach를 써요.','C1','emotion',3,20,'stress burnout limit exhaustion breaking point','After weeks of overwork, she finally reached a breaking point.','몇 주간의 과로 끝에 그녀는 결국 한계에 다다랐어요.','He knew he was reaching a breaking point and asked for help.','그는 자신이 한계에 다가가고 있다는 걸 알고 도움을 요청했어요.','He reached a breaking point and decided to take a long vacation.','그는 한계에 다다라서 긴 휴가를 가기로 결심했어요.','Many caregivers reach a breaking point without proper support.','많은 간병인들은 적절한 지원 없이 한계에 다다라요.','The constant noise from the construction reached a breaking point for the residents.','공사장의 끊임없는 소음이 주민들에게 한계에 다다랐어요.'),
('col_emotion_C1_01','vent','frustration','vent frustration','답답함을 토로하다','say','쌓인 부정적 감정을 말이나 행동으로 풀어낸다는 뜻이에요. 직장 상담이나 인터뷰에서 자주 쓰는 격식 표현이에요.','C1','emotion',2,0,'person venting','She needed a trusted colleague to vent her frustration after the meeting.','그녀는 회의 후 답답함을 토로할 믿을 만한 동료가 필요했어요.','Employees often vent their frustration in anonymous surveys.','직원들은 익명 설문에서 답답함을 토로하곤 해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_emotion_C1_02','express','gratitude','express gratitude','감사를 표하다','say','감사한 마음을 격식 있게 전한다는 뜻이에요. ''say thanks''보다 훨씬 정중하고 글쓰기에서 표준 표현이에요.','C1','emotion',2,0,'thank you note','He took a moment to express his gratitude to the entire research team.','그는 잠시 시간을 내어 연구팀 전체에 감사를 표했어요.','In her acceptance speech, she expressed gratitude to her mentors.','수상 소감에서 그녀는 멘토들에게 감사를 표했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_emotion_C1_03','hide','disappointment','hide disappointment','실망감을 감추다','cover','속으로는 실망했지만 겉으로는 드러내지 않으려 한다는 뜻이에요. 인터뷰, 협상, 가족 대화에서 자주 보여요.','C1','emotion',2,0,'sad face','She tried to hide her disappointment when the promotion went to someone else.','승진이 다른 사람에게 갔을 때 그녀는 실망감을 감추려 했어요.','He could barely hide his disappointment at the verdict.','그는 판결에 대한 실망감을 거의 감추지 못했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_emotion_C1_04','show','empathy','show empathy','공감을 보이다','feel','단순히 느끼는 것을 넘어 상대에게 공감하는 태도를 드러낸다는 뜻이에요. 리더십, 상담, 의료 현장에서 핵심 표현이에요.','C1','emotion',2,0,'caring conversation','Effective managers show empathy without losing their professional edge.','유능한 관리자는 전문성을 잃지 않으면서 공감을 보여요.','Nurses are trained to show empathy under stressful conditions.','간호사들은 스트레스 상황에서도 공감을 보이도록 훈련받아요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_emotion_C1_05','bottle up','emotions','bottle up emotions','감정을 억누르다','keep','감정을 표현하지 않고 속에 쌓아둔다는 뜻이에요. 심리학, 자기계발 글에서 표준으로 쓰는 표현이에요.','C1','emotion',2,0,'bottle silhouette','Bottling up your emotions for years can take a serious toll on your health.','수년간 감정을 억누르면 건강에 큰 타격을 줄 수 있어요.','He has a tendency to bottle up his emotions instead of talking them through.','그는 감정을 털어놓기보다 억누르는 경향이 있어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_emotion_C2_01','harbor','resentment','harbor resentment','원한을 품다','have','오랜 시간 마음속에 부정적 감정을 간직한다는 격식 있는 문어체 표현이에요. 문학이나 심리 분석에서 자주 보여요.','C2','emotion',3,0,'pensive woman shadow','She had harbored resentment toward her former mentor for nearly a decade.','그녀는 거의 10년 동안 옛 멘토에 대한 원한을 품어왔어요.','Harboring resentment only corrodes one''s own peace of mind.','원한을 품는 것은 자신의 평정심을 갉아먹을 뿐이에요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_emotion_C2_02','exhibit','composure','exhibit composure','침착함을 보이다','show','위기 상황에서도 평정을 드러낸다는 격식 표현이에요. 외교, 위기 관리, 법정 보도에 적절해요.','C2','emotion',3,0,'calm executive','The diplomat exhibited remarkable composure during the heated exchange.','그 외교관은 격렬한 논쟁 중에도 놀라운 침착함을 보였어요.','She exhibited composure even as the verdict was read aloud.','판결문이 낭독되는 순간에도 그녀는 침착함을 보였어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_emotion_C2_03','succumb','despair','succumb to despair','절망에 굴복하다','feel','저항하다가 결국 부정적 감정에 무너진다는 문학적 표현이에요. ''succumb to''는 격식 있는 동사구예요.','C2','emotion',3,0,'lonely figure rain','Even in exile, the poet refused to succumb to despair.','망명 중에도 그 시인은 절망에 굴복하기를 거부했어요.','After months of setbacks, he nearly succumbed to despair.','몇 달간의 좌절 끝에 그는 거의 절망에 굴복할 뻔했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_emotion_C2_04','evoke','nostalgia','evoke nostalgia','향수를 불러일으키다','make','기억이나 감정을 자연스럽게 떠오르게 한다는 우아한 표현이에요. 예술 평론과 광고 카피에서 자주 등장해요.','C2','emotion',3,0,'old photograph','The faded photograph evoked a profound nostalgia for his childhood village.','바랜 사진은 그의 어린 시절 마을에 대한 깊은 향수를 불러일으켰어요.','The melody evokes a quiet nostalgia in anyone who hears it.','그 선율은 듣는 누구에게나 잔잔한 향수를 불러일으켜요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_emotion_C2_05','betray','emotion','betray emotion','감정을 드러내다','show','숨기려 했던 감정이 무심코 드러난다는 문학적 표현이에요. 표정이나 목소리가 ''배신''한다는 뉘앙스예요.','C2','emotion',3,0,'subtle expression','Her steady voice did not betray the slightest emotion.','그녀의 차분한 목소리는 어떤 감정도 드러내지 않았어요.','A faint tremor in his hand betrayed his emotion.','미세하게 떨리는 손이 그의 감정을 드러냈어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_environment_21','plant','tree','plant a tree','나무를 심다','grow','"grow a tree"는 키운다는 의미. 처음 심는 건 plant a tree.','A2','environment',1,0,'planting tree garden shovel earth nature','We planted a tree in the backyard.','뒤뜰에 나무를 심었어요.','She plants a tree every year on her birthday.','그녀는 매년 생일에 나무를 심어요.','The community planted hundreds of trees.','지역 사회는 수백 그루의 나무를 심었어요.','Planting a tree is a small but meaningful act.','나무를 심는 건 작지만 의미 있는 행동이에요.','They planted trees to restore the forest.','그들은 숲을 복원하기 위해 나무를 심었어요.'),
('col_environment_23','protect','nature','protect nature','자연을 보호하다','save','"save nature"도 가능하지만 protect nature가 더 자연스러운 일상 표현이에요.','A2','environment',1,0,'nature forest conservation protected green landscape','It''s our duty to protect nature.','자연을 보호하는 건 우리의 의무예요.','They work hard to protect nature in the park.','그들은 공원의 자연을 보호하기 위해 열심히 일해요.','Protecting nature starts with small actions.','자연 보호는 작은 행동에서 시작해요.','We must protect nature for future generations.','미래 세대를 위해 자연을 보호해야 해요.','Volunteers help protect nature in this reserve.','자원봉사자들이 이 보호 구역의 자연 보호를 도와요.'),
('col_environment_01','take','action','take action','조치를 취하다','make','"make action"은 틀린 표현이에요. 조치를 취할 때는 take를 써요.','B1','environment',1,1,'action climate environment green policy','Governments need to take action on climate change immediately.','정부는 즉시 기후 변화에 대한 조치를 취해야 해요.','We can all take action to reduce our carbon footprint.','우리 모두 탄소 발자국을 줄이기 위한 조치를 취할 수 있어요.','Schools are taking action to reduce single-use plastics on campus.','학교들은 캠퍼스에서 일회용 플라스틱을 줄이기 위한 조치를 취하고 있어요.','It''s time to take action instead of waiting for someone else.','다른 누군가를 기다리는 대신 조치를 취할 때예요.','Cities took action by adding more bike lanes and electric buses.','도시들은 자전거 도로와 전기 버스를 추가하는 조치를 취했어요.'),
('col_environment_02','make','a difference','make a difference','변화를 만들다','do','"do a difference"는 틀린 표현이에요. 변화를 일으킬 때는 make를 써요.','B1','environment',1,2,'difference impact environment change green','Even small changes in daily habits can make a big difference.','일상 습관의 작은 변화도 큰 차이를 만들 수 있어요.','Choosing to recycle makes a difference for the planet.','재활용을 선택하는 것이 지구를 위해 변화를 만들어요.','Switching to a reusable bottle really does make a difference.','재사용 가능한 물병으로 바꾸는 것이 정말로 변화를 만들어요.','Small businesses make a difference by sourcing locally.','소규모 사업체들은 지역에서 조달함으로써 변화를 만들어요.','Volunteering at a local park is one way to make a difference.','지역 공원에서 봉사하는 것은 변화를 만드는 한 방법이에요.'),
('col_environment_08','get','involved','get involved','참여하다','join','"join"도 맞지만 get involved는 적극적으로 참여하는 뉘앙스예요.','B1','environment',1,8,'volunteer environment community involved green','Anyone can get involved in local environmental projects.','누구나 지역 환경 프로젝트에 참여할 수 있어요.','She got involved in a beach clean-up volunteer program.','그녀는 해변 청소 자원봉사 프로그램에 참여했어요.','Anyone can get involved by joining a local cleanup event.','지역 청소 행사에 참여하면 누구나 참여할 수 있어요.','He got involved in a tree-planting project after retirement.','그는 은퇴 후 나무 심기 프로젝트에 참여했어요.','Getting involved early in life shapes your values.','어린 시절부터 참여하는 것이 가치관을 형성해요.'),
('col_environment_17','go','green','go green','친환경적으로 되다','become','"become green"도 맞지만 go green이 더 구어체적이에요.','B1','environment',1,17,'green sustainable eco-friendly lifestyle energy','More and more households are going green with solar panels.','점점 더 많은 가정이 태양열 패널로 친환경적이 되고 있어요.','The company pledged to go green within the next five years.','회사는 향후 5년 내에 친환경적으로 전환하겠다고 약속했어요.','Their family went green by installing rooftop solar last year.','그 가족은 작년에 옥상 태양광을 설치하여 친환경적으로 됐어요.','It''s easier to go green when your neighborhood supports it.','동네가 지원해 줄 때 친환경적으로 되는 게 더 쉬워요.','Many small businesses are going green to attract younger customers.','많은 소규모 사업체들이 젊은 고객들을 끌어들이기 위해 친환경적으로 되고 있어요.'),
('col_environment_22','reduce','waste','reduce waste','쓰레기를 줄이다','cut','"cut waste"도 가능하지만 환경 맥락에서는 reduce waste가 표준 표현이에요.','B1','environment',1,0,'recycling bins waste reduction sustainability green','We need to reduce waste at home and work.','집과 직장에서 쓰레기를 줄여야 해요.','She reduces waste by composting food scraps.','그녀는 음식 찌꺼기를 퇴비화해서 쓰레기를 줄여요.','The company is trying to reduce waste in production.','회사는 생산 과정에서 쓰레기 줄이기를 시도해요.','Simple changes can reduce waste significantly.','간단한 변화로도 쓰레기를 크게 줄일 수 있어요.','How can we reduce waste in this office?','이 사무실에서 어떻게 쓰레기를 줄일 수 있을까요?'),
('col_environment_03','reduce','emissions','reduce emissions','배출량을 줄이다','decrease','"decrease emissions"도 맞지만 reduce가 더 자주 쓰이는 환경 표현이에요.','B2','environment',1,3,'emissions carbon reduction climate electric','The government has pledged to reduce carbon emissions by 50% by 2030.','정부는 2030년까지 탄소 배출량을 50% 줄이겠다고 약속했어요.','Electric vehicles can help reduce emissions in urban areas.','전기 자동차는 도시 지역의 배출량을 줄이는 데 도움이 될 수 있어요.','Companies are under pressure to reduce emissions across their supply chains.','기업들은 공급망 전반에 걸쳐 배출량을 줄이라는 압력을 받고 있어요.','We can reduce household emissions by using less hot water.','뜨거운 물 사용을 줄여서 가정 배출량을 줄일 수 있어요.','Forests help reduce emissions by absorbing carbon dioxide.','숲은 이산화탄소를 흡수해서 배출량을 줄이는 데 도움이 돼요.'),
('col_environment_04','break','a habit','break a habit','(나쁜) 습관을 끊다','stop','"stop a habit"도 맞지만 break a habit은 오래된 습관을 끊는 뉘앙스예요.','B2','environment',2,4,'habit change recycle green lifestyle','Breaking the habit of using single-use plastics takes effort.','일회용 플라스틱 사용 습관을 끊는 데는 노력이 필요해요.','We need to break the habit of driving short distances.','짧은 거리를 차로 이동하는 습관을 끊어야 해요.','It''s hard to break the habit of accepting plastic bags at the store.','가게에서 비닐봉지를 받는 습관을 끊기는 어려워요.','They broke the habit of food waste by meal planning every Sunday.','그들은 매주 일요일 식사를 계획해서 음식물 쓰레기 습관을 끊었어요.','Breaking the habit of long showers helps save water.','긴 샤워 습관을 끊으면 물 절약에 도움이 돼요.'),
('col_environment_05','run','a campaign','run a campaign','캠페인을 진행하다','do','"do a campaign"은 어색해요. 캠페인을 운영할 때는 run을 써요.','B2','environment',2,5,'campaign environment NGO awareness green','The NGO ran a successful campaign to ban plastic bags.','그 NGO는 비닐봉지 금지를 위한 성공적인 캠페인을 진행했어요.','They''re running a recycling awareness campaign this month.','이번 달 재활용 인식 캠페인을 진행하고 있어요.','The students ran a campaign to install more recycling bins on campus.','학생들은 캠퍼스에 재활용 분리수거함을 더 설치하기 위한 캠페인을 진행했어요.','They run a campaign every Earth Day to plant trees.','그들은 매 지구의 날마다 나무 심기 캠페인을 진행해요.','The non-profit ran a campaign to clean up the local river.','비영리 단체는 지역 강을 청소하는 캠페인을 진행했어요.'),
('col_environment_06','hold','a protest','hold a protest','시위를 열다','make','"make a protest"는 어색해요. 시위를 개최할 때는 hold를 써요.','B2','environment',2,6,'protest climate rally march environment','Activists held a protest outside the parliament building.','활동가들은 의회 건물 밖에서 시위를 열었어요.','Thousands of young people held protests demanding climate action.','수천 명의 젊은이들이 기후 행동을 요구하며 시위를 열었어요.','Students held a peaceful protest demanding clean energy on campus.','학생들은 캠퍼스에서 청정 에너지를 요구하며 평화로운 시위를 열었어요.','Indigenous communities held protests to stop the new pipeline.','원주민 공동체들은 새 송유관을 막기 위해 시위를 열었어요.','They hold a protest every Friday in front of city hall.','그들은 매주 금요일 시청 앞에서 시위를 열어요.'),
('col_environment_07','make','an impact','make an impact','영향을 미치다','do','"do an impact"는 틀린 표현이에요. 영향을 줄 때는 make an impact를 써요.','B2','environment',2,7,'impact sustainable environment change effect','Individual choices can make a real impact on the environment.','개인의 선택이 환경에 실질적인 영향을 미칠 수 있어요.','She wanted to make an impact through sustainable fashion.','그녀는 지속 가능한 패션을 통해 영향을 미치고 싶었어요.','Even one person can make a real impact on their local community.','한 사람도 지역사회에 실질적인 영향을 미칠 수 있어요.','She made a lasting impact through her environmental advocacy.','그녀는 환경 옹호 활동을 통해 지속적인 영향을 미쳤어요.','The new policy is expected to make a major impact on air quality.','새 정책은 대기 질에 큰 영향을 미칠 것으로 예상돼요.'),
('col_environment_09','set','targets','set targets','목표를 설정하다','make','"make targets"는 어색해요. 환경 목표를 설정할 때는 set을 써요.','B2','environment',2,9,'targets climate emission goal policy','The UN set ambitious targets to limit global warming to 1.5°C.','유엔은 지구 온난화를 1.5°C로 제한하는 야심 찬 목표를 설정했어요.','The company set targets to achieve net-zero emissions by 2040.','회사는 2040년까지 탄소 중립 배출을 달성하는 목표를 설정했어요.','Schools set targets for reducing their water consumption.','학교들은 물 소비량 감소 목표를 설정했어요.','Each city sets its own targets for carbon neutrality.','각 도시는 자체적으로 탄소 중립 목표를 설정해요.','Setting clear targets helps measure progress over time.','명확한 목표를 설정하면 시간에 따른 진전을 측정하는 데 도움이 돼요.'),
('col_environment_10','conserve','energy','conserve energy','에너지를 절약하다','save','"save energy"도 맞지만 conserve는 환경 맥락에서 더 격식 있는 표현이에요.','B2','environment',2,10,'energy conservation solar panel electricity','Turn off appliances when not in use to conserve energy.','에너지를 절약하기 위해 사용하지 않을 때는 가전제품을 끄세요.','Solar panels help conserve energy and reduce electricity bills.','태양열 패널은 에너지 절약과 전기 요금 절감에 도움이 돼요.','Insulating your home is a simple way to conserve energy.','집 단열은 에너지를 절약하는 간단한 방법이에요.','We installed LED bulbs throughout the office to conserve energy.','우리는 에너지를 절약하기 위해 사무실 전체에 LED 전구를 설치했어요.','Smart thermostats help families conserve energy automatically.','스마트 온도조절기는 가정이 자동으로 에너지를 절약하는 데 도움이 돼요.'),
('col_environment_12','tackle','pollution','tackle pollution','오염을 해결하다','solve','"solve pollution"도 맞지만 tackle은 적극적으로 맞서는 뉘앙스예요.','B2','environment',2,12,'pollution tackling air water environment policy','Cities are trying innovative ways to tackle air pollution.','도시들은 대기 오염을 해결하기 위한 혁신적인 방법을 시도하고 있어요.','The government introduced new laws to tackle ocean pollution.','정부는 해양 오염을 해결하기 위한 새로운 법률을 도입했어요.','New technologies are helping tackle pollution in major rivers.','신기술이 주요 강의 오염을 해결하는 데 도움을 주고 있어요.','Tackling pollution requires cooperation between governments and citizens.','오염을 해결하려면 정부와 시민들의 협력이 필요해요.','She founded a startup to tackle plastic pollution in oceans.','그녀는 해양 플라스틱 오염을 해결하기 위해 스타트업을 설립했어요.'),
('col_environment_13','switch','to renewables','switch to renewables','재생에너지로 전환하다','change','"change to renewables"도 맞지만 switch to는 전환을 강조해요.','B2','environment',2,13,'renewable energy switch solar wind power','The company plans to switch to renewable energy by 2025.','회사는 2025년까지 재생에너지로 전환할 계획이에요.','Many households are switching to solar power to cut costs.','많은 가정이 비용을 절감하기 위해 태양광으로 전환하고 있어요.','Countries are switching to renewables faster than expected.','국가들이 예상보다 빠르게 재생에너지로 전환하고 있어요.','Some islands have completely switched to renewables.','일부 섬들은 완전히 재생에너지로 전환했어요.','Switching to renewables is good for both the planet and long-term economics.','재생에너지로 전환하는 것은 지구와 장기 경제에 모두 좋아요.'),
('col_environment_14','raise','awareness','raise awareness','인식을 높이다','increase','"increase awareness"도 맞지만 raise awareness가 더 자주 쓰여요.','B2','environment',1,14,'awareness environment campaign education climate','The documentary raised awareness about plastic pollution.','그 다큐멘터리는 플라스틱 오염에 대한 인식을 높였어요.','She uses social media to raise awareness about climate change.','그녀는 기후 변화에 대한 인식을 높이기 위해 소셜 미디어를 이용해요.','She raises awareness through her popular environmental podcast.','그녀는 인기 있는 환경 팟캐스트를 통해 인식을 높여요.','The poster campaign raised awareness about endangered species.','포스터 캠페인은 멸종 위기 종에 대한 인식을 높였어요.','Schools can raise awareness through hands-on environmental projects.','학교는 실습 환경 프로젝트를 통해 인식을 높일 수 있어요.'),
('col_environment_16','cut','down on waste','cut down on waste','폐기물을 줄이다','reduce','"reduce waste"도 맞지만 cut down on은 더 생활밀착형 표현이에요.','B2','environment',2,16,'waste reduction recycling packaging green','We can all cut down on food waste by planning meals ahead.','식사를 미리 계획함으로써 음식 낭비를 줄일 수 있어요.','The company cut down on packaging waste by switching to reusable materials.','회사는 재사용 가능한 재료로 전환하여 포장 폐기물을 줄였어요.','Cooking at home helps you cut down on packaging waste.','집에서 요리하면 포장 폐기물을 줄일 수 있어요.','The cafe cut down on waste by introducing a reusable cup program.','그 카페는 재사용 컵 프로그램을 도입해서 폐기물을 줄였어요.','You can cut down on waste by buying only what you''ll actually use.','실제로 사용할 것만 구매하면 폐기물을 줄일 수 있어요.'),
('col_environment_11','protect','biodiversity','protect biodiversity','생물 다양성을 보호하다','save','"save biodiversity"도 맞지만 protect는 체계적인 보호를 강조해요.','C1','environment',3,11,'biodiversity nature wildlife protection conservation','We must protect biodiversity before it''s too late.','너무 늦기 전에 생물 다양성을 보호해야 해요.','The new nature reserve was created to protect biodiversity.','새 자연 보호구역은 생물 다양성을 보호하기 위해 만들어졌어요.','Protecting biodiversity helps maintain healthy ecosystems.','생물 다양성을 보호하는 것은 건강한 생태계 유지에 도움이 돼요.','National parks play a vital role in protecting biodiversity.','국립공원은 생물 다양성 보호에 중요한 역할을 해요.','Local efforts can also help protect biodiversity in cities.','지역의 노력도 도시의 생물 다양성을 보호하는 데 도움이 돼요.'),
('col_environment_15','adopt','sustainable practices','adopt sustainable practices','지속 가능한 관행을 채택하다','use','"use sustainable practices"도 맞지만 adopt는 공식적인 도입을 강조해요.','C1','environment',3,15,'sustainable practices green business environment','More companies are adopting sustainable practices to reduce their footprint.','더 많은 기업들이 발자국을 줄이기 위해 지속 가능한 관행을 채택하고 있어요.','The school adopted sustainable practices like composting and recycling.','학교는 퇴비화 및 재활용과 같은 지속 가능한 관행을 채택했어요.','Restaurants are adopting sustainable practices like composting food scraps.','식당들은 음식물 찌꺼기 퇴비화 같은 지속 가능한 관행을 채택하고 있어요.','The company adopted sustainable practices to attract eco-conscious customers.','회사는 환경 의식이 있는 고객을 끌어들이기 위해 지속 가능한 관행을 채택했어요.','Adopting sustainable practices takes effort but pays off in the long run.','지속 가능한 관행을 채택하는 데는 노력이 필요하지만 장기적으로 보람이 있어요.'),
('col_environment_18','support','conservation efforts','support conservation efforts','보존 노력을 지지하다','help','"help conservation efforts"도 맞지만 support는 더 체계적인 지원을 강조해요.','C1','environment',3,18,'conservation wildlife national park donation','You can support conservation efforts by donating to wildlife charities.','야생동물 자선단체에 기부함으로써 보존 노력을 지지할 수 있어요.','The government committed to supporting conservation efforts in national parks.','정부는 국립공원에서의 보존 노력을 지지하겠다고 약속했어요.','You can support conservation efforts by adopting an endangered animal.','멸종 위기 동물을 입양함으로써 보존 노력을 지지할 수 있어요.','Local volunteers support conservation efforts in nearby wetlands.','지역 자원봉사자들이 인근 습지의 보존 노력을 지지해요.','The new tax incentive supports conservation efforts on private land.','새 세금 인센티브는 사유지에서의 보존 노력을 지지해요.'),
('col_environment_19','face','extinction','face extinction','멸종 위기에 처하다','become','"become extinct"도 맞지만 face extinction은 위기를 마주하는 과정을 강조해요.','C1','environment',3,19,'extinction endangered species wildlife habitat','Many species are facing extinction due to habitat destruction.','많은 종들이 서식지 파괴로 인해 멸종 위기에 처해 있어요.','Without protection, the snow leopard could face extinction within decades.','보호 없이는 눈표범이 수십 년 내에 멸종 위기에 처할 수 있어요.','Coral reefs face extinction unless ocean temperatures stabilize.','해양 온도가 안정화되지 않는 한 산호초는 멸종 위기에 처해요.','Many languages and cultures also face extinction worldwide.','많은 언어와 문화도 전 세계에서 멸종 위기에 처해 있어요.','Sea turtles face extinction in part because of plastic pollution.','바다거북은 부분적으로 플라스틱 오염 때문에 멸종 위기에 처해 있어요.'),
('col_environment_20','offset','carbon','offset carbon','탄소를 상쇄하다','reduce','offset은 다른 곳에서 줄여서 배출을 보상하는 뉘앙스이고, reduce는 직접 줄이는 것이에요.','C1','environment',3,20,'carbon offset footprint climate tree planting','You can offset your carbon from flying by planting trees.','나무 심기로 비행으로 인한 탄소를 상쇄할 수 있어요.','The company offsets its carbon emissions through renewable energy projects.','회사는 재생에너지 프로젝트를 통해 탄소 배출을 상쇄해요.','Many airlines now offer ways for travelers to offset carbon.','많은 항공사들이 이제 여행자들이 탄소를 상쇄할 수 있는 방법을 제공해요.','The festival offset carbon by funding local reforestation projects.','그 축제는 지역 산림 재조림 프로젝트에 자금을 지원해서 탄소를 상쇄했어요.','Companies can offset carbon by investing in renewable energy.','기업들은 재생에너지에 투자해서 탄소를 상쇄할 수 있어요.'),
('col_environment_C1_01','reduce','emissions','reduce emissions','배출을 줄이다','lower','''lower''도 가능하지만, 환경 정책에서는 ''reduce emissions''가 표준 표현이에요. 모든 기후 보고서에 등장해요.','C1','environment',2,0,'factory emissions','The new policy aims to reduce emissions by 40 percent by 2030.','새 정책은 2030년까지 배출량을 40퍼센트 줄이는 것을 목표로 해요.','Electric buses help cities reduce emissions in dense urban areas.','전기 버스는 도시가 인구 밀집 지역의 배출을 줄이는 데 도움이 돼요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_environment_C1_02','protect','wildlife','protect wildlife','야생동물을 보호하다','save','''save''는 위급한 구조의 뉘앙스, ''protect''는 지속적인 보호 활동이라는 뜻이에요. 보전 정책에서는 ''protect''가 표준이에요.','C1','environment',2,0,'wildlife reserve','National parks were established to protect wildlife and natural habitats.','국립공원은 야생동물과 자연 서식지를 보호하기 위해 설립됐어요.','Stronger laws are needed to protect wildlife from illegal trade.','야생동물을 불법 거래로부터 보호하려면 더 강력한 법이 필요해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_environment_C1_03','tackle','pollution','tackle pollution','오염에 대처하다','stop','오염 문제를 체계적으로 다룬다는 정책 표현이에요. ''stop''은 너무 단순해서 신문이나 보고서에 안 어울려요.','C1','environment',2,0,'polluted river','The city launched a bold plan to tackle air pollution.','시는 대기 오염에 대처하기 위해 과감한 계획을 시작했어요.','Tackling plastic pollution requires global cooperation.','플라스틱 오염에 대처하려면 글로벌 협력이 필요해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_environment_C1_04','adopt','sustainable practices','adopt sustainable practices','지속 가능한 관행을 도입하다','use','회사나 개인이 친환경 방식을 받아들인다는 격식 표현이에요. ESG 보고서에 자주 나와요.','C1','environment',2,0,'sustainable farm','More farms are adopting sustainable practices to preserve soil health.','더 많은 농장이 토양 건강을 지키기 위해 지속 가능한 관행을 도입하고 있어요.','Companies that adopt sustainable practices often see long-term cost savings.','지속 가능한 관행을 도입하는 회사는 장기적으로 비용 절감 효과를 보는 경우가 많아요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_environment_C1_05','raise','awareness','raise awareness','인식을 높이다','tell','캠페인을 통해 사회적 관심을 끌어올린다는 표준 표현이에요. 비영리, 정책, 마케팅 모두에서 써요.','C1','environment',2,0,'environmental campaign','The documentary helped raise awareness of declining bee populations.','그 다큐멘터리는 감소하는 벌 개체수에 대한 인식을 높이는 데 기여했어요.','School programs raise awareness about recycling among young children.','학교 프로그램은 어린이들 사이에서 재활용에 대한 인식을 높여요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_environment_C2_01','mitigate','emissions','mitigate emissions','배출을 완화하다','reduce','배출량의 영향을 완화한다는 표준 환경 용어예요. IPCC 보고서나 ESG 문서에서 표준 표현이에요.','C2','environment',3,0,'factory emissions','Carbon capture technologies aim to mitigate industrial emissions at the source.','탄소 포집 기술은 산업 배출을 발생원에서 완화하는 것을 목표로 해요.','Governments are under pressure to mitigate emissions ahead of the summit.','정부는 정상회담을 앞두고 배출을 완화하라는 압박을 받고 있어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_environment_C2_02','preserve','biodiversity','preserve biodiversity','생물 다양성을 보존하다','keep','생물 다양성을 적극적으로 보존한다는 학술·정책 표현이에요. ''keep''은 캐주얼해서 어울리지 않아요.','C2','environment',3,0,'rainforest wildlife','Protected marine reserves help preserve biodiversity in fragile ecosystems.','해양 보호구역은 취약한 생태계의 생물 다양성을 보존하는 데 도움이 돼요.','Indigenous land stewardship has preserved biodiversity for millennia.','원주민들의 토지 관리가 수천 년간 생물 다양성을 보존해 왔어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_environment_C2_03','exacerbate','degradation','exacerbate degradation','훼손을 악화시키다','worsen','환경 훼손을 더 심각하게 만든다는 격식 표현이에요. ''worsen''보다 학술 글에 더 잘 어울려요.','C2','environment',3,0,'deforestation','Unchecked deforestation exacerbates soil degradation across the basin.','통제되지 않은 벌목이 유역 전반의 토양 훼손을 악화시켜요.','Industrial runoff exacerbates the degradation of coastal wetlands.','산업 폐수는 연안 습지의 훼손을 악화시켜요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_environment_C2_04','champion','sustainability','champion sustainability','지속가능성을 옹호하다','support','지속가능성을 앞장서서 옹호하고 추진한다는 뜻이에요. ESG 리더십을 묘사하는 표준 표현이에요.','C2','environment',3,0,'sustainability leader','The CEO has championed sustainability across the firm''s global supply chain.','CEO는 전 세계 공급망 전반에 걸쳐 지속가능성을 옹호해 왔어요.','NGOs have long championed sustainability in fashion manufacturing.','NGO들은 오랫동안 패션 제조에서의 지속가능성을 옹호해 왔어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_environment_C2_05','deplete','resources','deplete resources','자원을 고갈시키다','use','자원을 점차 고갈시킨다는 격식 환경 용어예요. ''use''는 너무 중립적이라 위기감을 전달하지 못해요.','C2','environment',3,0,'dry riverbed','Intensive agriculture rapidly depletes soil nutrients and groundwater resources.','집약적 농업은 토양 영양분과 지하수 자원을 빠르게 고갈시켜요.','Overfishing has depleted resources in once-thriving coastal communities.','남획은 한때 번성했던 연안 공동체의 자원을 고갈시켰어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_family_B1_01','raise','children','raise children','아이를 키우다','grow','''grow''는 식물이나 머리카락에 쓰고, 사람을 양육할 때는 ''raise''를 써요.','B1','family',1,0,'parents children together','They raised three children together.','그들은 함께 세 아이를 키웠어요.','It''s not easy to raise children these days.','요즘 아이를 키우는 건 쉽지 않아요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_family_B1_02','start','a family','start a family','가정을 꾸리다','open','''open a family''는 틀리고, 결혼해서 아이를 가지는 의미는 ''start a family''예요.','B1','family',1,0,'young couple baby','We''re planning to start a family next year.','우리는 내년에 가정을 꾸릴 계획이에요.','They got married and started a family.','그들은 결혼해서 가정을 꾸렸어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_family_B1_03','spend','time','spend time with family','가족과 시간을 보내다','pass','''pass time''은 시간을 때운다는 뉘앙스이고, 의미 있게 함께할 때는 ''spend time''을 써요.','B1','family',1,0,'family dinner together','I love to spend time with my family on weekends.','저는 주말에 가족과 시간 보내는 걸 좋아해요.','He doesn''t spend enough time with his kids.','그는 아이들과 충분한 시간을 보내지 않아요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_family_B1_04','have','an argument','have an argument','말다툼하다','do','''do an argument''는 틀리고, 다툼·논쟁은 ''have an argument''로 표현해요.','B1','family',1,0,'siblings arguing','My parents had an argument about money.','부모님이 돈 문제로 말다툼했어요.','We had a big argument last night.','우리는 어젯밤 크게 말다툼했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_family_B1_05','make','up','make up with someone','누군가와 화해하다','fix','''fix up''은 수리하다이고, 다툰 뒤 화해할 때는 ''make up''을 써요.','B1','family',1,0,'siblings hugging reconcile','My sister and I always make up after a fight.','언니와 저는 다투고 나면 항상 화해해요.','They made up after a long argument.','그들은 오랜 다툼 끝에 화해했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_family_B2_01','honor','your parents','honor your parents','부모를 공경하다','respect-only','''respect''도 가능하지만, 깊은 존경과 효도의 뉘앙스는 ''honor''가 더 강해요.','B2','family',2,0,'asian family respect bow','In our culture, we honor our parents.','우리 문화에서는 부모님을 공경해요.','She always tries to honor her parents'' wishes.','그녀는 늘 부모님의 뜻을 공경하려 해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_family_B2_02','set','a good example','set a good example','좋은 본보기가 되다','make','''make an example''은 본보기로 벌준다는 뉘앙스이고, 모범을 보이는 건 ''set an example''이에요.','B2','family',2,0,'older sibling role model','Older siblings should set a good example.','손위 형제는 좋은 본보기가 되어야 해요.','Parents set a good example by reading every day.','부모님은 매일 독서로 좋은 본보기가 되세요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_family_B2_03','establish','boundaries','establish boundaries','경계를 정하다','build','''build boundaries''보다 ''establish''가 더 자연스럽고, 인간관계의 선을 긋는 뉘앙스예요.','B2','family',2,0,'family conversation serious','It''s important to establish boundaries with relatives.','친척과 경계를 정하는 건 중요해요.','We established clear boundaries with our in-laws.','우리는 시댁과 분명한 경계를 정했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_family_B2_04','resolve','conflicts','resolve conflicts','갈등을 해결하다','solve','''solve''도 가능하지만, 사람 사이의 갈등에는 ''resolve''가 더 격식 있고 자연스러워요.','B2','family',2,0,'family talking peace','Every family needs to learn how to resolve conflicts.','모든 가족은 갈등 해결 방법을 배워야 해요.','They resolved their conflicts through honest talks.','그들은 솔직한 대화로 갈등을 해결했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_family_B2_05','maintain','ties','maintain family ties','가족과의 유대를 유지하다','keep-only','''keep ties''도 쓰지만, ''maintain''이 더 격식 있고 꾸준한 노력의 뉘앙스를 담아요.','B2','family',2,0,'video call family','It''s hard to maintain family ties when you live abroad.','해외에 살면 가족 유대를 유지하기 어려워요.','We maintain ties through weekly video calls.','우리는 매주 영상통화로 유대를 유지해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_family_C1_01','uphold','values','uphold family values','가족의 가치를 지키다','hold','''hold values''보다 ''uphold''는 ''굳건히 지키다''는 결의의 뉘앙스가 강해요.','C1','family',2,0,'multigenerational family traditions','They uphold traditional family values.','그들은 전통적인 가족 가치를 지켜요.','She upholds the values her grandmother taught her.','그녀는 할머니께서 가르치신 가치를 지켜요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_family_C1_02','nurture','relationships','nurture relationships','관계를 보살피며 키우다','grow','''grow relationships''도 쓰이지만, ''nurture''는 ''정성껏 가꾸다''라는 따뜻한 결을 가져요.','C1','family',2,0,'mother child garden','You have to nurture relationships with your siblings.','형제자매와의 관계를 정성껏 가꿔야 해요.','They nurtured their relationship over decades.','그들은 수십 년에 걸쳐 관계를 가꿔 왔어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_family_C1_03','mediate','disputes','mediate disputes','분쟁을 중재하다','middle','''middle''은 동사로 잘 안 쓰고, 분쟁을 중재할 때는 ''mediate''가 정확한 단어예요.','C1','family',2,0,'family mediation discussion','The eldest son often mediates disputes at home.','장남이 집안의 분쟁을 자주 중재해요.','She mediated the dispute between her brothers.','그녀는 오빠들 사이의 분쟁을 중재했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_family_C1_04','preserve','traditions','preserve family traditions','가족 전통을 보존하다','save','''save traditions''보다 ''preserve''가 ''소중히 보존하다''의 격식 있는 표현이에요.','C1','family',2,0,'traditional ceremony family','They work hard to preserve their family traditions.','그들은 가족 전통을 보존하려 노력해요.','My grandmother preserves recipes from her ancestors.','할머니는 조상으로부터 내려온 요리법을 보존하세요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_family_C1_05','foster','independence','foster independence','자립심을 길러주다','make','''make independence''는 부자연스럽고, 자질을 길러줄 때는 ''foster''를 써요.','C1','family',2,0,'child confident solo','Good parents foster independence in their children.','좋은 부모는 자녀의 자립심을 길러줘요.','She fostered independence by letting them choose.','그녀는 선택권을 주며 자립심을 길러줬어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_family_C2_01','perpetuate','a legacy','perpetuate a family legacy','가문의 유산을 영속시키다','continue','''continue''보다 ''perpetuate''는 세대를 이어 ''영구히 잇다''는 무게 있는 표현이에요.','C2','family',3,0,'old family portrait estate','He vowed to perpetuate his family''s legacy.','그는 가문의 유산을 영속시키겠다고 다짐했어요.','They perpetuate a legacy of public service.','그들은 공직 봉사의 유산을 이어가요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_family_C2_02','navigate','complexities','navigate family complexities','복잡한 가족 관계를 헤쳐 나가다','pass','''pass''는 단순히 지나가는 뉘앙스이고, ''navigate''는 신중히 풀어나간다는 의미예요.','C2','family',3,0,'complex family tree branches','Adults must navigate the complexities of blended families.','어른은 복합 가족의 복잡함을 헤쳐 나가야 해요.','She navigates family complexities with grace.','그녀는 가족의 복잡함을 우아하게 헤쳐 나가요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_family_C2_03','reconcile','differences','reconcile differences','차이를 화해시키다','fix','''fix''는 가볍고, 깊은 갈등이나 신념 차이를 ''reconcile''로 풀어요.','C2','family',3,0,'two hands reconciliation','They finally reconciled their differences after years.','그들은 수년 만에 마침내 차이를 화해시켰어요.','It takes wisdom to reconcile generational differences.','세대 차이를 화해시키려면 지혜가 필요해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_family_C2_04','instill','principles','instill principles','원칙을 심어주다','teach-only','''teach''도 가능하지만, ''instill''은 가치관을 ''서서히 깊이 새기다''는 뉘앙스예요.','C2','family',3,0,'mother teaching child seriously','Parents instill principles in their children early on.','부모는 아이에게 일찍부터 원칙을 심어줘요.','She instilled the principle of honesty in her sons.','그녀는 아들들에게 정직의 원칙을 심어줬어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_family_C2_05','transcend','generations','transcend generations','세대를 초월하다','cross','''cross''는 단순히 건너가다이고, ''transcend''는 ''뛰어넘어 이어진다''는 깊은 의미예요.','C2','family',3,0,'old photo generations','Their love transcended generations.','그들의 사랑은 세대를 초월했어요.','Some family stories transcend generations.','어떤 가족 이야기는 세대를 초월해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_greeting_10','take','a seat','take a seat','자리에 앉다','sit','"sit a seat"는 틀린 표현이에요. 자리를 권할 때는 take a seat를 써요.','A2','greeting',1,10,'reception waiting room sitting polite','Please take a seat and I''ll be with you shortly.','자리에 앉으세요, 곧 뵐게요.','The receptionist asked me to take a seat while I waited.','안내 직원이 기다리는 동안 자리에 앉으라고 했어요.','Take a seat anywhere — class will begin in a few minutes.','아무 자리에나 앉으세요 — 수업이 곧 시작돼요.','She took a seat in the front row to see the stage better.','그녀는 무대를 더 잘 보기 위해 앞줄에 자리를 잡았어요.','He politely offered to let the elderly woman take a seat.','그는 정중하게 어르신께 자리에 앉으시라고 양보했어요.'),
('col_greeting_13','keep','in touch','keep in touch','연락을 유지하다','stay','"stay in touch"도 맞지만 keep in touch가 더 자주 쓰여요.','A2','greeting',1,13,'phone message contact friends staying connected','Let''s keep in touch after the conference ends.','컨퍼런스가 끝난 후에도 연락을 유지해요.','She made an effort to keep in touch with her old classmates.','그녀는 옛 동창들과 연락을 유지하기 위해 노력했어요.','We try to keep in touch even though we live in different cities.','다른 도시에 살지만 우리는 연락을 유지하려고 노력해요.','Social media makes it easier to keep in touch with distant friends.','소셜 미디어 덕분에 멀리 사는 친구들과 연락을 유지하기 쉬워졌어요.','I promised to keep in touch with my host family after the trip.','여행 후에도 호스트 가족과 연락을 유지하겠다고 약속했어요.'),
('col_greeting_21','make','friends','make friends','친구를 사귀다','do','"do friends"는 틀린 표현이에요. 친구를 사귄다는 의미는 make friends.','A2','greeting',1,0,'friends group laughing together smiling','It''s easy to make friends at university.','대학교에서는 친구 사귀기 쉬워요.','She made many friends during her exchange program.','그녀는 교환학생 기간 동안 친구를 많이 사귀었어요.','It can be hard to make friends in a new city.','새 도시에서 친구를 사귀는 게 어려울 수 있어요.','Sports are a great way to make friends.','운동은 친구를 사귀는 좋은 방법이에요.','He made friends with everyone at the office.','그는 사무실의 모든 사람들과 친구가 됐어요.'),
('col_greeting_01','make','an introduction','make an introduction','소개를 하다','do','"do an introduction"은 어색해요. 소개할 때는 make를 써요.','B1','greeting',2,1,'handshake introduction meeting people','Let me make an introduction — this is my colleague, Ji-yeon.','소개할게요 — 제 동료 지연이에요.','He made a brief introduction before the meeting started.','그는 회의가 시작되기 전에 간단히 소개를 했어요.','Could you make an introduction at the dinner tonight?','오늘 저녁 식사에서 소개를 해주실 수 있어요?','She makes thoughtful introductions whenever new people join the group.','그녀는 새로운 사람들이 그룹에 합류할 때마다 사려 깊게 소개를 해요.','It''s polite to make an introduction when guests don''t know each other.','손님들이 서로 모를 때는 소개를 하는 것이 예의예요.'),
('col_greeting_02','give','a compliment','give a compliment','칭찬을 하다','make','"make a compliment"도 쓰이지만 give가 더 자연스러워요.','B1','greeting',2,2,'compliment smile praise conversation','She gave him a sincere compliment on his presentation.','그녀는 그의 발표에 진심 어린 칭찬을 했어요.','It''s always nice to give a compliment when someone does well.','누군가 잘했을 때 칭찬을 하는 건 언제나 좋아요.','My manager gave me a compliment about the report I wrote.','제 매니저는 제가 작성한 보고서에 대해 칭찬을 했어요.','Try to give a compliment to your partner every day.','매일 파트너에게 칭찬을 해보세요.','He gave the chef a compliment on the delicious meal.','그는 셰프에게 맛있는 음식에 대한 칭찬을 했어요.'),
('col_greeting_03','pay','attention','pay attention','주의를 기울이다','give','"give attention"보다 pay attention이 훨씬 자주 쓰여요.','B1','greeting',1,3,'listening attention focus conversation','Please pay attention when someone is speaking to you.','누군가 말할 때 주의를 기울여 주세요.','He didn''t pay attention and missed the important details.','그는 주의를 기울이지 않아서 중요한 세부 사항을 놓쳤어요.','You should pay attention to road signs while driving.','운전할 때는 도로 표지판에 주의를 기울여야 해요.','Children find it hard to pay attention for long periods.','아이들은 오랜 시간 주의를 기울이는 걸 어려워해요.','Pay attention to your posture when sitting at a desk all day.','하루 종일 책상에 앉아 있을 때는 자세에 주의를 기울이세요.'),
('col_greeting_04','take','turns','take turns','교대로 하다','do','"do turns"는 틀린 표현이에요. 순서를 바꿀 때는 take turns를 써요.','B1','greeting',2,4,'turn-taking group conversation teamwork','We should take turns speaking so everyone gets a chance.','모두가 기회를 얻을 수 있도록 교대로 말해야 해요.','The children took turns reading aloud in class.','아이들은 수업에서 교대로 소리 내어 읽었어요.','My husband and I take turns doing the dishes after dinner.','저와 남편은 저녁 식사 후에 교대로 설거지를 해요.','Let''s take turns choosing the music for our road trip.','우리 자동차 여행에서 음악은 교대로 골라요.','The players took turns rolling the dice during the game.','선수들은 게임 중에 교대로 주사위를 굴렸어요.'),
('col_greeting_06','make','small talk','make small talk','가벼운 대화를 나누다','do','"do small talk"은 어색해요. 가벼운 잡담은 make small talk이에요.','B1','greeting',1,6,'casual conversation social small talk','He''s good at making small talk at networking events.','그는 네트워킹 행사에서 가벼운 대화를 잘 나눠요.','Making small talk with strangers can feel awkward at first.','낯선 사람과 가벼운 대화를 나누는 건 처음엔 어색할 수 있어요.','We made small talk in the elevator on the way up.','우리는 올라가는 엘리베이터에서 가벼운 대화를 나눴어요.','She doesn''t enjoy making small talk and prefers deeper conversations.','그녀는 가벼운 대화보다 깊은 대화를 더 좋아해요.','Making small talk about the weather is common in many cultures.','날씨에 관한 가벼운 대화는 여러 문화에서 흔해요.'),
('col_greeting_07','hold','a conversation','hold a conversation','대화를 이어가다','do','"do a conversation"은 틀린 표현이에요. 대화를 유지할 때는 hold를 써요.','B1','greeting',2,7,'conversation talking people dialogue','She can hold a conversation in English quite naturally now.','그녀는 이제 영어로 꽤 자연스럽게 대화를 이어갈 수 있어요.','It''s hard to hold a conversation in a noisy place.','시끄러운 곳에서는 대화를 이어가기가 어려워요.','He struggles to hold a conversation when he''s feeling shy.','그는 부끄러울 때 대화를 이어가는 걸 힘들어해요.','They held a conversation in Spanish throughout the whole dinner.','그들은 저녁 내내 스페인어로 대화를 이어갔어요.','Toddlers start learning to hold a conversation around age two.','유아들은 두 살 무렵부터 대화를 이어가는 법을 배우기 시작해요.'),
('col_greeting_08','give','a warm welcome','give a warm welcome','따뜻하게 환영하다','make','"make a warm welcome"보다 give a warm welcome이 훨씬 자연스러워요.','B1','greeting',2,8,'welcome reception hospitality greeting','The host gave all the guests a warm welcome at the door.','주최자는 문에서 모든 손님을 따뜻하게 환영했어요.','We gave the new team member a warm welcome on her first day.','우리는 첫날에 새 팀원을 따뜻하게 환영했어요.','The audience gave the speaker a warm welcome with loud applause.','청중은 큰 박수로 연사를 따뜻하게 환영했어요.','Let''s give our exchange student a warm welcome to the school.','교환학생을 학교에 따뜻하게 환영해 줍시다.','The community gave the new family a warm welcome with home-cooked meals.','그 동네에서는 집밥을 들고 와서 새 가족을 따뜻하게 환영해 줬어요.'),
('col_greeting_09','make','eye contact','make eye contact','눈을 마주치다','do','"do eye contact"는 틀린 표현이에요. 시선을 마주칠 때는 make를 써요.','B1','greeting',1,9,'eye contact confidence communication','It''s important to make eye contact when you greet someone.','누군가를 인사할 때 눈을 마주치는 것이 중요해요.','She found it difficult to make eye contact in group settings.','그녀는 단체 상황에서 눈을 마주치는 게 어렵다고 느꼈어요.','Try to make eye contact during the job interview to show confidence.','면접에서는 자신감을 보이기 위해 눈을 마주치도록 해보세요.','He avoided making eye contact when he told the lie.','그는 거짓말을 할 때 눈을 마주치는 것을 피했어요.','Making eye contact with the audience helps you connect during a speech.','청중과 눈을 마주치는 것은 발표 중 소통에 도움이 돼요.'),
('col_greeting_11','exchange','greetings','exchange greetings','인사를 나누다','do','"do greetings"는 어색해요. 인사를 주고받을 때는 exchange를 써요.','B1','greeting',2,11,'business greeting formal handshake','They exchanged greetings before getting down to business.','그들은 본론으로 들어가기 전에 인사를 나눴어요.','We exchanged greetings with the visitors from the overseas office.','우리는 해외 사무소에서 온 방문객들과 인사를 나눴어요.','The two leaders exchanged greetings at the start of the summit.','두 정상은 회담 시작에 인사를 나눴어요.','It''s polite to exchange greetings with your neighbors when you see them.','이웃을 마주칠 때 인사를 나누는 건 예의예요.','They exchanged warm greetings after not seeing each other for years.','그들은 오랜 시간 못 만난 끝에 따뜻한 인사를 나눴어요.'),
('col_greeting_15','make','a good impression','make a good impression','좋은 인상을 주다','give','"give a good impression"도 쓰이지만 make가 훨씬 더 자주 쓰여요.','B1','greeting',1,15,'first impression interview professional smile','She dressed carefully to make a good impression at the interview.','그녀는 면접에서 좋은 인상을 주기 위해 신경 써서 옷을 입었어요.','First meetings are a great opportunity to make a good impression.','첫 만남은 좋은 인상을 줄 수 있는 좋은 기회예요.','He worked hard to make a good impression on his future in-laws.','그는 미래의 시댁/처가에 좋은 인상을 주려고 열심히 노력했어요.','Arriving on time is essential to make a good impression at work.','직장에서 좋은 인상을 주려면 정시에 도착하는 것이 필수예요.','Her warm smile helped her make a good impression on the team.','그녀의 따뜻한 미소가 팀에 좋은 인상을 주는 데 도움이 됐어요.'),
('col_greeting_16','offer','a handshake','offer a handshake','악수를 청하다','do','"do a handshake"는 어색해요. 악수를 청할 때는 offer를 써요.','B1','greeting',2,16,'handshake business meeting introduction','He offered a handshake as soon as she walked in.','그녀가 들어오자마자 그는 악수를 청했어요.','It''s customary to offer a handshake when meeting someone for the first time.','처음 만나는 사람에게 악수를 청하는 것은 관례예요.','The CEO offered a handshake to congratulate the new employee.','CEO는 신입 직원을 축하하기 위해 악수를 청했어요.','She offered a handshake instead of a hug to keep things professional.','그녀는 격식을 지키기 위해 포옹 대신 악수를 청했어요.','The coach offered a handshake to the opposing team after the match.','코치는 경기 후 상대팀에게 악수를 청했어요.'),
('col_greeting_18','send','regards','send regards','안부를 전하다','give','"give regards"도 가능하지만 send regards가 더 자주 쓰여요.','B1','greeting',2,18,'regards message family polite','Please send my regards to your family.','가족분들께 안부 전해 주세요.','He asked me to send his regards to everyone on the team.','그는 팀 모두에게 안부를 전해달라고 했어요.','She sends her regards from Seoul through the postcard.','그녀는 서울에서 엽서로 안부를 전해요.','Don''t forget to send my regards to your grandmother.','할머니께 안부 전하는 거 잊지 마세요.','He sent his regards to the bride and groom through a video message.','그는 영상 메시지로 신랑 신부에게 안부를 전했어요.'),
('col_greeting_20','make','a farewell','make a farewell','작별 인사를 하다','do','"do a farewell"은 어색해요. 작별할 때는 make a farewell 또는 say farewell을 써요.','B1','greeting',2,20,'farewell goodbye airport departure','They made a farewell at the airport with tears in their eyes.','그들은 눈물을 글썽이며 공항에서 작별 인사를 했어요.','We gathered to make a farewell for our retiring manager.','우리는 은퇴하는 매니저를 위해 모여 작별 인사를 했어요.','She made a brief farewell speech before leaving the company.','그녀는 퇴사 전에 짧은 작별 인사 연설을 했어요.','He made a quiet farewell to his old home before moving away.','그는 이사 가기 전에 옛 집에 조용히 작별 인사를 했어요.','The students made a heartfelt farewell to their favorite teacher.','학생들은 가장 좋아하는 선생님께 진심 어린 작별 인사를 했어요.'),
('col_greeting_22','keep','touch','keep in touch','계속 연락하다','stay','"stay in touch"도 가능. 둘 다 자연스러워요. keep이 약간 더 형식적.','B1','greeting',1,0,'friends phone message keeping in touch communication','Let''s keep in touch after you move.','이사 가도 계속 연락해요.','We''ve kept in touch for over ten years.','우리는 10년 넘게 연락을 유지해 왔어요.','It''s easier to keep in touch with social media.','SNS 덕분에 연락 유지가 더 쉬워요.','I want to keep in touch with my old classmates.','옛 동창들과 계속 연락하고 싶어요.','Promise me you''ll keep in touch.','계속 연락한다고 약속해 주세요.'),
('col_greeting_23','give','hand','give a hand','도와주다','lend','"lend a hand"도 같은 의미예요. give a hand는 박수치다 의미로도 쓰여서 맥락 주의.','B1','greeting',1,0,'people helping moving box assistance friends','Could you give me a hand with this box?','이 상자 옮기는 거 도와줄 수 있어요?','She always gives a hand when I''m busy.','그녀는 제가 바쁠 때 항상 도와줘요.','He gave us a hand moving into the new apartment.','그는 우리가 새 아파트로 이사하는 것을 도와줬어요.','Let''s give him a hand — he looks overwhelmed.','그를 도와줘요 — 너무 힘들어 보여요.','Thanks for giving me a hand earlier.','아까 도와줘서 고마워요.'),
('col_greeting_05','break','the ice','break the ice','어색한 분위기를 깨다','melt','"melt the ice"는 틀린 표현이에요. 어색한 분위기를 깰 때는 break를 써요.','B2','greeting',1,5,'party social gathering conversation icebreaker','He told a joke to break the ice at the party.','그는 파티에서 어색한 분위기를 깨기 위해 농담을 했어요.','A simple question can break the ice in a new group.','간단한 질문 하나가 새 그룹에서 분위기를 풀어줄 수 있어요.','She brought cookies to help break the ice with her new neighbors.','그녀는 새 이웃들과 어색한 분위기를 깨기 위해 쿠키를 가져왔어요.','The team-building activity was designed to break the ice quickly.','팀 빌딩 활동은 어색한 분위기를 빠르게 깨도록 설계됐어요.','Sharing a funny story is a great way to break the ice.','재미있는 이야기를 나누는 건 어색한 분위기를 깨는 좋은 방법이에요.'),
('col_greeting_12','extend','an invitation','extend an invitation','초대장을 보내다','give','"give an invitation"도 가능하지만 extend가 더 격식 있는 표현이에요.','B2','greeting',3,12,'invitation formal event dinner','We''d like to extend an invitation to you for our annual dinner.','저희 연례 만찬에 초대 말씀을 드리고 싶어요.','The committee extended invitations to all department heads.','위원회는 모든 부서장에게 초대장을 보냈어요.','The president extended an invitation to the ambassador''s residence.','대통령은 대사관 관저에 초대장을 보냈어요.','She extended an invitation to her wedding only to close friends.','그녀는 친한 친구들에게만 결혼식 초대장을 보냈어요.','The company extended invitations to top clients for the launch party.','회사는 출시 파티에 주요 고객들에게 초대장을 보냈어요.'),
('col_greeting_14','strike up','a conversation','strike up a conversation','대화를 시작하다','start','"start a conversation"도 맞지만 strike up이 더 자연스럽고 생동감 있어요.','B2','greeting',2,14,'conversation strangers meeting talking','He struck up a conversation with a stranger at the bus stop.','그는 버스 정류장에서 낯선 사람과 대화를 시작했어요.','It''s easy to strike up a conversation when you share a common interest.','공통 관심사가 있으면 대화를 시작하기 쉬워요.','She struck up a conversation with the woman next to her on the plane.','그녀는 비행기 옆자리 여성과 대화를 시작했어요.','He often strikes up conversations with people in coffee shops.','그는 카페에서 사람들과 자주 대화를 시작해요.','My dad can strike up a conversation with almost anyone he meets.','아빠는 만나는 거의 모든 사람과 대화를 시작할 수 있어요.'),
('col_greeting_17','get','acquainted','get acquainted','알게 되다, 친해지다','become','"become acquainted"도 맞지만 get acquainted가 더 일상적이에요.','B2','greeting',3,17,'meeting new people social event','We got acquainted at a friend''s birthday party.','우리는 친구의 생일 파티에서 알게 됐어요.','It takes time to get acquainted with a new culture.','새로운 문화에 익숙해지는 데는 시간이 걸려요.','The new neighbors invited us over to get acquainted.','새 이웃들이 친해지자고 우리를 초대했어요.','Let''s grab a coffee so we can get acquainted before the project starts.','프로젝트가 시작되기 전에 친해질 수 있게 커피 한잔해요.','He got acquainted with his coworkers during the company retreat.','그는 회사 워크숍에서 동료들과 친해졌어요.'),
('col_greeting_19','accept','an apology','accept an apology','사과를 받아들이다','take','"take an apology"는 틀린 표현이에요. 사과를 받아들일 때는 accept를 써요.','B2','greeting',3,19,'apology forgiveness reconciliation','She graciously accepted his apology and they moved on.','그녀는 그의 사과를 흔쾌히 받아들이고 앞으로 나아갔어요.','It can be hard to accept an apology when you''re still hurt.','여전히 상처받은 상태에서 사과를 받아들이는 건 어려울 수 있어요.','He accepted her apology with a hug and a quiet smile.','그는 포옹과 조용한 미소로 그녀의 사과를 받아들였어요.','The teacher accepted the student''s apology for being late.','선생님은 늦은 학생의 사과를 받아들였어요.','Sometimes it takes time to truly accept an apology and move on.','때로는 진심으로 사과를 받아들이고 앞으로 나아가는 데 시간이 걸려요.'),
('col_greeting_C1_01','exchange','pleasantries','exchange pleasantries','인사말을 주고받다','say','본론에 들어가기 전에 격식 있는 가벼운 인사말을 주고받는다는 뜻이에요. 비즈니스 미팅 도입부 표준 표현이에요.','C1','greeting',2,0,'handshake meeting','The two delegations exchanged pleasantries before the negotiations began.','두 대표단은 협상이 시작되기 전에 인사말을 주고받았어요.','After exchanging pleasantries, we got straight to the agenda.','인사말을 주고받은 뒤 우리는 곧바로 안건으로 들어갔어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_greeting_C1_02','make','small talk','make small talk','잡담을 나누다','do','날씨나 가벼운 주제로 짧게 대화한다는 뜻이에요. 네트워킹 자리에서 가장 자주 쓰는 격식 표현이에요.','C1','greeting',2,0,'networking event','He is excellent at making small talk with clients before formal meetings.','그는 공식 회의 전에 고객들과 잡담을 나누는 데 능숙해요.','Making small talk in a second language can feel surprisingly demanding.','제2외국어로 잡담을 나누는 일은 의외로 부담스러울 수 있어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_greeting_C1_03','extend','welcome','extend a welcome','환영을 표하다','give','공식적이고 따뜻한 환영의 뜻을 전한다는 격식 표현이에요. 행사 개회사에서 표준이에요.','C1','greeting',2,0,'welcome ceremony','On behalf of the board, I would like to extend a warm welcome to our guests.','이사회를 대표해 손님 여러분께 따뜻한 환영을 표하고 싶어요.','The mayor extended a welcome to the visiting delegation.','시장은 방문단에게 환영을 표했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_greeting_C1_04','introduce','yourself','introduce yourself','자기소개를 하다','tell','이름과 소속을 격식 있게 밝힌다는 표현이에요. 면접, 회의, 워크숍에서 표준이에요.','C1','greeting',2,0,'introduction badge','Please introduce yourself briefly so the panel can get to know you.','심사위원단이 알 수 있도록 자기소개를 간단히 해 주세요.','She introduced herself as the new head of research.','그녀는 신임 연구 책임자로 자기소개를 했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_greeting_C1_05','shake','hands','shake hands','악수하다','do','인사로 손을 맞잡는다는 표준 표현이에요. ''do handshake'' 같은 표현은 어색하니 ''shake hands''로 기억하세요.','C1','greeting',2,0,'handshake business','It is customary to shake hands firmly during a business introduction.','비즈니스 자리에서 자기소개를 할 때는 손을 단단히 잡고 악수하는 게 관례예요.','They shook hands warmly after signing the agreement.','그들은 합의서에 서명한 뒤 따뜻하게 악수했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_greeting_C2_01','extend','pleasantries','extend pleasantries','의례적 인사를 건네다','say','격식 있는 자리에서 정중한 인사말을 정성껏 건넨다는 뜻이에요. 외교, 비즈니스 미팅 보도의 표준이에요.','C2','greeting',3,0,'diplomatic handshake','The ambassador extended pleasantries before turning to the substantive agenda.','대사는 본격적인 안건으로 넘어가기 전에 의례적 인사를 건넸어요.','They extended pleasantries over tea in the embassy garden.','그들은 대사관 정원에서 차를 마시며 의례적 인사를 건넸어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_greeting_C2_02','exchange','formalities','exchange formalities','의례를 주고받다','do','서로 정중한 격식의 말을 주고받는 절차적 행위를 가리켜요. 의전적 만남 묘사에서 표준 표현이에요.','C2','greeting',3,0,'formal meeting bow','The two delegations exchanged formalities before the negotiations commenced.','두 대표단은 협상이 시작되기 전 의례를 주고받았어요.','After exchanging formalities, they settled into a more candid discussion.','의례를 주고받은 후, 그들은 더 솔직한 논의로 들어갔어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_greeting_C2_03','convey','regards','convey regards','안부를 전하다','say','직접 만나지 못한 사람에게 정중히 안부를 전달한다는 격식 표현이에요. 편지, 외교 전문, 공식 인사말에 적합해요.','C2','greeting',3,0,'handwritten letter','Please convey my warmest regards to your esteemed family.','존경하는 가족분들께 가장 따뜻한 안부를 전해 주세요.','She asked me to convey her regards to the entire faculty.','그녀는 저에게 교수진 전체에게 안부를 전해달라고 부탁했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_greeting_C2_04','make','acquaintance','make one''s acquaintance','인사를 나누다','meet','처음 만나 인사하게 되어 영광이라는 매우 격식 있는 표현이에요. ''Pleased to make your acquaintance''는 표준 격식 인사예요.','C2','greeting',3,0,'formal introduction','I am delighted to make your acquaintance at last, Professor.','교수님, 마침내 인사를 나누게 되어 기쁩니다.','It was a privilege to make her acquaintance at the embassy reception.','대사관 리셉션에서 그녀와 인사를 나눈 것은 영광이었어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_greeting_C2_05','tender','greetings','tender greetings','인사를 정중히 전하다','send','정중하고 의례적으로 인사를 ''올린다''는 매우 격식 있는 동사예요. 공식 서신과 의전 연설에서 보여요.','C2','greeting',3,0,'formal podium','On behalf of the council, I tender greetings to our distinguished guests.','의회를 대표하여, 귀한 손님들께 인사를 정중히 올립니다.','The chairperson tendered greetings to the assembly before opening the session.','의장은 회의를 개시하기 전 의회에 인사를 정중히 전했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_health_22','take','shower','take a shower','샤워하다','have','미국에서는 take a shower, 영국에서는 have a shower도 쓰여요. 둘 다 정답.','A1','health',1,0,'bathroom shower water cleansing morning','I take a shower every morning before work.','저는 출근 전 매일 아침 샤워를 해요.','She took a long shower after the gym.','그녀는 운동 후 오래 샤워를 했어요.','Do you want to take a shower first?','먼저 샤워할래요?','He takes a quick shower in the evening.','그는 저녁에 빠르게 샤워를 해요.','I''ll take a shower as soon as I get home.','집에 가자마자 샤워할게요.'),
('col_health_23','get','sick','get sick','병에 걸리다, 아프다','become','"become sick"는 문어체. 일상에서는 get sick이 압도적으로 자연스러워요.','A1','health',1,0,'sick person bed thermometer flu tissue','I got sick last week and missed three days of work.','지난주에 아파서 3일 결근했어요.','Wash your hands so you don''t get sick.','아프지 않으려면 손을 씻으세요.','She got really sick after the long flight.','그녀는 장거리 비행 후에 정말 아팠어요.','Kids often get sick during the winter.','아이들은 겨울에 자주 아파요.','I got sick from eating something bad.','상한 음식을 먹어서 아팠어요.'),
('col_health_02','take','medicine','take medicine','약을 먹다','eat','"eat medicine"는 틀린 표현이에요. 약을 복용할 때는 take를 써요.','A2','health',1,2,'medicine pill pharmacy health prescription','Remember to take your medicine twice a day with food.','하루 두 번 식사와 함께 약을 먹는 것을 기억하세요.','He forgot to take his medicine this morning.','그는 오늘 아침 약 먹는 것을 잊었어요.','Take your medicine with a full glass of water.','약을 충분한 물 한 잔과 함께 복용하세요.','She set an alarm so she wouldn''t forget to take her medicine.','그녀는 약 먹는 걸 잊지 않으려고 알람을 설정했어요.','Take your medicine even if you start to feel better.','컨디션이 좋아지기 시작해도 약을 계속 복용하세요.'),
('col_health_16','catch','a cold','catch a cold','감기에 걸리다','get','"get a cold"도 맞지만 catch a cold가 더 생동감 있는 표현이에요.','A2','health',1,16,'cold flu sick ill sneeze winter','He caught a cold after being out in the rain.','그는 빗속에 있다가 감기에 걸렸어요.','Make sure you wash your hands to avoid catching a cold.','감기에 걸리지 않도록 손을 씻어야 해요.','I caught a cold during the long flight to Europe.','저는 유럽으로 가는 긴 비행 중에 감기에 걸렸어요.','She caught a cold from her son who was sick last week.','그녀는 지난주에 아팠던 아들에게서 감기에 옮았어요.','Try not to catch a cold during finals week.','기말고사 주에 감기에 걸리지 않도록 조심하세요.'),
('col_health_21','catch','cold','catch a cold','감기에 걸리다','get','"get a cold"도 사용되지만, 감기에 걸리는 행위 자체는 catch a cold가 더 자연스러워요.','A2','health',1,0,'sick person tissue cold flu blanket','Don''t go out without a coat — you''ll catch a cold.','코트 없이 나가지 마세요 — 감기 걸려요.','I caught a cold last week and had to take time off.','지난주에 감기에 걸려서 쉬어야 했어요.','She caught a bad cold from her son.','그녀는 아들에게서 심한 감기에 걸렸어요.','You can catch a cold from someone sneezing nearby.','근처에서 누가 재채기하면 감기에 걸릴 수 있어요.','I always catch a cold when the weather changes.','저는 날씨가 바뀔 때마다 감기에 걸려요.'),
('col_health_01','make','a recovery','make a recovery','회복하다','do','"do a recovery"는 틀린 표현이에요. 병에서 회복할 때는 make a recovery를 써요.','B1','health',1,1,'recovery hospital heal patient wellness','She made a full recovery after the surgery.','그녀는 수술 후 완전히 회복했어요.','He is slowly making a recovery and should be home next week.','그는 서서히 회복하고 있으며 다음 주에 귀가할 수 있을 것 같아요.','My grandfather made a remarkable recovery after his heart surgery.','저희 할아버지는 심장 수술 후 놀라운 회복을 하셨어요.','The patient is making a steady recovery in the rehab center.','환자는 재활 센터에서 꾸준히 회복하고 있어요.','It took her months to make a full recovery from the accident.','그녀가 사고에서 완전히 회복하는 데 몇 달이 걸렸어요.'),
('col_health_03','get','exercise','get exercise','운동하다','do','"do exercise"도 맞지만 get exercise는 운동을 충분히 한다는 뉘앙스예요.','B1','health',1,3,'exercise fitness walking health active','Make sure you get some exercise every day, even a short walk.','매일 짧은 산책이라도 운동을 하도록 하세요.','She doesn''t get enough exercise, which affects her energy levels.','그녀는 운동이 충분하지 않아 에너지 레벨에 영향을 받아요.','Try to get some exercise during your lunch break each day.','매일 점심시간에 운동을 좀 하려고 해보세요.','She gets her exercise by walking the dog every morning.','그녀는 매일 아침 강아지 산책으로 운동해요.','Getting enough exercise can really improve your sleep quality.','충분한 운동은 수면의 질을 크게 향상시킬 수 있어요.'),
('col_health_04','have','surgery','have surgery','수술을 받다','do','"do surgery"는 의사가 수술할 때 써요. 환자는 have surgery를 써야 해요.','B1','health',1,4,'surgery hospital operation medical patient','She had knee surgery last month and is recovering well.','그녀는 지난달에 무릎 수술을 받았고 잘 회복하고 있어요.','He had surgery to remove the tumor and it went smoothly.','그는 종양 제거 수술을 받았고 순조롭게 진행되었어요.','He''s having surgery on his shoulder next Tuesday.','그는 다음 주 화요일에 어깨 수술을 받아요.','She had surgery as a child and doesn''t remember much of it.','그녀는 어린 시절에 수술을 받아서 잘 기억나지 않아요.','They had surgery on the same day at the same hospital.','그들은 같은 날 같은 병원에서 수술을 받았어요.'),
('col_health_05','keep','fit','keep fit','건강을 유지하다','stay','"stay fit"도 맞지만 keep fit은 지속적인 노력을 강조해요.','B1','health',1,5,'fitness healthy lifestyle gym exercise','She goes to the gym regularly to keep fit.','그녀는 건강을 유지하기 위해 규칙적으로 헬스장에 가요.','Eating well and sleeping enough helps you keep fit.','잘 먹고 충분히 자는 것이 건강을 유지하는 데 도움이 돼요.','Walking 10,000 steps a day is a simple way to keep fit.','하루 만 보 걷기는 건강을 유지하는 간단한 방법이에요.','He keeps fit by swimming three times a week.','그는 일주일에 세 번 수영해서 건강을 유지해요.','Yoga and proper nutrition help her keep fit at 60.','요가와 올바른 영양 섭취가 60대인 그녀가 건강을 유지하는 데 도움이 돼요.'),
('col_health_07','run','a fever','run a fever','열이 나다','have','"have a fever"도 맞지만 run a fever는 열이 지속되는 뉘앙스예요.','B1','health',1,7,'fever sick child temperature ill','The child was running a fever and couldn''t go to school.','아이가 열이 나서 학교에 갈 수 없었어요.','He''s been running a high fever since last night.','그는 어젯밤부터 고열이 나고 있어요.','My daughter is running a fever and won''t eat anything.','제 딸이 열이 나고 아무것도 안 먹어요.','He kept running a low fever for several days.','그는 며칠 동안 미열이 계속 났어요.','If you''re running a fever over 38°C, please call the clinic.','열이 38도가 넘으면 병원에 전화해 주세요.'),
('col_health_08','make','an appointment','make an appointment','예약하다','do','"do an appointment"는 틀린 표현이에요. 진료 예약할 때는 make를 써요.','B1','health',1,8,'appointment doctor clinic booking medical','I need to make an appointment with my doctor this week.','이번 주에 의사 예약을 해야 해요.','She made an appointment with the specialist for next Monday.','그녀는 다음 월요일에 전문의 예약을 했어요.','I made an appointment for a dental cleaning next month.','저는 다음 달 치과 스케일링을 예약했어요.','She made an appointment with the eye doctor for an annual checkup.','그녀는 안과 정기 검진 예약을 했어요.','You can make an appointment online or by calling the clinic.','온라인 또는 병원에 전화해서 예약할 수 있어요.'),
('col_health_09','get','a checkup','get a checkup','건강 검진을 받다','do','"do a checkup"은 틀린 표현이에요. 검진을 받을 때는 get a checkup을 써요.','B1','health',1,9,'checkup health exam doctor annual','Everyone should get a checkup at least once a year.','모두 적어도 1년에 한 번은 건강 검진을 받아야 해요.','He got a full checkup after noticing some unusual symptoms.','그는 이상한 증상을 발견하고 전체 건강 검진을 받았어요.','She gets a checkup every spring as part of her health routine.','그녀는 건강 관리의 일환으로 매년 봄에 건강 검진을 받아요.','My dad got a checkup that revealed early signs of diabetes.','저희 아빠는 건강 검진을 받고 당뇨 초기 증상을 발견했어요.','I''m planning to get a checkup before the new semester starts.','새 학기가 시작하기 전에 건강 검진을 받을 계획이에요.'),
('col_health_10','take','a rest','take a rest','휴식을 취하다','have','"have a rest"도 맞지만 take a rest는 적극적으로 쉬는 뉘앙스예요.','B1','health',1,10,'rest relaxing tired bed recovery','You should take a rest — you''ve been working non-stop all day.','하루 종일 쉬지 않고 일했으니 좀 쉬어야 해요.','Take a rest when you need to — pushing too hard can make things worse.','필요할 때 쉬세요 — 너무 무리하면 상태가 악화될 수 있어요.','Take a rest for a few minutes between sets at the gym.','헬스장에서 세트 사이에 몇 분간 휴식을 취하세요.','The doctor told her to take a rest for at least a week.','의사는 그녀에게 최소 일주일은 휴식을 취하라고 했어요.','I took a rest in the shade before continuing the hike.','저는 등산을 계속하기 전에 그늘에서 휴식을 취했어요.'),
('col_health_12','lose','weight','lose weight','체중을 줄이다','reduce','"reduce weight"는 어색해요. 체중 감량은 lose weight를 써요.','B1','health',1,12,'weight loss fitness healthy diet exercise','He started jogging every morning to lose weight.','그는 체중을 줄이기 위해 매일 아침 조깅을 시작했어요.','The doctor advised her to lose weight gradually through diet and exercise.','의사는 식이요법과 운동으로 서서히 체중을 줄이라고 조언했어요.','She lost weight by simply walking more and eating less sugar.','그녀는 단순히 더 많이 걷고 설탕을 덜 먹어서 체중을 줄였어요.','He lost weight quickly but gained it all back later.','그는 체중을 빨리 줄였지만 나중에 다 다시 쪘어요.','Try not to lose weight too fast — slow progress is healthier.','너무 빠르게 체중을 줄이지 마세요 — 천천히 진행하는 게 더 건강해요.'),
('col_health_19','be','in good shape','be in good shape','건강 상태가 좋다','have','"have good health"도 맞지만 be in good shape은 신체 상태를 더 구체적으로 표현해요.','B1','health',2,19,'fit health shape body active strong','He''s 60 but still in very good shape.','그는 60살이지만 여전히 건강 상태가 매우 좋아요.','You need to be in good shape before attempting that mountain hike.','그 산행을 시도하기 전에 건강 상태가 좋아야 해요.','You need to be in good shape to climb that mountain safely.','그 산을 안전하게 오르려면 건강 상태가 좋아야 해요.','She''s been in good shape since starting Pilates last year.','그녀는 작년에 필라테스를 시작한 후 건강 상태가 좋아요.','For his age, my grandfather is in remarkably good shape.','나이에 비해 저희 할아버지는 놀라울 정도로 건강 상태가 좋으세요.'),
('col_health_06','break','a habit','break a habit','습관을 끊다','stop','"stop a habit"도 맞지만 break a habit은 오래된 습관을 끊는 뉘앙스예요.','B2','health',2,6,'habit break routine change lifestyle','Breaking a bad habit takes time and persistence.','나쁜 습관을 끊는 데는 시간과 인내가 필요해요.','She finally broke the habit of eating late at night.','그녀는 마침내 밤늦게 먹는 습관을 끊었어요.','It took two years for him to break the smoking habit.','그가 흡연 습관을 끊는 데 2년이 걸렸어요.','Breaking a habit becomes easier when you replace it with a new one.','새로운 습관으로 대체하면 습관을 끊기가 더 쉬워져요.','She broke the habit of biting her nails by wearing nail polish.','그녀는 매니큐어를 발라서 손톱 깨무는 습관을 끊었어요.'),
('col_health_11','follow','a diet','follow a diet','식단을 따르다','do','"do a diet"는 어색해요. 식단을 실천할 때는 follow a diet를 써요.','B2','health',2,11,'diet food healthy eating nutrition','She''s been following a low-carb diet for the past three months.','그녀는 지난 세 달 동안 저탄수화물 식단을 따르고 있어요.','It''s hard to follow a strict diet when eating out.','외식할 때 엄격한 식단을 따르는 건 어려워요.','My nutritionist designed a diet I can follow without feeling hungry.','영양사가 배고프지 않게 따를 수 있는 식단을 짜줬어요.','He follows a Mediterranean diet for heart health.','그는 심장 건강을 위해 지중해식 식단을 따라요.','Following a balanced diet is more sustainable than extreme diets.','균형 잡힌 식단을 따르는 것이 극단적인 다이어트보다 지속 가능해요.'),
('col_health_13','boost','immunity','boost immunity','면역력을 높이다','increase','"increase immunity"도 맞지만 boost가 더 생동감 있는 표현이에요.','B2','health',2,13,'immunity vitamins health boost wellness','Getting enough sleep can help boost your immunity.','충분한 수면은 면역력을 높이는 데 도움이 될 수 있어요.','Vitamin C is known to boost immunity during cold season.','비타민 C는 감기 시즌에 면역력을 높이는 것으로 알려져 있어요.','Eating ginger and garlic is said to boost immunity.','생강과 마늘을 먹는 것이 면역력을 높여준다고 해요.','Regular exercise can boost your immunity over time.','규칙적인 운동은 시간이 지나면서 면역력을 높여줄 수 있어요.','She drinks a green smoothie every morning to boost her immunity.','그녀는 면역력을 높이기 위해 매일 아침 그린 스무디를 마셔요.'),
('col_health_14','manage','stress','manage stress','스트레스를 관리하다','control','"control stress"도 쓰이지만 manage stress가 더 일반적인 표현이에요.','B2','health',2,14,'stress management mental health wellness calm','Learning to manage stress is essential for good mental health.','스트레스를 관리하는 법을 배우는 것은 좋은 정신 건강을 위해 필수적이에요.','Exercise is one of the best ways to manage stress effectively.','운동은 스트레스를 효과적으로 관리하는 가장 좋은 방법 중 하나예요.','Meditation has helped me manage stress at work.','명상은 제가 직장에서 스트레스를 관리하는 데 도움이 됐어요.','She manages stress by journaling every night before bed.','그녀는 잠자기 전 일기 쓰기로 스트레스를 관리해요.','Companies should help employees manage stress more effectively.','회사는 직원들이 스트레스를 더 효과적으로 관리하도록 도와야 해요.'),
('col_health_15','suffer','from','suffer from','~을 앓다','have','"have"도 쓰이지만 suffer from은 지속적인 병이나 고통을 강조해요.','B2','health',2,15,'suffer chronic illness pain condition','She suffers from chronic back pain due to her desk job.','그녀는 사무직 때문에 만성 허리 통증을 앓고 있어요.','Many people suffer from anxiety without knowing it.','많은 사람이 자신도 모르게 불안 장애를 앓고 있어요.','He suffers from seasonal allergies every spring.','그는 매년 봄마다 계절성 알레르기를 앓아요.','She has suffered from migraines since her teenage years.','그녀는 십대 시절부터 편두통을 앓고 있어요.','Many elderly people suffer from joint pain in cold weather.','많은 노인분들이 추운 날씨에 관절 통증을 앓으세요.'),
('col_health_18','seek','medical attention','seek medical attention','진료를 받다','get','"get medical attention"도 맞지만 seek은 적극적으로 찾아가는 뉘앙스예요.','B2','health',2,18,'medical attention doctor emergency health','If the pain continues, please seek medical attention right away.','통증이 계속되면 즉시 진료를 받으세요.','She should have sought medical attention sooner.','그녀는 더 일찍 진료를 받았어야 했어요.','She sought medical attention as soon as the rash appeared.','그녀는 발진이 나타나자마자 진료를 받았어요.','Don''t wait — seek medical attention for chest pain immediately.','기다리지 마세요 — 가슴 통증은 즉시 진료를 받으세요.','He sought medical attention abroad while traveling for work.','그는 출장 중 해외에서 진료를 받았어요.'),
('col_health_20','cut','down on','cut down on','~을 줄이다','reduce','"reduce"도 맞지만 cut down on은 식습관이나 생활 습관 변화에 더 자연스러워요.','B2','health',2,20,'diet reduce caffeine sugar health lifestyle','The doctor told him to cut down on salt and sugar.','의사는 그에게 소금과 설탕을 줄이라고 했어요.','She''s been trying to cut down on caffeine since last year.','그녀는 작년부터 카페인을 줄이려고 노력하고 있어요.','I''m trying to cut down on screen time before bed.','저는 자기 전 화면 시간을 줄이려고 노력 중이에요.','He cut down on red meat for environmental reasons.','그는 환경적인 이유로 적색육 섭취를 줄였어요.','She cut down on coffee and her sleep improved noticeably.','그녀는 커피를 줄였고 수면이 눈에 띄게 좋아졌어요.'),
('col_health_24','break','sweat','break a sweat','땀을 흘리다, 힘을 쓰다','have','"have a sweat"는 어색해요. 운동이나 노력으로 땀이 날 때는 break a sweat.','B2','health',1,0,'person exercising sweating workout effort gym','I didn''t even break a sweat during the workout.','운동하면서 땀도 안 났어요.','She broke a sweat just walking up the stairs.','그녀는 계단을 오르기만 해도 땀이 났어요.','The test was so easy — I didn''t break a sweat.','시험이 너무 쉬워서 식은땀도 안 났어요.','You need to break a sweat to see real results.','진짜 결과를 보려면 땀을 흘려야 해요.','He broke a sweat trying to fix the bike.','그는 자전거를 고치려고 진땀을 흘렸어요.'),
('col_health_17','go','under the knife','go under the knife','수술대에 오르다','have','"have surgery"보다 구어체적이고 비유적인 표현이에요.','C1','health',3,17,'surgery operating room knife hospital','She finally decided to go under the knife to fix her knee.','그녀는 결국 무릎을 고치기 위해 수술대에 오르기로 했어요.','He was nervous about going under the knife for the first time.','그는 처음으로 수술대에 오르는 것이 긴장됐어요.','He went under the knife to remove a small tumor.','그는 작은 종양을 제거하기 위해 수술대에 올랐어요.','She was reluctant to go under the knife for a cosmetic procedure.','그녀는 미용 시술을 위해 수술대에 오르는 걸 망설였어요.','After years of pain, he finally went under the knife.','몇 년간의 고통 끝에 그는 결국 수술대에 올랐어요.'),
('col_health_C1_01','seek','treatment','seek treatment','치료를 받다','get','병원이나 전문가의 도움을 적극적으로 찾는다는 격식 있는 표현이에요. 의료 기사나 상담 자리에서 자주 써요.','C1','health',2,0,'doctor consultation','You should seek treatment as soon as the symptoms worsen.','증상이 악화되면 즉시 치료를 받아야 해요.','Many patients hesitate to seek treatment for mental health issues.','많은 환자들이 정신 건강 문제로 치료받기를 망설여요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_health_C1_02','follow','doctor''s orders','follow doctor''s orders','의사의 지시를 따르다','listen','처방이나 권고 사항을 충실히 지킨다는 관용적 표현이에요. 격식 있는 회복 안내에서 흔히 써요.','C1','health',2,0,'doctor prescription','She made a full recovery because she followed her doctor''s orders to the letter.','그녀는 의사의 지시를 철저히 따라서 완전히 회복했어요.','Patients who follow doctor''s orders tend to heal faster.','의사의 지시를 따르는 환자들이 더 빨리 낫는 경향이 있어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_health_C1_03','make','recovery','make a recovery','회복하다','do','병이나 부상에서 회복하는 과정을 격식 있게 표현해요. ''make a full/speedy/remarkable recovery''처럼 형용사를 자주 동반해요.','C1','health',2,0,'hospital recovery','He made a remarkable recovery after the surgery.','그는 수술 후에 놀라울 정도로 회복했어요.','The patient is expected to make a full recovery within weeks.','환자는 몇 주 안에 완전히 회복할 것으로 예상돼요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_health_C1_04','boost','immunity','boost immunity','면역력을 높이다','increase','면역 체계를 강화한다는 건강 분야의 전형적인 콜로케이션이에요. 잡지나 광고에서 자주 등장해요.','C1','health',2,0,'healthy food vitamins','Eating a balanced diet helps boost your immunity during winter.','균형 잡힌 식단은 겨울철 면역력을 높이는 데 도움이 돼요.','Regular exercise has been shown to boost immunity over time.','규칙적인 운동은 시간이 지나면서 면역력을 높이는 것으로 밝혀졌어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_health_C1_05','manage','stress','manage stress','스트레스를 관리하다','control','스트레스를 완전히 없애기보다 잘 다룬다는 의미예요. 자기계발과 건강 칼럼에서 표준 표현이에요.','C1','health',2,0,'meditation calm','Meditation can help you manage stress more effectively.','명상은 스트레스를 더 효과적으로 관리하는 데 도움이 돼요.','Learning to manage stress is essential for long-term well-being.','스트레스 관리법을 배우는 것은 장기적인 웰빙에 필수적이에요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_health_C2_01','exhibit','symptoms','exhibit symptoms','증상을 보이다','show','의학 논문이나 임상 보고서에서 증상의 발현을 기술할 때 표준이에요. ''show''보다 객관적이고 격식 있어요.','C2','health',3,0,'clinical examination','The patient began to exhibit symptoms consistent with early-onset Parkinson''s disease.','환자는 조기 발병 파킨슨병과 일치하는 증상을 보이기 시작했어요.','Approximately 30 percent of subjects exhibited symptoms within 72 hours of exposure.','피험자의 약 30%가 노출 후 72시간 이내에 증상을 보였어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_health_C2_02','alleviate','discomfort','alleviate discomfort','불편함을 완화하다','reduce','통증이나 불쾌감을 부드럽게 줄여준다는 의학적·격식 표현이에요. 처방 안내문이나 의료 광고에 자주 등장해요.','C2','health',3,0,'medical relief','A warm compress can alleviate discomfort in the affected joint.','온찜질은 환부 관절의 불편함을 완화할 수 있어요.','The new formulation is designed to alleviate discomfort without inducing drowsiness.','새 제형은 졸음을 유발하지 않으면서 불편함을 완화하도록 설계됐어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_health_C2_03','administer','treatment','administer treatment','치료를 시행하다','give','의료진이 공식적으로 치료를 시행한다는 뜻으로, 진료 기록이나 의학 저널의 표준 표현이에요.','C2','health',3,0,'emergency treatment','Paramedics administered treatment at the scene before transferring the patient.','구급대원은 환자를 이송하기 전에 현장에서 치료를 시행했어요.','The trial assessed how quickly clinicians could administer treatment in remote areas.','그 임상 시험은 의료진이 오지에서 얼마나 빨리 치료를 시행할 수 있는지 평가했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_health_C2_04','succumb','illness','succumb to illness','병에 굴복하다','lose','병을 이기지 못하고 결국 사망하거나 압도된다는 문어체·격식 표현이에요. 부고나 역사적 기술에 자주 써요.','C2','health',3,0,'hospital bedside','The renowned scholar succumbed to a prolonged illness at the age of eighty-two.','저명한 학자는 82세에 오랜 투병 끝에 별세했어요.','Without timely intervention, vulnerable patients may succumb to the illness within days.','적시 개입이 없으면 취약한 환자는 며칠 안에 병에 굴복할 수 있어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_health_C2_05','warrant','intervention','warrant intervention','개입을 요하다','need','심각도나 위험도가 개입을 정당화한다는 의학적·정책적 표현이에요. 임상 가이드라인이나 보고서에 표준이에요.','C2','health',3,0,'medical chart','Elevated troponin levels typically warrant immediate cardiac intervention.','트로포닌 수치 상승은 대개 즉각적인 심장 개입을 요해요.','The committee concluded that the situation warranted intervention at the federal level.','위원회는 그 상황이 연방 차원의 개입을 요한다고 결론지었어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_home_21','do','laundry','do laundry','빨래를 하다','make','"make laundry"는 틀린 표현이에요. 집안일은 대부분 do와 함께 (do dishes, do laundry, do chores).','A1','home',1,0,'laundry washing machine clothes basket detergent','I usually do laundry on Saturdays.','저는 보통 토요일에 빨래를 해요.','Could you do the laundry today?','오늘 빨래해 줄 수 있어요?','She does laundry twice a week.','그녀는 일주일에 두 번 빨래를 해요.','I haven''t done laundry in two weeks.','저는 2주 동안 빨래를 안 했어요.','My dad taught me how to do laundry when I was twelve.','아빠가 제가 열두 살 때 빨래하는 법을 알려 주셨어요.'),
('col_home_22','do','dishes','do the dishes','설거지를 하다','make','"wash up"도 가능하지만 do the dishes가 가장 일반적이에요. wash the dishes도 OK.','A1','home',1,0,'dishes sink kitchen washing plates','I''ll cook if you do the dishes.','제가 요리할 테니 설거지 해 주세요.','My brother and I take turns doing the dishes.','저와 형은 교대로 설거지를 해요.','Did you do the dishes after dinner?','저녁 먹고 설거지했어요?','She hates doing the dishes by hand.','그녀는 손으로 설거지하는 걸 싫어해요.','Let''s do the dishes together to finish faster.','같이 설거지해서 빨리 끝내요.'),
('col_home_01','do','the chores','do the chores','집안일을 하다','make','"make the chores"는 틀린 표현이에요. 집안일을 할 때는 do를 써요.','A2','home',1,1,'chores housework cleaning home domestic','We take turns doing the chores in our house.','우리 집에서는 교대로 집안일을 해요.','She does the chores every Sunday morning.','그녀는 매주 일요일 아침에 집안일을 해요.','My partner and I split the chores fifty-fifty during the week.','저와 파트너는 평일에 집안일을 반반씩 나눠서 해요.','He does the chores quickly in the morning before work.','그는 출근 전에 아침에 집안일을 빠르게 해요.','It''s easier to do the chores when you have a clear routine.','명확한 루틴이 있으면 집안일을 하기가 더 쉬워요.'),
('col_home_02','make','the bed','make the bed','침대를 정리하다','do','"do the bed"는 틀린 표현이에요. 침대를 정리할 때는 make the bed를 써요.','A2','home',1,2,'bed making tidy room morning routine','I always make the bed as soon as I wake up.','나는 일어나자마자 항상 침대를 정리해요.','She taught her kids to make their beds every morning.','그녀는 아이들에게 매일 아침 침대를 정리하도록 가르쳤어요.','My dad taught me to make the bed with hospital corners.','저희 아빠는 저에게 단정하게 침대를 정리하는 법을 가르쳐 주셨어요.','She forgot to make the bed and felt rushed all morning.','그녀는 침대 정리를 잊어서 아침 내내 마음이 급했어요.','Making the bed is the first small win of the day.','침대 정리는 하루의 첫 번째 작은 성취예요.'),
('col_home_03','do','the dishes','do the dishes','설거지를 하다','wash','"wash the dishes"도 맞지만 do the dishes가 더 구어체적이에요.','A2','home',1,3,'dishes washing kitchen cleaning sink','Can you do the dishes tonight? I cooked dinner.','오늘 밤 설거지 해줄 수 있어요? 내가 저녁을 요리했잖아요.','He does the dishes right after dinner every night.','그는 매일 저녁 식사 후 바로 설거지를 해요.','I''ll do the dishes if you handle bedtime stories.','당신이 잠자리 동화를 해주면 제가 설거지를 할게요.','They take turns doing the dishes after every meal.','그들은 매 식사 후에 교대로 설거지를 해요.','Doing the dishes is a great time to listen to podcasts.','설거지하는 시간은 팟캐스트 듣기에 좋아요.'),
('col_home_05','keep','clean','keep the house clean','집을 청결하게 유지하다','make','"make the house clean"은 어색해요. 상태를 유지할 때는 keep을 써요.','A2','home',1,5,'clean house tidy organized home','It''s hard to keep the house clean with two young kids.','어린 아이 둘이 있을 때 집을 청결하게 유지하기가 어려워요.','She keeps the kitchen particularly clean and organized.','그녀는 특히 주방을 청결하고 정돈되게 유지해요.','A weekly cleaning schedule helps us keep the house clean.','주간 청소 계획이 집을 청결하게 유지하는 데 도움이 돼요.','Pets make it harder to keep the house clean.','반려동물이 있으면 집을 청결하게 유지하기가 더 어려워요.','She keeps the house clean even when expecting unexpected guests.','그녀는 예상치 못한 손님이 와도 집을 청결하게 유지해요.'),
('col_home_08','set','the table','set the table','식탁을 차리다','make','"make the table"은 틀린 표현이에요. 식탁을 준비할 때는 set the table을 써요.','A2','home',1,8,'table setting dinner kitchen family','Could you set the table while I finish cooking?','내가 요리를 끝내는 동안 식탁을 차려줄 수 있어요?','The children take turns setting the table for dinner.','아이들은 저녁 식사를 위해 교대로 식탁을 차려요.','My daughter loves to set the table with fresh flowers.','제 딸은 신선한 꽃과 함께 식탁을 차리는 걸 좋아해요.','He set the table beautifully for their first anniversary.','그는 그들의 첫 번째 결혼기념일을 위해 식탁을 아름답게 차렸어요.','Please set the table for six — we have guests tonight.','6명분 식탁을 차려 주세요 — 오늘 밤 손님이 와요.'),
('col_home_10','take','out the trash','take out the trash','쓰레기를 버리다','throw','"throw out the trash"도 맞지만 take out the trash가 더 일상적인 표현이에요.','A2','home',1,10,'trash garbage bin household chores','Can you take out the trash before you go to bed?','자기 전에 쓰레기 좀 버려줄 수 있어요?','He takes out the trash on Tuesday and Friday mornings.','그는 화요일과 금요일 아침에 쓰레기를 버려요.','Don''t forget to take out the trash before the truck comes.','쓰레기 트럭이 오기 전에 쓰레기를 버리는 걸 잊지 마세요.','The kids argue about whose turn it is to take out the trash.','아이들은 누구 차례로 쓰레기를 버려야 하는지 다퉈요.','He takes out the trash and recycling separately.','그는 쓰레기와 재활용품을 따로 버려요.'),
('col_home_11','do','the laundry','do the laundry','빨래를 하다','wash','"wash the laundry"도 맞지만 do the laundry가 더 자연스러운 구어체예요.','A2','home',1,11,'laundry washing machine clothes household','I need to do the laundry — I''m out of clean clothes.','빨래를 해야 해요 — 깨끗한 옷이 없어요.','She does the laundry every Saturday morning.','그녀는 매주 토요일 아침에 빨래를 해요.','I usually do the laundry on rainy afternoons.','저는 보통 비 오는 오후에 빨래를 해요.','They do the laundry together to save time and water.','그들은 시간과 물을 아끼기 위해 함께 빨래를 해요.','Doing the laundry is more relaxing with music playing.','음악을 틀어놓고 빨래를 하면 더 편안해요.'),
('col_home_16','cook','a meal','cook a meal','식사를 준비하다','make','"make a meal"도 맞지만 cook은 실제 조리 과정을 강조해요.','A2','home',1,16,'cooking meal kitchen home food','She cooked a three-course meal for their anniversary dinner.','그녀는 결혼기념일 저녁을 위해 3코스 식사를 준비했어요.','He loves cooking a meal from scratch on weekends.','그는 주말에 처음부터 식사를 직접 조리하는 것을 좋아해요.','My dad cooks a hot meal for the family every Sunday.','저희 아빠는 매주 일요일에 가족을 위해 따뜻한 식사를 준비하세요.','She learned to cook simple meals after moving out for college.','그녀는 대학을 위해 독립한 후 간단한 식사를 준비하는 법을 배웠어요.','Cooking a meal at home is usually healthier than ordering in.','집에서 식사를 준비하는 게 보통 배달보다 더 건강해요.'),
('col_home_17','put','away','put away','제자리에 넣다, 치우다','clean','"clean away"는 어색해요. 물건을 제자리에 넣을 때는 put away를 써요.','A2','home',1,17,'tidy organize put away household','Please put away your things before guests arrive.','손님이 오기 전에 물건들을 치워두세요.','He put the toys away after the kids went to bed.','그는 아이들이 잠든 후 장난감을 치웠어요.','He put away the groceries as soon as he got home.','그는 집에 오자마자 식료품을 제자리에 정리했어요.','She put away the kids'' toys before sitting down for dinner.','그녀는 저녁 식사를 위해 앉기 전에 아이들 장난감을 치웠어요.','Please put away your dishes after eating.','식사 후 그릇은 제자리에 두세요.'),
('col_home_19','switch','off','switch off lights','불을 끄다','close','"close lights"는 틀린 표현이에요. 불을 끌 때는 switch off 또는 turn off를 써요.','A2','home',1,19,'lights switch off electricity saving home','Don''t forget to switch off all the lights before you leave.','나가기 전에 불을 다 끄는 것을 잊지 마세요.','She always switches off the TV before going to bed.','그녀는 자기 전에 항상 TV를 꺼요.','Please switch off the lights when you leave the room.','방을 나갈 때 불을 꺼주세요.','He switched off the lights and lit a candle for dinner.','그는 불을 끄고 저녁 식사를 위해 촛불을 켰어요.','Switching off lights when not needed saves on electricity bills.','필요 없을 때 불을 끄면 전기 요금을 절약할 수 있어요.'),
('col_home_23','take','nap','take a nap','낮잠을 자다','do','"do a nap"은 틀린 표현. 낮잠은 take a nap.','A2','home',1,0,'person napping sofa cozy resting blanket','I usually take a nap after lunch.','저는 보통 점심 후에 낮잠을 자요.','She took a quick nap before the meeting.','그녀는 회의 전에 빠르게 낮잠을 잤어요.','Babies need to take regular naps.','아기들은 정기적으로 낮잠을 자야 해요.','Why don''t you take a nap if you''re tired?','피곤하면 낮잠 좀 자는 게 어때요?','He takes a 20-minute nap to recharge.','그는 충전하려고 20분 낮잠을 자요.'),
('col_home_04','pay','the rent','pay the rent','월세를 내다','give','"give the rent"는 어색해요. 임대료를 낼 때는 pay를 써요.','B1','home',1,4,'rent payment apartment landlord monthly','We pay the rent on the first of every month.','우리는 매월 1일에 월세를 내요.','She struggled to pay the rent after losing her job.','그녀는 직장을 잃은 후 월세 내기가 힘들었어요.','The rent went up again this year, so we''re budgeting carefully.','올해 월세가 또 올라서 예산을 신중히 짜고 있어요.','He pays the rent through automatic bank transfer.','그는 자동 이체로 월세를 내요.','It''s standard to pay the rent on the first of the month here.','여기는 매월 1일에 월세를 내는 게 일반적이에요.'),
('col_home_06','run','errands','run errands','볼일을 보다, 심부름을 하다','do','"do errands"도 쓰이지만 run errands가 훨씬 더 자주 쓰여요.','B1','home',1,6,'errands shopping tasks daily routine','I need to run some errands this afternoon — bank, pharmacy, supermarket.','오늘 오후에 볼일이 몇 가지 있어요 — 은행, 약국, 슈퍼마켓이요.','She ran errands all morning and finally got home at noon.','그녀는 오전 내내 볼일을 보고 정오에 겨우 집에 왔어요.','I have to run a few errands before picking up the kids.','아이들을 데리러 가기 전에 몇 가지 볼일을 봐야 해요.','He combined his errands into one trip to save time.','그는 시간을 절약하기 위해 볼일을 한 번에 묶었어요.','Running errands on Saturday morning is one of my routines.','토요일 아침에 볼일을 보는 게 제 루틴 중 하나예요.'),
('col_home_09','do','repairs','do repairs','수리하다','make','"make repairs"도 쓰이지만 do repairs가 일상적인 수리 작업에서 더 자주 쓰여요.','B1','home',2,9,'repairs home DIY maintenance tools','He spent the weekend doing repairs around the house.','그는 주말 동안 집 이곳저곳을 수리했어요.','We need to do some repairs before putting the house on the market.','집을 내놓기 전에 수리를 좀 해야 해요.','He does repairs around the house every weekend.','그는 매주 주말마다 집 안 수리를 해요.','They had to do some repairs before the inspection.','그들은 점검 전에 수리를 좀 해야 했어요.','YouTube tutorials help me do small repairs by myself.','유튜브 튜토리얼이 제가 간단한 수리를 직접 하는 데 도움이 돼요.'),
('col_home_13','move','in','move in','이사 들어오다','come','"come in"은 다른 의미예요. 새로운 집에 들어올 때는 move in을 써요.','B1','home',1,13,'moving in new home apartment boxes','We moved in to our new apartment last weekend.','우리는 지난 주말에 새 아파트로 이사 들어왔어요.','When are you planning to move in?','이사 들어올 계획이 언제예요?','They moved in to the new flat just before the baby arrived.','그들은 아기가 태어나기 직전에 새 아파트로 이사 들어왔어요.','My sister moved in with us during her job transition.','제 동생은 이직 기간 동안 저희와 함께 살았어요.','When did you move in to this neighborhood?','이 동네에 이사 오신 게 언제예요?'),
('col_home_15','fix','a leak','fix a leak','누수를 수리하다','repair','"repair a leak"도 맞지만 fix가 더 구어체적인 표현이에요.','B1','home',2,15,'leak plumber fix pipe water repair','The plumber came to fix the leak under the sink.','배관공이 싱크대 아래 누수를 수리하러 왔어요.','We need to fix the leak in the roof before winter comes.','겨울이 오기 전에 지붕 누수를 수리해야 해요.','We fixed the leak ourselves with a quick plumbing tutorial.','우리는 간단한 배관 튜토리얼로 직접 누수를 수리했어요.','The leak was small, but fixing it prevented bigger damage.','누수는 작았지만 수리한 덕분에 큰 피해를 막을 수 있었어요.','It took the plumber two hours to fix the leak in the bathroom.','배관공이 욕실의 누수를 수리하는 데 두 시간이 걸렸어요.'),
('col_home_18','mow','the lawn','mow the lawn','잔디를 깎다','cut','"cut the lawn"도 맞지만 mow the lawn이 더 표준적인 표현이에요.','B1','home',2,18,'lawn grass mowing garden weekend','He mows the lawn every other Saturday in summer.','그는 여름에 격주 토요일마다 잔디를 깎아요.','Could you mow the lawn before the party this weekend?','이번 주말 파티 전에 잔디 좀 깎아줄 수 있어요?','He mows the lawn early to avoid the afternoon heat.','그는 오후 더위를 피하려고 일찍 잔디를 깎아요.','I helped my neighbor mow the lawn after he hurt his back.','저는 허리를 다친 이웃이 잔디 깎는 걸 도와드렸어요.','They mow the lawn every other week in the growing season.','그들은 성장기에 격주로 잔디를 깎아요.'),
('col_home_24','throw','party','throw a party','파티를 열다','have','"have a party"도 가능하지만 throw a party가 더 활기차고 자연스러워요.','B1','home',1,0,'party guests home celebration friends','We''re throwing a party for her birthday.','그녀 생일 파티를 열 거예요.','They threw a huge party last weekend.','그들은 지난 주말 큰 파티를 열었어요.','I''ve never thrown a party at my apartment.','저는 우리 아파트에서 파티를 열어본 적이 없어요.','She loves throwing parties for her friends.','그녀는 친구들에게 파티 열어주는 걸 좋아해요.','Let''s throw a surprise party for him.','그를 위해 깜짝 파티를 열어요.'),
('col_home_07','hold','a gathering','hold a gathering','모임을 열다','make','"make a gathering"은 어색해요. 모임을 주최할 때는 hold를 써요.','B2','home',2,7,'gathering party home friends family','We held a small gathering at our place last Friday.','우리는 지난 금요일에 집에서 작은 모임을 열었어요.','She holds a family gathering every year at Christmas.','그녀는 매년 크리스마스에 가족 모임을 열어요.','We''re holding a gathering for my grandmother''s 80th birthday.','저희 할머니의 80번째 생신을 위해 모임을 열어요.','They held a gathering in the backyard with about twenty guests.','그들은 약 20명의 손님과 함께 뒷마당에서 모임을 열었어요.','It''s nice to hold a gathering even without a special occasion.','특별한 일이 없어도 모임을 여는 건 좋아요.'),
('col_home_12','sort','out clutter','sort out clutter','어질러진 것을 정리하다','clean','"clean clutter"는 어색해요. 어수선함을 정리할 때는 sort out을 써요.','B2','home',2,12,'clutter organize tidy home sorting','We spent the whole afternoon sorting out the clutter in the garage.','우리는 오후 내내 차고의 어질러진 것들을 정리했어요.','She finally sorted out the clutter in the spare room.','그녀는 마침내 여분 방의 어질러진 것들을 정리했어요.','I spent the weekend sorting out the clutter in my closet.','저는 주말에 옷장의 어질러진 것들을 정리하며 보냈어요.','She sorted out the clutter on her desk before starting work.','그녀는 일을 시작하기 전에 책상 위의 어질러진 것들을 정리했어요.','Decluttering experts can help you sort out the clutter at home.','정리 전문가가 집의 어질러진 것들을 정리하는 데 도와줄 수 있어요.'),
('col_home_14','redecorate','a room','redecorate a room','방을 새로 꾸미다','change','"change a room"은 어색해요. 방을 새로 꾸밀 때는 redecorate를 써요.','B2','home',2,14,'redecorate interior design room home','She decided to redecorate the living room over the holidays.','그녀는 연휴 동안 거실을 새로 꾸미기로 결정했어요.','They redecorated their bedroom with a calm, neutral color scheme.','그들은 차분하고 중성적인 색상 배합으로 침실을 새로 꾸몄어요.','She redecorated her kid''s room with pastel wallpaper.','그녀는 파스텔 벽지로 아이 방을 새로 꾸몄어요.','We redecorated the bathroom on a small budget.','우리는 적은 예산으로 욕실을 새로 꾸몄어요.','He redecorates a room every spring as a tradition.','그는 매년 봄마다 방 하나를 새로 꾸미는 전통이 있어요.'),
('col_home_20','settle','in','settle in','정착하다, 익숙해지다','adapt','"adapt"도 맞지만 settle in은 새 환경에서 편안해지는 뉘앙스예요.','B2','home',2,20,'settling home new neighborhood adapting','It took us a few weeks to settle in to our new home.','새집에 익숙해지는 데 몇 주가 걸렸어요.','Have you settled in to your new neighborhood yet?','새 동네에 아직 익숙해지셨나요?','It takes most people a few months to settle in to a new city.','대부분의 사람들이 새 도시에 익숙해지는 데 몇 달이 걸려요.','She settled in to her new role at work within weeks.','그녀는 몇 주 만에 직장의 새 역할에 익숙해졌어요.','Once we settled in, the neighborhood started to feel like home.','익숙해지고 나니 그 동네가 집처럼 느껴지기 시작했어요.'),
('col_home_C1_01','settle','in','settle in','새 집에 자리 잡다','enter','이사 후 새로운 공간에 익숙해지고 짐을 정리하며 안정되는 과정을 표현해요. 이사 인사나 안부에서 자주 들려요.','C1','home',2,0,'new apartment unpacking','Have you settled in yet?','이사 잘 적응하셨어요?','It takes about a month to fully settle in.','완전히 자리 잡는 데 한 달 정도 걸려요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_home_C1_02','do','up a place','do up a place','집을 꾸미다·수리하다','decorate','낡은 집을 보수하거나 새 집을 멋지게 꾸미는 것을 영국식으로 표현해요. 인테리어 잡지에서 자주 등장해요.','C1','home',2,0,'kitchen renovation home','They did up the cottage beautifully.','그들은 그 별장을 멋지게 꾸몄어요.','We''re doing up the kitchen next month.','다음 달에 부엌을 리모델링할 거예요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_home_C1_03','share','a flat','share a flat','집을 함께 쓰다','live','주로 영국식 표현으로, 한 아파트를 룸메이트와 공유한다는 뜻이에요. 미국식은 ''share an apartment''예요.','C1','home',2,0,'roommates flat london','I shared a flat with two friends in London.','런던에서 친구 둘과 집을 함께 썼어요.','Sharing a flat helps cut down on rent.','집을 함께 쓰면 월세를 줄일 수 있어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_home_C1_04','set','up home','set up home','살림을 차리다','make','결혼이나 이주 후 새 보금자리를 마련한다는 뜻으로, 다소 격식 있고 따뜻한 뉘앙스예요.','C1','home',2,0,'coastal town house','They set up home in a quiet coastal town.','그들은 조용한 해안 도시에 살림을 차렸어요.','After marriage, they set up home in Seoul.','결혼 후 그들은 서울에 보금자리를 마련했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_home_C1_05','feel','at home','feel at home','편안하다·내 집 같다','be','낯선 장소나 상황에서 편안함을 느낀다는 따뜻한 표현이에요. 손님맞이 인사에 자주 써요.','C1','home',2,0,'cozy living room','Please make yourself comfortable — feel at home.','편하게 계세요 — 내 집처럼요.','I felt at home from the moment I arrived.','도착한 순간부터 편안했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_home_C2_01','exude','warmth','exude warmth','따스함이 흘러나오다','have','공간이나 사람이 따스한 분위기를 자연스럽게 풍긴다는 표현이에요. 인테리어 잡지에서 자주 봐요.','C2','home',3,0,'cozy cottage','The reclaimed-oak interiors exude warmth and quiet sophistication.','재생 오크로 마감한 인테리어는 따스함과 차분한 세련됨을 풍겨요.','Her countryside cottage exudes warmth from every corner.','그녀의 시골 코티지는 구석구석에서 따스함이 흘러나와요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_home_C2_02','epitomize','elegance','epitomize elegance','우아함의 전형이 되다','show','특정 사물이 우아함의 완벽한 본보기라는 격식 있는 표현이에요. 디자인 비평에서 표준이에요.','C2','home',3,0,'marble foyer','The marble foyer epitomizes timeless elegance.','대리석 현관은 시대를 초월한 우아함의 전형이에요.','Her interior choices epitomize understated elegance.','그녀의 인테리어 선택은 절제된 우아함의 전형이에요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_home_C2_03','cultivate','ambiance','cultivate ambiance','분위기를 조성하다','make','의도적으로 시간을 들여 특정한 분위기를 만들어 낸다는 뜻이에요. 호스피탈리티 분야에서 자주 써요.','C2','home',3,0,'living room ambient','Dim lighting and soft jazz cultivate an intimate ambiance for guests.','은은한 조명과 부드러운 재즈가 손님을 위한 친밀한 분위기를 조성해요.','They have cultivated an ambiance that feels both refined and welcoming.','그들은 세련되면서도 환영하는 분위기를 조성했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_home_C2_04','evoke','nostalgia','evoke nostalgia','향수를 불러일으키다','remind','과거에 대한 그리움을 강하게 떠올리게 한다는 격식 표현이에요. 디자인, 영화, 음악 평론에 어울려요.','C2','home',3,0,'vintage wallpaper','The vintage wallpaper evokes nostalgia for postwar Parisian apartments.','빈티지 벽지는 전후 파리 아파트에 대한 향수를 불러일으켜요.','Family photographs lining the hallway evoke a deep sense of nostalgia.','복도에 걸린 가족 사진들은 깊은 향수를 불러일으켜요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_home_C2_05','preserve','heritage','preserve a heritage','유산을 보존하다','keep','문화적, 가문의 유산을 의식적으로 지킨다는 격식 표현이에요. 역사적 주택, 박물관 글에 자주 보여요.','C2','home',3,0,'heritage manor','The family has painstakingly preserved the heritage of the eighteenth-century manor.','그 가문은 18세기 저택의 유산을 정성껏 보존해 왔어요.','Architects worked closely with historians to preserve the building''s heritage.','건축가들은 건물의 유산을 보존하기 위해 역사학자들과 긴밀히 협업했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_humanities_08','preserve','a manuscript','preserve a manuscript','원고를 보존하다','keep','"keep a manuscript"는 어색해요. 원고와 같은 문화유산을 보존할 때는 preserve를 써요.','B1','humanities',1,8,'manuscript library archive preservation history','The library works to preserve ancient manuscripts from deterioration.','도서관은 고대 원고가 손상되지 않도록 보존하기 위해 노력해요.','Digitizing books is a modern way to preserve important manuscripts.','책을 디지털화하는 것은 중요한 원고를 보존하는 현대적인 방법이에요.','Special climate-controlled rooms preserve manuscripts for centuries.','특수 기후 조절실이 원고를 수 세기 동안 보존해요.','She helped preserve a manuscript that was nearly lost in a fire.','그녀는 거의 화재로 소실될 뻔한 원고를 보존하는 데 도움을 줬어요.','Preserving manuscripts is part of cultural memory.','원고를 보존하는 것은 문화적 기억의 일부예요.'),
('col_humanities_09','cite','a source','cite a source','출처를 인용하다','use','"use a source"도 맞지만 cite는 공식적으로 출처를 명시하는 것을 강조해요.','B1','humanities',1,9,'citation source reference academic essay','Always cite your sources when writing an academic essay.','학술 에세이를 작성할 때는 항상 출처를 인용하세요.','She cited three primary sources to support her argument.','그녀는 자신의 주장을 뒷받침하기 위해 세 가지 1차 출처를 인용했어요.','Always cite a source even when paraphrasing.','의역할 때도 항상 출처를 인용하세요.','She cited multiple sources to make her argument credible.','그녀는 주장의 신뢰성을 위해 여러 출처를 인용했어요.','Citing a source properly is a basic academic skill.','출처를 적절히 인용하는 것은 기본적인 학문 기술이에요.'),
('col_humanities_20','raise','awareness','raise awareness','인식을 높이다','increase','"increase awareness"도 맞지만 raise awareness는 사람들의 주의를 끄는 더 자연스러운 표현이에요.','B1','humanities',1,20,'awareness culture education raise society','The humanities help raise awareness of diverse cultural perspectives.','인문학은 다양한 문화적 관점에 대한 인식을 높이는 데 도움이 돼요.','The documentary raised awareness about the loss of endangered languages.','그 다큐멘터리는 멸종 위기 언어의 소실에 대한 인식을 높였어요.','Their research raises awareness of vanishing languages.','그들의 연구는 사라져가는 언어에 대한 인식을 높여요.','A simple poster can raise awareness in your community.','간단한 포스터 하나가 지역사회의 인식을 높일 수 있어요.','She raises awareness through public lectures and writing.','그녀는 공개 강의와 글쓰기를 통해 인식을 높여요.'),
('col_humanities_01','draw','a conclusion','draw a conclusion','결론을 도출하다','make','"make a conclusion"은 어색해요. 논리적 추론으로 결론을 낼 때는 draw를 써요.','B2','humanities',2,1,'conclusion research analysis study humanities','From the evidence, we can draw a conclusion about the author''s intent.','증거로부터 작가의 의도에 대한 결론을 도출할 수 있어요.','Historians draw conclusions by carefully examining primary sources.','역사가들은 1차 자료를 주의 깊게 검토하여 결론을 도출해요.','She drew a conclusion based on the patterns she observed in the data.','그녀는 데이터에서 관찰한 패턴을 바탕으로 결론을 도출했어요.','It''s risky to draw a conclusion from such a small sample.','그렇게 작은 표본에서 결론을 도출하는 것은 위험해요.','They drew a conclusion that surprised even their professors.','그들은 교수님들조차 놀라게 한 결론을 도출했어요.'),
('col_humanities_02','trace','the origins','trace the origins','기원을 추적하다','find','"find the origins"도 맞지만 trace는 역사적 경로를 따라가는 뉘앙스예요.','B2','humanities',2,2,'origins history trace etymology culture','Scholars have traced the origins of the English language to Anglo-Saxon.','학자들은 영어의 기원을 앵글로색슨어까지 추적해 왔어요.','It''s fascinating to trace the origins of common words and phrases.','일반적인 단어와 구절의 기원을 추적하는 것은 흥미로워요.','Linguists traced the origins of the word back to Old Norse.','언어학자들은 그 단어의 기원을 고대 노르드어까지 추적했어요.','The documentary traced the origins of jazz to early African American culture.','다큐멘터리는 재즈의 기원을 초기 아프리카계 미국인 문화까지 추적했어요.','She traced the origins of her family across four continents.','그녀는 자기 가족의 기원을 네 대륙에 걸쳐 추적했어요.'),
('col_humanities_03','conduct','research','conduct research','연구를 수행하다','do','"do research"도 맞지만 conduct research는 더 격식 있고 체계적인 연구를 강조해요.','B2','humanities',2,3,'research academic university library study','She conducted extensive research into medieval literature.','그녀는 중세 문학에 대해 광범위한 연구를 수행했어요.','The university is conducting research on the effects of social media on language.','대학은 소셜 미디어가 언어에 미치는 영향에 대한 연구를 수행하고 있어요.','He conducted research at the British Library for two years.','그는 영국 도서관에서 2년간 연구를 수행했어요.','Conducting research with ethical care is essential.','윤리적 주의를 기울여 연구를 수행하는 것이 필수예요.','She has conducted research across three universities.','그녀는 세 대학에 걸쳐 연구를 수행했어요.'),
('col_humanities_04','interpret','a text','interpret a text','텍스트를 해석하다','read','"read a text"는 단순히 읽는 것이고 interpret는 의미를 분석하고 해석하는 것이에요.','B2','humanities',2,4,'text interpretation literature analysis reading','Students are asked to interpret the text from a feminist perspective.','학생들은 페미니스트 관점에서 텍스트를 해석하도록 요청받아요.','How you interpret a text depends heavily on your cultural background.','텍스트를 어떻게 해석하는지는 문화적 배경에 크게 좌우돼요.','Different cultures interpret the same text in very different ways.','서로 다른 문화는 같은 텍스트를 매우 다른 방식으로 해석해요.','He interpreted the text through a postcolonial lens.','그는 그 텍스트를 탈식민주의 관점에서 해석했어요.','Interpreting a text requires both knowledge and imagination.','텍스트를 해석하려면 지식과 상상력이 모두 필요해요.'),
('col_humanities_07','analyse','a text','analyse a text','텍스트를 분석하다','study','"study a text"도 맞지만 analyse는 더 비판적이고 체계적인 분석을 강조해요.','B2','humanities',2,7,'analysis text literary critical study','The class was asked to analyse the text using literary theory.','수업에서 문학 이론을 사용하여 텍스트를 분석하도록 요청받았어요.','She analysed the text to identify recurring themes and motifs.','그녀는 반복되는 주제와 모티프를 찾아내기 위해 텍스트를 분석했어요.','She analysed the text by identifying repeated imagery.','그녀는 반복되는 이미지를 찾아내며 텍스트를 분석했어요.','Analysing a text closely takes time and careful attention.','텍스트를 면밀히 분석하는 데는 시간과 세심한 주의가 필요해요.','He analysed the text using multiple critical frameworks.','그는 여러 비평적 틀을 사용하여 텍스트를 분석했어요.'),
('col_humanities_10','examine','evidence','examine evidence','증거를 검토하다','look at','"look at evidence"도 쓰이지만 examine은 더 꼼꼼하고 체계적인 검토를 강조해요.','B2','humanities',2,10,'evidence research examine analyze study','The historian examined the evidence before writing her conclusions.','역사가는 결론을 쓰기 전에 증거를 검토했어요.','We need to examine all available evidence before making a judgment.','판단을 내리기 전에 모든 가용 증거를 검토해야 해요.','She examined the evidence before forming a judgment.','그녀는 판단을 내리기 전에 증거를 검토했어요.','They examined the evidence from multiple angles.','그들은 여러 각도에서 증거를 검토했어요.','Examining evidence carefully prevents premature conclusions.','증거를 신중히 검토하면 성급한 결론을 막을 수 있어요.'),
('col_humanities_11','explore','a theme','explore a theme','주제를 탐구하다','find','"find a theme"도 맞지만 explore는 주제를 깊이 탐구하는 뉘앙스예요.','B2','humanities',2,11,'theme exploration literature analysis subject','The novel explores the theme of identity in modern society.','그 소설은 현대 사회에서의 정체성이라는 주제를 탐구해요.','The lecture explored the theme of power in Shakespeare''s plays.','강의는 셰익스피어 희곡에서 권력이라는 주제를 탐구했어요.','The poem explores the theme of memory and time.','그 시는 기억과 시간이라는 주제를 탐구해요.','Many novels explore the theme of belonging.','많은 소설들이 소속감이라는 주제를 탐구해요.','She explored the theme of solitude through her photography.','그녀는 자기 사진을 통해 고독이라는 주제를 탐구했어요.'),
('col_humanities_13','convey','meaning','convey meaning','의미를 전달하다','show','"show meaning"도 맞지만 convey는 의도적으로 의미를 전달하는 뉘앙스예요.','B2','humanities',2,13,'meaning convey communication language expression','The painting conveys a deep sense of loss through its dark colour palette.','그 그림은 어두운 색채 팔레트를 통해 깊은 상실감을 전달해요.','Language can convey subtle meanings that body language cannot.','언어는 몸짓 언어가 전달하지 못하는 미묘한 의미를 전달할 수 있어요.','Music can convey meaning that words cannot.','음악은 말이 전달할 수 없는 의미를 전달할 수 있어요.','A single image can convey meaning across cultures.','한 장의 이미지가 문화를 넘어 의미를 전달할 수 있어요.','Poets choose every word carefully to convey precise meaning.','시인들은 정확한 의미를 전달하기 위해 모든 단어를 신중히 선택해요.'),
('col_humanities_15','make','an argument','make an argument','주장을 펼치다','say','"say an argument"는 어색해요. 논거를 제시하며 주장할 때는 make an argument를 써요.','B2','humanities',2,15,'argument essay academic debate humanities','The essay makes a compelling argument for the preservation of indigenous languages.','그 에세이는 토착 언어 보존을 위한 설득력 있는 주장을 펼쳐요.','She made a strong argument during the seminar discussion.','그녀는 세미나 토론에서 강력한 주장을 펼쳤어요.','She made an argument that has shaped the field for years.','그녀는 그 분야를 수년간 형성해 온 주장을 펼쳤어요.','He made a careful argument supported by detailed evidence.','그는 자세한 증거로 뒷받침된 신중한 주장을 펼쳤어요.','Making an argument well requires both logic and clarity.','주장을 잘 펼치려면 논리와 명확성이 모두 필요해요.'),
('col_humanities_16','reflect on','the past','reflect on the past','과거를 성찰하다','think about','"think about the past"도 맞지만 reflect on은 더 깊은 사고와 통찰을 강조해요.','B2','humanities',2,16,'reflection past history memory thinking','Historians reflect on the past to understand patterns in human behavior.','역사가들은 인간 행동의 패턴을 이해하기 위해 과거를 성찰해요.','The memoir encourages readers to reflect on their own past experiences.','그 회고록은 독자들이 자신의 과거 경험을 성찰하도록 이끌어요.','Older people often reflect on the past with mixed emotions.','노인들은 종종 복잡한 감정으로 과거를 성찰해요.','She reflected on the past while writing her memoir.','그녀는 회고록을 쓰면서 과거를 성찰했어요.','Reflecting on the past can give clarity for the future.','과거를 성찰하는 것은 미래를 위한 명확함을 줄 수 있어요.'),
('col_humanities_19','place','in context','place in context','맥락 속에 위치시키다','explain','"explain"도 맞지만 place in context는 더 넓은 배경 속에서 이해하는 뉘앙스예요.','B2','humanities',2,19,'context history culture setting interpretation','To understand the poem, you need to place it in its historical context.','시를 이해하려면 역사적 맥락 속에 위치시켜야 해요.','She placed the painting in the context of the Renaissance movement.','그녀는 그 그림을 르네상스 운동의 맥락 속에 위치시켰어요.','You can''t truly understand a poem without placing it in context.','시를 맥락 속에 위치시키지 않고는 진정으로 이해할 수 없어요.','She placed the painting in the context of the artist''s political views.','그녀는 그 그림을 작가의 정치적 견해의 맥락 속에 위치시켰어요.','Placing a quote in context changes how we read it.','인용을 맥락 속에 위치시키면 그것을 읽는 방식이 바뀌어요.'),
('col_humanities_05','challenge','a theory','challenge a theory','이론에 의문을 제기하다','question','"question a theory"도 맞지만 challenge는 더 적극적인 반박을 강조해요.','C1','humanities',3,5,'theory challenge critique academic debate','New archaeological findings challenge the established theory about ancient migration.','새로운 고고학적 발견은 고대 이주에 대한 기존 이론에 의문을 제기해요.','The essay challenges the theory that art reflects society passively.','그 에세이는 예술이 사회를 수동적으로 반영한다는 이론에 의문을 제기해요.','Her dissertation challenges the theory of cultural homogenization.','그녀의 논문은 문화 동질화 이론에 의문을 제기해요.','New evidence challenges a theory that''s been accepted for decades.','새로운 증거가 수십 년 동안 받아들여진 이론에 의문을 제기해요.','Scholars constantly challenge theories with new findings.','학자들은 새로운 발견으로 이론에 끊임없이 의문을 제기해요.'),
('col_humanities_06','shed light on','history','shed light on history','역사에 빛을 비추다, 역사를 밝히다','explain','"explain history"도 맞지만 shed light on은 새로운 이해나 통찰을 제공하는 뉘앙스예요.','C1','humanities',3,6,'history revelation research light understanding','New documents shed light on a period of history that was previously misunderstood.','새로운 문서들이 이전에 잘못 이해됐던 역사적 시기를 밝혀줬어요.','The research sheds light on how ancient societies dealt with climate change.','그 연구는 고대 사회가 기후 변화에 어떻게 대처했는지를 밝혀줘요.','Her book sheds light on an overlooked period of music history.','그녀의 책은 간과된 음악 역사의 한 시기에 빛을 비춰요.','Newly translated texts shed light on ancient daily life.','새로 번역된 텍스트들이 고대 일상 생활에 빛을 비춰요.','The exhibition sheds light on stories rarely told in textbooks.','그 전시는 교과서에 거의 나오지 않는 이야기에 빛을 비춰요.'),
('col_humanities_12','question','assumptions','question assumptions','가정에 의문을 품다','doubt','"doubt assumptions"도 맞지만 question은 건설적인 비판적 사고를 강조해요.','C1','humanities',3,12,'question assumption philosophy critical culture','Great philosophers question the assumptions of their time.','위대한 철학자들은 자신의 시대의 가정에 의문을 품어요.','The course encourages students to question their own cultural assumptions.','그 과목은 학생들이 자신의 문화적 가정에 의문을 품도록 독려해요.','Travel can quietly help you question assumptions you''ve held for years.','여행은 수년간 가져온 가정에 조용히 의문을 품게 할 수 있어요.','A good education teaches you to question assumptions, not just accept them.','좋은 교육은 가정을 단순히 받아들이는 것이 아니라 의문을 품도록 가르쳐요.','She questions assumptions about gender in her academic writing.','그녀는 학문적 글쓰기에서 성별에 대한 가정에 의문을 품어요.'),
('col_humanities_14','draw on','sources','draw on sources','자료를 활용하다','use','"use sources"도 맞지만 draw on은 다양한 출처에서 선택적으로 활용하는 뉘앙스예요.','C1','humanities',3,14,'sources research draw academic reference','The author drew on a wide range of historical sources to write the novel.','저자는 소설을 쓰기 위해 다양한 역사적 자료를 활용했어요.','Good academic writing draws on both primary and secondary sources.','좋은 학술 글쓰기는 1차 및 2차 자료를 모두 활용해요.','She drew on sources from three different languages for her thesis.','그녀는 논문을 위해 세 가지 다른 언어의 자료를 활용했어요.','He drew on personal interviews to enrich his research.','그는 연구를 풍부하게 하기 위해 개인 인터뷰를 활용했어요.','Drawing on diverse sources strengthens academic writing.','다양한 자료를 활용하는 것은 학문적 글쓰기를 강화해요.'),
('col_humanities_17','engage with','literature','engage with literature','문학과 상호작용하다','read','"read literature"도 맞지만 engage with는 단순히 읽는 것을 넘어 적극적으로 상호작용하는 것이에요.','C1','humanities',3,17,'literature engage reading critical thinking','Students are encouraged to actively engage with the literature, not just read it.','학생들은 문학을 단순히 읽는 것을 넘어 적극적으로 상호작용하도록 독려받아요.','She engages with literature by asking questions and forming her own opinions.','그녀는 질문하고 자신의 의견을 형성함으로써 문학과 상호작용해요.','She teaches her students to actively engage with literature.','그녀는 학생들에게 문학과 적극적으로 상호작용하도록 가르쳐요.','Engaging with literature can change how you see the world.','문학과 상호작용하면 세상을 보는 방식이 바뀔 수 있어요.','He engages with literature by writing reflections after each book.','그는 책마다 성찰을 적으며 문학과 상호작용해요.'),
('col_humanities_18','reshape','history','reshape history','역사를 새롭게 쓰다','change','"change history"도 맞지만 reshape는 역사의 이해나 방향을 바꾸는 뉘앙스예요.','C1','humanities',3,18,'history reshape change society impact','New discoveries can reshape our understanding of ancient history.','새로운 발견은 고대 역사에 대한 우리의 이해를 새롭게 쓸 수 있어요.','Social movements have the power to reshape history.','사회 운동은 역사를 새롭게 쓸 힘을 가지고 있어요.','A single artifact can reshape history as we know it.','단 하나의 유물이 우리가 아는 역사를 새롭게 쓸 수 있어요.','Recent translations are reshaping history in classrooms.','최근 번역들이 교실에서 역사를 새롭게 쓰고 있어요.','Movements led by women have reshaped history many times.','여성들이 이끈 운동이 여러 차례 역사를 새롭게 썼어요.'),
('col_humanities_C1_01','explore','themes','explore themes','주제를 탐구하다','see','문학, 영화, 예술 작품의 주제를 깊이 파헤친다는 격식 표현이에요. 비평이나 학술 글의 표준이에요.','C1','humanities',2,0,'open book','The novel explores themes of memory, loss, and identity.','그 소설은 기억, 상실, 정체성이라는 주제를 탐구해요.','Her latest essay explores themes that recur throughout postwar literature.','그녀의 최신 에세이는 전후 문학 전반에 반복되는 주제를 탐구해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_humanities_C1_02','analyze','texts','analyze texts','텍스트를 분석하다','read','텍스트의 구조, 의미, 맥락을 비판적으로 살핀다는 학문적 표현이에요. 인문학 강의실의 핵심 동사예요.','C1','humanities',2,0,'literary analysis','Students learn to analyze texts using a range of critical frameworks.','학생들은 다양한 비평 틀을 활용해 텍스트를 분석하는 법을 배워요.','She analyzed the texts side by side to trace the author''s evolution.','그녀는 작가의 변천을 추적하기 위해 텍스트들을 나란히 분석했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_humanities_C1_03','trace','origins','trace the origins','기원을 추적하다','find','어떤 개념이나 관습의 역사적 출처를 거슬러 올라간다는 뜻이에요. 역사학, 어원학에서 자주 써요.','C1','humanities',2,0,'ancient ruins','The book traces the origins of modern democracy to ancient Athens.','그 책은 현대 민주주의의 기원을 고대 아테네까지 추적해요.','Linguists trace the origins of the word to a medieval Latin root.','언어학자들은 그 단어의 기원을 중세 라틴어 어근까지 추적해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_humanities_C1_04','draw','parallels','draw parallels','유사점을 끌어내다','find','서로 다른 두 가지 사이의 닮은 점을 짚어낸다는 격식 표현이에요. 비교 분석 글에서 표준이에요.','C1','humanities',2,0,'parallel lines','The essay draws parallels between Roman and modern American politics.','그 에세이는 로마와 현대 미국 정치 사이의 유사점을 끌어내요.','Critics have drawn parallels between the two filmmakers'' visual styles.','비평가들은 두 영화감독의 시각적 스타일 사이에서 유사점을 끌어냈어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_humanities_C1_05','challenge','interpretations','challenge interpretations','해석에 이의를 제기하다','change','기존의 학설이나 해석에 비판적으로 도전한다는 뜻이에요. 학술 논문 서론에서 자주 보이는 표현이에요.','C1','humanities',2,0,'manuscript study','Her dissertation challenges long-standing interpretations of the text.','그녀의 박사 논문은 그 텍스트에 대한 오랜 해석에 이의를 제기해요.','Newly discovered manuscripts have challenged earlier interpretations of the war.','새로 발견된 사본들은 그 전쟁에 대한 기존 해석에 이의를 제기해 왔어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_humanities_C2_01','interrogate','assumptions','interrogate assumptions','전제를 비판적으로 검토하다','question','단순한 의심이 아니라 학문적으로 철저히 따져본다는 인문학·사회과학 학술 용어예요. ''question''보다 훨씬 무거운 무게감이에요.','C2','humanities',3,0,'philosophy seminar','The seminar urged students to interrogate the assumptions underlying classical economic theory.','그 세미나는 학생들에게 고전 경제 이론의 전제를 비판적으로 검토하라고 촉구했어요.','Good scholarship interrogates its own assumptions before critiquing others''.','훌륭한 학문은 타인을 비판하기에 앞서 자기 자신의 전제를 비판적으로 검토해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_humanities_C2_02','deconstruct','narrative','deconstruct a narrative','서사를 해체하다','analyze','데리다 이후 문학 비평의 표준 용어로, 서사의 이면 구조와 모순을 드러내는 작업이에요. 학술 논문에서 표준이에요.','C2','humanities',3,0,'library deconstruction','Postcolonial scholars deconstruct the dominant narrative of colonial benevolence.','탈식민주의 학자들은 식민지 자비라는 지배적 서사를 해체해요.','The essay deconstructs the narrative of inevitable progress.','그 에세이는 필연적 진보라는 서사를 해체해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_humanities_C2_03','contextualize','discourse','contextualize discourse','담론을 맥락화하다','place','담론을 역사적·사회적 맥락 속에서 이해할 수 있도록 자리매김한다는 학술 표현이에요. 인문학 논문의 핵심 동작이에요.','C2','humanities',3,0,'open archive book','The chapter contextualizes the discourse on liberty within Enlightenment thought.','그 장은 자유에 관한 담론을 계몽주의 사상의 맥락 속에 자리매김해요.','We must contextualize the discourse before pronouncing judgment.','판단을 내리기 전에 담론을 맥락화해야 해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_humanities_C2_04','trace','lineage','trace a lineage','계보를 추적하다','find','사상이나 양식의 기원과 흐름을 학술적으로 거슬러 올라간다는 표현이에요. 사상사·미술사·문학사에 필수적이에요.','C2','humanities',3,0,'genealogy chart','The monograph traces the intellectual lineage from Kant to contemporary critical theory.','그 논문은 칸트부터 현대 비판 이론까지의 지적 계보를 추적해요.','She traced the lineage of feminist thought across three continents.','그녀는 세 대륙에 걸친 페미니즘 사상의 계보를 추적했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_humanities_C2_05','elucidate','meaning','elucidate meaning','의미를 명확히 밝히다','explain','불분명한 의미를 학술적이고 체계적으로 해명한다는 격식 동사예요. ''explain''보다 훨씬 무거운 학문적 어조예요.','C2','humanities',3,0,'ancient text annotation','The footnotes elucidate the meaning of arcane theological terms.','각주들은 난해한 신학 용어의 의미를 명확히 밝혀요.','A careful reading of the original Greek elucidates the meaning lost in translation.','원전 그리스어를 세심히 읽으면 번역에서 사라진 의미가 명확히 드러나요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_media_21','take','photo','take a photo','사진을 찍다','make','"make a photo"는 어색해요. 사진 촬영은 take a photo (또는 take a picture).','A1','media',1,0,'camera photo person photographer landscape','Can you take a photo of us?','우리 사진 좀 찍어 줄 수 있어요?','She took hundreds of photos on her trip.','그녀는 여행에서 수백 장의 사진을 찍었어요.','I love taking photos of sunsets.','저는 석양 사진 찍는 걸 좋아해요.','Don''t take photos in the museum.','박물관에서는 사진을 찍지 마세요.','He took a perfect photo of the city skyline.','그는 도시 스카이라인의 완벽한 사진을 찍었어요.'),
('col_media_15','share','a post','share a post','게시물을 공유하다','forward','"forward"는 이메일에 더 잘 쓰여요. 소셜 미디어에서는 share를 써요.','A2','media',1,15,'share post social media spread content','She shared the post and it reached thousands of people.','그녀가 게시물을 공유하자 수천 명에게 도달했어요.','Could you share the post to help spread the word?','소식을 퍼뜨리는 데 도움이 되도록 게시물을 공유해 줄 수 있어요?','Please share the post if you found it helpful.','도움이 되셨다면 게시물을 공유해 주세요.','He shared a post about mental health awareness.','그는 정신 건강 인식에 대한 게시물을 공유했어요.','Sharing a post takes a second but can have a big impact.','게시물을 공유하는 데 1초밖에 안 걸리지만 큰 영향을 줄 수 있어요.'),
('col_media_22','post','comment','post a comment','댓글을 달다','do','"do a comment"는 어색해요. SNS에 댓글 달 때는 post a comment 또는 leave a comment.','A2','media',1,0,'phone social media comment section typing','She posted a thoughtful comment on the article.','그녀는 그 기사에 사려 깊은 댓글을 달았어요.','I posted a comment but no one replied.','댓글을 달았는데 아무도 답하지 않았어요.','Don''t post negative comments online.','온라인에 부정적인 댓글을 달지 마세요.','He posts comments on every photo she shares.','그는 그녀가 공유하는 모든 사진에 댓글을 달아요.','I post comments to support creators I follow.','제가 팔로우하는 크리에이터를 응원하려고 댓글을 달아요.'),
('col_media_23','share','link','share a link','링크를 공유하다','send','"send a link"도 가능하지만 1:1 메신저에 가까운 느낌. 공개 공유는 share a link.','A2','media',1,0,'phone link sharing social media chat','Could you share the link with the team?','팀에 그 링크를 공유해 줄 수 있어요?','I shared the article link on social media.','SNS에 그 기사 링크를 공유했어요.','She shared a link to a great podcast.','그녀는 좋은 팟캐스트 링크를 공유했어요.','Don''t share links from suspicious websites.','의심스러운 사이트의 링크는 공유하지 마세요.','He shared the link with everyone in the group chat.','그는 그룹 채팅의 모두에게 링크를 공유했어요.'),
('col_media_01','go','viral','go viral','바이럴이 되다','become','"become viral"도 쓰이지만 go viral이 더 자연스럽고 자주 쓰여요.','B1','media',1,1,'viral social media video trending internet','The video went viral and got over ten million views in a week.','그 영상은 바이럴이 되어 일주일 만에 천만 조회수를 넘었어요.','Her post went viral after a celebrity shared it.','유명인이 공유한 후 그녀의 게시물이 바이럴이 됐어요.','Her dance challenge video went viral overnight.','그녀의 댄스 챌린지 영상이 하룻밤 만에 바이럴이 됐어요.','Once a meme goes viral, it spreads to every platform.','밈이 한번 바이럴이 되면 모든 플랫폼으로 퍼져요.','The cat video went viral and made him a small fortune.','그 고양이 영상이 바이럴이 되어 그에게 작은 부를 가져다 줬어요.'),
('col_media_03','get','followers','get followers','팔로워를 얻다','have','"have followers"는 현재 상태이고, get은 새로 얻는 것을 강조해요.','B1','media',1,3,'followers social media influencer content creator','She got thousands of followers overnight after a viral post.','그녀는 바이럴 게시물 이후 하룻밤 만에 수천 명의 팔로워를 얻었어요.','How did you get so many followers so quickly?','어떻게 그렇게 빨리 많은 팔로워를 얻었어요?','I''m trying to get followers by being authentic, not by chasing trends.','저는 트렌드를 좇기보다 진솔함으로 팔로워를 얻으려고 해요.','She got followers from her cooking videos almost by accident.','그녀는 요리 영상으로 거의 우연히 팔로워를 얻었어요.','Many influencers get followers through consistent posting and engagement.','많은 인플루언서들이 꾸준한 게시물과 소통을 통해 팔로워를 얻어요.'),
('col_media_04','post','content','post content','콘텐츠를 올리다','upload','"upload"도 맞지만 post는 소셜 미디어에서 더 일상적으로 쓰여요.','B1','media',1,4,'content social media posting influencer','She posts content every day to keep her audience engaged.','그녀는 팔로워들의 참여를 유지하기 위해 매일 콘텐츠를 올려요.','He posts a variety of content — videos, photos, and stories.','그는 영상, 사진, 스토리 등 다양한 콘텐츠를 올려요.','I post content twice a week to keep things sustainable.','저는 지속 가능하도록 일주일에 두 번 콘텐츠를 올려요.','She posts content that''s educational and entertaining at the same time.','그녀는 교육적이면서도 재미있는 콘텐츠를 올려요.','Posting content regularly helps you build a real audience.','콘텐츠를 꾸준히 올리면 진정한 팬층을 쌓는 데 도움이 돼요.'),
('col_media_06','keep','updated','keep updated','최신 정보를 유지하다','stay','"stay updated"도 맞지만 keep updated가 더 지속적인 뉘앙스예요.','B1','media',2,6,'updated news app information digital','Follow our page to keep updated on the latest news.','최신 뉴스를 받아보려면 저희 페이지를 팔로우하세요.','She keeps updated by reading news apps every morning.','그녀는 매일 아침 뉴스 앱을 읽으며 최신 정보를 유지해요.','I keep updated on tech news through a weekly newsletter.','저는 주간 뉴스레터를 통해 기술 뉴스 최신 정보를 유지해요.','She keeps updated on world events by listening to podcasts.','그녀는 팟캐스트를 들으며 세계 뉴스에 대한 최신 정보를 유지해요.','You can keep updated by following just a few reliable sources.','몇 개의 믿을 만한 소스만 팔로우해도 최신 정보를 유지할 수 있어요.'),
('col_media_10','get','trending','get trending','트렌딩이 되다','become','"become trending"은 어색해요. 트렌딩이 될 때는 get trending을 써요.','B1','media',1,10,'trending social media viral hashtag internet','The hashtag got trending within hours of the announcement.','그 해시태그는 발표 후 몇 시간 만에 트렌딩이 됐어요.','Her music video got trending after a big influencer shared it.','유명 인플루언서가 공유한 후 그녀의 뮤직비디오가 트렌딩이 됐어요.','A meme about the election got trending in a few hours.','선거에 관한 밈이 몇 시간 만에 트렌딩이 됐어요.','Her song got trending after appearing in a popular drama.','그녀의 노래는 인기 드라마에 나온 후 트렌딩이 됐어요.','It''s hard to predict what will get trending on any given day.','어느 날 무엇이 트렌딩이 될지 예측하기는 어려워요.'),
('col_media_11','stream','content','stream content','콘텐츠를 스트리밍하다','watch','"watch content"도 맞지만 stream은 온라인 동영상 서비스를 강조해요.','B1','media',1,11,'streaming netflix content watching online','Millions of people stream content on platforms like Netflix daily.','수백만 명이 매일 넷플릭스 같은 플랫폼에서 콘텐츠를 스트리밍해요.','She streams live content every Friday evening.','그녀는 매주 금요일 저녁에 라이브 콘텐츠를 스트리밍해요.','I stream content while I cook dinner most evenings.','저는 저녁 식사를 요리하면서 대부분 콘텐츠를 스트리밍해요.','She streams content from independent creators rather than big studios.','그녀는 대형 스튜디오보다 독립 창작자들의 콘텐츠를 스트리밍해요.','Streaming content during long flights makes the time pass faster.','긴 비행 중에 콘텐츠를 스트리밍하면 시간이 더 빨리 가요.'),
('col_media_14','go','live','go live','라이브 방송을 하다','start','"start a broadcast"도 맞지만 go live는 소셜 미디어와 방송에서 자주 쓰여요.','B1','media',1,14,'live stream broadcast social media real-time','She went live on Instagram to announce the news.','그녀는 뉴스를 발표하기 위해 인스타그램에서 라이브 방송을 했어요.','The channel goes live every day at 7 p.m.','그 채널은 매일 오후 7시에 라이브 방송을 해요.','I''m going live in 10 minutes to answer your questions.','여러분의 질문에 답하기 위해 10분 후에 라이브 방송 갈게요.','He went live for the first time and got over 5,000 viewers.','그는 처음으로 라이브 방송을 했는데 5,000명 이상의 시청자가 봤어요.','She goes live every Sunday for a cooking session with fans.','그녀는 매주 일요일 팬들과 함께 요리 라이브를 해요.'),
('col_media_02','make','news','make news','뉴스가 되다','do','"do news"는 틀린 표현이에요. 뉴스에 나올 때는 make news를 써요.','B2','media',2,2,'news media headline coverage broadcast','The scandal made headlines and dominated the news for weeks.','그 스캔들은 헤드라인을 장식하며 몇 주 동안 뉴스를 지배했어요.','A small local story unexpectedly made national news.','작은 지역 소식이 뜻밖에 전국 뉴스가 됐어요.','The discovery made news around the world.','그 발견은 전 세계에서 뉴스가 됐어요.','Her career as an artist first made news in her hometown paper.','아티스트로서의 그녀의 경력은 고향 신문에서 처음 뉴스가 됐어요.','The minor incident unexpectedly made national news.','그 작은 사건이 뜻밖에 전국 뉴스가 됐어요.'),
('col_media_05','run','an ad','run an ad','광고를 집행하다','make','"make an ad"는 광고를 제작하는 것이고, run은 집행·게재하는 것이에요.','B2','media',2,5,'advertisement campaign digital media marketing','The company ran a targeted ad campaign on social media.','회사는 소셜 미디어에서 타겟 광고 캠페인을 집행했어요.','They''re running ads on three different platforms this month.','이번 달 세 개의 플랫폼에서 광고를 집행하고 있어요.','They ran an ad during the World Cup final to reach a wide audience.','그들은 더 많은 청중에게 도달하기 위해 월드컵 결승전 동안 광고를 집행했어요.','We ran an ad for two weeks and saw a 30% boost in sales.','우리는 2주간 광고를 집행했고 매출이 30% 증가했어요.','Running an ad on social media is much cheaper than on TV.','소셜 미디어에 광고를 집행하는 게 TV보다 훨씬 저렴해요.'),
('col_media_08','hold','attention','hold attention','관심을 유지하다','get','"get attention"은 처음 끌 때이고, hold는 계속 유지하는 것이에요.','B2','media',2,8,'attention audience engagement content media','The documentary held the audience''s attention from start to finish.','그 다큐멘터리는 처음부터 끝까지 관객의 관심을 유지했어요.','It''s hard to hold people''s attention on social media for long.','소셜 미디어에서 사람들의 관심을 오래 유지하기는 어려워요.','A strong opening line helps hold the audience''s attention.','강력한 첫 문장이 청중의 관심을 유지하는 데 도움이 돼요.','The series held viewers'' attention for all eight episodes.','그 시리즈는 여덟 화 전체에 걸쳐 시청자들의 관심을 유지했어요.','It''s tough to hold attention on TikTok past the first three seconds.','틱톡에서 처음 3초가 지난 후 관심을 유지하기는 어려워요.'),
('col_media_09','make','a headline','make a headline','헤드라인을 장식하다','do','"do a headline"은 틀린 표현이에요. 헤드라인에 나올 때는 make를 써요.','B2','media',2,9,'headline news media front page report','The scandal made the front page headline of every major newspaper.','그 스캔들은 모든 주요 신문의 1면 헤드라인을 장식했어요.','Her performance made headlines across the entertainment media.','그녀의 공연은 엔터테인먼트 미디어 전반의 헤드라인을 장식했어요.','Their merger made a headline in every business magazine.','그들의 합병이 모든 비즈니스 잡지의 헤드라인을 장식했어요.','The athlete made headlines for breaking the world record.','그 운동선수는 세계 기록을 깨면서 헤드라인을 장식했어요.','She made a headline in the local paper for her volunteer work.','그녀는 자원봉사 활동으로 지역 신문 헤드라인을 장식했어요.'),
('col_media_12','build','an audience','build an audience','팬층을 쌓다','get','"get an audience"도 맞지만 build는 점진적으로 쌓아가는 뉘앙스예요.','B2','media',2,12,'audience followers creator social media','It takes time and consistency to build an audience from scratch.','처음부터 팬층을 쌓으려면 시간과 일관성이 필요해요.','She built a loyal audience by posting authentic content.','그녀는 진솔한 콘텐츠를 올림으로써 충성스러운 팬층을 쌓았어요.','She built an audience of half a million followers in just a year.','그녀는 단 1년 만에 50만 명의 팔로워층을 쌓았어요.','You build an audience by giving people real value.','사람들에게 진정한 가치를 줌으로써 팬층을 쌓아요.','Building an audience takes more patience than most people expect.','팬층을 쌓는 데는 사람들이 예상하는 것보다 더 많은 인내가 필요해요.'),
('col_media_13','cover','a story','cover a story','기사를 취재하다','report','"report a story"도 맞지만 cover는 심층 취재를 강조해요.','B2','media',2,13,'journalism coverage story reporter news','The reporter was sent to cover the story on the ground.','기자는 현장에서 그 이야기를 취재하기 위해 파견됐어요.','The magazine has been covering this story for three months.','그 잡지는 3개월 동안 이 이야기를 취재해 왔어요.','The team flew across the country to cover the story.','그 팀은 이야기를 취재하기 위해 전국을 가로질러 비행했어요.','She covered the story from both sides for a balanced view.','그녀는 균형 잡힌 시각을 위해 양쪽에서 이야기를 취재했어요.','Covering a story properly takes time, sources, and verification.','이야기를 제대로 취재하려면 시간과 출처, 검증이 필요해요.'),
('col_media_17','edit','footage','edit footage','영상을 편집하다','cut','"cut footage"는 일부만 의미해요. 영상 편집은 edit footage를 써요.','B2','media',2,17,'editing video footage post-production content','He spent hours editing footage for the documentary.','그는 다큐멘터리 영상을 편집하는 데 몇 시간을 보냈어요.','She edits all her own footage before uploading to YouTube.','그녀는 유튜브에 업로드하기 전에 자신의 영상을 직접 편집해요.','He edits footage late at night when he can focus best.','그는 가장 집중이 잘 되는 늦은 밤에 영상을 편집해요.','She learned to edit footage from free tutorials online.','그녀는 무료 온라인 튜토리얼로 영상 편집을 배웠어요.','Editing footage well takes far longer than shooting it.','영상을 잘 편집하는 데는 촬영하는 것보다 훨씬 더 오래 걸려요.'),
('col_media_18','broadcast','live','broadcast live','생방송하다','stream','"stream live"도 맞지만 broadcast는 더 전통적인 방송 표현이에요.','B2','media',2,18,'broadcast live TV news coverage','The event will be broadcast live on national television.','그 행사는 전국 방송에서 생방송으로 방영될 예정이에요.','They broadcast live from the scene of the disaster.','그들은 재해 현장에서 생방송을 했어요.','They broadcast live from the stadium during the final game.','그들은 결승전 동안 경기장에서 생방송을 했어요.','The concert will be broadcast live in over 60 countries.','그 콘서트는 60여 개국에서 생방송으로 방영될 예정이에요.','She broadcasts live every weekday morning at six.','그녀는 매 평일 아침 6시에 생방송을 해요.'),
('col_media_19','reach','an audience','reach an audience','청중에게 닿다','get','"get an audience"도 맞지만 reach는 메시지가 도달하는 것을 강조해요.','B2','media',2,19,'audience reach media campaign global','Social media allows creators to reach a global audience.','소셜 미디어는 창작자들이 전 세계 청중에게 닿을 수 있게 해줘요.','The campaign reached a much wider audience than expected.','그 캠페인은 예상보다 훨씬 더 많은 청중에게 닿았어요.','Translating subtitles helps creators reach a global audience.','자막을 번역하는 것이 창작자들이 전 세계 청중에게 닿는 데 도움이 돼요.','Their podcast reached an audience of more than two million.','그들의 팟캐스트는 200만 명이 넘는 청중에게 도달했어요.','Reaching the right audience matters more than reaching a big one.','많은 청중에 닿는 것보다 적절한 청중에게 닿는 게 더 중요해요.'),
('col_media_07','break','news','break news','뉴스를 최초로 보도하다','report','"report news"도 맞지만 break news는 최초로 보도하는 것을 강조해요.','C1','media',2,7,'breaking news journalist scoop exclusive','The journalist broke the news about the government scandal.','그 기자는 정부 스캔들 뉴스를 최초로 보도했어요.','Which outlet was first to break the story?','어느 매체가 그 이야기를 최초로 보도했어요?','A small online outlet broke the story before mainstream media did.','주류 미디어보다 작은 온라인 매체가 그 이야기를 최초로 보도했어요.','Local journalists broke the news of the corruption scandal.','지역 기자들이 부패 스캔들 뉴스를 최초로 보도했어요.','They broke the news with verified evidence to back it up.','그들은 뒷받침할 검증된 증거와 함께 뉴스를 최초로 보도했어요.'),
('col_media_16','gain','exposure','gain exposure','노출을 얻다','get','"get exposure"도 맞지만 gain은 점차 쌓아가는 뉘앙스예요.','C1','media',3,16,'exposure publicity brand media recognition','The small brand gained huge exposure after a celebrity mention.','그 소규모 브랜드는 유명인의 언급 이후 엄청난 노출을 얻었어요.','Being featured in a popular magazine helped them gain exposure.','인기 잡지에 실리는 것이 그들이 노출을 얻는 데 도움이 됐어요.','The small designer gained exposure after a TV stylist used her dress.','TV 스타일리스트가 그녀의 드레스를 사용한 후 그 소규모 디자이너는 노출을 얻었어요.','Performing at the festival helped the band gain exposure abroad.','축제 공연이 그 밴드가 해외에서 노출을 얻는 데 도움이 됐어요.','Open source projects can help developers gain exposure with employers.','오픈소스 프로젝트는 개발자들이 고용주들에게 노출을 얻는 데 도움이 될 수 있어요.'),
('col_media_20','pull','a story','pull a story','기사를 내리다','delete','"delete a story"는 온라인에서 쓰이고, pull a story는 방송/인쇄에서 더 쓰여요.','C1','media',3,20,'journalism retract story editorial media','The editor decided to pull the story due to legal concerns.','편집장은 법적 우려로 인해 기사를 내리기로 결정했어요.','The station pulled the story after verifying the facts were wrong.','방송국은 사실이 틀렸음을 확인한 후 그 기사를 내렸어요.','They pulled the story before it could go to print.','그들은 인쇄되기 전에 그 기사를 내렸어요.','The producer pulled the segment after viewer complaints.','프로듀서는 시청자 항의 후에 그 코너를 내렸어요.','Pulling a story is rare but sometimes necessary for accuracy.','기사를 내리는 건 드물지만 정확성을 위해 때로는 필요해요.'),
('col_media_C1_01','go','viral','go viral','입소문 나다','become','콘텐츠가 인터넷에서 급속도로 퍼지는 현상을 뜻해요. 미디어, 마케팅 분야의 핵심 표현이에요.','C1','media',2,0,'viral video phone','Her dance video went viral overnight.','그녀의 댄스 영상은 하룻밤 사이에 입소문이 났어요.','Brands dream of creating content that goes viral.','브랜드들은 입소문 나는 콘텐츠를 만드는 걸 꿈꿔요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_media_C1_02','draw','attention','draw attention','주목을 끌다','pull','사람들의 시선이나 관심을 모은다는 격식 있는 표현이에요. 뉴스, 광고, 학술 글에서 두루 써요.','C1','media',2,0,'spotlight news camera','The documentary drew attention to climate change.','그 다큐멘터리는 기후 변화에 대한 주목을 끌었어요.','The campaign successfully drew attention to youth literacy.','그 캠페인은 청소년 문해력 문제에 성공적으로 주목을 끌었어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_media_C1_03','shape','narrative','shape the narrative','담론을 형성하다','make','이야기나 여론의 흐름을 의도적으로 만든다는 정치·미디어 분야의 핵심 표현이에요.','C1','media',2,0,'news headlines media','Social media now shapes the narrative around political events.','소셜 미디어는 이제 정치 이슈의 담론을 형성해요.','Public relations teams work to shape the narrative.','홍보팀은 담론을 형성하기 위해 노력해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_media_C1_04','stir','controversy','stir controversy','논란을 일으키다','cause','사회적으로 뜨거운 논쟁을 불러일으킨다는 격식 있는 저널리즘 표현이에요.','C1','media',2,0,'controversial news','The advertisement stirred controversy across social media.','그 광고는 소셜 미디어 전반에 논란을 일으켰어요.','His remarks stirred controversy among critics.','그의 발언은 비평가들 사이에 논란을 일으켰어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_media_C1_05','make','headlines','make headlines','머리기사를 장식하다','get','사건이 신문 1면을 차지할 만큼 큰 화제가 된다는 의미예요. 뉴스 보도와 일상 대화에서 모두 써요.','C1','media',2,0,'newspaper front page','The merger made headlines around the world.','그 합병은 전 세계 머리기사를 장식했어요.','Her humanitarian work made headlines last week.','그녀의 인도주의적 활동이 지난주 머리기사를 장식했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_media_C2_01','garner','attention','garner attention','주목을 받다','get','시간과 가치를 들여 주목이나 인정을 모은다는 격식 있는 표현이에요. 언론, 학술, 마케팅 보도자료에서 자주 보여요.','C2','media',3,0,'press conference','The documentary garnered widespread attention upon its festival debut.','그 다큐멘터리는 영화제 데뷔와 동시에 폭넓은 주목을 받았어요.','The whistleblower''s allegations garnered international attention.','내부 고발자의 폭로는 국제적 주목을 받았어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_media_C2_02','disseminate','information','disseminate information','정보를 전파하다','share','정보를 광범위하고 체계적으로 퍼뜨린다는 의미예요. 정부, 학술, 저널리즘 문서의 표준 표현이에요.','C2','media',3,0,'news broadcast','Public health officials worked to disseminate information about the outbreak.','공중보건 관리들은 그 발병에 대한 정보를 전파하기 위해 애썼어요.','Social media platforms can disseminate information at unprecedented speed.','소셜 미디어 플랫폼은 전례 없는 속도로 정보를 전파할 수 있어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_media_C2_03','shape','public opinion','shape public opinion','여론을 형성하다','change','대중의 인식과 태도에 의도적으로 영향을 미친다는 정치·언론 분석의 표준 표현이에요.','C2','media',3,0,'newspaper editorial','Editorial cartoons have long served to shape public opinion in subtle ways.','시사 만평은 오랫동안 여론을 미묘하게 형성하는 역할을 해왔어요.','Algorithms increasingly shape public opinion in ways we do not fully understand.','알고리즘은 우리가 완전히 이해하지 못하는 방식으로 점점 더 여론을 형성하고 있어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_media_C2_04','fabricate','narrative','fabricate a narrative','서사를 조작하다','make','사실이 아닌 이야기를 의도적으로 꾸며낸다는 비판적 표현이에요. 미디어 비평, 정치 보도에 자주 등장해요.','C2','media',3,0,'fake news headline','Critics accused the tabloid of fabricating a narrative to vilify the candidate.','비평가들은 그 타블로이드가 후보자를 비방하기 위해 서사를 조작했다고 비난했어요.','It is dangerous when state-controlled outlets fabricate narratives unchallenged.','국가가 통제하는 매체가 견제 없이 서사를 조작하는 건 위험해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_media_C2_05','court','controversy','court controversy','논란을 자초하다','cause','논란이 될 만한 발언이나 행동을 일부러, 혹은 기꺼이 한다는 격식 표현이에요. 명사 분석이나 인물 평론에서 자주 보여요.','C2','media',3,0,'provocative artist','The author has consistently courted controversy throughout her career.','그 작가는 경력 내내 일관되게 논란을 자초해 왔어요.','The director''s latest film courts controversy by depicting historical events provocatively.','그 감독의 최신 영화는 역사적 사건을 도발적으로 묘사하며 논란을 자초해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_negotiation_22','sign','contract','sign a contract','계약서에 서명하다','do','"do a contract"는 어색해요. 계약서 서명은 sign a contract.','A2','negotiation',1,0,'contract signing pen document business','We''ll sign the contract tomorrow.','내일 계약서에 서명할 거예요.','Read carefully before you sign a contract.','계약서에 서명하기 전에 신중하게 읽으세요.','She signed the contract without hesitation.','그녀는 망설임 없이 계약서에 서명했어요.','I''m not signing the contract until lawyers review it.','변호사가 검토할 때까지 계약서에 서명하지 않을 거예요.','Both parties signed the contract on Monday.','월요일에 양 당사자가 계약서에 서명했어요.'),
('col_negotiation_01','reach','an agreement','reach an agreement','합의에 도달하다','make','"make an agreement"도 쓰이지만 reach는 양측이 노력 끝에 도달하는 뉘앙스예요.','B1','negotiation',1,1,'agreement handshake deal business negotiation','After long negotiations, both sides reached an agreement.','오랜 협상 끝에 양측은 합의에 도달했어요.','We hope to reach an agreement before the end of the month.','이달 말 전에 합의에 도달하기를 바라요.','They reached an agreement after almost a year of discussions.','그들은 거의 1년에 걸친 논의 끝에 합의에 도달했어요.','We''re close to reaching an agreement on the terms.','우리는 조건에 대한 합의에 도달하기 직전이에요.','Reaching an agreement felt like a huge relief for both sides.','합의에 도달한 것은 양측에 큰 안도감을 줬어요.'),
('col_negotiation_12','meet','in the middle','meet in the middle','절충점을 찾다','compromise','"compromise"도 맞지만 meet in the middle은 양측이 동등하게 양보하는 뉘앙스예요.','B1','negotiation',1,12,'compromise middle meet deal negotiation','They met in the middle on price, and the deal was closed.','그들은 가격에서 절충점을 찾았고 거래가 성사됐어요.','If you can meet in the middle, we can move forward today.','절충점을 찾을 수 있다면 오늘 바로 진행할 수 있어요.','Let''s try to meet in the middle on the timeline.','일정에서 절충점을 찾아봐요.','They met in the middle and both walked away satisfied.','그들은 절충점을 찾았고 양쪽 모두 만족하며 돌아갔어요.','Meeting in the middle is often the path to long-term partnerships.','절충점을 찾는 것이 종종 장기적인 파트너십으로 가는 길이에요.'),
('col_negotiation_13','reject','an offer','reject an offer','제안을 거절하다','refuse','"refuse an offer"도 맞지만 reject는 더 공식적인 거절을 강조해요.','B1','negotiation',1,13,'rejection offer deal negotiation refuse','She rejected the first offer and proposed a counter-offer.','그녀는 첫 번째 제안을 거절하고 반대 제안을 했어요.','The board rejected the offer due to concerns about long-term viability.','이사회는 장기적인 실행 가능성에 대한 우려로 제안을 거절했어요.','He politely rejected the offer and proposed an alternative.','그는 정중하게 제안을 거절하고 대안을 제시했어요.','She rejected the offer because the timing wasn''t right.','그녀는 시기가 맞지 않아 제안을 거절했어요.','Rejecting an offer firmly but kindly keeps the door open.','단호하지만 친절하게 제안을 거절하면 문이 열려 있을 수 있어요.'),
('col_negotiation_15','sign','a contract','sign a contract','계약서에 서명하다','write','"write a contract"는 작성하는 것이고 sign은 서명하는 것이에요. 혼동하지 마세요.','B1','negotiation',1,15,'contract sign agreement legal business','Both parties signed the contract and shook hands.','양측은 계약서에 서명하고 악수를 나눴어요.','She refused to sign the contract until all the changes were made.','그녀는 모든 변경 사항이 이루어질 때까지 계약서에 서명하기를 거부했어요.','They signed the contract this morning in a brief ceremony.','그들은 오늘 아침 짧은 의식에서 계약서에 서명했어요.','She signed the contract only after consulting her lawyer.','그녀는 변호사와 상의한 후에야 계약서에 서명했어요.','Don''t sign a contract before you fully understand it.','계약서를 완전히 이해하기 전에는 서명하지 마세요.'),
('col_negotiation_16','negotiate','a price','negotiate a price','가격을 협상하다','discuss','"discuss a price"도 맞지만 negotiate는 서로 다른 입장에서 조율하는 뉘앙스예요.','B1','negotiation',1,16,'price negotiation deal business market','In many countries, it''s normal to negotiate the price at a market.','많은 나라에서 시장에서 가격을 협상하는 것이 일반적이에요.','She was able to negotiate a lower price for the property.','그녀는 부동산의 더 낮은 가격을 협상할 수 있었어요.','You can usually negotiate the price at antique markets.','골동품 시장에서는 보통 가격을 협상할 수 있어요.','He negotiated the price down by about 15%.','그는 가격을 약 15% 내려서 협상했어요.','Negotiating the price politely can save you a lot of money.','정중하게 가격을 협상하면 많은 돈을 절약할 수 있어요.'),
('col_negotiation_23','set','deadline','set a deadline','마감일을 정하다','make','"make a deadline"은 마감 시간을 맞춘다는 다른 의미예요. 마감일을 정하는 건 set a deadline.','B1','negotiation',1,0,'deadline calendar planning office stress','Let''s set a deadline for the project.','프로젝트 마감일을 정해요.','The boss set a tight deadline.','상사가 빡빡한 마감일을 정했어요.','We set the deadline for end of month.','우리는 마감일을 월말로 정했어요.','Setting a realistic deadline is important.','현실적인 마감일을 정하는 게 중요해요.','She set a deadline that everyone could meet.','그녀는 모두가 맞출 수 있는 마감일을 정했어요.'),
('col_negotiation_02','make','a concession','make a concession','양보하다','do','"do a concession"은 틀린 표현이에요. 양보할 때는 make a concession을 써요.','B2','negotiation',2,2,'concession deal negotiation business compromise','Both sides had to make concessions to reach the final deal.','양측은 최종 합의에 이르기 위해 양보해야 했어요.','She made a small concession on the price to close the deal quickly.','그녀는 거래를 빨리 성사시키기 위해 가격에 대해 약간 양보했어요.','She made a concession on delivery time to secure the deal.','그녀는 거래를 확보하기 위해 납기 시간에 양보했어요.','Sometimes you have to make a concession to keep the relationship.','관계를 유지하기 위해 때로는 양보해야 해요.','They made a small concession that opened the door to bigger talks.','그들은 더 큰 협상의 문을 여는 작은 양보를 했어요.'),
('col_negotiation_03','strike','a deal','strike a deal','거래를 성사시키다','make','"make a deal"도 맞지만 strike a deal은 더 극적이고 결정적인 순간을 강조해요.','B2','negotiation',2,3,'deal business agreement contract strike','The two companies struck a deal worth 50 million dollars.','두 회사는 5000만 달러 규모의 거래를 성사시켰어요.','He struck a deal with the supplier after weeks of back-and-forth.','그는 수 주간의 협상 끝에 공급업체와 거래를 성사시켰어요.','They struck a deal that benefits everyone involved.','그들은 관련된 모두에게 이로운 거래를 성사시켰어요.','She struck a deal with the local farm to supply ingredients.','그녀는 재료를 공급받기 위해 지역 농장과 거래를 성사시켰어요.','They struck a deal just before the deadline.','그들은 마감 직전에 거래를 성사시켰어요.'),
('col_negotiation_04','walk away','from the table','walk away from the table','협상 테이블을 떠나다','leave','"leave the table"도 맞지만 walk away from the table은 협상 결렬을 더 강하게 표현해요.','B2','negotiation',2,4,'walk away negotiation deal table','If the offer isn''t improved, we will walk away from the table.','제안이 개선되지 않으면 우리는 협상 테이블을 떠날 거예요.','She walked away from the table when they refused her key demand.','그들이 핵심 요구를 거부하자 그녀는 협상 테이블을 떠났어요.','She walked away from the table when no compromise was possible.','타협이 불가능해지자 그녀는 협상 테이블을 떠났어요.','Knowing when to walk away from the table is a critical skill.','언제 협상 테이블을 떠나야 할지 아는 것은 중요한 능력이에요.','They walked away from the table but came back the next day.','그들은 협상 테이블을 떠났지만 다음 날 다시 돌아왔어요.'),
('col_negotiation_07','set','terms','set terms','조건을 정하다','make','"make terms"는 어색해요. 협상 조건을 정할 때는 set terms를 써요.','B2','negotiation',2,7,'terms conditions agreement contract legal','Before signing, you should clearly set the terms of the agreement.','서명하기 전에 합의 조건을 명확하게 정해야 해요.','The landlord set strict terms for the lease renewal.','집주인은 임대 갱신에 대한 엄격한 조건을 정했어요.','They set clear terms for the partnership before signing.','그들은 서명 전에 파트너십에 대한 명확한 조건을 정했어요.','He set terms that protected both his interests and the client''s.','그는 자신과 고객의 이익을 모두 보호하는 조건을 정했어요.','Setting clear terms upfront prevents misunderstandings later.','처음부터 명확한 조건을 정하면 나중에 오해를 막을 수 있어요.'),
('col_negotiation_09','put','on the table','put something on the table','제안을 내놓다','say','"say an offer"는 어색해요. 제안을 공식적으로 내놓을 때는 put on the table을 써요.','B2','negotiation',2,9,'offer proposal table negotiation deal','What can you put on the table to make this deal work?','이 거래를 성사시키기 위해 어떤 제안을 내놓을 수 있어요?','They put a generous severance package on the table to end the dispute.','그들은 분쟁을 종식시키기 위해 넉넉한 퇴직금 패키지를 제안으로 내놓았어요.','She put a creative new option on the table during the meeting.','그녀는 회의 중에 창의적인 새 옵션을 제안으로 내놓았어요.','They put extra benefits on the table to attract the candidate.','그들은 후보자를 끌어들이기 위해 추가 혜택을 제안으로 내놓았어요.','Putting more on the table sometimes speeds up the discussion.','더 많은 것을 제안으로 내놓으면 때로는 논의가 빨라져요.'),
('col_negotiation_10','hold','firm','hold firm','입장을 굳건히 유지하다','stay','"stay firm"도 맞지만 hold firm은 압박에도 흔들리지 않는다는 뉘앙스예요.','B2','negotiation',2,10,'firm hold position negotiation pressure','Despite the pressure, she held firm on her original offer.','압박에도 불구하고 그녀는 원래 제안에 입장을 굳건히 유지했어요.','The union held firm on its demand for a 10% pay rise.','노조는 10% 임금 인상 요구에 대해 입장을 굳건히 유지했어요.','He held firm despite pressure to lower his asking price.','그는 호가를 낮추라는 압박에도 굳건한 입장을 유지했어요.','She held firm on her boundaries throughout the discussion.','그녀는 논의 내내 자신의 경계에 굳건한 입장을 유지했어요.','Holding firm is sometimes the only way to reach a fair outcome.','입장을 굳건히 유지하는 것이 때로 공정한 결과에 이르는 유일한 방법이에요.'),
('col_negotiation_11','draw up','a contract','draw up a contract','계약서를 작성하다','make','"make a contract"도 쓰이지만 draw up은 공식 문서를 법적으로 작성하는 뉘앙스예요.','B2','negotiation',2,11,'contract legal document business agreement','The lawyer drew up a contract for both parties to sign.','변호사는 양측이 서명할 계약서를 작성했어요.','We''ll draw up a contract once we''ve agreed on all the terms.','모든 조건에 합의하면 계약서를 작성할게요.','The lawyer drew up a contract that protected both parties.','변호사는 양측을 보호하는 계약서를 작성했어요.','She drew up a contract in plain language without legal jargon.','그녀는 법률 용어 없이 평이한 언어로 계약서를 작성했어요.','They drew up a contract that included all the agreed-upon terms.','그들은 합의된 모든 조건을 포함한 계약서를 작성했어요.'),
('col_negotiation_17','break down','negotiations','break down in negotiations','협상이 결렬되다','fail','"fail in negotiations"도 맞지만 break down은 협상이 갑자기 결렬되는 뉘앙스예요.','B2','negotiation',2,17,'breakdown negotiation failure deal talks','Negotiations broke down after a key disagreement on delivery terms.','납기 조건에 대한 핵심적인 이견 이후 협상이 결렬됐어요.','If talks break down, we will need to find another solution.','협상이 결렬되면 다른 해결책을 찾아야 해요.','Negotiations broke down over the issue of insurance coverage.','보험 적용 문제로 협상이 결렬됐어요.','If negotiations break down, the project will be delayed.','협상이 결렬되면 프로젝트가 지연될 거예요.','Negotiations broke down once but resumed two weeks later.','협상은 한 번 결렬됐지만 2주 후에 재개됐어요.'),
('col_negotiation_19','finalize','an agreement','finalize an agreement','합의를 최종 확정하다','finish','"finish an agreement"는 어색해요. 합의를 최종 확정할 때는 finalize를 써요.','B2','negotiation',2,19,'agreement finalize deal close contract','Both teams worked late to finalize the agreement before the deadline.','양 팀은 마감 기한 전에 합의를 최종 확정하기 위해 늦게까지 일했어요.','We expect to finalize the agreement by the end of the week.','이번 주말까지 합의를 최종 확정할 것으로 기대해요.','We expect to finalize the agreement before the holidays.','우리는 휴일 전에 합의를 최종 확정할 것으로 기대해요.','She finalized the agreement over a long lunch with the partner.','그녀는 파트너와의 긴 점심 식사를 통해 합의를 최종 확정했어요.','They finalized the agreement after one last round of revisions.','그들은 마지막 한 차례의 수정 끝에 합의를 최종 확정했어요.'),
('col_negotiation_21','reach','agreement','reach an agreement','합의에 도달하다','make','"make an agreement"는 계약을 체결한다는 의미에 더 가까워요. 합의 과정의 결과는 reach an agreement.','B2','negotiation',1,0,'business handshake agreement contract negotiation','After hours of talks, they reached an agreement.','몇 시간의 협상 끝에 합의에 도달했어요.','We need to reach an agreement by Friday.','금요일까지 합의에 도달해야 해요.','The two parties finally reached an agreement.','두 당사자는 마침내 합의에 도달했어요.','Reaching an agreement on price was the hardest part.','가격 합의가 가장 어려운 부분이었어요.','They couldn''t reach an agreement on terms.','그들은 조건에 대해 합의에 도달하지 못했어요.'),
('col_negotiation_05','drive','a hard bargain','drive a hard bargain','강하게 협상하다','make','"make a hard bargain"은 어색해요. 강경하게 협상할 때는 drive a hard bargain을 써요.','C1','negotiation',3,5,'bargain negotiation strong deal hard','He''s known for driving a hard bargain in contract negotiations.','그는 계약 협상에서 강하게 협상하는 것으로 알려져 있어요.','She drives a hard bargain but always keeps her word.','그녀는 강하게 협상하지만 항상 약속을 지켜요.','Her boss drives a hard bargain on every project budget.','그녀의 상사는 모든 프로젝트 예산에서 강하게 협상해요.','They drove a hard bargain but eventually closed the deal.','그들은 강하게 협상했지만 결국 거래를 성사시켰어요.','Driving a hard bargain doesn''t mean being aggressive.','강하게 협상하는 것이 공격적인 태도를 의미하지는 않아요.'),
('col_negotiation_06','come to','the table','come to the table','협상 테이블에 나서다','join','"join the negotiation"도 맞지만 come to the table은 협상 참여 의사를 나타내는 표현이에요.','C1','negotiation',3,6,'table negotiation meeting deal','Both parties need to come to the table with an open mind.','양측은 열린 마음으로 협상 테이블에 나서야 해요.','The union agreed to come to the table after the management made new offers.','경영진이 새로운 제안을 내놓자 노조는 협상 테이블에 나서기로 합의했어요.','Both parties have agreed to come to the table next Tuesday.','양측은 다음 주 화요일에 협상 테이블에 나서기로 합의했어요.','She came to the table with a clear list of priorities.','그녀는 명확한 우선순위 목록을 들고 협상 테이블에 나섰어요.','It took weeks just to get them to come to the table.','그들을 협상 테이블에 나서게 하는 데만 몇 주가 걸렸어요.'),
('col_negotiation_08','bridge','a gap','bridge a gap','격차를 좁히다','close','"close a gap"도 맞지만 bridge a gap은 양측의 차이를 잇는 뉘앙스예요.','C1','negotiation',3,8,'gap bridge difference negotiation compromise','The mediator helped bridge the gap between the two sides.','중재자는 양측의 격차를 좁히는 데 도움을 줬어요.','We need to bridge the gap in salary expectations before we proceed.','진행하기 전에 급여 기대치의 격차를 좁혀야 해요.','A skilled mediator helped them bridge the gap in expectations.','능숙한 중재자가 그들의 기대 격차를 좁히는 데 도움이 됐어요.','Bridging the gap between the two teams took months.','두 팀 사이의 격차를 좁히는 데 몇 달이 걸렸어요.','They bridged the gap by finding shared values.','그들은 공유된 가치를 찾아 격차를 좁혔어요.'),
('col_negotiation_14','push','for better terms','push for better terms','더 나은 조건을 요구하다','ask','"ask for better terms"도 맞지만 push는 더 강하게 요구한다는 뉘앙스예요.','C1','negotiation',3,14,'terms negotiation push demand better','The employee pushed for better terms before agreeing to the contract.','직원은 계약에 동의하기 전에 더 나은 조건을 강하게 요구했어요.','You have more leverage than you think — push for better terms.','생각보다 협상력이 있어요. 더 나은 조건을 요구해 보세요.','She pushed for better terms after researching the market rate.','그녀는 시장 가격을 조사한 후 더 나은 조건을 강하게 요구했어요.','He pushed for better terms by walking through his contributions.','그는 자신의 기여를 설명하며 더 나은 조건을 강하게 요구했어요.','Pushing for better terms is reasonable when you bring real value.','진정한 가치를 가져온다면 더 나은 조건을 요구하는 것은 합리적이에요.'),
('col_negotiation_18','table','a proposal','table a proposal','제안을 제출하다','bring','"bring a proposal"도 맞지만 table a proposal은 공식적인 안건 제출을 강조해요.','C1','negotiation',3,18,'proposal table submission meeting official','The union tabled a proposal for a four-day work week.','노조는 주 4일 근무제에 대한 제안을 제출했어요.','We''d like to table a proposal before the meeting ends.','회의가 끝나기 전에 제안을 제출하고 싶어요.','The team tabled a proposal that addressed all the major concerns.','그 팀은 모든 주요 우려를 다루는 제안을 제출했어요.','She tabled a proposal during the closing session.','그녀는 마무리 세션에서 제안을 제출했어요.','Tabling a proposal at the right moment matters as much as the content.','적절한 순간에 제안을 제출하는 것은 내용만큼 중요해요.'),
('col_negotiation_20','leverage','a position','leverage a position','유리한 위치를 활용하다','use','"use a position"도 맞지만 leverage는 전략적으로 강점을 활용하는 뉘앙스예요.','C1','negotiation',3,20,'leverage position strength negotiation strategy','They leveraged their market position to negotiate better prices.','그들은 더 나은 가격을 협상하기 위해 시장 지위를 활용했어요.','She leveraged her expertise to secure a favorable contract.','그녀는 유리한 계약을 따내기 위해 전문성을 활용했어요.','The startup leveraged its position to secure long-term partnerships.','그 스타트업은 장기 파트너십을 확보하기 위해 자기 위치를 활용했어요.','She leveraged her unique skills in the salary negotiation.','그녀는 연봉 협상에서 자신의 독특한 기술을 활용했어요.','Leveraging a position works best when paired with humility.','위치를 활용하는 것은 겸손과 함께할 때 가장 잘 작동해요.'),
('col_negotiation_C1_01','reach','agreement','reach an agreement','합의에 이르다','make','협상 끝에 양측이 동의에 이른다는 표준 표현이에요. ''make an agreement''보다 협상 과정의 결실이라는 뉘앙스가 강해요.','C1','negotiation',2,0,'business handshake','After months of talks, the two parties finally reached an agreement.','몇 달간의 협상 끝에 양측은 마침내 합의에 이르렀어요.','We hope to reach an agreement by the end of the quarter.','분기 말까지 합의에 이르기를 바라요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_negotiation_C1_02','make','concession','make a concession','양보를 하다','give','협상에서 자신의 요구를 일부 포기한다는 격식 표현이에요. 외교, 노사 협상, 비즈니스 딜에서 자주 써요.','C1','negotiation',2,0,'negotiation handshake','Both sides will need to make concessions to close this deal.','이 딜을 성사시키려면 양측이 양보를 해야 할 거예요.','The union made a significant concession on overtime pay.','노조는 초과근무 수당에 관해 중요한 양보를 했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_negotiation_C1_03','set','terms','set the terms','조건을 정하다','put','계약이나 협상의 조건을 정한다는 표현이에요. 누가 ''set the terms''하는지가 협상력의 핵심이에요.','C1','negotiation',2,0,'contract terms','The acquiring company sought to set the terms of the merger.','인수 회사는 합병 조건을 정하려 했어요.','Whoever sets the terms first often shapes the deal.','먼저 조건을 정하는 쪽이 종종 딜의 형태를 결정해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_negotiation_C1_04','walk','away','walk away from','협상을 결렬시키다','leave','협상이 자신에게 불리할 때 그만두고 나간다는 표현이에요. ''walk away from the table''로도 자주 써요.','C1','negotiation',2,0,'businessperson leaving','They were prepared to walk away from the deal if their terms weren''t met.','그들은 조건이 받아들여지지 않으면 딜을 결렬시킬 준비가 돼 있었어요.','Sometimes the best negotiation tactic is being willing to walk away.','때로는 결렬시킬 의향을 보이는 게 최고의 협상 전술이에요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_negotiation_C1_05','drive','bargain','drive a hard bargain','강하게 흥정하다','do','협상에서 자신에게 유리한 조건을 단호하게 끌어낸다는 표현이에요. 보통 ''drive a hard bargain'' 형태로 써요.','C1','negotiation',2,0,'business bargaining','She drives a hard bargain — expect lengthy negotiations.','그녀는 강하게 흥정하니까, 긴 협상을 예상하세요.','The supplier drove a hard bargain on bulk pricing.','공급업체는 대량 가격에서 강하게 흥정했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_negotiation_C2_01','broker','deal','broker a deal','거래를 중개하다','make','제3자가 양측 사이에서 협상을 이끌어 거래를 성사시킨다는 외교·금융 격식 표현이에요. ''make''는 단순 체결이라 의미가 약해요.','C2','negotiation',3,0,'diplomatic meeting','The envoy spent six months brokering a deal between the two governments.','특사는 두 정부 사이의 거래를 중개하는 데 6개월을 썼어요.','Investment bankers were brought in to broker the deal.','거래를 중개하기 위해 투자 은행가들이 투입되었어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_negotiation_C2_02','drive','bargain','drive a bargain','흥정을 강하게 이끌다','make','협상에서 자신에게 유리하도록 강하게 밀어붙인다는 비즈니스 격식 표현이에요. ''drive a hard bargain''으로도 자주 써요.','C2','negotiation',3,0,'business negotiation','Their lead negotiator drove a bargain that exceeded the board''s expectations.','그들의 수석 협상가는 이사회의 기대를 넘는 흥정을 이끌었어요.','She drives a bargain with the discipline of a seasoned trader.','그녀는 노련한 트레이더의 절도로 흥정을 이끌어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_negotiation_C2_03','yield','concessions','yield concessions','양보를 끌어내다','get','협상 끝에 상대로부터 양보를 받아낸다는 외교·노사 협상 격식 표현이에요. ''get''은 격이 떨어져요.','C2','negotiation',3,0,'negotiation table','Sustained pressure finally yielded concessions on labor standards.','지속적인 압박이 마침내 노동 기준에 관한 양보를 끌어냈어요.','The strategy yielded significant concessions from the opposing delegation.','그 전략은 상대 대표단으로부터 상당한 양보를 끌어냈어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_negotiation_C2_04','leverage','influence','leverage influence','영향력을 활용하다','use','자신의 영향력이나 자원을 전략적으로 활용한다는 비즈니스·정치 격식 표현이에요. ''use''보다 훨씬 전략적인 뉘앙스예요.','C2','negotiation',3,0,'corporate boardroom','She leveraged her influence with regulators to secure a favorable ruling.','그녀는 규제 당국에 대한 영향력을 활용해 유리한 결정을 끌어냈어요.','The coalition leveraged its collective influence at the summit.','연합체는 정상회담에서 집단적 영향력을 활용했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_negotiation_C2_05','stall','proceedings','stall proceedings','회의 진행을 지연시키다','stop','협상이나 절차의 진행을 의도적으로 늦춘다는 외교·법정 격식 표현이에요. ''stop''은 완전 중단을 뜻해 의미가 달라요.','C2','negotiation',3,0,'courtroom delay','The opposing counsel repeatedly stalled proceedings with procedural motions.','상대 측 변호인은 절차 동의로 회의 진행을 거듭 지연시켰어요.','Stalling proceedings may buy time, but it erodes goodwill.','진행 지연은 시간을 벌어주지만, 호의를 깎아내요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_news_01','break','news','break news','뉴스를 처음 보도하다','say','"say news"는 틀린 표현이에요. 뉴스를 처음 전할 때는 break news 또는 report를 써요.','B1','news',1,1,'news breaking report media journalism','The journalist broke the news of the minister''s resignation.','기자는 장관의 사임 소식을 처음 보도했어요.','It''s always difficult to break bad news to someone.','누군가에게 나쁜 소식을 처음 전하는 것은 항상 어려워요.','She broke the news of the company''s sale to her colleagues.','그녀는 동료들에게 회사 매각 소식을 처음 전했어요.','Local outlets broke the news long before national TV picked it up.','지역 매체들이 전국 TV가 다루기 한참 전에 그 소식을 처음 보도했어요.','Breaking bad news kindly is one of the hardest parts of journalism.','나쁜 소식을 친절하게 전하는 것은 언론의 가장 어려운 부분 중 하나예요.'),
('col_news_02','cover','a story','cover a story','기사를 취재하다','write','"write a story"도 맞지만 cover는 취재부터 보도까지의 전 과정을 강조해요.','B1','news',1,2,'reporter journalist story news media','The reporter covered the story from the front lines of the conflict.','기자는 분쟁 최전선에서 기사를 취재했어요.','She has covered major international stories for over 20 years.','그녀는 20년 이상 주요 국제 기사를 취재해 왔어요.','They sent a team of five to cover the story in person.','그들은 직접 그 기사를 취재하기 위해 5명의 팀을 보냈어요.','She has covered every election in this state for the past decade.','그녀는 지난 10년간 이 주의 모든 선거를 취재했어요.','Covering the story took her to three different countries.','그 기사를 취재하기 위해 그녀는 세 개의 나라를 다녀왔어요.'),
('col_news_03','publish','an article','publish an article','기사를 게재하다','put','"put an article"은 어색해요. 기사를 공식 게재할 때는 publish를 써요.','B1','news',1,3,'article publish newspaper media journalism','The newspaper published an article exposing corruption in the local government.','신문은 지방 정부의 부패를 폭로하는 기사를 게재했어요.','She published her first article at the age of 22.','그녀는 22세에 첫 기사를 게재했어요.','They published an article about the environmental impact of fast fashion.','그들은 패스트 패션의 환경 영향에 관한 기사를 게재했어요.','She published an article that started a wider conversation.','그녀는 더 넓은 대화를 시작하게 한 기사를 게재했어요.','Publishing an article in a major paper used to be much harder.','주요 신문에 기사를 게재하는 것은 예전에 훨씬 더 어려웠어요.'),
('col_news_04','report','on an event','report on an event','사건을 보도하다','tell','"tell about an event"도 맞지만 report on은 언론의 공식적인 보도를 강조해요.','B1','news',1,4,'report event journalism media news','Journalists reported on the protest from multiple viewpoints.','기자들은 여러 관점에서 시위를 보도했어요.','The television crew was on the ground to report on the disaster.','텔레비전 취재팀이 재해를 보도하기 위해 현장에 있었어요.','She reported on the event with care and balance.','그녀는 신중함과 균형을 가지고 그 사건을 보도했어요.','He reported on the event from inside the courthouse.','그는 법원 안에서 그 사건을 보도했어요.','Reporting on an event live takes real composure.','사건을 라이브로 보도하는 데는 진정한 침착함이 필요해요.'),
('col_news_07','confirm','a report','confirm a report','보도를 확인하다','check','"check a report"도 맞지만 confirm은 내용의 사실 여부를 공식적으로 확인하는 뉘앙스예요.','B1','news',1,7,'confirm report fact official news media','The spokesperson confirmed the report of the prime minister''s resignation.','대변인은 총리의 사임에 관한 보도를 확인했어요.','Neither the company nor the government would confirm the report.','회사도 정부도 그 보도를 확인하려 하지 않았어요.','The official confirmed the report at this morning''s briefing.','당국자는 오늘 아침 브리핑에서 보도를 확인했어요.','She confirmed the report after speaking with three sources.','그녀는 세 명의 출처와 통화한 후 보도를 확인했어요.','Confirming a report takes time but builds trust with readers.','보도를 확인하는 데는 시간이 걸리지만 독자와의 신뢰를 쌓아요.'),
('col_news_12','go','viral','go viral','바이럴이 되다','become','"become viral"도 쓰이지만 go viral이 훨씬 더 자연스러운 표현이에요.','B1','news',1,12,'viral social media internet news trend','The video of the incident went viral within hours of being posted.','사건 영상은 게시된 지 몇 시간 만에 바이럴이 됐어요.','A single tweet went viral and changed the course of the story.','하나의 트윗이 바이럴이 돼서 기사의 흐름을 바꿨어요.','The footage went viral on every social platform overnight.','그 영상은 하룻밤 만에 모든 소셜 플랫폼에서 바이럴이 됐어요.','Her quote went viral and was printed on coffee mugs.','그녀의 발언이 바이럴이 되어 커피 머그컵에 인쇄됐어요.','Going viral isn''t always good news for the person involved.','바이럴이 되는 것이 당사자에게 항상 좋은 소식만은 아니에요.'),
('col_news_13','conduct','an interview','conduct an interview','인터뷰를 하다','do','"do an interview"도 맞지만 conduct는 더 격식 있고 전문적인 인터뷰를 강조해요.','B1','news',1,13,'interview journalist media news conduct','The journalist conducted an interview with the prime minister.','기자는 총리와 인터뷰를 했어요.','She has conducted thousands of interviews over her 30-year career.','그녀는 30년 경력 동안 수천 건의 인터뷰를 했어요.','She conducted an interview with the artist behind the mural.','그녀는 그 벽화를 그린 작가와 인터뷰를 했어요.','He conducted an interview in three different languages.','그는 세 가지 다른 언어로 인터뷰를 진행했어요.','Conducting an interview live on air is more stressful than it looks.','생방송에서 인터뷰를 진행하는 것은 보기보다 더 스트레스가 많아요.'),
('col_news_19','quote','a source','quote a source','출처를 인용하다','use','"use a source"도 맞지만 quote는 출처의 말을 그대로 인용하는 것을 강조해요.','B1','news',1,19,'quote source journalism media reference','The article quoted a senior official who asked to remain anonymous.','그 기사는 익명을 요청한 고위 관료를 인용했어요.','Journalists must ensure they quote sources accurately.','기자들은 출처를 정확하게 인용해야 해요.','The article quoted a source close to the senator.','그 기사는 상원의원과 가까운 출처를 인용했어요.','She quoted a source from a leaked internal memo.','그녀는 유출된 내부 메모의 출처를 인용했어요.','Quoting a source out of context is a kind of distortion.','출처를 맥락 없이 인용하는 것은 일종의 왜곡이에요.'),
('col_news_20','hold','a press conference','hold a press conference','기자회견을 열다','make','"make a press conference"는 어색해요. 기자회견을 개최할 때는 hold를 써요.','B1','news',1,20,'press conference media journalism official announcement','The prime minister held a press conference to address the allegations.','총리는 혐의에 대해 해명하기 위해 기자회견을 열었어요.','The company held a press conference to announce the merger.','회사는 합병을 발표하기 위해 기자회견을 열었어요.','The CEO held a press conference outside the company''s headquarters.','CEO는 회사 본사 밖에서 기자회견을 열었어요.','They held a press conference to clarify the misinformation.','그들은 잘못된 정보를 명확히 하기 위해 기자회견을 열었어요.','Holding a press conference requires careful coordination.','기자회견을 여는 데는 신중한 조율이 필요해요.'),
('col_news_21','break','news','break news','뉴스를 전하다, 속보를 알리다','tell','"tell news"는 평범한 전달. break the news는 (특히 어려운/큰) 소식을 알린다는 의미.','B1','news',1,0,'breaking news reporter studio screen broadcast','Who''s going to break the news to her?','누가 그녀에게 그 소식을 전할 거예요?','The journalist broke the news first.','그 기자가 속보를 가장 먼저 전했어요.','I''m sorry to break the news, but he passed away.','이런 소식 전해 미안하지만, 그가 세상을 떠나셨어요.','She broke the news of her resignation today.','그녀는 오늘 사임 소식을 전했어요.','The network broke the news of the merger.','그 방송사가 합병 소식을 가장 먼저 전했어요.'),
('col_news_22','follow','story','follow a story','뉴스 이야기를 따라가다','chase','"chase a story"는 기자가 취재 활동하는 거예요. 일반 시청자가 뉴스를 따라가는 건 follow.','B1','news',1,0,'newspaper headlines reader following story tracking','I''ve been following this story for weeks.','이 뉴스 이야기를 몇 주째 따라가고 있어요.','It''s hard to follow the story when details keep changing.','세부 사항이 계속 바뀌어서 따라가기 어려워요.','She follows political stories closely.','그녀는 정치 뉴스를 면밀히 따라가요.','Let''s follow this story to see how it ends.','어떻게 끝나는지 보려고 이 뉴스를 따라가요.','I stopped following the story — too depressing.','그 뉴스 따라가는 거 그만뒀어요 — 너무 우울해서요.'),
('col_news_05','investigate','a claim','investigate a claim','주장을 조사하다','check','"check a claim"도 맞지만 investigate는 더 철저하고 체계적인 조사를 강조해요.','B2','news',2,5,'investigation journalism claim research fact','The journalist spent months investigating the company''s claims.','기자는 몇 달 동안 그 회사의 주장을 조사했어요.','Editors have a responsibility to investigate claims before publishing.','편집자들은 게재하기 전에 주장을 조사할 책임이 있어요.','The team investigated a claim that turned out to be unfounded.','그 팀은 근거 없는 것으로 밝혀진 주장을 조사했어요.','She investigated a claim involving a major government contract.','그녀는 주요 정부 계약에 관한 주장을 조사했어요.','Investigating a claim properly requires both time and trust.','주장을 제대로 조사하려면 시간과 신뢰가 모두 필요해요.'),
('col_news_06','run','a headline','run a headline','헤드라인을 싣다','write','"write a headline"도 맞지만 run은 신문이나 방송이 헤드라인을 내보내는 것을 강조해요.','B2','news',2,6,'headline newspaper front page media','The newspaper ran a sensational headline that caused a public outcry.','신문은 대중의 분노를 야기한 선정적인 헤드라인을 실었어요.','All the major papers ran the same headline on their front pages.','모든 주요 신문이 1면에 동일한 헤드라인을 실었어요.','Tabloid papers often run sensational headlines for clicks.','타블로이드 신문들은 클릭을 위해 선정적인 헤드라인을 자주 실어요.','They ran a quieter headline than expected given the news.','그 뉴스에 비해 그들은 예상보다 조용한 헤드라인을 실었어요.','The paper ran a headline that misrepresented the story.','그 신문은 기사를 잘못 표현하는 헤드라인을 실었어요.'),
('col_news_09','spread','misinformation','spread misinformation','잘못된 정보를 퍼뜨리다','share','"share misinformation"도 맞지만 spread는 정보가 광범위하게 퍼지는 뉘앙스예요.','B2','news',2,9,'misinformation social media fake news spread','Social media platforms are often used to spread misinformation.','소셜 미디어 플랫폼은 종종 잘못된 정보를 퍼뜨리는 데 사용돼요.','It''s important to verify information before spreading it online.','온라인에서 정보를 퍼뜨리기 전에 확인하는 것이 중요해요.','Bots are often used to spread misinformation rapidly online.','봇은 종종 온라인에서 잘못된 정보를 빠르게 퍼뜨리는 데 사용돼요.','It''s easy to accidentally spread misinformation just by resharing.','단순히 재공유하기만 해도 실수로 잘못된 정보를 퍼뜨릴 수 있어요.','Schools are teaching students how not to spread misinformation.','학교들은 학생들에게 잘못된 정보를 퍼뜨리지 않는 법을 가르치고 있어요.'),
('col_news_10','fact-check','a source','fact-check a source','출처를 팩트체크하다','verify','"verify a source"도 맞지만 fact-check는 뉴스의 사실 여부를 검증하는 특화된 표현이에요.','B2','news',2,10,'fact check journalism verification truth media','Good journalists fact-check every source before including it in an article.','좋은 기자들은 기사에 포함하기 전에 모든 출처를 팩트체크해요.','Several organisations were set up to fact-check claims made by politicians.','정치인들의 주장을 팩트체크하기 위해 여러 단체가 설립됐어요.','They fact-checked the source three different ways.','그들은 출처를 세 가지 다른 방식으로 팩트체크했어요.','She fact-checked every claim before her debate.','그녀는 토론 전에 모든 주장을 팩트체크했어요.','Fact-checking a source is a basic skill, not a special favor.','출처를 팩트체크하는 것은 특별한 호의가 아닌 기본 기술이에요.'),
('col_news_11','issue','a statement','issue a statement','성명을 발표하다','say','"say a statement"는 어색해요. 공식 성명을 낼 때는 issue 또는 release를 써요.','B2','news',2,11,'statement official press release government','The company issued a statement denying the allegations.','회사는 혐의를 부인하는 성명을 발표했어요.','The government issued a statement urging calm after the incident.','정부는 사건 후 냉정을 촉구하는 성명을 발표했어요.','The mayor''s office issued a statement on the housing plan.','시장실은 주택 계획에 관한 성명을 발표했어요.','The artist issued a statement apologizing for the offensive lyrics.','그 아티스트는 불쾌한 가사에 대해 사과하는 성명을 발표했어요.','Issuing a statement quickly can shape public perception.','빠르게 성명을 발표하면 대중 인식을 형성할 수 있어요.'),
('col_news_14','cite','a source','cite a source','출처를 인용하다','name','"name a source"도 맞지만 cite는 공식적으로 출처를 명시하는 뉘앙스예요.','B2','news',2,14,'source citation reference journalism media','The report cited anonymous sources within the government.','그 보도는 정부 내 익명의 출처를 인용했어요.','Always cite your sources to maintain journalistic credibility.','언론의 신뢰성을 유지하기 위해 항상 출처를 인용하세요.','The article cited a source from inside the company.','그 기사는 회사 내부의 출처를 인용했어요.','She cited a source familiar with the closed negotiations.','그녀는 비공개 협상에 정통한 출처를 인용했어요.','Citing a source is more than a formality — it''s journalism.','출처를 인용하는 것은 형식 이상의 일 — 그 자체가 저널리즘이에요.'),
('col_news_15','raise','a concern','raise a concern','우려를 제기하다','say','"say a concern"은 어색해요. 우려 사항을 공식적으로 언급할 때는 raise를 써요.','B2','news',2,15,'concern news report media issue','The report raised serious concerns about data privacy.','그 보도는 데이터 프라이버시에 대한 심각한 우려를 제기했어요.','Several journalists raised concerns about editorial independence.','여러 기자들이 편집 독립에 대한 우려를 제기했어요.','Residents raised a concern about the new construction project.','주민들은 새 건설 프로젝트에 대한 우려를 제기했어요.','Editors raised a concern about the article''s tone.','편집자들은 기사의 어조에 대한 우려를 제기했어요.','She raised a concern that turned out to be very important.','그녀는 매우 중요한 것으로 밝혀진 우려를 제기했어요.'),
('col_news_17','uncover','a scandal','uncover a scandal','스캔들을 폭로하다','find','"find a scandal"도 맞지만 uncover는 숨겨진 것을 드러내는 뉘앙스예요.','B2','news',2,17,'scandal uncover investigation journalism reveal','The investigative team uncovered a major political scandal.','탐사보도팀은 대규모 정치 스캔들을 폭로했어요.','The reporter uncovered the scandal after months of investigation.','기자는 몇 달간의 조사 끝에 스캔들을 폭로했어요.','The reporter uncovered a scandal involving multiple agencies.','그 기자는 여러 기관과 관련된 스캔들을 폭로했어요.','A whistleblower helped them uncover the scandal.','내부 고발자가 그들이 스캔들을 폭로하는 데 도움을 줬어요.','Uncovering a scandal can take years of careful work.','스캔들을 폭로하는 데는 몇 년의 신중한 작업이 걸릴 수 있어요.'),
('col_news_23','cover','event','cover an event','행사를 취재하다','do','"do an event"는 행사 자체를 진행한다는 의미. 취재·보도는 cover an event.','B2','news',1,0,'reporter camera microphone event coverage live','Major networks covered the event live.','주요 방송사들이 그 행사를 생중계 취재했어요.','She covered the Olympics for the newspaper.','그녀는 그 신문사를 위해 올림픽을 취재했어요.','I''m sending a reporter to cover the event.','기자를 보내 그 행사를 취재할 거예요.','They covered the protest from multiple angles.','그들은 여러 각도에서 시위를 취재했어요.','No journalists covered the small ceremony.','어떤 기자도 그 작은 의식을 취재하지 않았어요.'),
('col_news_08','retract','a story','retract a story','기사를 철회하다','remove','"remove a story"도 쓰이지만 retract는 잘못된 정보를 공식적으로 철회하는 뉘앙스예요.','C1','news',3,8,'retraction newspaper correction error media','The newspaper was forced to retract the story after new evidence emerged.','신문은 새로운 증거가 나오자 기사를 철회할 수밖에 없었어요.','The editor issued an apology when they retracted the false report.','편집장은 허위 보도를 철회하면서 사과문을 발표했어요.','They retracted the story and issued an apology to the readers.','그들은 기사를 철회하고 독자들에게 사과문을 발표했어요.','Several outlets retracted the story after new evidence emerged.','여러 매체들이 새로운 증거가 나오자 기사를 철회했어요.','Retracting a story is hard but sometimes the right thing to do.','기사를 철회하는 것은 어렵지만 때로는 옳은 일이에요.'),
('col_news_16','lead','with a story','lead with a story','기사를 첫 번째로 다루다','start','"start with a story"도 맞지만 lead with는 편집 결정으로 첫 뉴스로 다루는 뉘앙스예요.','C1','news',3,16,'headline lead news broadcast editorial','The evening news led with the story of the earthquake.','저녁 뉴스는 지진 기사를 첫 번째로 다뤘어요.','Most news channels led with the same story about the election result.','대부분의 뉴스 채널이 선거 결과에 관한 동일한 기사를 첫 번째로 다뤘어요.','The morning news led with a story about a local hero.','아침 뉴스는 지역 영웅 이야기를 첫 번째로 다뤘어요.','They led with the story to capture maximum attention.','그들은 최대한의 주목을 끌기 위해 그 기사를 첫 번째로 다뤘어요.','Leading with a positive story can shift the tone of the day.','긍정적인 기사로 시작하면 하루의 분위기를 바꿀 수 있어요.'),
('col_news_18','balance','coverage','balance coverage','균형 있게 보도하다','control','"control coverage"는 어색해요. 공정한 보도를 위해서는 balance coverage를 써요.','C1','news',3,18,'balance media coverage fair journalism','A responsible journalist always balances coverage of both sides.','책임감 있는 기자는 항상 양측을 균형 있게 보도해요.','Critics argued the channel failed to balance its coverage of the election.','비평가들은 그 채널이 선거 보도를 균형 있게 하지 못했다고 주장했어요.','Good editors work hard to balance coverage on contentious topics.','좋은 편집자들은 논쟁적인 주제에서 보도의 균형을 잡기 위해 열심히 일해요.','The paper failed to balance coverage during the campaign.','그 신문은 캠페인 기간 동안 보도의 균형을 잡지 못했어요.','Balancing coverage doesn''t mean treating all claims equally.','보도의 균형이 모든 주장을 동등하게 다룬다는 의미는 아니에요.'),
('col_news_C1_01','cover','story','cover a story','기사를 취재하다','write','''write''는 단순 작성이지만, ''cover''는 취재·보도 전체 과정을 의미하는 저널리즘 표준 동사예요.','C1','news',2,0,'journalist reporting','She has covered every major election story for the past decade.','그녀는 지난 10년간 주요 선거 기사를 모두 취재해 왔어요.','Foreign correspondents cover stories from conflict zones around the world.','해외 특파원들은 전 세계 분쟁 지역에서 기사를 취재해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_news_C1_02','leak','information','leak information','정보를 누설하다','tell','비공개 정보를 외부에 흘린다는 정확한 동사예요. ''tell''은 너무 일반적이라 보도 맥락에 안 맞아요.','C1','news',2,0,'leaked documents','An anonymous source leaked information about the upcoming merger.','익명의 소식통이 다가오는 합병에 대한 정보를 누설했어요.','Employees who leak information may face legal consequences.','정보를 누설한 직원은 법적 처벌을 받을 수 있어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_news_C1_03','issue','statement','issue a statement','성명을 발표하다','say','공식 입장을 정식으로 발표한다는 격식 표현이에요. 기업이나 정부 발표 기사에서 표준이에요.','C1','news',2,0,'press release','The minister issued a statement denying any wrongdoing.','장관은 어떠한 잘못도 없다고 부인하는 성명을 발표했어요.','The studio issued a statement late last night about the casting change.','스튜디오는 어젯밤 늦게 캐스팅 변경에 대한 성명을 발표했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_news_C1_04','hold','press conference','hold a press conference','기자회견을 열다','make','기자회견을 ''열다''는 ''hold''가 표준이에요. ''make''는 영어에서 어색해요.','C1','news',2,0,'press conference','The mayor will hold a press conference at noon to address the crisis.','시장은 위기를 다루기 위해 정오에 기자회견을 열 거예요.','They held a press conference to announce the partnership.','그들은 파트너십을 발표하기 위해 기자회견을 열었어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_news_C1_05','verify','sources','verify sources','출처를 확인하다','check','''check''도 통하지만, ''verify''가 저널리즘과 정보 검증에서 표준 동사예요. 팩트체크 보도의 핵심 표현이에요.','C1','news',2,0,'fact checking','Responsible journalists always verify sources before publishing.','책임감 있는 기자는 보도 전에 항상 출처를 확인해요.','In the age of social media, it is harder than ever to verify sources.','소셜 미디어 시대에는 출처를 확인하기가 그 어느 때보다 어려워요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_news_C2_01','break','story','break a story','특종을 보도하다','tell','다른 매체보다 먼저 뉴스를 보도한다는 저널리즘 표준 표현이에요. 한국어 ''특종''에 해당해요.','C2','news',3,0,'newspaper headline','The investigative team broke the story of the offshore tax scheme.','탐사 보도팀이 역외 탈세 스킴 특종을 보도했어요.','She broke the story that ultimately led to the minister''s resignation.','그녀가 결국 장관 사임으로 이어진 특종을 보도했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_news_C2_02','fan','flames','fan the flames','불에 기름을 붓다','increase','논쟁이나 갈등을 더욱 격화시킨다는 비유적 표현이에요. 언론 비평에서 자주 등장해요.','C2','news',3,0,'flame fire','Sensationalist coverage only fans the flames of public outrage.','선정적인 보도는 대중의 분노에 기름만 부을 뿐이에요.','Anonymous leaks have fanned the flames of the diplomatic dispute.','익명의 유출이 외교 분쟁의 불씨에 기름을 부었어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_news_C2_03','sway','opinion','sway opinion','여론을 흔들다','change','여론이나 사람들의 견해를 움직인다는 격식 표현이에요. 정치 보도와 미디어 분석에 표준이에요.','C2','news',3,0,'public opinion poll','Front-page editorials can decisively sway public opinion before an election.','1면 사설은 선거 직전 여론을 결정적으로 흔들 수 있어요.','The documentary swayed opinion against the proposed pipeline.','그 다큐멘터리는 송유관 계획에 반대하는 여론을 형성했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_news_C2_04','uncover','scandal','uncover a scandal','스캔들을 폭로하다','find','오랫동안 숨겨진 스캔들을 파헤쳐 드러낸다는 뜻이에요. 탐사 보도의 핵심 동사예요.','C2','news',3,0,'investigative journalism','A junior reporter uncovered the scandal that engulfed three cabinet ministers.','한 신참 기자가 세 명의 장관을 휩쓴 스캔들을 폭로했어요.','Their nine-month investigation uncovered a sprawling corruption scandal.','그들의 9개월간의 조사가 광범위한 부패 스캔들을 폭로했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_news_C2_05','circulate','rumours','circulate rumours','소문을 퍼뜨리다','tell','소문이 매체나 사람들 사이에 퍼져나간다는 격식 표현이에요. ''spread''보다 좀 더 문어체예요.','C2','news',3,0,'gossip tabloid','Tabloids have been circulating rumours of the actress''s engagement for weeks.','타블로이드들이 그 여배우의 약혼설을 몇 주째 퍼뜨리고 있어요.','Online forums circulated rumours that turned out to be fabricated.','온라인 포럼에서 퍼진 소문은 조작된 것으로 드러났어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_presentation_23','answer','questions','answer questions','질문에 답하다','respond','"respond to questions"도 가능 (격식). 일상에서는 answer questions가 자연스러워요.','A2','presentation',1,0,'Q&A session speaker microphone audience hand raised','I''ll answer questions at the end of the presentation.','발표 마지막에 질문에 답할게요.','She answered all the questions confidently.','그녀는 모든 질문에 자신 있게 답했어요.','He refused to answer questions about his past.','그는 자신의 과거에 관한 질문에 답하기를 거부했어요.','Please raise your hand if you want to answer.','답하고 싶으면 손을 들어 주세요.','The CEO answered questions for thirty minutes.','CEO는 30분간 질문에 답했어요.'),
('col_presentation_01','give','a presentation','give a presentation','발표를 하다','make','"make a presentation"도 쓰이지만 give a presentation이 훨씬 더 자연스러워요.','B1','presentation',1,1,'presentation business meeting speaker slides','She gave an impressive presentation to the board of directors.','그녀는 이사회에 인상적인 발표를 했어요.','He gives a presentation every Monday morning to update the team.','그는 팀 업데이트를 위해 매주 월요일 아침 발표를 해요.','She gave a 10-minute presentation on the project results.','그녀는 프로젝트 결과에 대한 10분 발표를 했어요.','I have to give a presentation in English for the first time.','저는 처음으로 영어로 발표를 해야 해요.','He gives a presentation at every team meeting.','그는 매번 팀 회의에서 발표를 해요.'),
('col_presentation_03','set up','a slide deck','set up a slide deck','슬라이드 덱을 준비하다','make','"make slides"도 맞지만 set up a slide deck은 준비를 포함한 더 격식 있는 표현이에요.','B1','presentation',1,3,'slides presentation setup technology screen','She spent the morning setting up her slide deck for the afternoon presentation.','그녀는 오후 발표를 위해 오전에 슬라이드 덱을 준비했어요.','Can you set up the slide deck before the clients arrive?','고객이 도착하기 전에 슬라이드 덱을 준비해 줄 수 있어요?','She set up her slide deck and ran a quick rehearsal.','그녀는 슬라이드 덱을 준비하고 빠른 리허설을 했어요.','Setting up the slide deck took longer than expected.','슬라이드 덱을 준비하는 데 예상보다 오래 걸렸어요.','He set up the slide deck the night before to avoid stress.','그는 스트레스를 피하려고 전날 밤 슬라이드 덱을 준비했어요.'),
('col_presentation_06','outline','the agenda','outline the agenda','안건을 개요로 설명하다','say','"say the agenda"는 어색해요. 안건을 설명할 때는 outline 또는 go through를 써요.','B1','presentation',1,6,'agenda outline meeting schedule presentation','She outlined the agenda at the beginning of the presentation.','그녀는 발표 시작 부분에 안건을 개요로 설명했어요.','Please outline the agenda so everyone knows what to expect.','모든 사람이 무엇을 기대해야 할지 알도록 안건을 설명해 주세요.','He outlined the agenda using just three clear points.','그는 단 세 가지 명확한 요점으로 안건을 설명했어요.','She outlined the agenda before introducing the speakers.','그녀는 연사들을 소개하기 전에 안건을 설명했어요.','Outlining the agenda helps the audience know what to expect.','안건을 설명하면 청중이 무엇을 기대해야 할지 알 수 있어요.'),
('col_presentation_07','make','eye contact','make eye contact','눈을 마주치다','do','"do eye contact"는 틀린 표현이에요. 눈을 마주칠 때는 make eye contact를 써요.','B1','presentation',1,7,'eye contact speaker audience engagement','Making eye contact with the audience builds trust and confidence.','청중과 눈을 마주치는 것은 신뢰와 자신감을 형성해요.','She made eye contact with different members of the audience throughout her talk.','그녀는 발표 내내 청중의 다양한 구성원과 눈을 마주쳤어요.','She made eye contact with each section of the audience in turn.','그녀는 청중의 각 구역과 차례로 눈을 마주쳤어요.','Making eye contact helps the audience feel personally addressed.','눈을 마주치는 것은 청중이 개인적으로 다뤄진다고 느끼는 데 도움이 돼요.','I struggle to make eye contact when I''m nervous.','저는 긴장하면 눈을 마주치는 게 힘들어요.'),
('col_presentation_12','refer','to a chart','refer to a chart','차트를 언급하다','show','"show a chart"도 맞지만 refer to는 발표 중에 차트를 가리키며 언급하는 뉘앙스예요.','B1','presentation',1,12,'chart slide data refer presentation','She referred to the chart on the left to support her argument.','그녀는 왼쪽 차트를 언급하며 자신의 주장을 뒷받침했어요.','If you refer to the chart on slide 5, you can see a clear trend.','슬라이드 5의 차트를 보시면 명확한 추세를 볼 수 있어요.','If you refer to the chart on slide 12, you''ll see the trend.','슬라이드 12의 차트를 보시면 추세를 볼 수 있어요.','She referred to a chart that showed three years of growth.','그녀는 3년간의 성장을 보여주는 차트를 언급했어요.','He referred to a chart to back up his key argument.','그는 핵심 주장을 뒷받침하기 위해 차트를 언급했어요.'),
('col_presentation_13','take','questions','take questions','질문을 받다','get','"get questions"도 쓰이지만 take questions는 질문을 받겠다는 공식적인 선언이에요.','B1','presentation',1,13,'questions audience speaker Q&A','I''ll take questions at the end of the presentation.','발표 마지막에 질문을 받을게요.','She took questions from the panel after her keynote speech.','그녀는 기조연설 후 패널의 질문을 받았어요.','I''ll take questions for the next ten minutes.','앞으로 10분 동안 질문을 받을게요.','She took questions both in the room and online.','그녀는 현장과 온라인 모두에서 질문을 받았어요.','Taking questions early can make the rest of the talk more interactive.','질문을 일찍 받으면 나머지 발표가 더 상호작용적일 수 있어요.'),
('col_presentation_21','give','speech','give a speech','연설을 하다','do','"do a speech"는 틀린 표현. 연설은 give a speech (또는 deliver a speech 격식체).','B1','presentation',1,0,'speaker podium speech audience microphone','She gave a powerful speech at the conference.','그녀는 학회에서 강력한 연설을 했어요.','I have to give a speech at my friend''s wedding.','친구 결혼식에서 축사를 해야 해요.','He gave a speech about climate action.','그는 기후 행동에 관한 연설을 했어요.','Giving a speech in front of strangers is scary.','낯선 사람들 앞에서 연설하는 건 무서워요.','She gave a moving speech that brought tears.','그녀는 눈물을 자아내는 감동적인 연설을 했어요.'),
('col_presentation_22','make','point','make a point','요점을 말하다, 강조하다','do','"do a point"는 틀린 표현. 의견·요점을 강조할 때는 make a point.','B1','presentation',1,0,'speaker pointing chart presentation key point','You made a great point in the meeting.','회의에서 좋은 요점을 짚었어요.','I want to make a point about transparency.','투명성에 관한 요점을 짚고 싶어요.','She made several important points.','그녀는 몇 가지 중요한 요점을 말했어요.','He made the point that we''re running low on time.','그는 우리에게 시간이 부족하다는 점을 강조했어요.','Let me make one more point before we move on.','넘어가기 전에 한 가지만 더 말할게요.'),
('col_presentation_02','deliver','a speech','deliver a speech','연설을 하다','say','"say a speech"는 틀린 표현이에요. 연설을 할 때는 give 또는 deliver를 써요.','B2','presentation',2,2,'speech delivery conference speaker audience','The CEO delivered a powerful speech at the annual conference.','최고경영자는 연례 회의에서 강력한 연설을 했어요.','He delivered a speech that moved the entire audience to tears.','그는 청중 전체를 눈물 짓게 만드는 연설을 했어요.','She delivered a memorable speech at her graduation.','그녀는 졸업식에서 기억에 남는 연설을 했어요.','He delivered a brief speech to thank his team.','그는 팀에게 감사를 표하는 짧은 연설을 했어요.','Delivering a speech in a second language takes real practice.','제2언어로 연설을 하는 데는 진정한 연습이 필요해요.'),
('col_presentation_04','walk through','the data','walk through the data','데이터를 설명하다','explain','"explain the data"도 맞지만 walk through는 단계별로 안내하는 뉘앙스예요.','B2','presentation',2,4,'data explanation walkthrough slides chart','Let me walk you through the data from last quarter.','지난 분기 데이터를 단계별로 설명해 드릴게요.','She walked through the research findings one slide at a time.','그녀는 연구 결과를 슬라이드 하나씩 설명했어요.','Let me walk you through the data from each region.','각 지역의 데이터를 단계별로 설명해 드릴게요.','She walked through the data carefully to avoid confusion.','그녀는 혼동을 피하기 위해 데이터를 신중하게 설명했어요.','Walking through the data step by step helps everyone understand.','데이터를 단계별로 설명하면 모두가 이해하는 데 도움이 돼요.'),
('col_presentation_05','capture','attention','capture attention','주의를 끌다','get','"get attention"도 맞지만 capture는 단번에 강하게 끌어들이는 뉘앙스예요.','B2','presentation',2,5,'attention audience speaker engagement','A strong opening sentence captures the audience''s attention immediately.','강한 첫 문장은 즉각적으로 청중의 주의를 끌어요.','Use a surprising statistic to capture attention at the start.','시작할 때 놀라운 통계를 사용해서 주의를 끄세요.','A great story at the start instantly captures attention.','시작 부분의 멋진 이야기는 즉시 주의를 끌어요.','She captured the attention of every executive in the room.','그녀는 그 방의 모든 임원의 주의를 끌었어요.','Capturing attention in the first 30 seconds is key.','첫 30초 안에 주의를 끄는 것이 핵심이에요.'),
('col_presentation_08','engage','the audience','engage the audience','청중을 사로잡다','entertain','"entertain the audience"도 맞지만 engage는 더 능동적인 참여를 강조해요.','B2','presentation',2,8,'audience engagement speaker interactive presentation','Good presenters know how to engage the audience from start to finish.','좋은 발표자는 처음부터 끝까지 청중을 사로잡는 방법을 알아요.','He used interactive questions to engage the audience.','그는 상호작용 질문으로 청중을 사로잡았어요.','He engaged the audience by asking them to vote on a question.','그는 청중에게 질문에 투표하라고 요청해서 사로잡았어요.','Good visuals can help engage the audience throughout.','좋은 시각 자료는 청중을 처음부터 끝까지 사로잡는 데 도움이 돼요.','She engages the audience by sharing personal stories.','그녀는 개인적인 이야기를 공유함으로써 청중을 사로잡아요.'),
('col_presentation_09','highlight','key findings','highlight key findings','핵심 결과를 강조하다','show','"show key findings"도 맞지만 highlight는 특별히 부각시키는 뉘앙스예요.','B2','presentation',2,9,'findings highlight research data slide','The presenter highlighted the key findings from the customer survey.','발표자는 고객 설문 조사의 핵심 결과를 강조했어요.','Be sure to highlight key findings in bold on your slides.','슬라이드에서 핵심 결과를 굵게 강조하세요.','She highlighted the key findings using simple charts.','그녀는 간단한 차트로 핵심 결과를 강조했어요.','He highlighted the key findings in bold red text.','그는 굵은 빨간 글씨로 핵심 결과를 강조했어요.','Highlighting the key findings at the start saves everyone time.','처음에 핵심 결과를 강조하면 모두의 시간을 절약해요.'),
('col_presentation_11','wrap up','a presentation','wrap up a presentation','발표를 마무리하다','finish','"finish a presentation"도 맞지만 wrap up은 요약과 함께 마무리하는 뉘앙스예요.','B2','presentation',2,11,'wrap up conclusion presentation end close','She wrapped up her presentation with a memorable call to action.','그녀는 기억에 남는 행동 촉구와 함께 발표를 마무리했어요.','Let''s wrap up the presentation in the next five minutes.','앞으로 5분 안에 발표를 마무리해요.','She wrapped up the presentation with a powerful summary slide.','그녀는 강력한 요약 슬라이드로 발표를 마무리했어요.','He wrapped up the presentation by inviting questions.','그는 질문을 받으며 발표를 마무리했어요.','Wrapping up a presentation with a call to action is effective.','행동 촉구로 발표를 마무리하면 효과적이에요.'),
('col_presentation_15','handle','nerves','handle nerves','긴장을 다스리다','control','"control nerves"도 맞지만 handle nerves는 실질적으로 관리하는 뉘앙스예요.','B2','presentation',2,15,'nerves anxiety stage presentation manage','She learned techniques to handle nerves before important presentations.','그녀는 중요한 발표 전에 긴장을 다스리는 기법을 배웠어요.','Deep breathing can help you handle nerves before going on stage.','심호흡은 무대에 오르기 전에 긴장을 다스리는 데 도움이 돼요.','She uses breathing exercises to handle her nerves.','그녀는 긴장을 다스리기 위해 호흡 운동을 사용해요.','He handles his nerves by focusing on the message, not himself.','그는 자신이 아닌 메시지에 집중함으로써 긴장을 다스려요.','Learning to handle nerves is a skill that improves with practice.','긴장을 다스리는 법을 배우는 것은 연습으로 발전하는 기술이에요.'),
('col_presentation_16','illustrate','a point','illustrate a point','요점을 설명하다','show','"show a point"는 어색해요. 예시를 들어 요점을 설명할 때는 illustrate를 써요.','B2','presentation',2,16,'illustration example point presentation explain','She used a real-life example to illustrate her point.','그녀는 실생활 예시를 사용해서 요점을 설명했어요.','He illustrated his point with a short video clip.','그는 짧은 영상 클립으로 요점을 설명했어요.','She illustrated her point with a clip from a popular movie.','그녀는 인기 영화의 클립으로 자신의 요점을 설명했어요.','He illustrated his point using a story from his own childhood.','그는 자신의 어린 시절 이야기로 요점을 설명했어요.','Illustrating a point with a real example makes it memorable.','실제 예시로 요점을 설명하면 기억에 남아요.'),
('col_presentation_17','run','over time','run over time','시간을 초과하다','exceed','"exceed the time"도 맞지만 run over time은 일상적인 발표 상황에서 더 자연스러워요.','B2','presentation',2,17,'time presentation over schedule clock','The presentation ran over time because there were so many questions.','질문이 너무 많아서 발표가 시간을 초과했어요.','Try not to run over time — keep an eye on the clock.','시간을 초과하지 않도록 시계를 확인하세요.','The Q&A ran over time because the audience had so many questions.','청중이 질문이 너무 많아 Q&A가 시간을 초과했어요.','Try not to run over time during a board presentation.','이사회 발표에서는 시간을 초과하지 않도록 하세요.','She ran over time but no one minded because she was engaging.','그녀는 시간을 초과했지만 사로잡는 발표였기에 아무도 개의치 않았어요.'),
('col_presentation_10','field','questions','field questions','질문을 처리하다','answer','"answer questions"도 맞지만 field는 다양한 질문들을 능숙하게 처리하는 뉘앙스예요.','C1','presentation',3,10,'questions audience Q&A presentation field','After the talk, he fielded questions from the audience for 20 minutes.','발표 후 그는 20분 동안 청중의 질문을 처리했어요.','She was well prepared to field any questions about the budget.','그녀는 예산에 관한 어떤 질문도 처리할 준비가 되어 있었어요.','She fielded questions calmly even under tough scrutiny.','그녀는 엄격한 조사 속에서도 침착하게 질문을 처리했어요.','He fielded questions from the press for over an hour.','그는 한 시간 넘게 언론의 질문을 처리했어요.','Fielding questions well requires preparation and confidence.','질문을 잘 처리하려면 준비와 자신감이 필요해요.'),
('col_presentation_14','lose','the thread','lose the thread','발표 흐름을 잃다','forget','"forget what to say"도 맞지만 lose the thread는 발표 흐름이 끊기는 것을 강조해요.','C1','presentation',3,14,'presentation focus flow thread clarity','He lost the thread halfway through and had to check his notes.','그는 중간에 흐름을 잃어 메모를 확인해야 했어요.','Don''t lose the thread by including too many unnecessary details.','불필요한 세부 사항을 너무 많이 포함해서 흐름을 잃지 마세요.','He lost the thread when an unexpected question came in.','그는 예상치 못한 질문이 들어왔을 때 흐름을 잃었어요.','She paused for water and lost the thread for a second.','그녀는 물을 마시려고 잠시 멈췄다가 흐름을 잠깐 잃었어요.','Losing the thread is normal — just smile and continue.','흐름을 잃는 건 흔한 일이에요 — 그냥 미소 짓고 계속하세요.'),
('col_presentation_18','transition','smoothly','transition smoothly','매끄럽게 전환하다','move','"move to the next slide"도 맞지만 transition smoothly는 발표 흐름의 자연스러움을 강조해요.','C1','presentation',3,18,'transition flow presentation smooth section','A good presenter transitions smoothly between sections.','좋은 발표자는 섹션 간에 매끄럽게 전환해요.','Practice transitioning smoothly so the audience follows along easily.','청중이 쉽게 따라올 수 있도록 매끄럽게 전환하는 연습을 하세요.','He transitions smoothly between his slides using consistent phrasing.','그는 일관된 표현으로 슬라이드 간에 매끄럽게 전환해요.','Transitioning smoothly requires practice and clear signposting.','매끄럽게 전환하려면 연습과 명확한 안내가 필요해요.','She transitioned smoothly from the problem to the proposed solution.','그녀는 문제에서 제안된 해결책으로 매끄럽게 전환했어요.'),
('col_presentation_19','tailor','a message','tailor a message','메시지를 맞춤화하다','change','"change the message"도 맞지만 tailor는 특정 청중에 맞게 조정하는 뉘앙스예요.','C1','presentation',3,19,'message audience tailor communication','You should tailor your message to the specific needs of your audience.','청중의 특정 니즈에 맞게 메시지를 맞춤화해야 해요.','She tailored her message differently for each department she presented to.','그녀는 발표한 각 부서에 맞게 메시지를 다르게 맞춤화했어요.','He tailored his message for the engineering team vs. the executives.','그는 엔지니어링 팀과 임원진에게 메시지를 다르게 맞춤화했어요.','Tailoring your message shows respect for your audience''s time.','메시지를 맞춤화하는 것은 청중의 시간에 대한 존중을 보여줘요.','She tailored her message based on a quick audience poll.','그녀는 청중 빠른 투표를 바탕으로 메시지를 맞춤화했어요.'),
('col_presentation_20','pause','for effect','pause for effect','효과를 위해 잠시 멈추다','stop','"stop"도 맞지만 pause for effect는 의도적인 극적 멈춤을 강조해요.','C1','presentation',3,20,'pause effect speech delivery timing','She paused for effect before revealing the final results.','그녀는 최종 결과를 발표하기 전에 효과를 위해 잠시 멈췄어요.','Great speakers know when to pause for effect to let key points sink in.','훌륭한 연사들은 핵심 요점이 스며들도록 언제 멈춰야 할지 알아요.','He paused for effect, letting the silence build the tension.','그는 효과를 위해 잠시 멈춰서 침묵이 긴장을 쌓도록 했어요.','She paused for effect just before the final reveal.','그녀는 마지막 공개 직전에 효과를 위해 잠시 멈췄어요.','Pausing for effect is a small move that has a big impact.','효과를 위해 잠시 멈추는 것은 큰 영향을 미치는 작은 움직임이에요.'),
('col_presentation_C1_01','deliver','speech','deliver a speech','연설을 하다','say','준비된 연설을 청중 앞에서 전달한다는 격식 표현이에요. ''give''도 가능하지만 ''deliver''가 더 전문적이에요.','C1','presentation',2,0,'speaker podium','She delivered a powerful keynote speech at the global summit.','그녀는 글로벌 정상회의에서 강력한 기조연설을 했어요.','He has been invited to deliver a commencement speech at his alma mater.','그는 모교에서 졸업 연설을 해 달라는 초청을 받았어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_presentation_C1_02','engage','audience','engage the audience','청중을 사로잡다','interest','청중의 주의를 끌고 적극적으로 참여시킨다는 뜻이에요. 발표 코칭에서 가장 자주 쓰는 표현 중 하나예요.','C1','presentation',2,0,'engaged crowd','A great presenter knows how to engage the audience from the first slide.','훌륭한 발표자는 첫 슬라이드부터 청중을 사로잡는 법을 알아요.','She engaged the audience by opening with a personal story.','그녀는 개인적인 이야기로 시작하며 청중을 사로잡았어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_presentation_C1_03','highlight','key points','highlight key points','핵심을 강조하다','show','발표나 글의 중요한 부분을 두드러지게 보여준다는 뜻이에요. 비즈니스 미팅과 학회 발표에서 표준이에요.','C1','presentation',2,0,'highlighted text','Let me highlight the key points before we open the floor for questions.','질의응답을 열기 전에 핵심을 강조해 드릴게요.','The executive summary highlights the key points of the report.','요약본은 보고서의 핵심을 강조해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_presentation_C1_04','field','question','field a question','질문에 답하다','answer','청중의 질문을 능숙하게 받아 답한다는 격식 표현이에요. 기자회견과 Q&A 세션에서 표준이에요.','C1','presentation',2,0,'press conference','The CEO fielded a difficult question about layoffs with composure.','CEO는 정리해고에 대한 까다로운 질문에 침착하게 답했어요.','She skillfully fielded questions from skeptical investors.','그녀는 회의적인 투자자들의 질문에 능숙하게 답했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_presentation_C1_05','wrap up','talk','wrap up a talk','발표를 마무리하다','finish','발표나 강연을 깔끔하게 마무리한다는 뜻이에요. 격식 자리에서도 자연스러운 비즈니스 표현이에요.','C1','presentation',2,0,'closing slide','Let me wrap up this talk with three actionable takeaways.','실행 가능한 시사점 세 가지로 이 발표를 마무리할게요.','She wrapped up her talk by inviting the audience to continue the conversation online.','그녀는 청중에게 온라인에서 대화를 이어가자고 제안하며 발표를 마무리했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_presentation_C2_01','captivate','audience','captivate an audience','청중을 사로잡다','interest','청중을 완전히 매혹시켜 시선을 떼지 못하게 한다는 강한 표현이에요. 발표 평론과 강연 후기에 표준이에요.','C2','presentation',3,0,'keynote speaker stage','Her opening anecdote captivated the audience from the very first sentence.','그녀의 도입부 일화는 첫 문장부터 청중을 사로잡았어요.','A skilled keynote speaker knows precisely how to captivate an audience.','능숙한 기조 연설자는 어떻게 청중을 사로잡을지 정확히 알아요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_presentation_C2_02','marshal','evidence','marshal evidence','증거를 정연하게 제시하다','show','증거를 체계적이고 설득력 있게 동원·배열한다는 격식 표현이에요. 법정, 학술, 임원 보고에서 표준이에요.','C2','presentation',3,0,'boardroom evidence','The consultant marshaled compelling evidence to support the restructuring proposal.','그 컨설턴트는 구조조정 제안을 뒷받침할 설득력 있는 증거를 정연하게 제시했어요.','You must marshal evidence carefully before the board challenges the assumptions.','이사회가 가정에 의문을 제기하기 전에 증거를 신중히 정렬해야 해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_presentation_C2_03','articulate','vision','articulate a vision','비전을 분명히 표현하다','tell','추상적인 비전을 청중이 이해하고 공감할 수 있도록 명료하게 풀어낸다는 격식 표현이에요. CEO 연설의 표준 동사예요.','C2','presentation',3,0,'CEO town hall','The new CEO articulated a vision of sustainable, decade-long growth.','신임 CEO는 지속 가능하고 10년에 걸친 성장 비전을 분명히 표현했어요.','Great leaders articulate a vision their teams can rally behind.','훌륭한 리더는 팀원들이 결집할 수 있는 비전을 분명히 표현해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_presentation_C2_04','underscore','points','underscore key points','핵심을 강조하다','show','발표 중 핵심 메시지를 의도적으로 강조한다는 격식 동사예요. ''emphasize''보다 더 차분하고 세련된 어조예요.','C2','presentation',3,0,'slide deck close','Throughout the address, she underscored three key points with quiet authority.','연설 내내 그녀는 차분한 권위로 세 가지 핵심을 강조했어요.','The closing slide underscored the key points of the entire presentation.','마지막 슬라이드는 발표 전체의 핵심을 강조했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_presentation_C2_05','field','questions','field questions','질문을 받아 응대하다','answer','질문을 능숙하게 받아 적절히 응대한다는 격식 표현이에요. 기자회견, Q&A 세션 보도에서 표준이에요.','C2','presentation',3,0,'press conference qa','After the keynote, she fielded questions from international journalists for over an hour.','기조연설 이후, 그녀는 한 시간 넘게 국제 기자들의 질문을 받아 응대했어요.','The minister fielded difficult questions with characteristic poise.','그 장관은 특유의 침착함으로 어려운 질문들을 받아 응대했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_shopping_22','spend','money','spend money','돈을 쓰다','use','"use money"는 일반적으로 어색해요. 구매에 돈을 사용할 때는 spend money.','A1','shopping',1,0,'shopping bags money credit card store','I spent too much money on clothes this month.','이번 달에 옷에 돈을 너무 많이 썼어요.','Don''t spend money on things you don''t need.','필요 없는 것에 돈을 쓰지 마세요.','They spent a lot of money on the wedding.','그들은 결혼식에 돈을 많이 썼어요.','How much money did you spend at the supermarket?','슈퍼마켓에서 돈을 얼마나 썼어요?','It''s easy to spend money when you''re bored.','지루할 때는 돈 쓰기가 쉬워요.'),
('col_shopping_02','pay','the bill','pay the bill','계산하다','make','"make the bill"은 틀린 표현이에요. 계산할 때는 pay를 써요.','A2','shopping',1,2,'bill payment restaurant checkout counter','Who''s going to pay the bill this time?','이번엔 누가 계산할 거예요?','She insisted on paying the bill even though it was his turn.','그의 차례였는데도 그녀가 계산을 하겠다고 고집했어요.','Let me pay the bill — you got it last time.','계산은 제가 할게요 — 지난번엔 당신이 냈잖아요.','My uncle always pays the bill at family dinners.','제 삼촌은 가족 식사에서 항상 계산을 하세요.','He paid the bill quietly and slipped out of the restaurant.','그는 조용히 계산을 하고 식당을 빠져나왔어요.'),
('col_shopping_11','try','on','try on','입어보다, 신어보다','wear','"wear"는 이미 착용 중인 상태를 말해요. 입어볼 때는 try on을 써요.','A2','shopping',1,11,'fitting room try on clothes shoes','Can I try on these shoes in a size 7?','이 신발 7사이즈로 신어볼 수 있을까요?','She tried on three dresses before choosing the blue one.','그녀는 파란 드레스를 고르기 전에 세 벌을 입어봤어요.','You can try on as many pairs of jeans as you like.','원하는 만큼 여러 청바지를 입어볼 수 있어요.','He tried on the suit but the shoulders were too tight.','그는 정장을 입어봤지만 어깨가 너무 끼었어요.','Always try on shoes in the afternoon when your feet are bigger.','발이 더 부어 있는 오후에 신발을 신어보는 게 좋아요.'),
('col_shopping_12','pay','in cash','pay in cash','현금으로 계산하다','use','"use cash"도 맞지만 pay in cash가 더 자연스러운 표현이에요.','A2','shopping',1,12,'cash payment money counter shop','Do you prefer to pay in cash or by card?','현금으로 계산하시겠어요, 카드로 계산하시겠어요?','I always pay in cash at the local market.','동네 시장에서는 항상 현금으로 계산해요.','I prefer to pay in cash at small family-owned shops.','저는 가족이 운영하는 작은 가게에서는 현금으로 계산하는 걸 선호해요.','He paid in cash to avoid using his credit card abroad.','그는 해외에서 신용카드 사용을 피하려고 현금으로 계산했어요.','Some food trucks only accept payment in cash.','어떤 푸드트럭은 현금으로만 결제를 받아요.'),
('col_shopping_13','go','window shopping','go window shopping','윈도 쇼핑하다','do','"do window shopping"은 어색해요. 윈도 쇼핑할 때는 go를 써요.','A2','shopping',1,13,'window shopping downtown stores display','We went window shopping downtown on a lazy Sunday.','우리는 여유로운 일요일에 시내로 윈도 쇼핑하러 갔어요.','She loves going window shopping even when she has no money to spend.','그녀는 돈이 없어도 윈도 쇼핑하는 걸 좋아해요.','On rainy days I like to go window shopping at the mall.','비 오는 날에 저는 쇼핑몰에서 윈도 쇼핑하는 걸 좋아해요.','They went window shopping for engagement rings before deciding.','그들은 결정하기 전에 약혼 반지를 윈도 쇼핑하러 다녔어요.','She enjoys going window shopping more than actually buying things.','그녀는 실제로 물건을 사는 것보다 윈도 쇼핑하는 걸 더 즐겨요.'),
('col_shopping_21','save','money','save money','돈을 절약하다','keep','"keep money"는 돈을 보관한다는 뜻에 가깝고, 아낀다는 의미는 save money예요.','A2','shopping',1,0,'piggy bank savings jar money coins','I''m trying to save money for a new laptop.','새 노트북을 위해 돈을 모으려고 해요.','Buying in bulk can save you a lot of money.','대량 구매하면 돈을 많이 절약할 수 있어요.','She saves money by cooking at home.','그녀는 집에서 요리해서 돈을 절약해요.','How much can we save by switching providers?','공급업체를 바꾸면 얼마나 절약할 수 있나요?','My parents taught me how to save money.','부모님은 저에게 돈 모으는 법을 가르쳐 주셨어요.'),
('col_shopping_23','pay','bill','pay a bill','청구서/요금을 내다','give','"give a bill"은 받는 사람 입장의 표현이에요. 지불은 항상 pay.','A2','shopping',1,0,'bill payment desk envelope receipt','I need to pay the electricity bill before Friday.','금요일 전에 전기 요금을 내야 해요.','Did you pay the credit card bill on time?','신용카드 요금 제때 냈어요?','We pay our bills online through the bank app.','저희는 은행 앱으로 청구서를 온라인으로 결제해요.','She forgot to pay the phone bill this month.','그녀는 이번 달 전화 요금을 내는 걸 잊었어요.','You can pay the bill in installments if needed.','필요하면 분할로 청구서를 결제할 수 있어요.'),
('col_shopping_01','make','a purchase','make a purchase','구매하다','do','"do a purchase"는 틀린 표현이에요. 구매할 때는 make를 써요.','B1','shopping',1,1,'shopping purchase store retail buy','She made several purchases at the sale yesterday.','그녀는 어제 세일에서 여러 번 구매했어요.','You can make a purchase online or in-store.','온라인이나 매장에서 구매할 수 있어요.','I made a small purchase at the local bookstore yesterday.','저는 어제 동네 서점에서 작은 구매를 했어요.','You can make a purchase using cash, card, or mobile pay.','현금, 카드, 또는 모바일 결제로 구매할 수 있어요.','He made a big purchase for the family without telling anyone.','그는 가족을 위한 큰 구매를 아무에게도 말하지 않고 했어요.'),
('col_shopping_03','get','a discount','get a discount','할인을 받다','take','"take a discount"도 쓰이지만 get a discount가 더 자연스러운 일상 표현이에요.','B1','shopping',1,3,'discount sale coupon shopping deal','Do you know if we can get a discount with this membership card?','이 멤버십 카드로 할인을 받을 수 있는지 아세요?','She got a 20% discount because she was a loyal customer.','그녀는 단골 고객이라 20% 할인을 받았어요.','Students often get a discount on movie tickets with their ID.','학생들은 학생증으로 영화표 할인을 받는 경우가 많아요.','I got a discount because the box was slightly damaged.','상자가 약간 손상돼서 할인을 받았어요.','You can get a discount if you sign up for the newsletter.','뉴스레터를 구독하면 할인을 받을 수 있어요.'),
('col_shopping_04','take','a refund','take a refund','환불을 받다','get','"get a refund"가 더 일반적이지만 take a refund도 자주 쓰여요.','B1','shopping',1,4,'refund return receipt store policy','She decided to take a refund instead of exchanging the item.','그녀는 물건을 교환하는 대신 환불을 받기로 했어요.','You can take a full refund if the product is faulty.','제품에 결함이 있으면 전액 환불을 받을 수 있어요.','I took a refund on the jacket because it didn''t fit properly.','재킷이 잘 맞지 않아서 환불을 받았어요.','She took a refund instead of waiting for a replacement.','그녀는 교환을 기다리는 대신 환불을 받았어요.','You can take a refund within fourteen days of purchase.','구매 후 14일 이내에 환불을 받을 수 있어요.'),
('col_shopping_05','keep','a receipt','keep a receipt','영수증을 보관하다','save','"save a receipt"도 맞지만 keep이 더 자연스러운 구어체 표현이에요.','B1','shopping',1,5,'receipt paper store purchase record','Always keep your receipt in case you need to return something.','반품이 필요할 경우에 대비해 항상 영수증을 보관하세요.','I always keep receipts from large purchases.','큰 구매 항목의 영수증은 항상 보관해요.','Keep your receipt in your wallet so you don''t lose it.','잃어버리지 않도록 영수증을 지갑에 보관하세요.','She keeps every receipt for her business expenses.','그녀는 사업 경비를 위한 모든 영수증을 보관해요.','I forgot to keep the receipt and couldn''t exchange the item.','영수증 보관을 잊어서 물건을 교환할 수 없었어요.'),
('col_shopping_06','place','an order','place an order','주문하다','make','"make an order"도 쓰이지만 place an order가 훨씬 더 자주 쓰이는 표현이에요.','B1','shopping',1,6,'order online shopping delivery app','I''d like to place an order for delivery to my address.','제 주소로 배달 주문을 하고 싶어요.','You can place an order through the app or by phone.','앱이나 전화로 주문하실 수 있어요.','I placed an order for two coffees and a sandwich.','저는 커피 두 잔과 샌드위치 하나를 주문했어요.','You can place an order online and pick it up at the store.','온라인으로 주문하고 매장에서 픽업할 수 있어요.','The customer placed an order for 50 units of the product.','그 고객은 제품 50개를 주문했어요.'),
('col_shopping_10','browse','through','browse through','구경하다, 둘러보다','look','"look through"도 쓰이지만 browse through는 편안하게 둘러보는 뉘앙스예요.','B1','shopping',1,10,'browsing shopping window display casual','She spent an hour just browsing through the boutique.','그녀는 부티크를 그냥 둘러보는 데 한 시간을 보냈어요.','He browsed through several online stores before deciding.','그는 결정하기 전에 여러 온라인 쇼핑몰을 둘러봤어요.','I love browsing through used bookstores on weekends.','저는 주말마다 헌책방을 둘러보는 걸 좋아해요.','We browsed through the market without buying anything.','우리는 아무것도 사지 않고 시장을 둘러봤어요.','She browsed through the rack and pulled out a green dress.','그녀는 옷걸이를 둘러보다가 초록색 드레스를 꺼냈어요.'),
('col_shopping_15','compare','prices','compare prices','가격을 비교하다','check','"check prices"도 맞지만 compare는 두 개 이상을 비교하는 뉘앙스예요.','B1','shopping',2,15,'price compare shopping deal bargain','Always compare prices before making a big purchase.','큰 구매를 하기 전에 항상 가격을 비교하세요.','He compared prices across five different websites.','그는 다섯 개의 다른 웹사이트에서 가격을 비교했어요.','I always compare prices on at least three websites before buying.','저는 구매 전에 항상 최소 세 곳의 웹사이트에서 가격을 비교해요.','Compare prices at different supermarkets to save money.','돈을 절약하려면 여러 슈퍼마켓에서 가격을 비교해 보세요.','She compared prices and chose the most affordable option.','그녀는 가격을 비교하고 가장 합리적인 옵션을 골랐어요.'),
('col_shopping_18','get','a bargain','get a bargain','저렴하게 사다','find','"find a bargain"도 맞지만 get은 실제로 구매한 것을 강조해요.','B1','shopping',1,18,'bargain deal cheap market value','She got a real bargain at the vintage market.','그녀는 빈티지 시장에서 정말 저렴하게 샀어요.','If you wait until January, you can usually get a bargain.','1월까지 기다리면 보통 저렴하게 살 수 있어요.','I got a bargain on a winter coat at the outlet mall.','저는 아울렛에서 겨울 코트를 저렴하게 샀어요.','You can get a real bargain if you shop during off-season sales.','비수기 세일 때 쇼핑하면 정말 저렴하게 살 수 있어요.','They got a bargain on the used car after some haggling.','흥정 끝에 그들은 중고차를 저렴하게 샀어요.'),
('col_shopping_20','return','an item','return an item','물건을 반품하다','give back','"give back an item"은 어색해요. 반품할 때는 return을 써요.','B1','shopping',1,20,'return policy refund shop customer','Can I return this item if it doesn''t fit?','맞지 않으면 이 물건을 반품할 수 있나요?','He returned the item within seven days for a full refund.','그는 전액 환불을 위해 7일 이내에 물건을 반품했어요.','I returned an item by mail because the size was wrong.','사이즈가 맞지 않아서 우편으로 물건을 반품했어요.','You can return an item to any of our branch locations.','저희 어느 지점에서든 물건을 반품할 수 있어요.','She returned the item and received store credit instead.','그녀는 물건을 반품하고 대신 상품권을 받았어요.'),
('col_shopping_24','make','payment','make a payment','결제를 하다','do','"do a payment"은 어색해요. 결제 행위는 make a payment.','B1','shopping',1,0,'payment credit card terminal checkout transaction','You can make a payment online or in person.','온라인이나 직접 방문해서 결제할 수 있어요.','She made the payment using her credit card.','그녀는 신용카드로 결제를 했어요.','Please make the payment within seven days.','7일 이내에 결제해 주세요.','I made a partial payment for the deposit.','보증금으로 부분 결제를 했어요.','Can I make a payment by bank transfer?','계좌 이체로 결제할 수 있나요?'),
('col_shopping_07','make','a complaint','make a complaint','불만을 제기하다','do','"do a complaint"는 틀린 표현이에요. 항의할 때는 make를 써요.','B2','shopping',2,7,'complaint customer service dissatisfied retail','She made a complaint about the damaged product to customer service.','그녀는 고객 서비스에 손상된 제품에 대한 불만을 제기했어요.','If you''re unhappy with the service, don''t hesitate to make a complaint.','서비스가 불만족스럽다면 망설이지 말고 불만을 제기하세요.','She made a complaint to the manager about the rude waiter.','그녀는 무례한 웨이터에 대해 매니저에게 불만을 제기했어요.','Customers often make a complaint when shipping takes too long.','배송이 너무 오래 걸리면 고객들은 종종 불만을 제기해요.','He made a complaint in writing rather than over the phone.','그는 전화 대신 서면으로 불만을 제기했어요.'),
('col_shopping_08','run','a sale','run a sale','세일을 진행하다','make','"make a sale"은 다른 의미예요(판매 한 건). 세일 행사를 진행할 때는 run을 써요.','B2','shopping',2,8,'sale promotion retail discount event store','The store is running a sale on all winter clothing.','그 매장은 모든 겨울 의류 세일을 진행 중이에요.','They run a sale at the end of every season.','그들은 매 시즌 말에 세일을 진행해요.','They run a sale every Black Friday with big discounts.','그들은 매년 블랙 프라이데이에 큰 할인 세일을 진행해요.','Our local bakery runs a sale on day-old bread every evening.','동네 빵집은 매일 저녁 하루 지난 빵을 세일해요.','The boutique runs a sale twice a year to clear out inventory.','그 부티크는 재고를 정리하기 위해 1년에 두 번 세일을 진행해요.'),
('col_shopping_14','claim','a warranty','claim a warranty','보증을 청구하다','use','"use a warranty"도 쓰이지만 claim이 더 격식 있는 표현이에요.','B2','shopping',2,14,'warranty claim product broken guarantee','The laptop broke after two months, so she claimed the warranty.','노트북이 두 달 만에 고장나서 그녀는 보증을 청구했어요.','You can claim the warranty within 12 months of purchase.','구매 후 12개월 이내에 보증을 청구할 수 있어요.','The phone stopped working, so I claimed the warranty.','전화기가 작동이 멈춰서 보증을 청구했어요.','You''ll need the receipt to claim a warranty on this product.','이 제품의 보증을 청구하려면 영수증이 필요해요.','He claimed the warranty after the washing machine broke down.','세탁기가 고장난 후 그는 보증을 청구했어요.'),
('col_shopping_16','take','advantage of','take advantage of a sale','세일을 이용하다','use','"use a sale"은 어색해요. 기회를 활용할 때는 take advantage of를 써요.','B2','shopping',2,16,'sale advantage opportunity discount stock','You should take advantage of the end-of-season sale.','시즌 말 세일을 이용하는 게 좋아요.','She took advantage of the discount to stock up on essentials.','그녀는 할인을 이용해 생필품을 잔뜩 샀어요.','You should take advantage of the free shipping offer.','무료 배송 혜택을 이용하는 게 좋아요.','They took advantage of the holiday sale to buy a new fridge.','그들은 휴일 세일을 이용해 새 냉장고를 샀어요.','Many shoppers take advantage of cashback offers when buying online.','많은 쇼핑객들이 온라인 구매 시 캐시백 혜택을 이용해요.'),
('col_shopping_17','go','over budget','go over budget','예산을 초과하다','exceed','"exceed budget"도 맞지만 go over budget이 훨씬 자연스러운 구어체예요.','B2','shopping',2,17,'budget overspending money shopping finance','We went over budget on the renovation by quite a bit.','우리는 리노베이션에서 예산을 꽤 많이 초과했어요.','Try not to go over budget just because things are on sale.','물건이 세일 중이라고 예산을 초과하지 않도록 하세요.','We went over budget at the grocery store again this week.','이번 주에도 식료품점에서 예산을 초과했어요.','It''s easy to go over budget when shopping with friends.','친구들과 쇼핑할 때 예산을 초과하기 쉬워요.','The wedding went over budget by several thousand dollars.','결혼식은 몇 천 달러나 예산을 초과했어요.'),
('col_shopping_19','carry','a range','carry a range of products','다양한 제품을 취급하다','sell','"sell a range"도 맞지만 carry는 매장이 재고를 보유하는 뉘앙스예요.','B2','shopping',2,19,'product range store stock variety','This store carries a wide range of organic products.','이 매장은 다양한 유기농 제품을 취급해요.','Do you carry any products for sensitive skin?','민감한 피부용 제품을 취급하시나요?','This pharmacy carries a wide range of imported medicines.','이 약국은 다양한 수입 의약품을 취급해요.','Does your shop carry a range of gluten-free options?','그 가게에서 다양한 글루텐 프리 제품을 취급하나요?','The bookstore carries a range of titles in five languages.','그 서점은 다섯 개 언어로 된 다양한 책을 취급해요.'),
('col_shopping_09','break','even','break even','손익분기점에 도달하다','reach','"reach even"은 틀린 표현이에요. 손익분기점을 맞출 때는 break even을 써요.','C1','shopping',3,9,'break even profit loss business finance','The new product line barely broke even in its first year.','새 제품 라인은 첫 해에 겨우 손익분기점을 맞췄어요.','We need at least 500 sales to break even on this investment.','이 투자에서 손익분기점을 맞추려면 최소 500개 이상 판매해야 해요.','The restaurant didn''t break even for the first six months.','그 식당은 처음 6개월간 손익분기점에 도달하지 못했어요.','Most startups take a few years to break even.','대부분의 스타트업은 손익분기점에 도달하는 데 몇 년이 걸려요.','We finally broke even after a strong holiday season.','강력한 연휴 시즌 후 우리는 마침내 손익분기점에 도달했어요.'),
('col_shopping_C1_01','browse','the shelves','browse the shelves','진열대를 둘러보다','look','특정 상품을 정하지 않고 천천히 진열대를 구경한다는 뜻이에요. 서점이나 마트 묘사에 자주 어울려요.','C1','shopping',2,0,'bookstore shelves browsing','I love browsing the shelves at the bookstore.','서점에서 책장 둘러보는 걸 좋아해요.','She spent an hour browsing the shelves.','그녀는 한 시간 동안 진열대를 둘러봤어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_shopping_C1_02','snap','up a bargain','snap up a bargain','특가 상품을 잽싸게 사다','get','좋은 물건이 매진되기 전 재빨리 낚아챈다는 활기찬 표현이에요. 세일이나 한정 판매 맥락에 잘 어울려요.','C1','shopping',2,0,'sale rush shoppers','Shoppers snapped up the bargains within minutes.','쇼핑객들이 몇 분 만에 특가 상품을 다 채갔어요.','I snapped up a bargain on a winter coat.','겨울 코트를 특가로 잽싸게 샀어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_shopping_C1_03','compare','prices','compare prices','가격을 비교하다','check','구매 전 여러 가게나 사이트의 가격을 따져본다는 기본적인 쇼핑 표현이에요. 온라인 쇼핑 맥락에서 더 자주 들려요.','C1','shopping',2,0,'price comparison online','I always compare prices before I buy.','저는 늘 사기 전에 가격을 비교해요.','You can compare prices across multiple sites.','여러 사이트에서 가격을 비교할 수 있어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_shopping_C1_04','splash','out on','splash out on','큰돈을 쓰다','spend','평소보다 큰돈을 흔쾌히 쓴다는 뉘앙스로, 약간의 사치를 즐기는 어감이에요. 영국식에서 더 자주 들려요.','C1','shopping',2,0,'luxury handbag boutique','They splashed out on a designer handbag.','그들은 명품 가방에 큰돈을 썼어요.','I splashed out on a nice dinner last night.','어젯밤 멋진 저녁에 꽤 돈을 썼어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_shopping_C1_05','stick','to a budget','stick to a budget','예산을 지키다','keep','미리 정한 예산 범위 안에서 쇼핑한다는 책임 있는 표현이에요. 가계부나 재테크 맥락에 자주 등장해요.','C1','shopping',2,0,'budget planner wallet','It''s hard to stick to a budget during the holidays.','연말엔 예산을 지키기가 어려워요.','She always sticks to her shopping budget.','그녀는 늘 쇼핑 예산을 지켜요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_shopping_C2_01','indulge','luxury','indulge in luxury','사치를 누리다','buy','죄책감을 약간 동반한 채 호화로움을 즐긴다는 격식 있는 표현이에요. 마케팅 카피에 자주 등장해요.','C2','shopping',3,0,'luxury boutique','Once a year, she indulges in the luxury of a Savile Row bespoke suit.','일 년에 한 번, 그녀는 새빌로 비스포크 정장이라는 사치를 누려요.','Travelers can indulge in the luxury of private butler service.','여행자들은 개인 집사 서비스라는 사치를 누릴 수 있어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_shopping_C2_02','scrutinize','quality','scrutinize quality','품질을 꼼꼼히 살피다','check','단순히 확인하는 게 아니라 세세한 부분까지 면밀히 검토한다는 뜻이에요. 명품, 보석, 시계 구매 맥락에 어울려요.','C2','shopping',3,0,'jewelry inspection','Discerning buyers scrutinize the quality of every stitch before purchase.','안목 있는 구매자들은 구매 전 모든 박음질의 품질을 꼼꼼히 살펴요.','The auctioneer scrutinized the quality of the antique under a loupe.','경매사는 루페로 골동품의 품질을 면밀히 살폈어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_shopping_C2_03','haggle','price','haggle over the price','가격을 흥정하다','discuss','가격을 두고 끈질기게 협상한다는 표현이에요. 시장, 골동품, B2B 거래에서 모두 써요.','C2','shopping',3,0,'moroccan souk','Seasoned collectors haggle over the price at every Sotheby''s preview.','노련한 수집가들은 소더비 프리뷰마다 가격을 흥정해요.','It is customary to haggle over the price in the souks of Marrakesh.','마라케시 시장에서는 가격을 흥정하는 게 관례예요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_shopping_C2_04','incur','expense','incur an expense','비용이 발생하다','pay','비용이 자연스럽게 발생한다는 회계, 비즈니스 표준 표현이에요. ''pay''보다 훨씬 격식 있어요.','C2','shopping',3,0,'wine cellar','Importing rare vintages inevitably incurs significant expense.','희귀 빈티지를 수입하면 상당한 비용이 불가피하게 발생해요.','The renovation incurred expenses well beyond the initial estimate.','리노베이션은 초기 견적을 훨씬 넘는 비용을 발생시켰어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_shopping_C2_05','discern','value','discern value','가치를 분별하다','see','겉으로 잘 드러나지 않는 진정한 가치를 알아본다는 격식 표현이에요. 미술, 빈티지, 투자 맥락에 어울려요.','C2','shopping',3,0,'art gallery','An experienced dealer can discern value where amateurs see only clutter.','경험 많은 딜러는 아마추어가 잡동사니로만 보는 것에서 가치를 분별해요.','It takes years to discern value in the secondary art market.','미술 2차 시장에서 가치를 분별하려면 수년이 걸려요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_sports_12','score','a goal','score a goal','골을 넣다','make','"make a goal"은 틀린 표현이에요. 축구에서 골을 넣을 때는 score를 써요.','A2','sports',1,12,'goal football soccer score match','He scored the winning goal in the final minute of the game.','그는 경기 마지막 1분에 결승 골을 넣었어요.','She scored three goals in one game, completing a hat trick.','그녀는 한 경기에서 세 골을 넣으며 해트트릭을 달성했어요.','He scored a goal with his weaker foot.','그는 잘 안 쓰는 발로 골을 넣었어요.','She scored two goals against the league leaders.','그녀는 리그 1위 팀을 상대로 두 골을 넣었어요.','Scoring a goal in injury time felt almost unbelievable.','부상 시간에 골을 넣는 건 거의 믿기지 않는 기분이었어요.'),
('col_sports_21','score','goal','score a goal','득점하다','make','"make a goal"은 어색. 축구·하키 등에서 골을 넣는 건 score a goal.','A2','sports',1,0,'soccer goal celebration scored stadium','He scored the winning goal in the final minute.','그는 마지막 1분에 결승골을 넣었어요.','She scored two goals in the match.','그녀는 경기에서 두 골을 넣었어요.','The striker scored a beautiful goal.','공격수가 멋진 골을 넣었어요.','They scored a goal from outside the penalty box.','그들은 페널티 박스 밖에서 골을 넣었어요.','It''s rare to score a goal from such a distance.','그렇게 먼 거리에서 골을 넣는 건 드물어요.'),
('col_sports_22','win','match','win a match','경기를 이기다','take','"take a match"는 어색. 경기 승리는 win a match.','A2','sports',1,0,'team celebration victory trophy match','They won the match 3-1.','그들은 3:1로 경기를 이겼어요.','She won her first match of the season.','그녀는 시즌 첫 경기에서 승리했어요.','We need to win this match to qualify.','우리는 진출하려면 이 경기를 이겨야 해요.','He''s never won a match against her.','그는 그녀를 상대로 경기를 이겨본 적이 없어요.','Winning the match was a huge moment.','그 경기를 이긴 건 엄청난 순간이었어요.'),
('col_sports_01','break','a record','break a record','기록을 깨다','set','기록을 처음으로 세울 때는 set, 기존 기록을 뛰어넘을 때는 break를 써요.','B1','sports',1,1,'record athlete sports sprint achievement','She broke the world record for the 200m sprint.','그녀는 200m 단거리 달리기 세계 기록을 깼어요.','He broke the national record three times in one season.','그는 한 시즌에 세 번이나 국가 기록을 깼어요.','He broke a record during yesterday''s qualifying round.','그는 어제 예선에서 기록을 깼어요.','She broke a record that had stood for over a decade.','그녀는 10년 이상 유지된 기록을 깼어요.','The young swimmer broke a record at her very first international event.','그 어린 수영 선수는 첫 국제 대회에서 기록을 깼어요.'),
('col_sports_03','take','the lead','take the lead','선두에 서다','get','"get the lead"도 쓰이지만 take the lead가 더 능동적인 뉘앙스예요.','B1','sports',1,3,'lead race sports competition winning','The team took the lead in the second half and never looked back.','팀은 후반전에 선두에 서고 나서 계속 앞서 나갔어요.','She took the lead at the halfway point and held it to the finish.','그녀는 중반에 선두에 서서 결승선까지 유지했어요.','She took the lead early and dictated the pace of the race.','그녀는 일찍 선두에 서서 경주의 페이스를 주도했어요.','He took the lead in the third lap and stayed there.','그는 3번째 랩에서 선두에 서서 그대로 유지했어요.','Our team finally took the lead at the start of the fourth quarter.','우리 팀은 4쿼터 시작에 마침내 선두에 섰어요.'),
('col_sports_04','get','injured','get injured','부상을 입다','have','"have an injury"도 맞지만 get injured는 부상이 발생하는 순간을 강조해요.','B1','sports',1,4,'injury sports athlete training pain','He got injured during training and missed the whole season.','그는 훈련 중에 부상을 입어 시즌 전체를 놓쳤어요.','She got injured in the final match, which was devastating.','그녀는 결승전에서 부상을 입어 정말 힘들었어요.','He got injured in practice and missed three weeks of training.','그는 연습 중에 부상을 입어 3주간의 훈련을 놓쳤어요.','She got injured falling off her bike during the cycling race.','그녀는 사이클 경주 중 자전거에서 떨어져 부상을 입었어요.','Two players got injured during the rough match.','거친 경기 동안 두 선수가 부상을 입었어요.'),
('col_sports_05','keep','fit','keep fit','건강을 유지하다','stay','"stay fit"도 맞지만 keep fit은 지속적인 노력을 강조해요.','B1','sports',1,5,'fitness training health sports active','Professional athletes work very hard to keep fit throughout the season.','프로 운동선수들은 시즌 내내 건강을 유지하기 위해 매우 열심히 노력해요.','She keeps fit by swimming three times a week.','그녀는 일주일에 세 번 수영을 해서 건강을 유지해요.','He keeps fit by running every morning before work.','그는 출근 전 매일 아침 달리기로 건강을 유지해요.','You don''t need a gym membership to keep fit.','건강을 유지하는 데 헬스장 회원권이 필요한 건 아니에요.','Walking to work helps me keep fit without much effort.','걸어서 출퇴근하면 큰 노력 없이 건강을 유지할 수 있어요.'),
('col_sports_08','run','a marathon','run a marathon','마라톤을 하다','do','"do a marathon"도 쓰이지만 run a marathon이 훨씬 더 자연스러워요.','B1','sports',1,8,'marathon running race fitness endurance','She trained for six months before running her first marathon.','그녀는 첫 마라톤을 하기 전에 6개월 동안 훈련했어요.','He runs a marathon every year for charity.','그는 자선 활동을 위해 매년 마라톤을 해요.','My uncle has run a marathon on every continent.','저희 삼촌은 모든 대륙에서 마라톤을 했어요.','She runs a marathon every spring for the same charity.','그녀는 매년 봄 같은 자선 단체를 위해 마라톤을 해요.','Running a marathon was on her bucket list since college.','마라톤을 하는 건 대학 시절부터 그녀의 버킷 리스트에 있었어요.'),
('col_sports_10','set','a record','set a record','기록을 세우다','make','"make a record"는 다른 의미예요. 새 기록을 세울 때는 set을 써요.','B1','sports',1,10,'record new personal best sports competition','She set a new personal record at the national competition.','그녀는 전국 대회에서 새 개인 기록을 세웠어요.','The swimmer set a world record that still stands today.','그 수영 선수는 오늘날에도 여전히 유지되는 세계 기록을 세웠어요.','He set a personal record at the marathon last year.','그는 작년 마라톤에서 개인 기록을 세웠어요.','She set a record that hasn''t been broken in twenty years.','그녀는 20년 동안 깨지지 않은 기록을 세웠어요.','The athlete set a record in front of a home crowd.','그 선수는 홈 관중 앞에서 기록을 세웠어요.'),
('col_sports_11','win','a title','win a title','타이틀을 따다','get','"get a title"도 맞지만 win은 경쟁을 통해 획득한다는 뉘앙스예요.','B1','sports',1,11,'title championship win trophy sports','The team won the league title for the third consecutive year.','팀은 3년 연속으로 리그 타이틀을 땄어요.','She won the title after an intense match that went to overtime.','그녀는 연장전까지 간 치열한 경기 끝에 타이틀을 땄어요.','She won her first major title at the age of 19.','그녀는 19세에 첫 메이저 타이틀을 땄어요.','They won the title without losing a single match.','그들은 단 한 경기도 지지 않고 타이틀을 땄어요.','Winning a title at home was a dream come true for the team.','홈에서 타이틀을 따는 것은 그 팀의 꿈이 이루어진 순간이었어요.'),
('col_sports_13','train','hard','train hard','열심히 훈련하다','practice','"practice hard"도 맞지만 train hard는 체계적인 훈련을 강조해요.','B1','sports',1,13,'training hard work athlete dedication sport','You have to train hard every day if you want to reach the top.','정상에 오르고 싶다면 매일 열심히 훈련해야 해요.','She trained hard for six months and it showed in her performance.','그녀는 6개월 동안 열심히 훈련했고 경기력에서 그것이 드러났어요.','She trains hard six days a week to stay at the top.','그녀는 정상을 유지하기 위해 일주일에 6일 열심히 훈련해요.','You have to train hard, but you also have to rest properly.','열심히 훈련해야 하지만 제대로 쉬기도 해야 해요.','They train hard year-round, even in the off-season.','그들은 비시즌에도 일 년 내내 열심히 훈련해요.'),
('col_sports_19','beat','an opponent','beat an opponent','상대를 이기다','win','"win an opponent"는 틀린 표현이에요. 상대를 이길 때는 beat를 써요.','B1','sports',1,19,'opponent match win defeat sport','She beat her opponent in straight sets to win the trophy.','그녀는 3세트 연속으로 상대를 이겨 트로피를 차지했어요.','He has beaten his main opponent six times in a row.','그는 주요 상대를 연속으로 6번 이겼어요.','She beat her opponent in a stunning upset victory.','그녀는 충격적인 역전 승리로 상대를 이겼어요.','He beat his opponent in straight sets without much trouble.','그는 별 어려움 없이 스트레이트 세트로 상대를 이겼어요.','Beating an opponent ranked higher than you feels incredible.','자기보다 순위가 높은 상대를 이기는 건 정말 놀라운 기분이에요.'),
('col_sports_23','set','record','set a record','기록을 세우다','make','"make a record"는 음반을 만들거나 다른 의미. 신기록은 set a record.','B1','sports',1,0,'athlete record stadium scoreboard achievement','She set a new world record yesterday.','그녀는 어제 새 세계 기록을 세웠어요.','He set a record for the fastest time.','그는 최단 시간 기록을 세웠어요.','The team set a record for most wins this season.','그 팀은 이번 시즌 최다승 기록을 세웠어요.','Setting a record requires years of training.','기록을 세우려면 수년의 훈련이 필요해요.','She set the record while still a teenager.','그녀는 10대 때 그 기록을 세웠어요.'),
('col_sports_24','break','record','break a record','기록을 깨다','beat','"beat a record"도 쓰이지만 break a record가 더 강력한 표현이에요.','B1','sports',1,0,'athlete record breaking finish line celebration','He broke the school''s long jump record.','그는 학교 멀리뛰기 기록을 깼어요.','She broke the world record by 0.3 seconds.','그녀는 0.3초 차이로 세계 기록을 깼어요.','Records are made to be broken.','기록은 깨지기 위해 만들어진다.','The team broke several records this year.','그 팀은 올해 여러 기록을 깼어요.','Few athletes break records in their first year.','첫 해에 기록을 깨는 선수는 드물어요.'),
('col_sports_02','make','a comeback','make a comeback','복귀하다, 재기하다','do','"do a comeback"은 어색해요. 선수가 복귀할 때는 make a comeback을 써요.','B2','sports',1,2,'comeback athlete return sports champion','After two years out with injury, she made an incredible comeback.','부상으로 2년간 공백 후, 그녀는 놀라운 복귀를 했어요.','The veteran player made a comeback at the age of 35.','그 베테랑 선수는 35세에 복귀했어요.','He made a comeback two years after his retirement was announced.','그는 은퇴 발표 2년 만에 복귀했어요.','The team made a comeback in the last five minutes of the game.','그 팀은 경기 마지막 5분에 재기했어요.','Making a comeback after a serious injury takes incredible discipline.','심각한 부상 후 복귀하는 데는 놀라운 자기 절제가 필요해요.'),
('col_sports_06','hold','a championship','hold a championship','선수권 대회를 개최하다','make','"make a championship"은 어색해요. 대회를 개최할 때는 hold를 써요.','B2','sports',2,6,'championship tournament sports hosting event','The city will hold the national swimming championship next year.','그 도시는 내년에 전국 수영 선수권 대회를 개최할 예정이에요.','The club has held the regional championship for five years running.','클럽은 5년 연속으로 지역 선수권 대회를 개최해 왔어요.','The federation will hold the championship in Seoul next month.','연맹은 다음 달 서울에서 선수권 대회를 개최해요.','They held the championship at a brand-new arena downtown.','그들은 시내에 새로 지어진 경기장에서 선수권 대회를 개최했어요.','The country has held the championship multiple times.','그 나라는 여러 차례 선수권 대회를 개최했어요.'),
('col_sports_07','make','a tackle','make a tackle','태클을 하다','do','"do a tackle"은 어색해요. 축구에서 태클할 때는 make a tackle을 써요.','B2','sports',2,7,'tackle football soccer challenge sport','He made a clean tackle to win the ball back.','그는 공을 되찾기 위해 깔끔한 태클을 했어요.','Making a reckless tackle in the penalty area is very risky.','페널티 에어리어에서 무모한 태클을 하는 것은 매우 위험해요.','He made a brilliant tackle to stop the attacker right at the goal.','그는 골 바로 앞에서 공격수를 막는 멋진 태클을 했어요.','The defender made a tackle that the crowd cheered for.','수비수는 관중이 환호한 태클을 했어요.','She made a clean tackle and won possession back.','그녀는 깔끔한 태클을 해서 공 소유권을 되찾았어요.'),
('col_sports_09','give','a performance','give a performance','경기력을 보여주다','do','"do a performance"는 어색해요. 경기력을 선보일 때는 give를 써요.','B2','sports',2,9,'performance athlete competition sports excellence','The young gymnast gave a flawless performance at the World Championships.','그 젊은 체조 선수는 세계 선수권 대회에서 완벽한 경기력을 선보였어요.','She gave the performance of her career in the Olympic final.','그녀는 올림픽 결승에서 선수 생활 최고의 경기력을 선보였어요.','The figure skater gave a performance that brought tears to many.','그 피겨 스케이터는 많은 사람을 눈물 짓게 한 경기력을 선보였어요.','He gave a strong performance under intense pressure.','그는 강한 압박 속에서 좋은 경기력을 보여줬어요.','She gave a performance worth remembering at the regional final.','그녀는 지역 결승에서 기억할 만한 경기력을 보여줬어요.'),
('col_sports_14','compete','in','compete in','~에 출전하다','join','"join a competition"도 맞지만 compete in은 실제 경쟁에 참가하는 것을 강조해요.','B2','sports',2,14,'competition tournament international athlete event','She competed in the Olympics for the first time at age 18.','그녀는 18세에 처음으로 올림픽에 출전했어요.','He has competed in over 50 international tournaments.','그는 50개 이상의 국제 토너먼트에 출전해 왔어요.','She competed in three Olympic Games during her career.','그녀는 선수 생활 동안 세 번의 올림픽에 출전했어요.','He has competed in dozens of national championships.','그는 수십 번의 전국 선수권 대회에 출전했어요.','Athletes compete in events all around the world each season.','선수들은 매 시즌 전 세계의 대회에 출전해요.'),
('col_sports_15','retire','from','retire from','~에서 은퇴하다','stop','"stop playing"도 맞지만 retire from은 공식적인 은퇴를 강조해요.','B2','sports',2,15,'retirement athlete career ending sports','He retired from professional tennis at the age of 38.','그는 38세에 프로 테니스에서 은퇴했어요.','She retired from competitive swimming after winning the gold medal.','그녀는 금메달을 딴 후 경쟁 수영에서 은퇴했어요.','She retired from international competition at the age of 32.','그녀는 32세에 국제 대회에서 은퇴했어요.','He retired from the sport but stayed on as a coach.','그는 그 스포츠에서 은퇴했지만 코치로 남았어요.','It''s hard to imagine retiring from a sport you love.','사랑하는 스포츠에서 은퇴하는 걸 상상하기는 어려워요.'),
('col_sports_16','suffer','a defeat','suffer a defeat','패배를 당하다','lose','"lose a match"도 맞지만 suffer a defeat는 더 격식 있는 표현이에요.','B2','sports',2,16,'defeat loss match sports competition','The team suffered a heavy defeat in the championship final.','팀은 챔피언십 결승에서 큰 패배를 당했어요.','Suffering a defeat early in the season motivated them to improve.','시즌 초반의 패배가 그들이 성장하도록 동기를 부여했어요.','The defending champions suffered a surprising defeat in the opening match.','디펜딩 챔피언은 개막전에서 충격적인 패배를 당했어요.','Suffering a defeat early in the tournament can be devastating.','토너먼트 초반에 패배를 당하는 건 정말 충격적일 수 있어요.','The team suffered a narrow defeat in the final seconds.','그 팀은 마지막 몇 초에 근소한 차이로 패배를 당했어요.'),
('col_sports_17','reach','the final','reach the final','결승에 진출하다','go','"go to the final"도 맞지만 reach the final은 대회를 통해 나아가는 뉘앙스예요.','B2','sports',2,17,'final tournament sports competition round','It was the first time the club had reached the final.','그 클럽이 결승에 진출한 것은 처음이었어요.','She reached the final of the Grand Slam tournament for the second time.','그녀는 두 번째로 그랜드 슬램 토너먼트 결승에 진출했어요.','Our team reached the final for the first time in club history.','우리 팀은 클럽 역사상 처음으로 결승에 진출했어요.','She reached the final without dropping a single set.','그녀는 단 한 세트도 내주지 않고 결승에 진출했어요.','They reached the final after an exciting semifinal.','그들은 흥미진진한 준결승 끝에 결승에 진출했어요.'),
('col_sports_20','pull','out of','pull out of','~에서 기권하다','leave','"leave a competition"도 맞지만 pull out of는 예상치 못한 기권을 강조해요.','B2','sports',2,20,'withdrawal sports injury retirement race','She pulled out of the tournament due to a knee injury.','그녀는 무릎 부상으로 인해 토너먼트에서 기권했어요.','He was forced to pull out of the race at the last minute.','그는 막판에 어쩔 수 없이 경기를 기권해야 했어요.','He pulled out of the tournament after testing positive for the flu.','그는 독감 양성 판정을 받은 후 토너먼트에서 기권했어요.','She pulled out of the match to recover from a back injury.','그녀는 허리 부상에서 회복하기 위해 경기를 기권했어요.','Several athletes pulled out of the competition last-minute.','여러 선수들이 막판에 대회를 기권했어요.'),
('col_sports_18','put','in a performance','put in a performance','경기에서 보여주다','make','"make a performance"는 어색해요. 특정 경기에서의 수행을 표현할 때는 put in을 써요.','C1','sports',3,18,'performance athlete sport match pressure','He really put in a strong performance during the semifinals.','그는 준결승에서 정말 강한 경기력을 선보였어요.','She put in a world-class performance under incredible pressure.','그녀는 엄청난 압박 속에서 세계 수준의 경기력을 보여줬어요.','He put in his best performance ever at the regional championship.','그는 지역 선수권 대회에서 역대 최고의 경기력을 보여줬어요.','The team put in a strong performance against the league favorites.','그 팀은 리그 우승 후보를 상대로 강한 경기력을 보여줬어요.','She put in a performance that earned her a place on the national team.','그녀는 국가대표 자리를 얻을 만한 경기력을 보여줬어요.'),
('col_sports_C1_01','win','match','win a match','경기에서 이기다','beat','''beat''는 상대를 이기는 것, ''win a match''는 시합 자체를 이긴다는 뜻이라 미묘하게 달라요. 경기 결과 표현의 기본이에요.','C1','sports',2,0,'tennis match','They need to win the next match to qualify for the finals.','그들이 결승에 진출하려면 다음 경기에서 이겨야 해요.','She has won every match in straight sets this tournament.','그녀는 이번 토너먼트에서 모든 경기를 스트레이트 세트로 이겼어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_sports_C1_02','make','comeback','make a comeback','재기하다','do','부진이나 부상 후 다시 활약한다는 표준 표현이에요. ''do a comeback''은 영어에서 어색해요.','C1','sports',2,0,'athlete returning','The veteran striker is hoping to make a comeback next season.','그 베테랑 공격수는 다음 시즌에 재기하기를 바라고 있어요.','After two surgeries, she made a remarkable comeback at the Olympics.','두 차례 수술 후 그녀는 올림픽에서 놀라운 재기를 이뤄냈어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_sports_C1_03','set','record','set a record','기록을 세우다','make','새로운 최고 기록을 만든다는 표준 동사 조합이에요. ''make a record''는 음반 만들 때 써서 헷갈리기 쉬워요.','C1','sports',2,0,'stadium record','He set a world record in the 200 meters at last summer''s championships.','그는 지난여름 챔피언십에서 200미터 세계 기록을 세웠어요.','The team set a new club record for consecutive wins.','그 팀은 연승 부문에서 새로운 구단 기록을 세웠어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_sports_C1_04','score','goal','score a goal','골을 넣다','make','축구, 하키 등에서 득점한다는 가장 기본적이고 정확한 동사예요. ''make a goal''은 어색해요.','C1','sports',2,0,'soccer goal','He scored a stunning goal from outside the penalty box.','그는 페널티 박스 밖에서 멋진 골을 넣었어요.','She has scored a goal in every match this season.','그녀는 이번 시즌 모든 경기에서 골을 넣었어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_sports_C1_05','claim','victory','claim victory','승리를 거머쥐다','get','경쟁 후 승리를 공식적으로 차지한다는 격식 있는 표현이에요. 스포츠 헤드라인의 단골이에요.','C1','sports',2,0,'victory celebration','The underdogs claimed victory after a thrilling penalty shootout.','약체 팀이 짜릿한 승부차기 끝에 승리를 거머쥐었어요.','She claimed victory in her debut tournament with surprising ease.','그녀는 데뷔 토너먼트에서 의외로 수월하게 승리를 거머쥐었어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_sports_C2_01','demonstrate','prowess','demonstrate prowess','기량을 보여주다','show','특히 운동이나 전문 분야의 뛰어난 기량을 격식 있게 드러낸다는 표현이에요. ''show''보다 훨씬 문어체예요.','C2','sports',3,0,'athlete performance','She demonstrated extraordinary prowess on the balance beam in the final round.','그녀는 결선에서 평균대에서 엄청난 기량을 보여줬어요.','The young midfielder demonstrated tactical prowess beyond his years.','그 어린 미드필더는 나이를 뛰어넘는 전술적 기량을 보여줬어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_sports_C2_02','uphold','sportsmanship','uphold sportsmanship','스포츠맨십을 지키다','keep','경기 윤리를 일관되게 지킨다는 격식 표현이에요. 올림픽 헌장이나 스포츠 평론에서 자주 보여요.','C2','sports',3,0,'handshake sports','Even in defeat, the captain upheld the highest standards of sportsmanship.','패배 속에서도 주장은 가장 높은 수준의 스포츠맨십을 지켰어요.','Coaches are expected to uphold sportsmanship as a model for younger players.','코치들은 어린 선수들의 본보기로서 스포츠맨십을 지켜야 해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_sports_C2_03','secure','victory','secure victory','승리를 거머쥐다','get','경기 끝까지 우위를 지켜 승리를 확정한다는 격식 표현이에요. 스포츠 기사 헤드라인에 단골이에요.','C2','sports',3,0,'victory celebration','A late penalty secured victory for the home side in injury time.','추가 시간에 막판 페널티킥으로 홈팀이 승리를 거머쥐었어요.','They secured victory after a gruelling five-set match.','그들은 격렬한 5세트 경기 끝에 승리를 거머쥐었어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_sports_C2_04','concede','defeat','concede defeat','패배를 인정하다','lose','패배를 공식적으로, 품위 있게 인정한다는 격식 표현이에요. 스포츠와 정치 양쪽에서 자주 써요.','C2','sports',3,0,'match end','After a valiant comeback attempt, she finally conceded defeat in the fifth set.','용감한 역전 시도 끝에 그녀는 5세트에서 결국 패배를 인정했어요.','The challenger conceded defeat with a gracious post-match speech.','도전자는 경기 후 품위 있는 연설로 패배를 인정했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_sports_C2_05','exhibit','stamina','exhibit stamina','체력을 보여주다','show','지구력을 격식 있게 드러낸다는 표현이에요. 스포츠 기자나 코칭 보고서에 자주 등장해요.','C2','sports',3,0,'marathon runner','Marathon runners must exhibit remarkable stamina over the final ten kilometres.','마라톤 선수들은 마지막 10km에서 놀라운 체력을 보여줘야 해요.','The veteran goalkeeper exhibited the stamina of a player half his age.','베테랑 골키퍼는 절반 나이의 선수다운 체력을 보여줬어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_technology_21','send','email','send an email','이메일을 보내다','do','"do an email"은 틀린 표현. 이메일 발송은 send.','A2','technology',1,0,'laptop email inbox typing sending','I''ll send you an email with the details.','자세한 내용을 이메일로 보내 드릴게요.','She sends emails throughout the day.','그녀는 하루 종일 이메일을 보내요.','Did you send the email to the client?','고객에게 이메일 보냈어요?','Please send an email confirming the booking.','예약 확인 이메일을 보내 주세요.','He sent dozens of emails before noon.','그는 정오 전에 수십 통의 이메일을 보냈어요.'),
('col_technology_22','download','file','download a file','파일을 다운로드하다','take','"take a file"은 다른 의미. 인터넷에서 받는 건 download.','A2','technology',1,0,'computer download progress bar file transfer','I downloaded the file from the company portal.','회사 포털에서 파일을 다운로드했어요.','Can you download the attached file?','첨부된 파일 다운로드할 수 있어요?','She accidentally downloaded a malicious file.','그녀는 실수로 악성 파일을 다운로드했어요.','It takes a few minutes to download the file.','파일 다운로드에 몇 분 걸려요.','Always scan a file before downloading.','다운로드하기 전에 항상 파일을 검사하세요.'),
('col_technology_24','update','app','update an app','앱을 업데이트하다','refresh','"refresh an app"은 새로고침. 새 버전 적용은 update an app.','A2','technology',1,0,'phone app update screen download progress','I need to update the app — it''s outdated.','앱이 구버전이라 업데이트해야 해요.','She updates her apps automatically.','그녀는 앱을 자동으로 업데이트해요.','Did you update the banking app this week?','이번 주에 은행 앱 업데이트했어요?','You should update apps regularly for security.','보안을 위해 앱을 정기적으로 업데이트해야 해요.','He hates updating apps — they always change.','그는 앱 업데이트를 싫어해요 — 항상 바뀌니까.'),
('col_technology_01','develop','software','develop software','소프트웨어를 개발하다','make','"make software"도 쓰이지만 develop은 전문적인 개발 과정을 강조해요.','B1','technology',1,1,'software development coding tech laptop','The team spent six months developing the new software platform.','팀은 새로운 소프트웨어 플랫폼을 개발하는 데 6개월을 보냈어요.','She develops software for financial institutions around the world.','그녀는 전 세계 금융 기관을 위한 소프트웨어를 개발해요.','He develops software for hospitals in his spare time.','그는 여가 시간에 병원을 위한 소프트웨어를 개발해요.','She started developing software when she was still in high school.','그녀는 고등학교 시절부터 소프트웨어를 개발하기 시작했어요.','Developing software for accessibility is becoming a priority.','접근성을 위한 소프트웨어 개발이 우선순위가 되고 있어요.'),
('col_technology_02','run','a program','run a program','프로그램을 실행하다','open','"open a program"도 맞지만 run은 프로그램이 실행되는 것을 강조해요.','B1','technology',1,2,'program computer run software execute','You can run the program by double-clicking the icon.','아이콘을 더블 클릭하면 프로그램을 실행할 수 있어요.','The server runs the program automatically every night at midnight.','서버는 매일 밤 자정에 자동으로 프로그램을 실행해요.','You can run a program in the background while you work.','작업하는 동안 백그라운드에서 프로그램을 실행할 수 있어요.','She runs a program that converts photos to text automatically.','그녀는 사진을 자동으로 텍스트로 변환하는 프로그램을 실행해요.','The phone keeps running a program even when the screen is off.','화면이 꺼져 있을 때도 휴대폰은 프로그램을 계속 실행해요.'),
('col_technology_03','launch','an app','launch an app','앱을 출시하다','make','"make an app"은 앱을 만드는 것이에요. 공식적으로 출시할 때는 launch를 써요.','B1','technology',1,3,'app launch startup mobile release','The startup launched its new app to great critical acclaim.','그 스타트업은 큰 호평을 받으며 새 앱을 출시했어요.','They plan to launch the app in three new markets next year.','그들은 내년에 세 개의 새 시장에서 앱을 출시할 계획이에요.','The team launched an app for tracking personal carbon emissions.','그 팀은 개인 탄소 배출을 추적하는 앱을 출시했어요.','They launched an app that became popular in just a few weeks.','그들은 단 몇 주 만에 인기를 끈 앱을 출시했어요.','She launched an app to help students manage their schedules.','그녀는 학생들이 일정을 관리하도록 돕는 앱을 출시했어요.'),
('col_technology_04','store','data','store data','데이터를 저장하다','save','"save data"도 맞지만 store는 시스템이나 클라우드에 저장하는 더 기술적인 표현이에요.','B1','technology',1,4,'data storage cloud server digital','The system stores all user data on secure cloud servers.','시스템은 모든 사용자 데이터를 안전한 클라우드 서버에 저장해요.','Companies must be transparent about how they store personal data.','기업은 개인 데이터를 어떻게 저장하는지 투명하게 공개해야 해요.','Smart watches store data about your sleep and heart rate.','스마트 워치는 수면과 심박수에 대한 데이터를 저장해요.','They store data in encrypted form for added safety.','그들은 추가 안전을 위해 데이터를 암호화된 형태로 저장해요.','Storing data responsibly is more than a technical question.','데이터를 책임감 있게 저장하는 것은 단순한 기술 문제 이상이에요.'),
('col_technology_06','update','software','update software','소프트웨어를 업데이트하다','change','"change software"는 다른 의미예요. 버전을 최신화할 때는 update를 써요.','B1','technology',1,6,'software update security patch digital','Remember to update your software regularly to stay protected from threats.','위협으로부터 보호받기 위해 소프트웨어를 정기적으로 업데이트하세요.','The company updated its software to fix a critical security vulnerability.','회사는 심각한 보안 취약점을 수정하기 위해 소프트웨어를 업데이트했어요.','She updates her software every Sunday evening.','그녀는 매주 일요일 저녁에 소프트웨어를 업데이트해요.','The app prompted me to update the software before I could log in.','앱은 로그인하기 전에 소프트웨어를 업데이트하라고 안내했어요.','Updating software can sometimes break compatibility with other apps.','소프트웨어를 업데이트하면 때로 다른 앱과의 호환성이 깨질 수 있어요.'),
('col_technology_12','back up','data','back up data','데이터를 백업하다','save','"save data"도 맞지만 back up은 복사본을 만들어 보호하는 뉘앙스예요.','B1','technology',1,12,'backup data storage cloud recovery','You should back up your data regularly in case of system failure.','시스템 장애에 대비해 데이터를 정기적으로 백업해야 해요.','The IT department backs up all company data every 24 hours.','IT 부서는 24시간마다 모든 회사 데이터를 백업해요.','Please back up your data before installing the new operating system.','새 운영체제를 설치하기 전에 데이터를 백업하세요.','He backed up his data to two different cloud services.','그는 두 가지 다른 클라우드 서비스에 데이터를 백업했어요.','Backing up data is the cheapest insurance you''ll ever buy.','데이터를 백업하는 것은 당신이 살 수 있는 가장 저렴한 보험이에요.'),
('col_technology_15','access','a network','access a network','네트워크에 접속하다','connect','"connect to a network"도 맞지만 access는 네트워크에 들어가는 것을 강조해요.','B1','technology',1,15,'network access internet connection technology','Remote workers can securely access the company network via VPN.','원격 근무자는 VPN을 통해 회사 네트워크에 안전하게 접속할 수 있어요.','She couldn''t access the network because she forgot her password.','그녀는 비밀번호를 잊어서 네트워크에 접속할 수 없었어요.','You need a special password to access the network.','네트워크에 접속하려면 특별한 비밀번호가 필요해요.','She can''t access the network from her home connection today.','그녀는 오늘 집 연결에서 네트워크에 접속할 수 없어요.','Visitors can access a guest network with limited permissions.','방문자는 제한된 권한으로 게스트 네트워크에 접속할 수 있어요.'),
('col_technology_23','install','software','install software','소프트웨어를 설치하다','put','"put software"는 어색해요. 컴퓨터 프로그램 설치는 install.','B1','technology',1,0,'computer installation progress screen software setup','I installed the new design software yesterday.','어제 새 디자인 소프트웨어를 설치했어요.','You need admin rights to install software.','소프트웨어를 설치하려면 관리자 권한이 필요해요.','She installed antivirus software on all computers.','그녀는 모든 컴퓨터에 백신 소프트웨어를 설치했어요.','Don''t install software from unknown sources.','출처 모르는 소프트웨어는 설치하지 마세요.','Installing the software took about ten minutes.','소프트웨어 설치에 약 10분 걸렸어요.'),
('col_technology_05','process','data','process data','데이터를 처리하다','analyse','"analyse data"도 맞지만 process는 데이터를 변환하거나 처리하는 기계적 단계를 강조해요.','B2','technology',2,5,'data process computing AI speed','The algorithm can process millions of data points per second.','알고리즘은 초당 수백만 개의 데이터 포인트를 처리할 수 있어요.','Modern computers process data far faster than those of twenty years ago.','현대 컴퓨터는 20년 전보다 훨씬 빠르게 데이터를 처리해요.','AI systems can process data faster than humans by a wide margin.','AI 시스템은 인간보다 훨씬 빠르게 데이터를 처리할 수 있어요.','Modern processors can process data in real time.','현대의 프로세서는 데이터를 실시간으로 처리할 수 있어요.','Processing data ethically matters as much as processing it efficiently.','데이터를 윤리적으로 처리하는 것은 효율적으로 처리하는 것만큼 중요해요.'),
('col_technology_07','breach','security','breach security','보안을 침해하다','break','"break security"도 쓰이지만 breach는 보안 맥락에서 더 전문적인 표현이에요.','B2','technology',2,7,'security breach hacker cyber privacy','Hackers breached the company''s security and stole customer data.','해커들이 회사의 보안을 침해하고 고객 데이터를 훔쳤어요.','The system was designed to prevent anyone from breaching its security.','그 시스템은 누구도 보안을 침해할 수 없도록 설계됐어요.','The hackers breached security and accessed sensitive records.','해커들이 보안을 침해하고 민감한 기록에 접근했어요.','A small flaw can be enough for someone to breach security.','작은 결함 하나로 누군가가 보안을 침해할 수 있어요.','They breached security through a phishing email sent to staff.','그들은 직원들에게 보낸 피싱 이메일로 보안을 침해했어요.'),
('col_technology_08','integrate','systems','integrate systems','시스템을 통합하다','connect','"connect systems"도 맞지만 integrate는 여러 시스템을 하나로 합치는 뉘앙스예요.','B2','technology',2,8,'integration system platform technology connect','The project aims to integrate the company''s existing systems into one platform.','그 프로젝트는 회사의 기존 시스템을 하나의 플랫폼으로 통합하는 것을 목표로 해요.','Integrating new software with legacy systems can be challenging.','새 소프트웨어를 기존 시스템과 통합하는 것은 어려울 수 있어요.','The company spent two years integrating systems after the merger.','회사는 합병 후 시스템 통합에 2년을 보냈어요.','Integrating systems across departments often reveals hidden issues.','부서 간 시스템을 통합하면 숨겨진 문제가 종종 드러나요.','They integrated systems by using open APIs and standard protocols.','그들은 오픈 API와 표준 프로토콜을 사용해 시스템을 통합했어요.'),
('col_technology_09','automate','a process','automate a process','프로세스를 자동화하다','do automatically','"do automatically"는 어색해요. 업무나 프로세스를 자동화할 때는 automate를 써요.','B2','technology',2,9,'automation AI process technology efficiency','The company has automated its invoicing process to save time.','회사는 시간을 절약하기 위해 청구서 발행 프로세스를 자동화했어요.','AI is increasingly used to automate repetitive tasks in the workplace.','직장에서 반복적인 업무를 자동화하기 위해 AI가 점점 더 많이 사용되고 있어요.','She automated her email replies during her vacation.','그녀는 휴가 동안 이메일 답장을 자동화했어요.','Many factories have automated processes that used to take hours.','많은 공장들이 예전에는 몇 시간씩 걸리던 프로세스를 자동화했어요.','Automating processes thoughtfully can reduce burnout.','프로세스를 사려 깊게 자동화하면 번아웃을 줄일 수 있어요.'),
('col_technology_11','troubleshoot','an issue','troubleshoot an issue','문제를 해결하다','fix','"fix an issue"도 맞지만 troubleshoot은 원인을 찾아 해결하는 과정을 강조해요.','B2','technology',2,11,'troubleshoot issue fix error tech support','The engineer spent three hours troubleshooting the network issue.','엔지니어는 3시간 동안 네트워크 문제를 해결하는 데 시간을 보냈어요.','If you troubleshoot the issue before calling support, it often saves time.','지원팀에 연락하기 전에 문제를 해결하려고 시도하면 시간을 절약할 수 있어요.','I''m troubleshooting an issue with the printer driver.','저는 프린터 드라이버 문제를 해결하고 있어요.','She troubleshot an issue that had been stumping the team for weeks.','그녀는 팀이 몇 주째 풀지 못하던 문제를 해결했어요.','Troubleshooting an issue often starts with restarting the device.','문제 해결은 종종 기기를 재시작하는 것부터 시작돼요.'),
('col_technology_13','encrypt','data','encrypt data','데이터를 암호화하다','protect','"protect data"도 맞지만 encrypt는 데이터를 암호화하는 특정 기술 방법을 강조해요.','B2','technology',2,13,'encryption data security privacy digital','All sensitive data is encrypted before being transmitted.','모든 민감한 데이터는 전송 전에 암호화돼요.','You should encrypt your data to prevent unauthorized access.','무단 접근을 방지하기 위해 데이터를 암호화해야 해요.','Messaging apps encrypt data so only the sender and receiver can read it.','메시지 앱은 발신자와 수신자만 읽을 수 있도록 데이터를 암호화해요.','You should encrypt data on any device that travels with you.','당신과 함께 이동하는 어떤 기기든 데이터를 암호화해야 해요.','They encrypt data both in transit and at rest.','그들은 전송 중과 저장 중 모두 데이터를 암호화해요.'),
('col_technology_16','migrate','to the cloud','migrate to the cloud','클라우드로 이전하다','move','"move to the cloud"도 맞지만 migrate는 데이터나 시스템의 공식적인 이전을 강조해요.','B2','technology',2,16,'cloud migration data storage server','The company plans to migrate all its data to the cloud by next year.','회사는 내년까지 모든 데이터를 클라우드로 이전할 계획이에요.','Migrating to the cloud can reduce infrastructure costs significantly.','클라우드로 이전하면 인프라 비용을 크게 줄일 수 있어요.','The school migrated to the cloud over the summer break.','그 학교는 여름방학 동안 클라우드로 이전했어요.','Many small businesses migrate to the cloud to save on hardware costs.','많은 소규모 사업체가 하드웨어 비용 절감을 위해 클라우드로 이전해요.','Migrating to the cloud needs a clear plan and good backups.','클라우드로 이전하려면 명확한 계획과 좋은 백업이 필요해요.'),
('col_technology_17','detect','a bug','detect a bug','버그를 발견하다','find','"find a bug"도 맞지만 detect는 자동화된 시스템이나 테스트 도구를 통해 발견하는 뉘앙스예요.','B2','technology',2,17,'bug detection software testing code','The testing software detected a critical bug before the product launched.','테스팅 소프트웨어는 제품 출시 전에 심각한 버그를 발견했어요.','It can be hard to detect bugs in complex software without proper tools.','적절한 도구 없이 복잡한 소프트웨어에서 버그를 발견하기 어려울 수 있어요.','Automated tests detected a bug right before launch.','자동화 테스트가 출시 직전에 버그를 발견했어요.','She detected a bug that the entire team had missed.','그녀는 팀 전체가 놓친 버그를 발견했어요.','Modern tools detect bugs that humans would never notice.','현대의 도구는 사람이 절대 알아차리지 못할 버그를 발견해요.'),
('col_technology_10','deploy','a solution','deploy a solution','솔루션을 배포하다','use','"use a solution"도 맞지만 deploy는 기술적 맥락에서 시스템을 가동하는 전문 표현이에요.','C1','technology',3,10,'deploy solution IT system rollout','The IT team deployed the new solution across all departments.','IT 팀은 모든 부서에 새 솔루션을 배포했어요.','They plan to deploy the software update in three phases.','그들은 3단계로 소프트웨어 업데이트를 배포할 계획이에요.','They deployed a solution that runs without internet.','그들은 인터넷 없이도 작동하는 솔루션을 배포했어요.','She deployed a security solution across all employee laptops.','그녀는 모든 직원 노트북에 보안 솔루션을 배포했어요.','Deploying a solution at scale needs careful staging.','솔루션을 대규모로 배포하려면 신중한 단계적 진행이 필요해요.'),
('col_technology_14','scale up','operations','scale up operations','운영 규모를 확대하다','grow','"grow operations"도 맞지만 scale up은 기술 스타트업 맥락에서 더 자연스러운 표현이에요.','C1','technology',3,14,'scale startup growth operations technology','The startup scaled up operations after securing Series B funding.','그 스타트업은 시리즈 B 투자를 받은 후 운영 규모를 확대했어요.','Cloud infrastructure makes it easy to scale up operations quickly.','클라우드 인프라는 빠르게 운영 규모를 확대하기 쉽게 해줘요.','They scaled up operations to handle the holiday rush.','그들은 휴일 성수기를 처리하기 위해 운영 규모를 확대했어요.','Scaling up operations too quickly can hurt service quality.','운영 규모를 너무 빠르게 확대하면 서비스 품질에 해를 끼칠 수 있어요.','The startup is scaling up operations after Series A funding.','그 스타트업은 시리즈 A 투자를 받고 운영 규모를 확대하고 있어요.'),
('col_technology_18','roll out','an update','roll out an update','업데이트를 단계적으로 배포하다','give','"give an update"도 맞지만 roll out은 단계적이고 계획적인 배포를 강조해요.','C1','technology',3,18,'rollout update deployment software release','The company rolled out the update to users in phases.','회사는 단계적으로 사용자에게 업데이트를 배포했어요.','They plan to roll out the new feature globally next month.','그들은 다음 달에 전 세계적으로 새 기능을 배포할 계획이에요.','They''re rolling out an update gradually to test for issues.','그들은 문제를 테스트하기 위해 점진적으로 업데이트를 배포하고 있어요.','The team rolled out the update to 1% of users first.','팀은 먼저 1%의 사용자에게 업데이트를 배포했어요.','Rolling out an update in waves helps catch problems early.','단계적으로 업데이트를 배포하면 문제를 일찍 발견하는 데 도움이 돼요.'),
('col_technology_19','disrupt','an industry','disrupt an industry','산업을 혁신하다','change','"change an industry"도 맞지만 disrupt는 기존 질서를 뒤흔드는 혁신적인 변화를 강조해요.','C1','technology',3,19,'disruption innovation industry tech AI','Smartphones disrupted the photography industry almost overnight.','스마트폰은 거의 하룻밤 사이에 사진 산업을 혁신했어요.','AI has the potential to disrupt almost every industry in the world.','AI는 세계의 거의 모든 산업을 혁신할 잠재력을 가지고 있어요.','Ride-share apps disrupted the taxi industry around the world.','차량 공유 앱은 전 세계 택시 산업을 혁신했어요.','Streaming services have disrupted the music industry completely.','스트리밍 서비스는 음악 산업을 완전히 혁신했어요.','Smart home tech is starting to disrupt the energy industry.','스마트 홈 기술이 에너지 산업을 혁신하기 시작했어요.'),
('col_technology_20','harness','technology','harness technology','기술을 활용하다','use','"use technology"도 맞지만 harness는 기술의 잠재력을 최대한 활용하는 뉘앙스예요.','C1','technology',3,20,'technology harness innovation solution digital','The organization harnesses technology to deliver better services to its users.','그 조직은 사용자에게 더 나은 서비스를 제공하기 위해 기술을 활용해요.','We need to harness technology responsibly to address global challenges.','글로벌 과제를 해결하기 위해 기술을 책임감 있게 활용해야 해요.','Schools harness technology to bring guest speakers from abroad.','학교들은 해외 초청 연사를 모시기 위해 기술을 활용해요.','Farmers harness technology to monitor soil and weather.','농부들은 토양과 날씨를 모니터링하기 위해 기술을 활용해요.','Charities are harnessing technology to reach more donors.','자선 단체들은 더 많은 기부자에게 닿기 위해 기술을 활용하고 있어요.'),
('col_technology_C1_01','adopt','innovation','adopt innovation','혁신을 도입하다','take','새로운 기술이나 방식을 조직 차원에서 받아들인다는 뜻이에요. 비즈니스 보고서의 표준 표현이에요.','C1','technology',2,0,'modern office tech','Hospitals have been slow to adopt innovation in patient record systems.','병원들은 환자 기록 시스템 혁신을 도입하는 데 느렸어요.','Successful firms continually adopt innovation to stay competitive.','성공하는 기업은 경쟁력을 유지하기 위해 끊임없이 혁신을 도입해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_technology_C1_02','integrate','systems','integrate systems','시스템을 통합하다','join','서로 다른 IT 시스템을 하나로 연동시킨다는 기술 표현이에요. ''join''은 단순 결합이라 정확하지 않아요.','C1','technology',2,0,'server room','The acquisition will require us to integrate systems across three continents.','이번 인수로 3개 대륙에 걸친 시스템을 통합해야 해요.','It took six months to fully integrate the new CRM system with our database.','새 CRM 시스템을 우리 데이터베이스와 완전히 통합하는 데 6개월이 걸렸어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_technology_C1_03','deploy','software','deploy software','소프트웨어를 배포하다','put','소프트웨어를 운영 환경에 설치하고 가동시킨다는 IT 표준 동사예요. ''put''은 너무 일상적이에요.','C1','technology',2,0,'developer screen','The team will deploy the software update across all servers tonight.','팀은 오늘 밤 모든 서버에 소프트웨어 업데이트를 배포할 거예요.','We deploy software in stages to minimize disruption.','우리는 지장을 최소화하기 위해 단계적으로 소프트웨어를 배포해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_technology_C1_04','tackle','bugs','tackle bugs','버그를 해결하다','kill','''kill bugs''도 쓰이지만, ''tackle''이 체계적으로 문제를 해결한다는 전문적인 뉘앙스라 더 격식 있어요.','C1','technology',2,0,'debugging code','Our QA engineers are tackling the most critical bugs before launch.','우리 QA 엔지니어들이 출시 전에 가장 심각한 버그를 해결하고 있어요.','The patch tackles several long-standing bugs reported by users.','이 패치는 사용자들이 보고한 여러 고질적인 버그를 해결해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_technology_C1_05','scale','operations','scale operations','운영 규모를 확장하다','grow','''grow''는 일반적이지만, ''scale''은 효율을 유지하며 규모를 키운다는 스타트업/테크 용어예요.','C1','technology',2,0,'data center','Cloud infrastructure allows startups to scale operations rapidly.','클라우드 인프라 덕분에 스타트업이 운영 규모를 빠르게 확장할 수 있어요.','We need a better hiring strategy before we scale operations into Asia.','아시아로 운영을 확장하기 전에 더 나은 채용 전략이 필요해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_technology_C2_01','leverage','innovation','leverage innovation','혁신을 활용하다','use','기술 혁신을 전략적으로 활용해 성과를 낸다는 비즈니스 표현이에요. ''use''보다 훨씬 격식 있고 능동적이에요.','C2','technology',3,0,'innovation lab','Startups must leverage innovation to compete with established incumbents.','스타트업은 기존 강자들과 경쟁하려면 혁신을 활용해야 해요.','The firm leveraged AI-driven innovation to streamline its supply chain.','그 회사는 AI 기반 혁신을 활용해 공급망을 간소화했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_technology_C2_02','pioneer','advancement','pioneer an advancement','발전을 선도하다','start','새로운 기술 발전을 가장 먼저 개척하고 이끈다는 뜻이에요. 학술 논문과 산업 보고서에 자주 쓰여요.','C2','technology',3,0,'research lab','The lab pioneered key advancements in quantum computing.','그 연구소는 양자 컴퓨팅의 핵심 발전을 선도했어요.','Her team pioneered an advancement in low-power chip design.','그녀의 팀은 저전력 칩 설계 분야의 발전을 선도했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_technology_C2_03','harness','algorithms','harness algorithms','알고리즘을 활용하다','use','복잡한 알고리즘의 힘을 효과적으로 끌어내 활용한다는 뜻이에요. AI/ML 관련 글에 표준적으로 등장해요.','C2','technology',3,0,'algorithm code','Modern logistics firms harness algorithms to optimise delivery routes in real time.','현대 물류 기업들은 알고리즘을 활용해 실시간으로 배송 경로를 최적화해요.','Researchers harness algorithms to detect anomalies in genomic data.','연구자들은 알고리즘을 활용해 유전체 데이터의 이상을 탐지해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_technology_C2_04','circumvent','security','circumvent security','보안을 우회하다','avoid','보안 조치를 교묘하게 우회한다는 격식 표현이에요. 사이버보안과 법률 문서에서 표준 용어예요.','C2','technology',3,0,'cybersecurity breach','The hackers found a novel way to circumvent the firm''s multi-factor security.','해커들은 그 회사의 다중 인증 보안을 우회하는 새로운 방법을 찾아냈어요.','Insiders can sometimes circumvent security protocols undetected.','내부자는 때때로 보안 프로토콜을 들키지 않고 우회할 수 있어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_technology_C2_05','facilitate','integration','facilitate integration','통합을 용이하게 하다','help','시스템 간 통합을 매끄럽게 만든다는 뜻이에요. IT 컨설팅과 엔터프라이즈 소프트웨어 문서에 자주 등장해요.','C2','technology',3,0,'system integration','Standardised APIs facilitate seamless integration across platforms.','표준화된 API가 플랫폼 간 매끄러운 통합을 가능하게 해요.','Middleware is designed to facilitate integration between legacy and cloud systems.','미들웨어는 레거시 시스템과 클라우드 시스템 간의 통합을 용이하게 하도록 설계됐어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_transport_01','take','a bus','take a bus','버스를 타다','ride','"ride a bus"도 맞지만 take a bus가 더 일반적인 표현이에요.','A2','transport',1,1,'bus public transport commute city','I usually take a bus to work to avoid traffic.','나는 보통 교통 체증을 피하기 위해 버스를 타고 출근해요.','Why don''t we take a bus? It''s more eco-friendly.','버스를 타는 건 어때요? 더 친환경적이에요.','My mother takes a bus to her yoga class every Tuesday.','저희 어머니는 매주 화요일에 요가 수업에 버스를 타고 가세요.','It''s cheaper to take a bus than to drive into the city.','시내로 운전해서 가는 것보다 버스를 타는 게 더 저렴해요.','We took a bus through the countryside and enjoyed the views.','우리는 시골을 가로지르는 버스를 타고 풍경을 즐겼어요.'),
('col_transport_03','get','on','get on','(교통수단에) 타다','take','"take"는 이동 전체를 의미하고, get on은 탑승 행위 자체를 말해요.','A2','transport',1,3,'boarding train bus platform door','Make sure you get on the right train at platform 4.','4번 플랫폼에서 맞는 기차에 타세요.','We got on the bus just as the doors were closing.','우리는 문이 닫히는 순간에 버스에 탔어요.','Please get on at the front door and tap your card.','앞문으로 타시고 카드를 찍어 주세요.','She got on the elevator carrying three bags of groceries.','그녀는 식료품 가방 세 개를 들고 엘리베이터에 탔어요.','I got on the train just before the doors closed.','문이 닫히기 직전에 저는 기차에 탔어요.'),
('col_transport_04','get','off','get off','(교통수단에서) 내리다','leave','"leave the bus"도 쓰이지만 get off가 더 자연스러운 구어체 표현이에요.','A2','transport',1,4,'station exit bus stop passengers','Get off at the next stop and walk two blocks north.','다음 정류장에서 내려서 북쪽으로 두 블록 걸어가세요.','She got off the train and realized she was at the wrong station.','그녀는 기차에서 내리고 나서 엉뚱한 역에 내렸다는 걸 알았어요.','Let me know when to get off — I''m not familiar with this area.','언제 내려야 하는지 알려주세요 — 이 지역을 잘 몰라요.','We got off the bus and walked the rest of the way.','우리는 버스에서 내려 나머지 길은 걸어갔어요.','He fell asleep and missed the stop where he should have got off.','그는 잠들어서 내려야 할 정류장을 지나쳤어요.'),
('col_transport_06','hold','the door','hold the door','문을 잡아주다','keep','"keep the door"는 문을 잠그는 등 다른 의미예요. 문을 잡아줄 때는 hold를 써요.','A2','transport',1,6,'door elevator courtesy hold open','Could you hold the door? I''m just a few steps behind.','문 좀 잡아줄 수 있어요? 바로 뒤에 있어요.','He held the door open for the woman with the stroller.','그는 유모차를 밀고 있는 여성을 위해 문을 잡아줬어요.','Thanks for holding the door — my hands are full.','문 잡아줘서 고마워요 — 손이 가득해서요.','He held the door for the older man getting off the train.','그는 기차에서 내리는 노신사를 위해 문을 잡아줬어요.','She held the door open with her foot while juggling bags.','그녀는 가방을 들고 있으면서 발로 문을 잡았어요.'),
('col_transport_10','miss','a bus','miss a bus','버스를 놓치다','lose','"lose a bus"는 틀린 표현이에요. 교통수단을 놓칠 때는 miss를 써요.','A2','transport',1,10,'miss bus late transport schedule','I missed the last bus and had to take a taxi home.','막차를 놓쳐서 택시를 타고 집에 갔어요.','If you miss the bus, the next one isn''t for 30 minutes.','버스를 놓치면 다음 버스는 30분 후예요.','Don''t miss the bus — there isn''t another one for an hour.','버스 놓치지 마세요 — 한 시간 동안 다음 버스가 없어요.','He missed the bus by just a few seconds.','그는 몇 초 차이로 버스를 놓쳤어요.','She missed the last bus and ended up walking home.','그녀는 막차를 놓쳐서 결국 집까지 걸어갔어요.'),
('col_transport_21','catch','bus','catch the bus','버스를 타다 (시간 맞춰)','get','"get the bus"도 영국에서 흔해요. catch는 시간 맞춰 잡아탄다는 뉘앙스.','A2','transport',1,0,'bus stop person running boarding morning','I have to run to catch the bus.','버스 타려면 뛰어가야 해요.','Did you catch the early bus this morning?','오늘 아침에 일찍 버스 탔어요?','She caught the bus just in time.','그녀는 가까스로 버스를 탔어요.','I missed the bus, so I had to catch the next one.','버스를 놓쳐서 다음 거를 타야 했어요.','We caught the bus to the airport at 6 AM.','우리는 새벽 6시에 공항행 버스를 탔어요.'),
('col_transport_22','miss','train','miss the train','기차를 놓치다','lose','"lose the train"은 틀린 표현. 시간 맞춰 못 탄 건 miss.','A2','transport',1,0,'train platform missed running late station','I missed the train by just two minutes.','단 2분 차이로 기차를 놓쳤어요.','She missed the last train and had to take a taxi.','그녀는 막차를 놓쳐서 택시를 타야 했어요.','Don''t miss the train — it''s the only one tonight.','기차 놓치지 마세요 — 오늘 밤 유일한 거예요.','They missed the train because of traffic.','그들은 교통 체증 때문에 기차를 놓쳤어요.','I''d rather wait than miss the train.','기차를 놓치느니 차라리 기다릴래요.'),
('col_transport_24','take','flight','take a flight','비행기를 타다','do','"do a flight"은 틀린 표현. 비행기 이용은 take a flight.','A2','transport',1,0,'airplane airport flight passenger boarding','I''m taking a flight to Seoul tomorrow.','내일 서울행 비행기를 타요.','She took a red-eye flight to New York.','그녀는 뉴욕행 야간 비행기를 탔어요.','How often do you take flights for work?','업무로 비행기를 얼마나 자주 타세요?','We took a direct flight to avoid layovers.','우리는 경유를 피하려고 직항을 탔어요.','He''s nervous about taking long flights.','그는 장거리 비행을 타는 게 긴장돼요.'),
('col_transport_05','run','late','run late','늦다, 지연되다','be','"be late"도 맞지만 run late는 점점 늦어지는 뉘앙스를 담고 있어요.','B1','transport',1,5,'late delay traffic commute schedule','Sorry, I''m running a bit late — I''ll be there in 10 minutes.','죄송해요, 조금 늦을 것 같아요 — 10분 후에 도착할게요.','The bus is running late due to heavy traffic.','버스가 심한 교통 체증으로 인해 지연되고 있어요.','I''m running late, but I should be there in 15 minutes.','늦고 있는데, 15분 후에는 도착할 수 있을 거예요.','The flight is running late due to bad weather at the origin.','출발지의 악천후로 인해 항공편이 지연되고 있어요.','She''s running late because of an unexpected meeting.','그녀는 예상치 못한 회의로 인해 늦어지고 있어요.'),
('col_transport_08','catch','a flight','catch a flight','비행기를 타다','take','"take a flight"도 맞지만 catch a flight는 시간 맞춰 타는 뉘앙스가 있어요.','B1','transport',1,8,'flight airport boarding gate departure','We need to leave now if we want to catch our flight.','비행기를 타려면 지금 출발해야 해요.','She barely caught her flight after the delay at security.','그녀는 보안 검사 지연 후 간신히 비행기를 탔어요.','I almost didn''t catch my flight because of the traffic.','교통 체증 때문에 비행기를 놓칠 뻔했어요.','He caught the last flight back home that evening.','그는 그날 저녁 집으로 돌아가는 마지막 비행기를 탔어요.','We had to skip lunch to catch our connecting flight.','우리는 연결 비행기를 타기 위해 점심을 거너야 했어요.'),
('col_transport_09','get','stuck in traffic','get stuck in traffic','교통 체증에 걸리다','be','"be stuck in traffic"도 맞지만 get stuck은 교통 체증에 새로 막히는 뉘앙스예요.','B1','transport',1,9,'traffic jam stuck car road commute','We got stuck in traffic on the highway for two hours.','우리는 고속도로에서 두 시간 동안 교통 체증에 걸렸어요.','I always get stuck in traffic when I take this route.','이 경로로 가면 항상 교통 체증에 걸려요.','We got stuck in traffic and missed the start of the concert.','우리는 교통 체증에 걸려서 콘서트 시작을 놓쳤어요.','You''ll get stuck in traffic if you leave any later than seven.','7시보다 늦게 출발하면 교통 체증에 걸릴 거예요.','Taking the back roads helped us avoid getting stuck in traffic.','뒷길로 가니까 교통 체증을 피할 수 있었어요.'),
('col_transport_11','book','a ticket','book a ticket','티켓을 예매하다','buy','"buy a ticket"도 맞지만 book은 미리 예약하는 뉘앙스가 있어요.','B1','transport',1,11,'ticket booking travel train flight','You can book a train ticket online up to three months in advance.','기차표는 온라인으로 최대 3개월 전에 예매할 수 있어요.','I booked my flight ticket as soon as the sale was announced.','세일이 발표되자마자 비행기 표를 예매했어요.','I booked a ticket for the early morning train to save money.','돈을 아끼려고 이른 아침 기차표를 예매했어요.','She booked her ticket months ago to get the best price.','그녀는 가장 좋은 가격을 위해 몇 달 전에 표를 예매했어요.','You can book a ticket on the app and skip the line.','앱으로 표를 예매하고 줄을 건너뛸 수 있어요.'),
('col_transport_12','transfer','lines','transfer lines','노선을 환승하다','change','"change lines"도 맞지만 transfer는 대중교통에서 더 격식 있는 표현이에요.','B1','transport',2,12,'subway metro transfer line station','Transfer at Seoul Station to take the green line.','서울역에서 환승하여 녹색 노선을 타세요.','You need to transfer lines twice to get to the airport.','공항까지 가려면 두 번 환승해야 해요.','Transfer lines at the next station to reach the museum.','박물관에 가려면 다음 역에서 노선을 환승하세요.','She had to transfer lines three times to get to the airport.','그녀는 공항까지 가려고 세 번이나 노선을 환승해야 했어요.','The map shows you where to transfer lines clearly.','지도가 노선 환승 위치를 명확하게 보여줘요.'),
('col_transport_16','give','a ride','give a ride','태워다 주다','offer','"offer a ride"도 맞지만 give a ride는 실제로 태워주는 것을 강조해요.','B1','transport',1,16,'ride car lift driving neighbor kindness','Could you give me a ride to the station?','역까지 태워다 줄 수 있어요?','She gave her neighbor a ride to the airport.','그녀는 이웃을 공항까지 태워다 줬어요.','My coworker gave me a ride home when my car broke down.','제 차가 고장 났을 때 동료가 집까지 태워다 줬어요.','Could you give us a ride to the venue tonight?','오늘 밤 행사장까지 우리를 태워다 줄 수 있어요?','He gave his sister a ride to college every Sunday evening.','그는 매주 일요일 저녁에 누나를 대학까지 태워다 줬어요.'),
('col_transport_17','check','in','check in','탑승 수속을 밟다','register','"register"도 맞지만 check in이 공항이나 호텔에서 더 일반적인 표현이에요.','B1','transport',1,17,'check in airport boarding flight counter','We need to check in at least two hours before the flight.','비행기 출발 최소 두 시간 전에 탑승 수속을 밟아야 해요.','Online check-in opens 24 hours before departure.','온라인 체크인은 출발 24시간 전에 열려요.','We checked in at the hotel and dropped off our luggage.','우리는 호텔에 체크인하고 짐을 맡겼어요.','You can check in online up to 24 hours before your flight.','비행기 출발 24시간 전까지 온라인으로 체크인할 수 있어요.','They checked in early but their room wasn''t ready yet.','그들은 일찍 체크인했지만 방이 아직 준비되지 않았어요.'),
('col_transport_19','top','up','top up a transit card','교통 카드를 충전하다','recharge','"recharge"도 맞지만 top up이 더 영국/아시아권에서 자주 쓰여요.','B1','transport',2,19,'transit card top up kiosk metro','I need to top up my transit card before boarding.','탑승 전에 교통 카드를 충전해야 해요.','You can top up your card at any station kiosk.','역 내 어느 키오스크에서나 카드를 충전할 수 있어요.','You can top up your transit card at any 7-Eleven store.','어느 세븐일레븐에서나 교통 카드를 충전할 수 있어요.','I forgot to top up my card and got stopped at the gate.','카드 충전을 잊어서 게이트에서 막혔어요.','She tops up her card automatically each month through the app.','그녀는 매달 앱을 통해 자동으로 카드를 충전해요.'),
('col_transport_20','hit','the road','hit the road','길을 떠나다, 출발하다','start','"start driving"도 맞지만 hit the road는 구어체로 더 생동감 있는 표현이에요.','B1','transport',2,20,'road trip departure driving adventure travel','We should hit the road before it gets too late.','너무 늦기 전에 출발해야 해요.','"Let''s hit the road!" he said as he started the engine.','"출발하자!" 그는 엔진을 켜며 말했어요.','We hit the road at six and drove until lunchtime.','우리는 6시에 출발해서 점심 시간까지 운전했어요.','It''s time to hit the road — we''ve got a long drive ahead.','이제 출발해야 해요 — 갈 길이 멀어요.','They hit the road right after breakfast to beat the traffic.','그들은 교통 체증을 피하기 위해 아침 식사 직후 출발했어요.'),
('col_transport_23','hit','traffic','hit traffic','교통 체증에 걸리다','meet','"meet traffic"은 틀린 표현. 갑자기 교통 체증을 만나면 hit traffic.','B1','transport',1,0,'traffic jam cars highway congestion road','We hit terrible traffic on the way home.','집에 오는 길에 끔찍한 교통 체증에 걸렸어요.','I''ll be late — I hit some traffic.','늦을 것 같아요 — 교통 체증에 걸렸어요.','They hit traffic and missed the start of the movie.','그들은 교통 체증에 걸려 영화 시작을 놓쳤어요.','We always hit traffic at this time of day.','이 시간엔 항상 교통 체증에 걸려요.','Leave early so you don''t hit rush hour traffic.','출근 시간 체증에 안 걸리게 일찍 나가세요.'),
('col_transport_02','make','a connection','make a connection','환승하다','take','"take a connection"은 어색해요. 환승에 성공할 때는 make a connection을 써요.','B2','transport',2,2,'connection transfer airport transit flight','We barely made our connection in Frankfurt.','우리는 프랑크푸르트에서 간신히 환승했어요.','Will we have enough time to make the connection at the airport?','공항에서 환승할 시간이 충분할까요?','They made their connection with five minutes to spare.','그들은 5분 여유를 두고 환승에 성공했어요.','I missed the train and couldn''t make my connection in Berlin.','저는 기차를 놓쳐서 베를린에서 환승하지 못했어요.','Making the connection is tight, but it should be possible.','환승 시간이 빠듯하지만 가능할 거예요.'),
('col_transport_07','keep','to schedule','keep to schedule','일정을 지키다','follow','"follow schedule"도 맞지만 keep to schedule이 더 자연스러운 교통 표현이에요.','B2','transport',2,7,'schedule on time train bus punctual','The train was keeping to schedule despite the earlier delays.','기차는 이전의 지연에도 불구하고 일정을 지키고 있었어요.','We need to keep to schedule if we want to catch the last train.','막차를 타려면 일정을 지켜야 해요.','The subway usually keeps to schedule, even at rush hour.','지하철은 출퇴근 시간에도 보통 일정을 지켜요.','It''s impressive how Japanese trains keep to schedule to the minute.','일본 기차가 분 단위로 일정을 지키는 게 인상적이에요.','The tour bus kept to schedule despite the heavy crowds.','관광버스는 인파에도 불구하고 일정을 지켰어요.'),
('col_transport_13','hail','a taxi','hail a taxi','택시를 잡다','take','"take a taxi"는 타는 것 전체이고, hail은 손을 들어 잡는 행위예요.','B2','transport',2,13,'taxi cab street hailing city','She hailed a taxi outside the hotel and headed to the airport.','그녀는 호텔 밖에서 택시를 잡아 공항으로 향했어요.','It can be hard to hail a taxi during rush hour.','출퇴근 시간에는 택시를 잡기 어려울 수 있어요.','I tried to hail a taxi in the rain, but none would stop.','빗속에서 택시를 잡으려 했는데 아무도 서지 않았어요.','He hailed a taxi from his phone using a ride-share app.','그는 공유 차량 앱으로 휴대폰에서 택시를 잡았어요.','You can hail a taxi at any major intersection downtown.','시내 어느 주요 교차로에서나 택시를 잡을 수 있어요.'),
('col_transport_14','set','off','set off','출발하다','leave','"leave"도 맞지만 set off는 여행이나 여정의 시작을 강조해요.','B2','transport',2,14,'departure journey road trip start travel','We set off early to avoid the morning rush.','아침 혼잡을 피하기 위해 일찍 출발했어요.','They set off on the road trip with excitement.','그들은 설레는 마음으로 자동차 여행을 떠났어요.','We set off at sunrise to make the most of the day.','우리는 하루를 알차게 보내기 위해 해 뜰 때 출발했어요.','They set off on foot since the road was blocked.','도로가 막혀서 그들은 걸어서 출발했어요.','She set off with just a backpack and a small map.','그녀는 배낭 하나와 작은 지도만 들고 출발했어요.'),
('col_transport_15','pull','over','pull over','차를 갓길에 세우다','stop','"stop"도 맞지만 pull over는 갓길이나 도로 옆에 세우는 것을 뜻해요.','B2','transport',2,15,'car road driving pullover police stop','The police officer asked her to pull over.','경찰관이 그녀에게 차를 세우라고 했어요.','He pulled over to check the map when he got lost.','그는 길을 잃었을 때 지도를 확인하기 위해 차를 세웠어요.','Pull over here — I can walk the rest of the way.','여기서 세워주세요 — 나머지 길은 걸을 수 있어요.','She pulled over to answer the urgent phone call.','그녀는 급한 전화를 받기 위해 차를 세웠어요.','The driver pulled over to let the ambulance pass.','운전자는 구급차가 지나갈 수 있도록 차를 세웠어요.'),
('col_transport_18','go','through customs','go through customs','세관을 통과하다','pass','"pass customs"도 쓰이지만 go through customs가 더 자연스러운 표현이에요.','B2','transport',2,18,'customs airport border control immigration','Going through customs took over an hour at the airport.','공항에서 세관을 통과하는 데 한 시간이 넘게 걸렸어요.','You have to declare any items over the limit when you go through customs.','세관을 통과할 때 한도를 초과하는 물품은 신고해야 해요.','We went through customs quickly because we had nothing to declare.','신고할 것이 없어서 우리는 세관을 빠르게 통과했어요.','Going through customs can take a while at busy airports.','바쁜 공항에서는 세관을 통과하는 데 시간이 좀 걸릴 수 있어요.','She went through customs without being asked any questions.','그녀는 아무 질문도 받지 않고 세관을 통과했어요.'),
('col_transport_C1_01','hail','cab','hail a cab','택시를 잡다','call','길에서 손을 들어 지나가는 택시를 세운다는 의미예요. ''call''은 전화로 부르는 거라 어감이 달라요.','C1','transport',2,0,'hailing taxi street','It''s nearly impossible to hail a cab in this rainstorm.','이 폭우 속에서는 택시를 잡기가 거의 불가능해요.','She stepped onto the curb and hailed a cab.','그녀는 인도로 나가서 택시를 잡았어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_transport_C1_02','miss','bus','miss the bus','버스를 놓치다','lose','교통수단을 시간 안에 못 타는 것은 ''miss''를 써요. ''lose''는 의미가 달라져요.','C1','transport',2,0,'missed bus stop','I missed the last bus and had to walk home.','막차를 놓쳐서 집까지 걸어가야 했어요.','If we don''t leave now, we''ll miss the bus.','지금 출발하지 않으면 버스를 놓칠 거예요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_transport_C1_03','catch','train','catch the train','기차를 잡아타다','take','출발 직전의 기차를 타는 데 성공한다는 뉘앙스예요. ''take the train''보다 시간 압박이 있어요.','C1','transport',2,0,'train platform departure','We caught the train just before it left the platform.','우리는 기차가 플랫폼을 떠나기 직전에 잡아탔어요.','Hurry, or we won''t catch the train.','서둘러요, 안 그러면 기차를 못 타요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_transport_C1_04','navigate','traffic','navigate traffic','교통 체증을 헤쳐 나가다','pass','혼잡한 도로를 능숙하게 운전해 빠져나간다는 표현이에요. 격식 있는 글이나 운전 칼럼에서 자주 써요.','C1','transport',2,0,'city traffic jam','Experienced drivers know how to navigate traffic during rush hour.','능숙한 운전자는 출퇴근 시간에 교통 체증을 헤쳐 나갈 줄 알아요.','It took us two hours to navigate the city traffic.','도심 교통을 헤쳐 나가는 데 두 시간이 걸렸어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_transport_C1_05','make','connections','make connections','환승하다','change','비행기, 기차 등을 갈아탄다는 격식 있는 표현이에요. 항공 안내나 여행기에서 자주 등장해요.','C1','transport',2,0,'airport connection terminal','Passengers must make connections in Frankfurt before flying to Seoul.','승객들은 서울행 비행 전에 프랑크푸르트에서 환승해야 해요.','I had only 30 minutes to make connections at the airport.','공항에서 환승할 시간이 30분밖에 없었어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_transport_C2_01','navigate','congestion','navigate congestion','혼잡을 헤쳐 나가다','drive','단순한 운전이 아니라 복잡한 교통 상황을 능숙하게 통과한다는 격식 있는 표현이에요. 도시 계획, 물류 보고서에서 자주 써요.','C2','transport',3,0,'city traffic jam','Delivery drivers must navigate congestion that has worsened markedly in recent years.','배송 기사들은 최근 몇 년간 현저히 악화된 혼잡을 헤쳐 나가야 해요.','The new ring road allows commuters to navigate congestion more efficiently.','새 순환도로는 출퇴근하는 사람들이 더 효율적으로 혼잡을 헤쳐 나갈 수 있게 해줘요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_transport_C2_02','embark','voyage','embark on a voyage','항해를 시작하다','start','배나 비행기로 긴 여정을 시작한다는 문어체 표현이에요. 비유적으로 ''중요한 여정을 시작하다''로도 자주 써요.','C2','transport',3,0,'cruise ship departure','The vessel embarked on a voyage that would circumnavigate the globe.','그 선박은 세계 일주가 될 항해를 시작했어요.','She embarked on a voyage of self-discovery after leaving the firm.','그녀는 회사를 떠난 뒤 자아를 찾는 여정을 시작했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_transport_C2_03','traverse','terrain','traverse terrain','지형을 가로지르다','cross','험하거나 광대한 지형을 가로지른다는 문학적·기술적 표현이에요. 탐험기, 차량 광고, 군사 문서에 잘 어울려요.','C2','transport',3,0,'mountain off-road','The all-terrain vehicle is engineered to traverse rugged terrain with ease.','그 사륜구동차는 험준한 지형을 손쉽게 가로지르도록 설계됐어요.','The explorers traversed inhospitable terrain for nearly a year.','탐험가들은 거의 1년 동안 척박한 지형을 가로질렀어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_transport_C2_04','expedite','delivery','expedite delivery','배송을 신속히 처리하다','speed up','공식적이고 절차적인 신속 처리를 의미해요. 물류, 무역, 정부 문서의 표준 표현이에요.','C2','transport',3,0,'express courier','A surcharge applies if you wish to expedite delivery to international destinations.','국제 배송을 신속히 처리하고 싶으시면 추가 요금이 부과돼요.','The agency expedited delivery of medical supplies to the disaster zone.','그 기관은 재난 지역으로의 의료품 배송을 신속히 처리했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_transport_C2_05','circumvent','traffic','circumvent traffic','교통체증을 우회하다','avoid','교통 체증을 영리하게 돌아간다는 격식 표현이에요. ''circumvent''는 규칙이나 장애물을 회피한다는 뉘앙스도 있어요.','C2','transport',3,0,'navigation app','Seasoned commuters know which back streets to take to circumvent traffic.','노련한 출퇴근자들은 교통체증을 우회하려고 어느 뒷길로 가야 하는지 알아요.','The new app suggests routes designed to circumvent traffic in real time.','새 앱은 실시간으로 교통체증을 우회하도록 설계된 경로를 제안해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_travel_04','pack','luggage','pack luggage','짐을 싸다','prepare','"prepare luggage"는 어색해요. 짐을 쌀 때는 pack을 써요.','A2','travel',1,4,'packing suitcase travel luggage preparation','She started packing her luggage the night before the flight.','그녀는 비행 전날 밤에 짐을 싸기 시작했어요.','I always pack light when I travel.','나는 여행할 때 항상 짐을 간단하게 싸요.','I packed my luggage carefully so nothing would break.','저는 아무것도 깨지지 않도록 짐을 조심스럽게 쌌어요.','He packed his luggage in twenty minutes and rushed to the airport.','그는 20분 만에 짐을 싸고 공항으로 서둘렀어요.','She rolls her clothes when she packs her luggage to save space.','그녀는 공간을 절약하기 위해 짐을 쌀 때 옷을 둘둘 말아요.'),
('col_travel_08','take','photos','take photos','사진을 찍다','make','"make photos"는 틀린 표현이에요. 사진을 찍을 때는 take를 써요.','A2','travel',1,8,'photos camera travel tourist photography','We took hundreds of photos during the trip.','우리는 여행 동안 수백 장의 사진을 찍었어요.','She stopped to take photos at every scenic viewpoint.','그녀는 아름다운 전망 포인트마다 멈춰서 사진을 찍었어요.','He took photos of the locals with their permission.','그는 허락을 받고 현지인들의 사진을 찍었어요.','I take photos mostly with my phone these days.','요즘은 주로 휴대폰으로 사진을 찍어요.','She took photos of every meal during the food tour.','그녀는 음식 투어 중 모든 식사 사진을 찍었어요.'),
('col_travel_01','make','a booking','make a booking','예약하다','do','"do a booking"은 틀린 표현이에요. 예약할 때는 make a booking을 써요.','B1','travel',1,1,'hotel booking reservation travel online','I made a booking at a hotel near the city center.','시내 중심부 근처 호텔을 예약했어요.','You can make a booking online or by calling the hotel directly.','온라인이나 호텔에 직접 전화해서 예약할 수 있어요.','I made a booking at a guesthouse run by a local family.','저는 현지 가족이 운영하는 게스트하우스를 예약했어요.','She made a booking for two nights with breakfast included.','그녀는 조식 포함 2박 예약을 했어요.','Make a booking now while the early-bird discount is still available.','얼리버드 할인이 아직 가능할 때 지금 예약하세요.'),
('col_travel_02','take','a trip','take a trip','여행을 하다','do','"do a trip"은 어색해요. 여행할 때는 take a trip을 써요.','B1','travel',1,2,'trip travel journey suitcase adventure','We''re planning to take a trip to Japan next spring.','우리는 내년 봄에 일본 여행을 계획하고 있어요.','She took a solo trip to Europe and loved every minute of it.','그녀는 혼자 유럽 여행을 했고 매 순간이 좋았어요.','They took a road trip across the entire country.','그들은 나라 전체를 자동차로 여행했어요.','I want to take a trip somewhere quiet over the long weekend.','저는 긴 주말에 조용한 곳으로 여행을 가고 싶어요.','She took a trip to her hometown for the first time in years.','그녀는 몇 년 만에 고향으로 여행을 갔어요.'),
('col_travel_03','get','a visa','get a visa','비자를 받다','take','"take a visa"는 어색해요. 비자를 받을 때는 get을 써요.','B1','travel',1,3,'visa passport travel document immigration','You need to get a visa before traveling to that country.','그 나라를 여행하기 전에 비자를 받아야 해요.','It took two weeks to get a visa for the trip.','여행을 위한 비자를 받는 데 2주가 걸렸어요.','I had to apply six weeks early to get a visa for India.','인도 비자를 받기 위해 저는 6주 일찍 신청해야 했어요.','She got a student visa to study in Australia for a year.','그녀는 호주에서 1년 공부하기 위해 학생 비자를 받았어요.','You can get a visa on arrival in some countries.','어떤 나라에서는 도착 시 비자를 받을 수 있어요.'),
('col_travel_05','check','in','check in','체크인하다','register','"register"도 쓰이지만 check in이 호텔과 공항에서 더 일반적이에요.','B1','travel',1,5,'hotel check-in reception travel flight','We checked in at the hotel and went straight to our room.','우리는 호텔에 체크인하고 바로 방으로 갔어요.','You can check in online 24 hours before your flight.','비행 24시간 전에 온라인으로 체크인할 수 있어요.','We checked in late and missed the welcome drink.','우리는 늦게 체크인해서 웰컴 드링크를 놓쳤어요.','She checked in at the kiosk to avoid the long counter line.','그녀는 긴 카운터 줄을 피하려고 키오스크에서 체크인했어요.','Let''s check in early so we have more time to explore.','탐험할 시간을 더 갖기 위해 일찍 체크인해요.'),
('col_travel_07','go','sightseeing','go sightseeing','관광하다','do','"do sightseeing"도 쓰이지만 go sightseeing이 더 자연스러운 표현이에요.','B1','travel',1,7,'sightseeing tourist attraction landmarks city','On our first day, we went sightseeing around the old town.','첫날에는 구시가지를 돌아다니며 관광했어요.','We only had a few hours to go sightseeing before our flight.','비행 전에 관광할 시간이 몇 시간밖에 없었어요.','They went sightseeing by bike to cover more ground.','그들은 더 넓은 지역을 둘러보기 위해 자전거로 관광했어요.','We''ll go sightseeing in the morning when it''s cooler.','시원한 아침에 관광을 갈 거예요.','Going sightseeing with a local guide gave us deeper insights.','현지 가이드와 관광하니까 더 깊은 통찰을 얻었어요.'),
('col_travel_10','lose','one''s way','lose one''s way','길을 잃다','miss','"miss your way"는 틀린 표현이에요. 길을 잃을 때는 lose your way를 써요.','B1','travel',1,10,'lost map navigation travel direction','We lost our way in the narrow streets of the old city.','우리는 구시가지의 좁은 골목길에서 길을 잃었어요.','It''s easy to lose your way in a city you''ve never visited before.','처음 가보는 도시에서는 길을 잃기 쉬어요.','We lost our way in the markets but enjoyed the unexpected detour.','우리는 시장에서 길을 잃었지만 뜻밖의 우회로를 즐겼어요.','It''s easy to lose your way in cities without grid streets.','격자형 도로가 없는 도시에서는 길을 잃기 쉬워요.','She lost her way and ended up at a beautiful park.','그녀는 길을 잃었지만 결국 아름다운 공원에 도착했어요.'),
('col_travel_11','exchange','currency','exchange currency','환전하다','change','"change currency"도 쓰이지만 exchange가 더 격식 있는 표현이에요.','B1','travel',2,11,'currency exchange money travel bank foreign','It''s best to exchange currency before you leave the airport.','공항을 떠나기 전에 환전하는 게 가장 좋아요.','She exchanged currency at the bank for a better rate.','그녀는 더 좋은 환율을 위해 은행에서 환전했어요.','I prefer to exchange currency at official banks rather than street vendors.','저는 길거리 상인보다 공식 은행에서 환전하는 걸 선호해요.','You can exchange currency at the airport, but rates are usually worse.','공항에서 환전할 수 있지만 환율이 보통 더 나빠요.','She exchanged currency just enough for the first day''s expenses.','그녀는 첫날 비용에 딱 맞춰 환전했어요.'),
('col_travel_12','book','accommodation','book accommodation','숙박을 예약하다','reserve','"reserve accommodation"도 맞지만 book이 더 구어체적이에요.','B1','travel',1,12,'accommodation hotel hostel booking reservation','We booked accommodation close to the main tourist area.','우리는 주요 관광 지역 근처에 숙박을 예약했어요.','It''s cheaper to book accommodation well in advance.','숙박은 미리 예약하면 더 저렴해요.','They booked accommodation through a homestay platform.','그들은 홈스테이 플랫폼을 통해 숙박을 예약했어요.','Always book accommodation that offers free cancellation.','무료 취소가 가능한 숙박을 항상 예약하세요.','She booked accommodation near the conference venue to save commuting time.','그녀는 통근 시간을 절약하기 위해 컨퍼런스 장소 근처에 숙박을 예약했어요.'),
('col_travel_06','make','an itinerary','make an itinerary','여행 일정을 짜다','do','"do an itinerary"는 어색해요. 여행 일정을 만들 때는 make를 써요.','B2','travel',2,6,'itinerary planning trip schedule tourist','Let''s make a detailed itinerary so we don''t miss anything.','빠뜨리는 것이 없도록 자세한 여행 일정을 짜봐요.','She made a packed itinerary that covered seven cities in ten days.','그녀는 10일 동안 7개 도시를 포함하는 빽빽한 일정을 짰어요.','He made a flexible itinerary to allow for spontaneous changes.','그는 즉흥적인 변경이 가능하도록 유연한 일정을 짰어요.','We made an itinerary together using a shared online document.','우리는 공유 온라인 문서로 함께 일정을 짰어요.','Her itinerary included a full day at the local food market.','그녀의 일정에는 현지 음식 시장에서 보내는 하루가 포함됐어요.'),
('col_travel_09','keep','a diary','keep a diary','일기를 쓰다','write','"write a diary"도 맞지만 keep a diary는 꾸준히 쓰는 것을 강조해요.','B2','travel',2,9,'diary journal travel writing memories','She kept a travel diary to remember every detail of the trip.','그녀는 여행의 모든 세부 사항을 기억하기 위해 여행 일기를 썼어요.','He kept a diary throughout his six-month backpacking adventure.','그는 6개월 배낭여행 내내 일기를 썼어요.','I keep a small diary just for travel memories.','저는 여행 추억만을 위한 작은 일기를 써요.','Keeping a diary helped her process the long journey.','일기를 쓰는 것이 그녀가 긴 여정을 정리하는 데 도움이 됐어요.','He kept a diary in two languages for practice.','그는 연습을 위해 두 가지 언어로 일기를 썼어요.'),
('col_travel_13','pick','up a language','pick up a language','언어를 조금 익히다','learn','"learn a language"는 체계적인 학습이고, pick up은 자연스럽게 익히는 것이에요.','B2','travel',2,13,'language learning travel culture phrases','She managed to pick up a few phrases in Italian during her trip.','그녀는 여행 중에 이탈리아어 몇 마디를 익혔어요.','Traveling is a great way to pick up a language naturally.','여행은 언어를 자연스럽게 익히는 훌륭한 방법이에요.','He picked up a bit of French during his summer in Paris.','그는 파리에서 보낸 여름 동안 프랑스어를 조금 익혔어요.','You can pick up a language faster if you talk to locals daily.','현지인과 매일 대화하면 언어를 더 빨리 익힐 수 있어요.','She picked up enough Korean to order food and ask directions.','그녀는 음식을 주문하고 길을 물을 만큼의 한국어를 익혔어요.'),
('col_travel_15','experience','culture shock','experience culture shock','문화 충격을 겪다','have','"have culture shock"도 쓰이지만 experience가 더 강렬한 경험을 강조해요.','B2','travel',2,15,'culture shock abroad different country','She experienced culture shock when she first moved to the US.','그녀는 처음 미국으로 이사했을 때 문화 충격을 겪었어요.','Travelers often experience culture shock when visiting very different countries.','여행자들은 매우 다른 나라를 방문할 때 종종 문화 충격을 겪어요.','I experienced culture shock more from the food than from anything else.','저는 어느 것보다 음식에서 문화 충격을 더 많이 겪었어요.','He experienced culture shock when he returned home after living abroad.','그는 해외에 살다가 고국에 돌아왔을 때 문화 충격을 겪었어요.','You can experience culture shock even between regions of the same country.','같은 나라의 다른 지역 사이에서도 문화 충격을 겪을 수 있어요.'),
('col_travel_16','catch','a connection','catch a connection','연결 비행/열차를 타다','take','"take a connection"도 쓰이지만 catch는 시간 내에 타는 것을 강조해요.','B2','travel',2,16,'connection airport terminal running transfer','We had only 45 minutes to catch our connection in Amsterdam.','우리는 암스테르담에서 연결 비행기를 타는 데 45분밖에 없었어요.','She ran through the terminal to catch her connection.','그녀는 연결 비행기를 타기 위해 터미널을 뛰어갔어요.','We barely caught our connection because of long immigration lines.','입국 심사 줄이 길어서 우리는 간신히 연결편을 탔어요.','He sprinted across the airport to catch his connection.','그는 연결편을 타려고 공항을 가로질러 전력 질주했어요.','They couldn''t catch their connection and were rebooked for the next day.','그들은 연결편을 타지 못해 다음 날 편으로 다시 예약됐어요.'),
('col_travel_17','go','backpacking','go backpacking','배낭여행을 하다','do','"do backpacking"은 어색해요. 배낭여행할 때는 go backpacking을 써요.','B2','travel',2,17,'backpacking travel young adventure hostel','After graduating, he went backpacking through Southeast Asia.','졸업 후 그는 동남아시아를 배낭여행했어요.','Going backpacking is a great way to see the world on a budget.','배낭여행은 적은 예산으로 세계를 볼 수 있는 좋은 방법이에요.','My friend went backpacking through South America for six months.','제 친구는 남미를 6개월간 배낭여행했어요.','Going backpacking taught her how to live with less.','배낭여행은 그녀에게 적게 가지고 사는 법을 가르쳐 줬어요.','They went backpacking during the gap year between high school and college.','그들은 고등학교와 대학 사이 갭이어 동안 배낭여행을 했어요.'),
('col_travel_18','carry','travel insurance','carry travel insurance','여행 보험을 가입하다','have','"have travel insurance"도 맞지만 carry는 항상 보험을 갖고 다닌다는 의미예요.','B2','travel',2,18,'travel insurance safety policy abroad','Always carry travel insurance, especially when traveling abroad.','특히 해외 여행 시에는 항상 여행 보험에 가입하세요.','She carried comprehensive travel insurance for her three-month trip.','그녀는 3개월 여행을 위해 포괄적인 여행 보험을 가입했어요.','We always carry travel insurance, even for short domestic trips.','우리는 짧은 국내 여행에도 항상 여행 보험을 가입해요.','He didn''t carry travel insurance and regretted it after a small accident.','그는 여행 보험을 가입하지 않았다가 작은 사고 후 후회했어요.','Most credit cards offer some basic travel insurance.','대부분의 신용카드는 기본 여행 보험을 제공해요.'),
('col_travel_19','set','off','set off on a journey','여정을 시작하다','start','"start a journey"도 맞지만 set off는 여정의 시작을 더 생동감 있게 표현해요.','B2','travel',2,19,'journey departure adventure travel excitement','They set off on their journey at dawn to beat the traffic.','그들은 교통 체증을 피하기 위해 새벽에 여정을 시작했어요.','She felt a mix of excitement and nerves as she set off on her trip.','여정을 시작하면서 그녀는 설렘과 긴장이 뒤섞인 감정을 느꼈어요.','They set off on a journey across three continents in one year.','그들은 1년에 세 대륙을 가로지르는 여정을 시작했어요.','She set off on her journey alone but met friends along the way.','그녀는 혼자 여정을 시작했지만 도중에 친구들을 만났어요.','Before setting off on a journey, double-check your documents.','여정을 시작하기 전에 서류를 다시 확인하세요.'),
('col_travel_14','get','off the beaten track','get off the beaten track','인적 드문 곳을 탐험하다','find','"find off the beaten track"은 어색해요. 색다른 여행을 할 때는 get off the beaten track을 써요.','C1','travel',3,14,'adventure off-track discovery hidden places','They preferred to get off the beaten track rather than visit tourist hotspots.','그들은 관광 명소보다 인적 드문 곳을 탐험하는 것을 더 좋아했어요.','Getting off the beaten track can lead to amazing discoveries.','인적 드문 곳을 탐험하면 놀라운 발견으로 이어질 수 있어요.','Getting off the beaten track let us see how local people really live.','인적 드문 곳을 탐험하면서 현지 사람들이 실제로 어떻게 사는지 봤어요.','She loves to get off the beaten track and try unusual food.','그녀는 인적 드문 곳을 탐험하며 특이한 음식을 시도하는 걸 좋아해요.','Getting off the beaten track requires some planning and courage.','인적 드문 곳을 탐험하려면 약간의 계획과 용기가 필요해요.'),
('col_travel_20','broaden','one''s horizons','broaden one''s horizons','시야를 넓히다','expand','"expand horizons"도 맞지만 broaden one''s horizons이 더 관용적인 표현이에요.','C1','travel',3,20,'travel world view perspective experience','Traveling abroad is one of the best ways to broaden your horizons.','해외 여행은 시야를 넓히는 가장 좋은 방법 중 하나예요.','She went abroad to broaden her horizons and gain new perspectives.','그녀는 시야를 넓히고 새로운 관점을 얻기 위해 해외로 갔어요.','Reading books from different cultures helps broaden your horizons.','다양한 문화의 책을 읽는 것이 시야를 넓히는 데 도움이 돼요.','She moved to a new country to broaden her horizons.','그녀는 시야를 넓히기 위해 새로운 나라로 이사했어요.','Volunteering abroad really broadens your horizons.','해외 봉사활동은 정말 시야를 넓혀줘요.'),
('col_travel_C1_01','book','accommodations','book accommodations','숙소를 예약하다','reserve','''book''이 영어권에서 훨씬 자연스러워요. ''accommodations''(미국식 복수)는 호텔·숙박 시설을 포괄하는 격식 단어예요.','C1','travel',2,0,'hotel booking laptop','Have you booked your accommodations yet?','숙소 예약은 하셨어요?','I always book my accommodations months in advance.','저는 늘 몇 달 전에 숙소를 예약해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_travel_C1_02','settle','into a routine','settle into a routine','일상에 적응하다','enter','새로운 환경에 점차 익숙해져 안정된 패턴을 만든다는 뜻이에요. 장기 여행이나 이주 후의 적응 과정을 표현할 때 어울려요.','C1','travel',2,0,'morning routine abroad','It took a week to settle into a routine abroad.','해외 일상에 적응하는 데 일주일 걸렸어요.','Once you settle into a routine, travel feels easier.','일상이 자리 잡히면 여행이 더 수월해져요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_travel_C1_03','wander','aimlessly','wander aimlessly','정처 없이 거닐다','walk','뚜렷한 목적지 없이 자유롭게 돌아다닌다는 낭만적인 뉘앙스가 있어요. 여행 에세이나 일기에 자주 등장해요.','C1','travel',2,0,'old town wander walking','I love to wander aimlessly through old towns.','오래된 도시를 정처 없이 거니는 걸 좋아해요.','We wandered aimlessly until we found a hidden plaza.','숨겨진 광장을 발견할 때까지 정처 없이 걸었어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_travel_C1_04','absorb','the culture','absorb the culture','문화를 흡수하다','learn','단순히 보거나 배우는 게 아니라 깊이 체험하고 받아들인다는 의미예요. 문화 여행이나 어학연수 설명에 잘 어울려요.','C1','travel',2,0,'local market culture','Living there really lets you absorb the culture.','거기 살면 문화를 제대로 흡수하게 돼요.','She traveled slowly to absorb the local culture.','그녀는 현지 문화를 체득하려 천천히 여행했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_travel_C1_05','soak','up the atmosphere','soak up the atmosphere','분위기를 만끽하다','feel','한 장소의 분위기와 정취를 천천히 즐긴다는 표현이에요. 카페, 광장, 축제 같은 장소 묘사에 자주 써요.','C1','travel',2,0,'night market atmosphere','We just sat there and soaked up the atmosphere.','그냥 거기 앉아 분위기를 만끽했어요.','I soaked up the atmosphere of the night market.','야시장의 분위기를 흠뻑 즐겼어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_travel_C2_01','embark','journey','embark on a journey','여정을 시작하다','start','뜻깊은 여행이나 모험을 시작한다는 문학적이고 격식 있는 표현이에요. 단순한 ''start''보다 훨씬 의미가 깊어요.','C2','travel',3,0,'train journey','They embarked on a transcontinental journey aboard the Trans-Siberian Railway.','그들은 시베리아 횡단철도를 타고 대륙 횡단 여정을 시작했어요.','She embarked on a solo journey through Patagonia.','그녀는 파타고니아를 가로지르는 홀로 여정을 시작했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_travel_C2_02','traverse','continent','traverse a continent','대륙을 횡단하다','cross','광활한 지역을 가로질러 이동한다는 격식 있는 동사예요. 여행 회고록이나 다큐멘터리에 자주 등장해요.','C2','travel',3,0,'desert expedition','The explorers traversed the African continent on foot.','탐험가들은 도보로 아프리카 대륙을 횡단했어요.','Few have traversed the continent of Antarctica unsupported.','도움 없이 남극 대륙을 횡단한 사람은 거의 없어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_travel_C2_03','immerse','oneself','immerse oneself in culture','문화에 흠뻑 빠지다','enjoy','단순히 즐기는 것이 아니라 그 문화에 깊이 몰입한다는 의미예요. 여행 에세이나 인터뷰에 어울려요.','C2','travel',3,0,'tea ceremony','He spent six months in Kyoto immersing himself in tea ceremony culture.','그는 교토에서 여섯 달을 보내며 다도 문화에 흠뻑 빠졌어요.','To learn a language, you must immerse yourself in the culture.','언어를 배우려면 그 문화에 흠뻑 빠져야 해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_travel_C2_04','savor','experience','savor the experience','경험을 음미하다','enjoy','경험을 천천히 깊이 즐긴다는 격식 있는 표현이에요. 여행, 미식, 공연 후기에 적절해요.','C2','travel',3,0,'safari sunset','Rather than rushing through Rome, take time to savor the experience.','로마를 서둘러 둘러보지 말고, 천천히 경험을 음미해 보세요.','They savored every moment of their once-in-a-lifetime safari.','그들은 일생에 한 번뿐인 사파리의 모든 순간을 음미했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_travel_C2_05','venture','territory','venture into uncharted territory','미지의 영역으로 나아가다','go','잘 알려지지 않은 곳으로 위험을 무릅쓰고 나아간다는 뜻이에요. 비유적으로 비즈니스에서도 자주 써요.','C2','travel',3,0,'amazon jungle','The expedition ventured into uncharted territory deep in the Amazon basin.','탐험대는 아마존 분지 깊숙한 미지의 영역으로 나아갔어요.','By launching the new line, the brand ventured into uncharted territory.','새 라인을 출시하며 그 브랜드는 미지의 영역에 발을 들였어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_weather_02','take','an umbrella','take an umbrella','우산을 챙기다','bring','"bring an umbrella"도 맞지만 take는 출발 시점을 강조해요.','A2','weather',1,2,'umbrella rain preparation forecast','You should take an umbrella — it looks like rain.','우산을 챙기세요 — 비가 올 것 같아요.','I forgot to take an umbrella and got completely soaked.','우산을 챙기는 것을 잊어서 완전히 흠뻑 젖었어요.','Please take an umbrella with you on your morning walk.','아침 산책 때 우산을 챙기세요.','She always takes an umbrella, even on sunny days, just in case.','그녀는 만일을 대비해 맑은 날에도 항상 우산을 챙겨요.','I took an umbrella but the rain never came.','저는 우산을 챙겼는데 결국 비는 오지 않았어요.'),
('col_weather_06','keep','warm','keep warm','따뜻하게 지내다','stay','"stay warm"도 맞지만 keep warm은 적극적으로 유지하는 뉘앙스예요.','A2','weather',1,6,'warm winter cold clothes layering','Make sure to keep warm during the cold snap this week.','이번 주 한파 동안 따뜻하게 지내세요.','She layered her clothes to keep warm on the mountain.','그녀는 산에서 따뜻하게 지내기 위해 옷을 겹쳐 입었어요.','Drink something hot to keep warm during the freezing night.','얼어붙는 밤에는 따뜻한 음료를 마셔서 따뜻하게 지내세요.','The blanket helps keep him warm while he sleeps.','담요가 그가 잘 때 따뜻하게 지낼 수 있도록 도와줘요.','Bring extra socks to keep warm at the outdoor concert.','야외 콘서트에서 따뜻하게 지내려면 여분의 양말을 가져가세요.'),
('col_weather_15','wrap','up','wrap up warm','따뜻하게 차려입다','dress','"dress warm"도 맞지만 wrap up (warm)이 영국 영어에서 더 자주 쓰여요.','A2','weather',1,15,'winter coat scarf warm clothing cold','Wrap up warm before going out — it''s freezing today.','오늘 엄청 추우니까 나가기 전에 따뜻하게 차려입으세요.','Mom always reminded us to wrap up warm in winter.','엄마는 항상 겨울에는 따뜻하게 입으라고 하셨어요.','Wrap up warm before walking the dog tonight.','오늘 밤 강아지 산책 전에 따뜻하게 차려입으세요.','The kids wrapped up warm and ran out to play in the snow.','아이들은 따뜻하게 차려입고 눈에서 놀러 뛰어나갔어요.','You''ll want to wrap up warm if you''re watching the game outside.','밖에서 경기를 본다면 따뜻하게 차려입는 게 좋아요.'),
('col_weather_21','take','umbrella','take an umbrella','우산을 챙기다','bring','"bring an umbrella"도 가능. take는 가져갈 때, bring은 도착지로 가져갈 때.','A2','weather',1,0,'umbrella rain person walking street','Take an umbrella — it''s going to rain.','우산 챙기세요 — 비 올 거예요.','I forgot to take an umbrella this morning.','오늘 아침에 우산 챙기는 걸 잊었어요.','She always takes an umbrella in her bag.','그녀는 항상 가방에 우산을 챙겨 다녀요.','You should take an umbrella just in case.','만일을 대비해 우산 챙기세요.','He took a small umbrella for the hike.','그는 등산을 위해 작은 우산을 챙겼어요.'),
('col_weather_22','wear','sunscreen','wear sunscreen','자외선 차단제를 바르다','put','"put sunscreen"도 쓰이지만 wear sunscreen이 더 자연스러워요 (apply도 가능).','A2','weather',1,0,'sunscreen sunny beach skincare protection','Wear sunscreen even on cloudy days.','흐린 날에도 자외선 차단제를 바르세요.','She always wears sunscreen at the beach.','그녀는 해변에서 항상 자외선 차단제를 발라요.','I forgot to wear sunscreen and got a burn.','자외선 차단제 바르는 걸 잊어서 화상 입었어요.','Doctors recommend wearing sunscreen daily.','의사들은 매일 자외선 차단제 바르기를 권장해요.','He wears sunscreen on his face year-round.','그는 일년 내내 얼굴에 자외선 차단제를 발라요.'),
('col_weather_01','get','caught in the rain','get caught in the rain','비를 맞다','fall','"fall in the rain"은 다른 의미예요. 뜻밖에 비를 맞을 때는 get caught in the rain을 써요.','B1','weather',1,1,'rain caught umbrella wet street','We got caught in the rain without an umbrella.','우리는 우산도 없이 비를 맞았어요.','She got caught in the rain on her way home from work.','그녀는 퇴근 길에 비를 맞았어요.','They got caught in the rain while hiking in the mountains.','그들은 산에서 등산하다가 비를 맞았어요.','I got caught in the rain on my way to the bus stop.','저는 버스 정류장으로 가는 길에 비를 맞았어요.','The picnic was ruined when we got caught in the rain.','우리가 비를 맞는 바람에 소풍이 망쳤어요.'),
('col_weather_05','get','soaked','get soaked','흠뻑 젖다','become','"become soaked"도 맞지만 get soaked가 구어체에서 훨씬 자주 쓰여요.','B1','weather',1,5,'soaked rain wet storm outdoor','I got soaked walking to the station in the storm.','폭풍 속에 역까지 걸어가다가 흠뻑 젖었어요.','We got soaked even though we had raincoats on.','우비를 입었는데도 흠뻑 젖었어요.','My shoes got completely soaked from walking through the puddles.','제 신발은 웅덩이를 지나면서 완전히 흠뻑 젖었어요.','The kids got soaked playing in the sprinklers all afternoon.','아이들은 오후 내내 스프링클러에서 놀다가 흠뻑 젖었어요.','Don''t leave your jacket outside or it''ll get soaked.','재킷을 밖에 두지 마세요, 안 그러면 흠뻑 젖을 거예요.'),
('col_weather_07','set','a record','set a record','기록을 세우다','make','"make a record"는 다른 의미예요. 새 기록을 세울 때는 set을 써요.','B1','weather',2,7,'record extreme weather snow temperature','The storm set a record for the most rainfall in a single day.','그 폭풍은 하루 최대 강수량 기록을 세웠어요.','This winter has set a record for the lowest temperatures in 50 years.','이번 겨울은 50년 만의 최저 기온 기록을 세웠어요.','The athlete set a new record at the championship yesterday.','그 선수는 어제 챔피언십에서 새 기록을 세웠어요.','July set a record for the most consecutive sunny days here.','7월은 이곳에서 가장 많은 연속 맑은 날 기록을 세웠어요.','The hurricane set a record for wind speed in the region.','그 허리케인은 그 지역에서 풍속 기록을 세웠어요.'),
('col_weather_09','clear','up','clear up','날씨가 맑아지다','become','"become clear"도 맞지만 clear up은 날씨 변화에 자주 쓰이는 자연스러운 표현이에요.','B1','weather',1,9,'clear sky sunshine weather improvement outdoor','The sky cleared up just in time for the outdoor event.','야외 행사에 딱 맞게 날씨가 맑아졌어요.','It should clear up by the afternoon, according to the forecast.','예보에 따르면 오후쯤에는 날씨가 맑아질 거예요.','The weather finally cleared up just before sunset.','날씨가 일몰 직전에 마침내 맑아졌어요.','I hope it clears up by the weekend for our hike.','주말 등산까지 날씨가 맑아지길 바라요.','The fog cleared up as the morning warmed up.','아침이 따뜻해지면서 안개가 걷히고 날이 맑아졌어요.'),
('col_weather_10','drop','in temperature','drop in temperature','기온이 떨어지다','fall','"fall in temperature"도 쓰이지만 drop이 더 급격한 변화를 강조해요.','B1','weather',2,10,'temperature drop cold winter forecast','There''s been a sharp drop in temperature overnight.','밤 사이에 기온이 급격히 떨어졌어요.','The forecast shows a significant drop in temperature for the weekend.','예보에 따르면 주말에 기온이 크게 떨어질 거예요.','There''s usually a drop in temperature once the sun goes down.','해가 지면 보통 기온이 떨어져요.','The sudden drop in temperature surprised everyone at the beach.','갑작스러운 기온 하강에 해변의 모두가 놀랐어요.','You can feel a drop in temperature when you enter the basement.','지하실에 들어가면 기온이 떨어지는 게 느껴져요.'),
('col_weather_12','take','shelter','take shelter','피신하다, 대피하다','find','"find shelter"도 맞지만 take shelter는 즉각적인 행동을 강조해요.','B1','weather',2,12,'shelter storm safety hiding emergency','We took shelter under a tree when the storm hit.','폭풍이 몰아쳤을 때 우리는 나무 아래로 피했어요.','Residents were advised to take shelter during the tornado warning.','주민들은 토네이도 경보 동안 대피하라는 안내를 받았어요.','Hikers took shelter in a cave when the lightning began.','등산객들은 번개가 치기 시작하자 동굴로 피했어요.','We took shelter under the bus stop awning during the downpour.','폭우 동안 우리는 버스 정류장 차양 아래로 피했어요.','The animals took shelter in the barn before the storm arrived.','동물들은 폭풍이 도착하기 전 헛간으로 피했어요.'),
('col_weather_18','go','below zero','go below zero','영하로 내려가다','drop','"drop below zero"도 맞지만 go below zero는 더 구어체적이에요.','B1','weather',2,18,'freezing below zero winter temperature cold','Temperatures are expected to go below zero tonight.','오늘 밤 기온이 영하로 내려갈 것으로 예상돼요.','It hasn''t gone below zero this winter yet.','이번 겨울에는 아직 영하로 내려가지 않았어요.','The temperature went below zero for the first time this fall.','이번 가을 처음으로 기온이 영하로 내려갔어요.','When temperatures go below zero, pipes can freeze and burst.','기온이 영하로 내려가면 수도관이 얼어서 터질 수 있어요.','It went below zero last night, so I''m wearing extra layers today.','어젯밤 영하로 내려가서 오늘은 옷을 더 껴입었어요.'),
('col_weather_19','pour','down','pour down','비가 쏟아지다','fall','"fall down"은 비에 잘 쓰이지 않아요. 비가 세차게 올 때는 pour down을 써요.','B1','weather',1,19,'heavy rain pouring wet storm flood','It started pouring down just as we left the house.','우리가 집을 나서자마자 비가 쏟아지기 시작했어요.','The rain was pouring down so hard we could barely see.','비가 너무 세차게 쏟아져서 거의 아무것도 안 보였어요.','It started pouring down rain just as the wedding ended.','결혼식이 끝나자마자 비가 쏟아지기 시작했어요.','The rain poured down all night and flooded the streets.','비가 밤새 쏟아져서 거리가 침수됐어요.','We could hear the rain pouring down on the metal roof.','양철 지붕 위로 비가 쏟아지는 소리가 들렸어요.'),
('col_weather_03','make','a forecast','make a forecast','예보를 하다','do','"do a forecast"는 어색해요. 날씨 예보를 할 때는 make를 써요.','B2','weather',2,3,'weather forecast meteorology prediction','Meteorologists use data to make accurate weather forecasts.','기상학자들은 데이터를 사용하여 정확한 날씨 예보를 해요.','It''s hard to make a reliable forecast more than a week in advance.','일주일 이상 앞선 예보를 정확하게 하기는 어려워요.','The news channel makes a forecast every morning at seven.','뉴스 채널은 매일 아침 일곱 시에 예보를 해요.','They use satellites and supercomputers to make accurate forecasts.','그들은 정확한 예보를 하기 위해 위성과 슈퍼컴퓨터를 사용해요.','The app makes a forecast for any city in the world.','그 앱은 세계 어느 도시든지 예보를 해줘요.'),
('col_weather_04','break','a record','break a temperature record','기온 기록을 깨다','set','기록을 깰 때는 break, 새 기록을 세울 때는 set — 둘 다 쓰이지만 의미가 달라요.','B2','weather',2,4,'heatwave temperature record extreme heat','Last summer broke the record for the hottest July ever.','지난 여름은 역대 가장 더운 7월 기록을 깼어요.','The city broke multiple temperature records during the heatwave.','도시는 폭염 기간 동안 여러 기온 기록을 깼어요.','This week broke a temperature record for the coldest February ever.','이번 주는 역대 가장 추운 2월 기온 기록을 깼어요.','The town broke a temperature record three times this summer.','그 마을은 올여름 기온 기록을 세 번이나 깼어요.','Scientists say climate change is making us break temperature records more often.','과학자들은 기후 변화로 인해 기온 기록이 더 자주 깨지고 있다고 말해요.'),
('col_weather_08','face','harsh conditions','face harsh conditions','혹독한 날씨를 마주하다','get','"get harsh conditions"는 어색해요. 어려운 상황에 직면할 때는 face를 써요.','B2','weather',2,8,'harsh weather storm mountain expedition','Hikers must be prepared to face harsh conditions in the mountains.','등산객들은 산에서 혹독한 날씨를 마주할 준비를 해야 해요.','The rescue team faced harsh conditions during the blizzard.','구조대는 눈보라 속에서 혹독한 날씨를 마주했어요.','The explorers had to face harsh conditions in the Antarctic.','탐험가들은 남극에서 혹독한 환경을 마주해야 했어요.','Farmers in the region face harsh conditions almost every winter.','그 지역 농부들은 거의 매년 겨울 혹독한 환경을 마주해요.','Construction workers often face harsh conditions on cold mornings.','건설 노동자들은 종종 추운 아침에 혹독한 환경을 마주해요.'),
('col_weather_11','pick','up','pick up (wind)','(바람이) 강해지다','increase','"increase"도 맞지만 pick up은 바람·속도의 증가를 더 자연스럽게 표현해요.','B2','weather',2,11,'wind storm increasing speed weather change','The wind picked up as the storm approached.','폭풍이 다가오면서 바람이 강해졌어요.','Winds are expected to pick up during the evening hours.','저녁 시간대에 바람이 강해질 것으로 예상돼요.','The wind picked up suddenly and knocked over a few chairs.','바람이 갑자기 강해져서 의자 몇 개가 넘어졌어요.','Sailors check the forecast to see if the wind will pick up.','선원들은 바람이 강해질지 보려고 예보를 확인해요.','The wind picked up just as we sat down for our picnic.','우리가 소풍을 위해 앉자마자 바람이 강해졌어요.'),
('col_weather_13','ease','off','ease off (rain)','(비가) 그치다, 약해지다','stop','"stop"도 맞지만 ease off는 점차 약해지는 뉘앙스를 담고 있어요.','B2','weather',2,13,'rain easing lighter weather changing','The rain started to ease off around noon.','비가 정오쯤 점차 그치기 시작했어요.','Let''s wait until the storm eases off before heading out.','폭풍이 약해질 때까지 기다렸다가 나가요.','The rain eased off just enough for us to leave the building.','비가 우리가 건물을 나갈 만큼 약해졌어요.','Let''s wait inside until the rain eases off a bit.','비가 좀 약해질 때까지 안에서 기다려요.','The storm eased off after midnight and we finally slept.','폭풍이 자정 이후 약해져서 우리는 마침내 잠들었어요.'),
('col_weather_14','hold','off','hold off (rain)','(비가) 잠시 멈추다','stop','"stop"도 맞지만 hold off는 비가 일시적으로 내리지 않는 것을 의미해요.','B2','weather',3,14,'rain pause event outdoor hopes weather','The rain held off long enough for us to finish the barbecue.','바비큐를 마칠 만큼 비가 잠시 멈춰줬어요.','I hope the rain holds off until after the graduation ceremony.','졸업식이 끝날 때까지 비가 오지 않았으면 좋겠어요.','I hope the rain holds off until after the soccer game.','축구 경기가 끝날 때까지 비가 안 왔으면 좋겠어요.','The rain held off long enough for us to finish gardening.','비가 우리가 정원 일을 끝낼 만큼 잠시 멈춰줬어요.','Fingers crossed that the rain holds off for the parade.','퍼레이드 동안 비가 안 오기를 빌어요.'),
('col_weather_16','brace','for','brace for a storm','폭풍에 대비하다','prepare','"prepare for"도 맞지만 brace for는 긴박한 대비의 뉘앙스가 있어요.','B2','weather',2,16,'storm hurricane preparation brace emergency','Coastal residents braced for the approaching hurricane.','해안 주민들은 다가오는 허리케인에 대비했어요.','The city is bracing for the worst storm in a decade.','도시는 10년 만의 최악의 폭풍에 대비하고 있어요.','Schools are bracing for a winter storm later this week.','학교들은 이번 주 후반의 겨울 폭풍에 대비하고 있어요.','The town braced for flooding after three days of heavy rain.','그 마을은 사흘간의 폭우 후 홍수에 대비했어요.','Travelers are bracing for delays as the snowstorm approaches.','여행자들은 눈폭풍이 다가오면서 지연에 대비하고 있어요.'),
('col_weather_17','experience','a drought','experience a drought','가뭄을 겪다','have','"have a drought"도 쓰이지만 experience가 더 격식체에서 자주 쓰여요.','B2','weather',2,17,'drought dry land farmer crisis water','The region experienced its worst drought in 30 years.','그 지역은 30년 만에 최악의 가뭄을 겪었어요.','Farmers in the area have been experiencing drought conditions for months.','그 지역 농부들은 몇 달째 가뭄 상황을 겪고 있어요.','Many countries are experiencing droughts due to climate change.','많은 나라들이 기후 변화로 인해 가뭄을 겪고 있어요.','California has experienced several major droughts in recent decades.','캘리포니아는 최근 수십 년간 여러 차례 큰 가뭄을 겪었어요.','Crops fail when farmers experience a long drought.','농부들이 긴 가뭄을 겪으면 농작물이 망쳐요.'),
('col_weather_20','be','under a cloud','be under a cloud','흐린 날씨가 계속되다','have','"have a cloud"는 틀린 표현이에요. 흐린 날씨를 묘사할 때 under a cloud를 써요.','B2','weather',3,20,'cloudy overcast grey sky weather','We''ve been under a cloud all week with no sign of sun.','온 주일 동안 계속 흐려서 햇빛이 전혀 없었어요.','The forecast says we''ll be under a cloud until Friday.','예보에 따르면 금요일까지 계속 흐릴 거래요.','It''s been under a cloud here for almost two weeks straight.','여기는 거의 2주 동안 계속 흐려요.','London is often under a cloud, but locals don''t mind.','런던은 자주 흐리지만 현지인들은 개의치 않아요.','The whole region was under a cloud during the festival weekend.','축제 주말 동안 그 지역 전체가 흐렸어요.'),
('col_weather_C1_01','brave','cold','brave the cold','추위를 무릅쓰다','face','나쁜 날씨를 용감하게 견뎌낸다는 다소 문어적 표현이에요. 뉴스 기사나 여행기에 자주 등장해요.','C1','weather',2,0,'people in snow coats','Thousands braved the cold to watch the parade.','수천 명이 추위를 무릅쓰고 퍼레이드를 봤어요.','We braved the cold for a sunrise hike up the mountain.','우리는 추위를 무릅쓰고 일출 등산을 했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_weather_C1_02','battle','heat','battle the heat','더위와 싸우다','fight','극심한 더위에 맞서 버틴다는 비유적 표현이에요. 여름 기사나 스포츠 보도에서 자주 써요.','C1','weather',2,0,'hot summer sun','Construction workers battle the heat throughout July and August.','건설 노동자들은 7월과 8월 내내 더위와 싸워요.','Marathon runners had to battle the heat during the final stretch.','마라톤 선수들은 마지막 구간에서 더위와 싸워야 했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_weather_C1_03','endure','downpour','endure a downpour','폭우를 견뎌내다','pass','강한 비를 오랜 시간 참고 견딘다는 격식 있는 표현이에요. 야외 행사 보도나 여행기에서 자주 써요.','C1','weather',2,0,'heavy rain crowd','Spectators endured a torrential downpour to witness the match.','관중들은 경기를 보기 위해 억수같은 폭우를 견뎌냈어요.','We endured a downpour while waiting for the bus.','버스를 기다리며 폭우를 견뎌냈어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_weather_C1_04','shelter','rain','shelter from rain','비를 피하다','hide','비를 피하기 위해 잠시 어딘가에 들어간다는 자연스러운 표현이에요. ''hide''는 약간 부자연스러워요.','C1','weather',2,0,'rain shelter awning','We sheltered from the rain under a shop awning.','우리는 가게 차양 아래에서 비를 피했어요.','Hikers sheltered from the rain in a nearby cabin.','등산객들은 근처 오두막에서 비를 피했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_weather_C1_05','wrap','up warm','wrap up warm','따뜻하게 껴입다','dress','추운 날 두꺼운 옷으로 몸을 감싼다는 영국식 표현이에요. ''dress warm''보다 훨씬 자연스러워요.','C1','weather',2,0,'winter coat scarf','Wrap up warm — it''s freezing outside.','따뜻하게 껴입어요. 밖이 정말 추워요.','The children wrapped up warm before heading out to play in the snow.','아이들은 눈 속에서 놀러 나가기 전에 따뜻하게 껴입었어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_weather_C2_01','weather','storm','weather a storm','위기를 견뎌내다','survive','실제 폭풍을 견디는 뜻과 비유적으로 위기를 헤쳐나간다는 뜻 모두로 써요. 비즈니스 사설이나 정치 기사의 단골 표현이에요.','C2','weather',3,0,'ship in storm','The vessel weathered the storm despite sustaining considerable damage.','그 선박은 상당한 손상을 입었지만 폭풍을 견뎌냈어요.','The firm has weathered numerous economic storms over its centenary history.','그 회사는 100년 역사 동안 수많은 경제 위기를 헤쳐왔어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_weather_C2_02','brave','elements','brave the elements','악천후를 무릅쓰다','face','비, 눈, 바람 등 자연의 가혹한 조건에도 굴하지 않고 나선다는 문학적·격식 표현이에요. 여행기나 등반 기사에 자주 등장해요.','C2','weather',3,0,'hiker in blizzard','Hundreds of pilgrims braved the elements to attend the dawn ceremony.','수백 명의 순례자들이 악천후를 무릅쓰고 새벽 의식에 참석했어요.','The expedition team braved the elements for six gruelling weeks.','원정대는 6주간의 혹독한 시간 동안 악천후를 무릅썼어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_weather_C2_03','endure','inclement weather','endure inclement weather','궂은 날씨를 견디다','have','''inclement weather''는 격식 있는 ''궂은 날씨''예요. 항공 안내, 공식 발표, 기상 보고서의 표준 표현이에요.','C2','weather',3,0,'airport delay snow','Passengers were asked to endure the inclement weather while the runway was cleared.','활주로 정리 동안 승객들은 궂은 날씨를 견뎌야 했어요.','The infrastructure must endure inclement weather throughout the winter months.','그 기반 시설은 겨울 내내 궂은 날씨를 견뎌야 해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_weather_C2_04','herald','change','herald a change','변화를 알리다','show','어떤 사건이나 현상이 더 큰 변화의 신호탄이 된다는 문학적·언론적 표현이에요. 사설이나 분석 기사에 잘 어울려요.','C2','weather',3,0,'autumn frost','The early frost may herald a change in the region''s growing season.','이른 서리는 그 지역 농작기의 변화를 알리는 신호일 수 있어요.','Falling barometric pressure heralds a change in the prevailing weather pattern.','기압 하락은 우세한 기상 패턴의 변화를 예고해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_weather_C2_05','shroud','fog','shroud in fog','안개로 뒤덮다','cover','안개나 어둠이 무언가를 완전히 가려 신비롭거나 음울한 분위기를 자아낼 때 써요. 문학적·서술적 표현이에요.','C2','weather',3,0,'foggy valley','The valley was shrouded in fog so dense that visibility fell to mere metres.','계곡은 가시거리가 몇 미터에 불과할 정도로 짙은 안개로 뒤덮였어요.','At dawn, the medieval town remained shrouded in fog.','동틀 무렵, 그 중세 도시는 여전히 안개에 휩싸여 있었어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_work_21','have','meeting','have a meeting','회의를 하다','do','"do a meeting"이 아니라 "have a meeting"이 자연스러워요. meeting은 take/make와도 어울리지 않아요.','A2','work',1,0,'office meeting professionals conference room','We have a meeting at 3 PM today.','오늘 오후 3시에 회의가 있어요.','Let''s have a meeting to discuss the new project.','새 프로젝트 논의를 위해 회의를 합시다.','The team had a meeting about next quarter''s goals.','팀은 다음 분기 목표에 대해 회의를 했어요.','Can we have a meeting before the deadline?','마감 전에 회의를 할 수 있을까요?','I have a meeting with my manager every Monday.','저는 매주 월요일에 매니저와 회의가 있어요.'),
('col_work_22','take','break','take a break','휴식을 취하다','have','한국어 "쉬다"는 take a break — have a break도 영국식에서 쓰이지만 take가 더 보편적이에요.','A2','work',1,0,'office break coffee relaxing desk','Let''s take a break for ten minutes.','10분 동안 쉬어요.','You''ve been working all morning — take a break.','아침 내내 일했어요 — 쉬세요.','I take a break every two hours to stretch.','저는 2시간마다 스트레칭하려고 휴식을 취해요.','The team took a short break before continuing the meeting.','팀은 회의를 계속하기 전에 짧은 휴식을 취했어요.','It''s important to take a break from screens.','화면에서 휴식을 취하는 게 중요해요.'),
('col_work_25','run','late','run late','늦어지다','go','"go late"는 어색해요. 일정이 늦어질 때는 run late를 써요.','A2','work',1,0,'person running late watch clock office','Sorry, I''m running late for the meeting.','죄송해요, 회의에 늦어지고 있어요.','The train is running 15 minutes late today.','오늘 기차가 15분 늦게 운행되고 있어요.','We''re running a bit late — start without us.','조금 늦어지고 있어요 — 먼저 시작하세요.','She always runs late to morning classes.','그녀는 항상 아침 수업에 늦어요.','The project is running late due to delays.','프로젝트가 지연 때문에 늦어지고 있어요.'),
('col_work_01','make','a decision','make a decision','결정을 내리다','do','"do a decision"은 틀린 표현이에요. 결정할 때는 make를 써요.','B1','work',1,1,'decision office business meeting thinking','I need to make a decision about the new project by Friday.','금요일까지 새 프로젝트에 대한 결정을 내려야 해요.','She made a quick decision and informed the team.','그녀는 빠르게 결정을 내리고 팀에 알렸어요.','It''s tough to make a decision when both options look equally good.','두 옵션이 모두 똑같이 좋아 보일 때는 결정을 내리기 어려워요.','They made a decision to expand into the European market.','그들은 유럽 시장으로 확장하기로 결정을 내렸어요.','I made the decision to switch careers after a lot of thought.','저는 많은 고민 끝에 직업을 바꾸는 결정을 내렸어요.'),
('col_work_04','hold','a meeting','hold a meeting','회의를 열다','make','"make a meeting"은 틀린 표현이에요. 회의를 개최할 때는 hold를 써요.','B1','work',1,4,'meeting office conference boardroom team','We''re holding a team meeting every Monday at 9 a.m.','우리는 매주 월요일 오전 9시에 팀 회의를 열어요.','The director held an emergency meeting to address the issue.','이사는 그 문제를 해결하기 위해 긴급 회의를 열었어요.','We held a meeting to review the budget for next year.','내년 예산을 검토하기 위해 회의를 열었어요.','He holds short standing meetings to keep things efficient.','그는 효율성을 위해 짧은 스탠딩 회의를 열어요.','Let''s hold a meeting after lunch to discuss the new proposal.','새 제안을 논의하기 위해 점심 후에 회의를 열어요.'),
('col_work_05','meet','a deadline','meet a deadline','마감 기한을 지키다','reach','"reach a deadline"은 어색해요. 마감을 지킬 때는 meet a deadline을 써요.','B1','work',1,5,'deadline work pressure schedule office','The whole team worked overtime to meet the deadline.','팀 전체가 마감을 지키기 위해 초과 근무를 했어요.','She always meets her deadlines without fail.','그녀는 항상 어김없이 마감을 지켜요.','We just barely met the deadline thanks to everyone''s hard work.','모두의 노력 덕분에 우리는 간신히 마감 기한을 지켰어요.','She met the deadline despite a last-minute change in requirements.','그녀는 막판 요구 사항 변경에도 불구하고 마감을 지켰어요.','We need a buffer of two days to confidently meet the deadline.','자신 있게 마감을 지키려면 이틀의 여유가 필요해요.'),
('col_work_06','make','progress','make progress','진전을 이루다','do','"do progress"는 틀린 표현이에요. 진전이 있을 때는 make를 써요.','B1','work',1,6,'progress work project success development','We''re making good progress on the new software update.','새 소프트웨어 업데이트에서 좋은 진전을 이루고 있어요.','It was slow at first, but we''re finally making real progress.','처음에는 느렸지만 이제는 진정한 진전을 이루고 있어요.','I''ve been making slow but steady progress in learning Korean.','저는 한국어를 배우면서 느리지만 꾸준한 진전을 이루고 있어요.','Our team made remarkable progress in just three weeks.','우리 팀은 단 3주 만에 놀라운 진전을 이뤘어요.','You make progress every time you take small consistent steps.','꾸준히 작은 발걸음을 떼는 매 순간 진전을 이루는 거예요.'),
('col_work_07','give','a presentation','give a presentation','발표를 하다','make','"make a presentation"도 쓰이지만 give가 더 자연스럽고 자주 쓰여요.','B1','work',1,7,'presentation meeting slides office professional','She gave a confident presentation to the board of directors.','그녀는 이사회에 자신감 있게 발표를 했어요.','He practiced all week before giving his first big presentation.','그는 첫 번째 중요한 발표를 하기 전에 일주일 내내 연습했어요.','He gave a 20-minute presentation on the quarterly results.','그는 분기 결과에 대한 20분 발표를 했어요.','I have to give a presentation in English for the first time tomorrow.','저는 내일 처음으로 영어로 발표를 해야 해요.','She gave a presentation that won the team a major contract.','그녀는 팀이 큰 계약을 따내는 발표를 했어요.'),
('col_work_08','take','notes','take notes','메모하다, 필기하다','make','"make notes"도 쓰이지만 take notes가 더 일반적이에요.','B1','work',1,8,'notes notebook meeting office writing','Please take notes during the meeting in case someone asks later.','나중에 누가 물어볼 경우에 대비해 회의 중에 메모해 주세요.','She took detailed notes during the client call.','그녀는 고객 통화 중에 자세한 메모를 했어요.','He takes notes in a small notebook he carries everywhere.','그는 항상 들고 다니는 작은 수첩에 메모를 해요.','I took notes on my laptop during the all-day workshop.','저는 종일 진행된 워크숍 동안 노트북에 메모를 했어요.','Taking notes by hand can help you remember more.','손으로 메모하면 더 잘 기억하는 데 도움이 돼요.'),
('col_work_10','pay','attention','pay attention','주의를 기울이다','give','"give attention"보다 pay attention이 훨씬 더 자주 쓰여요.','B1','work',1,10,'attention focus work meeting briefing','Please pay attention to the safety guidelines before starting.','시작 전에 안전 지침에 주의를 기울여 주세요.','He failed to pay attention during the briefing and missed key points.','그는 브리핑 중 주의를 기울이지 않아 핵심 사항을 놓쳤어요.','Please pay attention to the new compliance rules.','새 컴플라이언스 규정에 주의를 기울여 주세요.','She pays attention to small details that others might miss.','그녀는 다른 사람들이 놓칠 수 있는 작은 세부 사항에 주의를 기울여요.','I had to pay extra attention during the audit week.','저는 감사 주간에 특별히 주의를 기울여야 했어요.'),
('col_work_14','submit','a report','submit a report','보고서를 제출하다','send','"send a report"도 맞지만 submit은 공식적인 제출을 강조해요.','B1','work',1,14,'report submit office deadline work','Please submit the monthly report by the end of Friday.','월간 보고서를 금요일 끝까지 제출해 주세요.','She submitted the report ahead of the deadline.','그녀는 마감 전에 보고서를 제출했어요.','She submitted the quarterly report two days before the deadline.','그녀는 마감 이틀 전에 분기 보고서를 제출했어요.','Please submit your report through the new internal portal.','새 내부 포털을 통해 보고서를 제출해 주세요.','He submitted a brief progress report at the end of each week.','그는 매주 말 간단한 진행 보고서를 제출했어요.'),
('col_work_23','give','presentation','give a presentation','발표를 하다','make','"make a presentation"도 가능하지만 give a presentation이 더 자연스러워요.','B1','work',1,0,'business presentation slide screen audience','I have to give a presentation tomorrow morning.','내일 아침에 발표를 해야 해요.','She gave a great presentation about market trends.','그녀는 시장 동향에 관한 훌륭한 발표를 했어요.','Have you ever given a presentation in English?','영어로 발표해 본 적 있어요?','He gave a presentation to the entire department.','그는 부서 전체에게 발표를 했어요.','I''m nervous about giving a presentation to the board.','이사회 앞에서 발표하려니 긴장돼요.'),
('col_work_24','run','business','run a business','사업을 운영하다','do','"do business"는 거래/장사를 한다는 다른 의미예요. 운영 자체는 run a business.','B1','work',1,0,'business owner shop entrepreneur store','It''s hard work to run a small business.','작은 사업을 운영하는 건 힘든 일이에요.','She runs a successful online business.','그녀는 성공적인 온라인 사업을 운영해요.','My uncle has been running a bakery for 20 years.','우리 삼촌은 20년째 빵집을 운영하고 있어요.','You need a license to run a business here.','여기서 사업을 운영하려면 면허가 필요해요.','They run a family-owned business together.','그들은 함께 가족 사업을 운영해요.'),
('col_work_02','take','responsibility','take responsibility','책임을 지다','have','"have responsibility"도 맞지만 take는 적극적으로 책임을 떠맡는 뉘앙스예요.','B2','work',1,2,'responsibility leadership accountability office','He took full responsibility for the mistake in the report.','그는 보고서의 실수에 대해 전적인 책임을 졌어요.','Good leaders take responsibility even when things go wrong.','훌륭한 리더는 일이 잘못되어도 책임을 져요.','She''s ready to take responsibility for the team''s results.','그녀는 팀 결과에 대한 책임을 질 준비가 됐어요.','You should take responsibility instead of blaming others.','다른 사람을 탓하기보다 책임을 져야 해요.','The new hire was eager to take responsibility from day one.','신입은 첫날부터 책임을 지려는 의지가 강했어요.'),
('col_work_03','give','feedback','give feedback','피드백을 주다','make','"make feedback"은 어색해요. 피드백을 줄 때는 give를 써요.','B2','work',1,3,'feedback review office work professional','The manager gave detailed feedback on the quarterly report.','매니저는 분기 보고서에 대한 자세한 피드백을 줬어요.','It''s important to give constructive feedback in a respectful way.','존중하는 방식으로 건설적인 피드백을 주는 것이 중요해요.','I always ask my team to give feedback after each project.','저는 매 프로젝트 후에 팀에 항상 피드백을 부탁해요.','She gave me honest feedback that really helped me improve.','그녀는 제가 정말 발전하는 데 도움이 되는 솔직한 피드백을 줬어요.','Giving feedback is easier when there is mutual trust.','상호 신뢰가 있으면 피드백을 주기가 더 쉬워요.'),
('col_work_09','run','a project','run a project','프로젝트를 이끌다','manage','"manage a project"도 맞지만 run은 더 실질적인 운영을 강조해요.','B2','work',2,9,'project management office team leadership','She''s been running the new product launch project for six months.','그녀는 6개월째 새 제품 출시 프로젝트를 이끌고 있어요.','He ran the infrastructure project from start to finish.','그는 인프라 프로젝트를 처음부터 끝까지 이끌었어요.','He''s been running multiple projects at the same time.','그는 여러 프로젝트를 동시에 이끌고 있어요.','Running a project remotely requires excellent communication.','원격으로 프로젝트를 이끌려면 뛰어난 소통 능력이 필요해요.','She''s been running the redesign project for nine months.','그녀는 9개월째 리디자인 프로젝트를 이끌고 있어요.'),
('col_work_11','set','targets','set targets','목표를 설정하다','make','"make targets"는 어색해요. 목표를 정할 때는 set을 써요.','B2','work',2,11,'targets goals work performance KPI','The sales team sets quarterly targets at the start of each month.','영업팀은 매월 초에 분기별 목표를 설정해요.','It''s important to set realistic targets that the team can achieve.','팀이 달성할 수 있는 현실적인 목표를 설정하는 것이 중요해요.','They set targets at the start of every fiscal year.','그들은 매 회계연도 초에 목표를 설정해요.','She set personal targets that were aligned with team goals.','그녀는 팀 목표와 일치하는 개인 목표를 설정했어요.','Setting clear targets helps everyone stay focused.','명확한 목표를 설정하면 모두가 집중하는 데 도움이 돼요.'),
('col_work_12','handle','a complaint','handle a complaint','불만을 처리하다','solve','"solve a complaint"는 어색해요. 불만을 처리할 때는 handle을 써요.','B2','work',2,12,'complaint customer service HR professional','She handled the customer''s complaint professionally and calmly.','그녀는 고객의 불만을 전문적이고 침착하게 처리했어요.','The HR team is trained to handle complaints fairly.','인사팀은 불만을 공정하게 처리하도록 교육받았어요.','The team is trained to handle complaints with empathy.','팀은 공감을 가지고 불만을 처리하도록 교육받았어요.','He handled the customer''s complaint better than expected.','그는 예상보다 더 잘 고객의 불만을 처리했어요.','Handling complaints quickly can turn unhappy customers into loyal ones.','불만을 빠르게 처리하면 불만 고객을 충성 고객으로 바꿀 수 있어요.'),
('col_work_16','put','in overtime','put in overtime','초과 근무를 하다','do','"do overtime"도 맞지만 put in overtime이 더 구어체적이에요.','B2','work',2,16,'overtime work late office long hours','She put in a lot of overtime to finish the project on time.','그녀는 프로젝트를 제때 마치기 위해 초과 근무를 많이 했어요.','He puts in overtime almost every week without extra pay.','그는 추가 급여도 없이 거의 매주 초과 근무를 해요.','Some teams put in overtime to launch the product on time.','일부 팀은 제품을 제때 출시하기 위해 초과 근무를 했어요.','Putting in too much overtime hurts long-term productivity.','너무 많은 초과 근무는 장기적인 생산성에 해를 끼쳐요.','She refused to put in overtime without proper compensation.','그녀는 적절한 보상 없이는 초과 근무를 거부했어요.'),
('col_work_18','take','initiative','take initiative','주도적으로 행동하다','have','"have initiative"는 성격을 설명할 때 쓰여요. 행동할 때는 take initiative를 써요.','B2','work',2,18,'initiative leadership proactive office work','He took initiative and fixed the bug before anyone asked him to.','그는 주도적으로 행동하여 누가 요청하기 전에 버그를 수정했어요.','We need someone who is willing to take initiative in this role.','이 역할에서 주도적으로 행동할 의지가 있는 사람이 필요해요.','Junior employees are encouraged to take initiative on small projects.','주니어 직원들은 작은 프로젝트에서 주도적으로 행동하도록 권장돼요.','She took the initiative to organize a quarterly retrospective.','그녀는 분기별 회고를 조직하는 주도적인 행동을 했어요.','Taking initiative often leads to growth in your career.','주도적으로 행동하는 것은 종종 경력 성장으로 이어져요.'),
('col_work_20','go','on leave','go on leave','휴가를 가다','take','"take leave"도 맞지만 go on leave는 공식적인 자리를 비우는 것을 강조해요.','B2','work',2,20,'leave vacation absence office HR','She went on maternity leave for three months.','그녀는 3개월 동안 육아 휴직을 갔어요.','He went on leave to recover from his illness.','그는 병에서 회복하기 위해 휴가를 갔어요.','He went on parental leave for two months after the birth.','그는 출산 후 두 달간 육아 휴직을 갔어요.','She went on leave to take care of her elderly mother.','그녀는 연로한 어머니를 돌보기 위해 휴가를 갔어요.','When she went on leave, the team divided up her responsibilities.','그녀가 휴가를 갔을 때 팀이 그녀의 책임을 나눠 가졌어요.'),
('col_work_26','close','deal','close a deal','거래를 성사시키다','make','"make a deal"은 거래를 제안/타결 의미. close a deal은 최종 마무리에 초점.','B2','work',1,0,'business handshake contract signing executives','We closed the deal after weeks of negotiation.','몇 주간의 협상 끝에 거래를 성사시켰어요.','She closed a major deal with the new client.','그녀는 새 고객과 큰 거래를 성사시켰어요.','They closed the deal at the last minute.','그들은 마지막 순간에 거래를 성사시켰어요.','Closing this deal will boost our quarterly results.','이 거래를 성사시키면 분기 실적이 크게 오를 거예요.','He''s known for closing deals quickly.','그는 거래를 빠르게 성사시키는 것으로 유명해요.'),
('col_work_13','delegate','tasks','delegate tasks','업무를 위임하다','give','"give tasks"도 쓰이지만 delegate는 권한을 위임한다는 뉘앙스예요.','C1','work',3,13,'delegate task management team leadership','A good manager knows when to delegate tasks to the team.','좋은 매니저는 언제 팀에 업무를 위임할지 알아요.','She delegated the research task to her junior colleague.','그녀는 연구 업무를 후배 동료에게 위임했어요.','She delegates tasks based on each person''s strengths.','그녀는 각 사람의 강점에 따라 업무를 위임해요.','Learning to delegate tasks is essential for new managers.','신임 관리자에게 업무를 위임하는 법을 배우는 것은 필수예요.','He struggled at first but learned to delegate tasks effectively.','그는 처음에는 힘들어했지만 효과적으로 업무를 위임하는 법을 배웠어요.'),
('col_work_15','close','a deal','close a deal','거래를 성사시키다','make','"make a deal"도 쓰이지만 close a deal은 협상을 마무리하는 뉘앙스예요.','C1','work',2,15,'deal business negotiation sales success','The sales team finally closed the deal after three months of negotiations.','영업팀은 세 달간의 협상 끝에 마침내 거래를 성사시켰어요.','She flew to Tokyo to close the deal in person.','그녀는 직접 거래를 성사시키기 위해 도쿄로 날아갔어요.','They closed the deal after a long video call with the partners.','그들은 파트너들과의 긴 영상 통화 끝에 거래를 성사시켰어요.','She''s great at closing deals with hesitant clients.','그녀는 망설이는 고객과 거래를 성사시키는 데 뛰어나요.','Closing a deal often requires patience and timing.','거래 성사에는 종종 인내와 타이밍이 필요해요.'),
('col_work_17','raise','a concern','raise a concern','우려를 제기하다','make','"make a concern"은 틀린 표현이에요. 우려를 표명할 때는 raise를 써요.','C1','work',2,17,'concern workplace safety issue meeting','She raised a concern about the safety of the new process.','그녀는 새 프로세스의 안전성에 대한 우려를 제기했어요.','If you have any concerns, please don''t hesitate to raise them.','우려 사항이 있으면 망설이지 말고 제기해 주세요.','He raised concerns about the new policy in the team chat.','그는 팀 채팅에서 새 정책에 대한 우려를 제기했어요.','Please raise any concerns during the open Q&A session.','공개 Q&A 세션 중에 우려 사항을 제기해 주세요.','She raised her concern privately with the project manager.','그녀는 프로젝트 매니저와 사석에서 우려를 제기했어요.'),
('col_work_19','reach','a consensus','reach a consensus','합의에 이르다','make','"make a consensus"는 틀린 표현이에요. 합의할 때는 reach a consensus를 써요.','C1','work',2,19,'consensus agreement team meeting decision','After a long discussion, the team reached a consensus on the approach.','긴 토론 끝에 팀은 접근 방식에 대한 합의에 이르렀어요.','It was difficult to reach a consensus given everyone''s different opinions.','모두의 의견이 달랐기 때문에 합의에 이르기가 어려웠어요.','The committee reached a consensus on the final design.','위원회는 최종 디자인에 대한 합의에 이르렀어요.','They couldn''t reach a consensus and decided to postpone the vote.','그들은 합의에 이르지 못해 투표를 연기하기로 결정했어요.','Reaching a consensus across departments took several weeks.','부서 간 합의에 이르는 데 몇 주가 걸렸어요.'),
('col_work_C1_01','meet','a deadline','meet a deadline','마감을 지키다','keep','직장에서 가장 자주 쓰이는 콜로케이션 중 하나예요. ''keep a deadline''은 어색하고 반드시 ''meet''을 써야 해요.','C1','work',2,0,'deadline calendar work','We''re struggling to meet the deadline.','마감을 맞추느라 고전하고 있어요.','She always meets her deadlines, no matter what.','그녀는 무슨 일이 있어도 늘 마감을 지켜요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_work_C1_02','delegate','tasks','delegate tasks','업무를 위임하다','give','관리자가 부하 직원에게 일을 맡기는 격식 있는 표현이에요. ''give tasks''보다 훨씬 전문적으로 들려요.','C1','work',2,0,'manager delegating team','Good managers know how to delegate tasks effectively.','훌륭한 관리자는 업무를 효과적으로 위임할 줄 알아요.','I need to delegate more tasks to focus on strategy.','전략에 집중하려면 업무를 더 많이 위임해야 해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_work_C1_03','step','up','step up','책임지고 나서다','stand','필요할 때 자발적으로 더 큰 역할이나 책임을 맡는다는 뜻이에요. 리더십 맥락에서 자주 들려요.','C1','work',2,0,'leadership team meeting','When the manager left, she stepped up immediately.','매니저가 떠나자 그녀가 바로 나섰어요.','We need someone to step up and lead the project.','나서서 프로젝트를 이끌 사람이 필요해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_work_C1_04','weigh','in','weigh in on','의견을 제시하다','say','논의나 결정에 본인의 의견을 보태는 격식 있는 표현이에요. 회의에서 ''Could you weigh in on this?''처럼 자주 써요.','C1','work',2,0,'meeting discussion opinion','Would you like to weigh in on the proposal?','이 제안에 의견 주실래요?','Several experts weighed in on the debate.','여러 전문가가 그 논쟁에 의견을 보탰어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_work_C1_05','follow','through','follow through','끝까지 해내다','finish','시작한 일을 끝까지 책임지고 완수한다는 뜻이에요. 약속이나 계획을 지키는 신뢰성을 강조할 때 써요.','C1','work',2,0,'project completion checklist','He always follows through on his commitments.','그는 늘 약속을 끝까지 지켜요.','Talking is easy, but you have to follow through.','말은 쉬워요, 끝까지 해내는 게 중요해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_work_C2_01','exercise','discretion','exercise discretion','재량을 발휘하다','use','재량껏 판단해서 결정한다는 격식 있는 표현이에요. 비즈니스, 법률, 정책 문서에서 표준이에요.','C2','work',3,0,'executive office','Managers are expected to exercise discretion when handling client complaints.','관리자들은 고객 불만을 처리할 때 재량을 발휘해야 해요.','The judge exercised discretion in reducing the sentence.','판사는 형량을 줄이는 데 재량을 발휘했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_work_C2_02','garner','support','garner support','지지를 얻다','get','시간과 노력을 들여 지지나 인정을 모은다는 뜻이에요. 정치, 비즈니스 기사에서 자주 보여요.','C2','work',3,0,'boardroom meeting','The proposal garnered widespread support across departments.','그 제안은 부서 전반에 걸쳐 폭넓은 지지를 얻었어요.','She garnered the board''s support for the restructuring plan.','그녀는 구조조정 계획에 대해 이사회의 지지를 얻었어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_work_C2_03','exert','influence','exert influence','영향력을 행사하다','have','의도적으로 영향력을 작용시킨다는 격식 표현이에요. ''have influence''보다 능동적이고 강한 뉘앙스예요.','C2','work',3,0,'corporate negotiation','Senior partners exert considerable influence over hiring decisions.','시니어 파트너들은 채용 결정에 상당한 영향력을 행사해요.','Lobbyists exert influence behind the scenes.','로비스트들은 뒤에서 영향력을 행사해요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_work_C2_04','spearhead','initiative','spearhead an initiative','주도하다','lead','새 프로젝트나 운동을 가장 앞장서서 이끈다는 뜻이에요. 임원급 업적을 설명할 때 적절해요.','C2','work',3,0,'leadership conference','She spearheaded the diversity initiative across the firm''s global offices.','그녀는 회사 전 세계 지사에 걸쳐 다양성 이니셔티브를 주도했어요.','He has spearheaded several pioneering initiatives in fintech.','그는 핀테크 분야에서 여러 선구적인 이니셔티브를 주도했어요.',NULL,NULL,NULL,NULL,NULL,NULL),
('col_work_C2_05','mitigate','risk','mitigate risk','위험을 완화하다','reduce','리스크의 영향이나 가능성을 체계적으로 줄인다는 의미예요. 금융, 컨설팅, 감사 보고서의 표준 표현이에요.','C2','work',3,0,'risk management chart','The new compliance framework is designed to mitigate operational risk.','새 컴플라이언스 체계는 운영 리스크를 완화하기 위해 설계됐어요.','Diversification helps mitigate investment risk.','분산 투자는 투자 위험을 완화하는 데 도움이 돼요.',NULL,NULL,NULL,NULL,NULL,NULL);
